-- Poems batch 205
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('ae800f7d-bf89-497a-8c05-5484e7259c07','小春六花 小桃','岳珂','宋','宋诗','song-poetry','','[]','霜晴著物利于刀，漏洩陽和是小桃。',64,'全唐诗/poet.song.193000.json','["霜晴著物利于刀，漏洩陽和是小桃。", "春色已看九重醉，秋風不管十分饕。", "青枝似愜烏棲月，紅浪不翻龍化濤。", "穠艷自同時節異，夫君於此見清高。"]'),
('a5c8ce87-5b22-4e06-8512-009b3e10219e','小春六花 黄菊','岳珂','宋','宋诗','song-poetry','','[]','花時已是過重陽，翠幹重開滿地黄。',64,'全唐诗/poet.song.193000.json','["花時已是過重陽，翠幹重開滿地黄。", "不爲晨暉借顔色，要將晚節看芬芳。", "宅邊豈必白衣至，甕裏不妨紅友香。", "喚起閒情老元亮，頹然一醉答秋光。"]'),
('9808a4a1-7916-47f2-b6f2-28e268f83cd9','小春六花 李花','岳珂','宋','宋诗','song-poetry','','[]','一枝眼底物華新，翠袖清霜更可人。',64,'全唐诗/poet.song.193000.json','["一枝眼底物華新，翠袖清霜更可人。", "靚色不須誇縞夜，韶容聊復返青春。", "日烘有意姿仍潔，露洗無言態更真。", "不趁繁華更孤迥，爲君喚起雪精神。"]'),
('eab418c0-57b9-4fd1-ae70-60a31405f49f','奉謝何正父日蝦荔實茶果宣瓜蜜朮之貺酬以露芽','岳珂','宋','宋诗','song-poetry','','[]','打門軍將到山家，小國長鬚海上楂。',64,'全唐诗/poet.song.193000.json','["打門軍將到山家，小國長鬚海上楂。", "冰片霞餐正浮蜜，雪穰風味更宜茶。", "頗思野䔩盤無荔，安得珍投瓊報瓜。", "汎水舊游渾不記，且看七椀岸巾紗。"]'),
('767acc44-9479-474f-9a13-64c26648495b','奉謝趙季茂遣餽鱟醤','岳珂','宋','宋诗','song-poetry','','[]','逃禪繡佛正長齋，誰遣缾罌海上來。',64,'全唐诗/poet.song.193000.json','["逃禪繡佛正長齋，誰遣缾罌海上來。", "鮫室玄雲按犀甲，蜃樓紅霧染珠胎。", "把螯便合閒雙手，據殻未應期九垓。", "尊俎折衝定無敵，江湖歲晚莫論才。"]'),
('80cec0bb-0f5b-4523-ba15-fb576c21fe01','太平宮遇雨','岳珂','宋','宋诗','song-poetry','','[]','山居五旬晴，山行一日雨。',48,'全唐诗/poet.song.193000.json','["山居五旬晴，山行一日雨。", "太平咫尺間，千里隔跬步。", "黄泥深三尺，風聲更號怒。", "誰語逋客知，山靈倘留汝。"]'),
('0714936d-f263-4f4e-a2ab-d28d30757695','宿太平宮葆清庵自和少年壁間戊辰歲所作韻是日聞虜大入滁濠二首  其一','岳珂','宋','宋诗','song-poetry','','[]','西風幾載動邊塵，不見長平奉國珍。',64,'全唐诗/poet.song.193000.json','["西風幾載動邊塵，不見長平奉國珍。", "汗浹歷時嘶石馬，鋒銷何日鑄金人。", "消磨日月平生志，慚媿煙霞自在身。", "天意不關人事倦，新醅小漉葛頭巾。"]'),
('07ec622a-40a7-459f-b068-2ee7af70cbc6','宿太平宮葆清庵自和少年壁間戊辰歲所作韻是日聞虜大入滁濠二首  其二','岳珂','宋','宋诗','song-poetry','','[]','書閣新宮記五雲，祠官來奉帝臺珍。',64,'全唐诗/poet.song.193000.json','["書閣新宮記五雲，祠官來奉帝臺珍。", "卜鄰巖穴無公事，拜賜江湖作散人。", "玩月吟風閒詠客，看雲管竹繫官身。", "從今便了草廬願，郭泰應無墊角巾。"]'),
('96e88037-967b-41f5-b3e9-d21781da2c7a','以廬山所産天花蕈冬筍玉延餉趙季茂通判','岳珂','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','已認山家作當家，與猨分栗雀分茶。',64,'全唐诗/poet.song.193000.json','["已認山家作當家，與猨分栗雀分茶。", "氣先十月地抽笋，光現五臺天雨花。", "幸有玉延炊夜月，肯令繡谷嚥朝霞。", "憑君試雋山中味，却較閒忙定不差。"]'),
('223c64f3-ac9b-475b-95d2-d11869e234ba','趙季茂遺予郭索侑之以詩予早上亦遣山肴兩介蓋相與駕肩也因和二首  其一','岳珂','宋','宋诗','song-poetry','','[]','驛書傳驛使，江蟹出江湄。',48,'全唐诗/poet.song.193000.json','["驛書傳驛使，江蟹出江湄。", "目早同蝦睅，螯曾與虎持。", "紫髯卸金甲，赤髓映瓊肌。", "正是清霜月，相從無厭時。"]'),
('10bd8cc6-a669-4820-9024-96553f21569b','趙季茂遺予郭索侑之以詩予早上亦遣山肴兩介蓋相與駕肩也因和二首  其二','岳珂','宋','宋诗','song-poetry','','[]','倚桂傍巖麓，采芝行谷湄。',48,'全唐诗/poet.song.193000.json','["倚桂傍巖麓，采芝行谷湄。", "偶因山雨駐，何有嶺雲持。", "鼎芼朝欺腹，窗寒夜切肌。", "開奩應一笑，會有憶人時。"]'),
('a110d9c4-d0f0-4435-9917-0bea1e3a168d','趙季茂有詩來適山間劚地得筍因以遺之併賡韻','岳珂','宋','宋诗','song-poetry','','[]','籬菊初黄楓葉丹，蒼筠共此屋三間。',64,'全唐诗/poet.song.193000.json','["籬菊初黄楓葉丹，蒼筠共此屋三間。", "拂天未带山雲白，斸地已凝湘暈斑。", "玉版有時堪咀嚼，石欄何日共躋攀。", "山家聊送清班兆，且爲屏星纖九關。"]'),
('1d79195c-a1ec-4eee-a489-e6aabed9d0a2','葆清值雨二首  其一','岳珂','宋','宋诗','song-poetry','','[]','積雨將旬浹，都無一日晴。',48,'全唐诗/poet.song.193000.json','["積雨將旬浹，都無一日晴。", "簷寒多雀噪，路滑少人行。", "雲氣連山暗，霜威徹骨清。", "更憐敧枕處，終夕聽泉聲。"]'),
('20571aa8-e8b2-4cd9-a2d3-8c99ad21135a','葆清值雨二首  其二','岳珂','宋','宋诗','song-poetry','','[]','松竹鎖靈宅，塵埃了不侵。',48,'全唐诗/poet.song.193000.json','["松竹鎖靈宅，塵埃了不侵。", "洞龍隨劍吷，檻鶴識琴心。", "路指三峰近，山通一徑深。", "壁間少年字，陳跡不堪尋。"]'),
('3ee6dc02-a45b-4e04-aa02-af75734d3583','予老病倦煩入山兩月頗得靜中趣良月六日趙南仲端明朱子明戶部曾編摩忽皆專介王囦衜諸人亦來而東老姪自石門至閣皂劉道士又以詩卷爲贄戲成','岳珂','宋','宋诗','song-poetry','','[]','鼓鐘不合饗鶢鶋，人事何因到野廬。',64,'全唐诗/poet.song.193000.json','["鼓鐘不合饗鶢鶋，人事何因到野廬。", "玉節金臺新貴字，寶章琰刻故交書。", "葛冠道士重溫卷，芝砌郎君亦下車。", "忽憶蘇州風雨夕，空山落葉昔何如。"]'),
('07d7fb4a-51b5-468a-8948-d75c6bd0a974','設醮太平宮竣事呈偕行諸君二首  其一','岳珂','宋','宋诗','song-poetry','','[]','星壇仙簴韻瓊瑶，仿髴神斿下九霄。',64,'全唐诗/poet.song.193000.json','["星壇仙簴韻瓊瑶，仿髴神斿下九霄。", "龍駕清都三境接，蜺旌絳節百靈朝。", "霜澄夜氣俱明徹，雲澹秋容想泬寥。", "耿耿寸衷天所鑒，憂時惟冀五兵銷。"]'),
('a836e4db-a5a9-41f8-8fa5-2107f62708fd','設醮太平宮竣事呈偕行諸君二首  其二','岳珂','宋','宋诗','song-poetry','','[]','九光影裏步虛聲，午夜封章叩紫廷。',64,'全唐诗/poet.song.193000.json','["九光影裏步虛聲，午夜封章叩紫廷。", "雲路鳴琚傳奏簡，天街擲火度流鈴。", "沈沈玉漏傳三鼓，爚爚銀河燦萬熒。", "仙仗煙霄正凝想，曉光浮動遠山青。"]'),
('481d073d-9b5b-477e-86c7-92309b521361','山居作報書竟夜有感戲成','岳珂','宋','宋诗','song-poetry','','[]','山居踰五旬，正以厭煩故。',288,'全唐诗/poet.song.193000.json','["山居踰五旬，正以厭煩故。", "誰持故人書，剝啄扣我戶。", "奩篚旅庭砌，缾罌列桯廡。", "啟緘讀風簷，盈幅字如縷。", "頗欲從簡易，人事正如許。", "厚意來遠方，殷勤不容阻。", "還欲混俗塵，又覺初志誤。", "筆研久荒穢，肩腕仍旅拒。", "沈沈青燈夜，窗牖打風雨。", "聊激懶惰心，小出啽囈語。", "霜㕙比鉛觚，玉蟲剔釵股。", "隃麋方弄墨，擘繭更伸楮。", "始焉據几案，敏捷疑得趣。", "倏爾懷交情，恍惚接良晤。", "緘題甫一二，手熟漸四五。", "溪毛簡精粗，報貺祝豐窶。", "札胥謹印蠟，僕隸治筐筥。", "但知役羣動，不覺向五鼓。", "作勞耳屢鳴，倦寫目如瞀。", "低頭觸屏風，入鼻飲辛霧。", "欠伸忽三喟，靜念起百慮。", "吾生何太勞，窮處尚弗恕。", "仕皆係窮達，世豈忘喜怒。", "人以情見憐，我獨影相顧。"]'),
('45d0012e-a3ee-4e61-89e5-e157fc3d721a','挽張貢父二章  其一','岳珂','宋','宋诗','song-poetry','','[]','龍津南國第，蟬冕左丞家。',48,'全唐诗/poet.song.193000.json','["龍津南國第，蟬冕左丞家。", "籙以文章䄠，人惟壽雋誇。", "秀庭看玉樹，喜帖報金花。", "揮涕東原路，悲風咽曉笳。"]'),
('261df934-67e3-49d6-83e7-0483bbe9bc70','挽張貢父二章  其二','岳珂','宋','宋诗','song-poetry','','[]','江國三千土，才名四十年。',48,'全唐诗/poet.song.193000.json','["江國三千土，才名四十年。", "君猶淹白首，吾欲問蒼天。", "鞮唱習池近，廛聲陶宅偏。", "功名獨遺恨，寂寞□□□。"]'),
('7fa777d4-0bf5-4512-b3c0-9d2cc37f07f5','十一月十五日忽苦舌瘍甚不能飲食憊卧一榻戲成','岳珂','宋','宋诗','song-poetry','','[]','君不見東坡昔步虎溪月，夜聽溪聲廣長舌。',227,'全唐诗/poet.song.193000.json','["君不見東坡昔步虎溪月，夜聽溪聲廣長舌。", "溪聲不斷流不枯，此段磊落真丈夫。", "一生吾伊換喑嗚，嗟哉三寸予豈無。", "公子搢紳陳禮法，枕麴無思噤如蛤。", "辯士說客談縱橫，叱牛惟解供力耕。", "爾來更自作奇痛，晝苦吟呻夜妨夢。", "伏床啜粥猶漓浪，臠肉持將堪底用。", "太倉受禾三百廛，大官烹羊俱鼎羶。", "瀛洲給膳稱學士，飽食端居今六年。", "生平元不負此舌，欲辦一奇了無說。", "更憎此舌工負予，乃復累我七尺軀。", "鴟夷榼載鸕鷀杓，向口低眉輒前却。", "齒牙助桀復摇落，誤殺流涎孤快嚼。", "仰天大笑絕冠纓，舌兮腹兮誰重輕。"]'),
('5b678aca-55aa-4962-a094-1f6e9b671daa','宿溪聲閣望香爐峰偶成二律  其一','岳珂','宋','宋诗','song-poetry','','[]','閴歷煙巖古，琮琤雪澗橫。',48,'全唐诗/poet.song.193000.json','["閴歷煙巖古，琮琤雪澗橫。", "海潮秋八月，山雨夜三更。", "肯作隨流想，難忘潄石情。", "壯懷徒激烈，聊復以詩鳴。"]'),
('94c69f3c-9aa9-441d-94d1-a8d6f81535ed','宿溪聲閣望香爐峰偶成二律  其二','岳珂','宋','宋诗','song-poetry','','[]','廬峰三萬丈，鳥道度嶙峋。',48,'全唐诗/poet.song.193000.json','["廬峰三萬丈，鳥道度嶙峋。", "宿雨留前躅，清風絕後塵。", "誰憐石樓客，同是玉階人。", "謝屐須乘興，千年草木春。"]'),
('8a265419-f82a-41a5-b935-58dceaffe74b','山居感舊百韻','岳珂','宋','宋诗','song-poetry','','[]','昔在淳熙日，中興最盛年。',288,'全唐诗/poet.song.193000.json','["昔在淳熙日，中興最盛年。", "身逢千載運，眼見五朝天。", "楚甸當澄按，岷江極泝沿。", "經途俱極險，問字始能言。", "衛國呼珠帽，閻公着玳筵。", "進思紅滿幄，便室白連椽。", "詔趁回衡雁，重聽下峽猿。", "講書聞嶽麓，論道識湘川。", "至治承三紀，康謠沸九㙻。", "親逢堯壽並，繼見禹功傳。", "階玉駢床笏，籯金課槧鉛。", "程書仍把學，句讀始精研。", "白髮沈詹事，青雲張集仙。", "遺經說東魯，大義指南軒。", "古郢十連地，脩門萬里船。", "歡呼瞻玉軑，恭請擁珠韉。", "全盛開京邑，升平沸市廛。", "民無買刀佩，士有誦聲絃。", "去國波浮鷁，炎陬瘴跕鳶。", "稍知遺枉白，僅齒與齡玄。", "附首丁寧切，垂膺涕泗連。", "止樊讒曖昧，皖簀恨纏綿。", "奏牒懷留語，慈親返故泉。", "名坊觀正獻，蕭寺餞忠宣。"]'),
('47d62e10-d249-4691-86c9-4b67b40174a3','寄道士楊休文','岳珂','宋','宋诗','song-poetry','','[]','羽衣來自閤山前，見說山中老散仙。',64,'全唐诗/poet.song.193000.json','["羽衣來自閤山前，見說山中老散仙。", "出岫無心雲傍日，歸巢有意澗鳴泉。", "同襟汗漫尋常客，掉鞅文章四十年。", "我亦近爲猿鶴侶，試從香火結前緣。"]'),
('afc7f46f-fde6-4656-94ba-1cf495323d45','己亥明禋恩封鄴侯感愧有作二首  其一','岳珂','宋','宋诗','song-poetry','','[]','靜即爲方動即圓，幼知棋局老饒先。',64,'全唐诗/poet.song.193000.json','["靜即爲方動即圓，幼知棋局老饒先。", "封同桑梓一千戶，蹟遠蓬萊二十年。", "品祿幸猶容後隠，幹畬何敢擬前賢。", "只餘築室疑相似，三萬牙籤還儼然。"]'),
('52dd68b4-7664-4c4c-a97b-8eecad9e390e','己亥明禋恩封鄴侯感愧有作二首  其二','岳珂','宋','宋诗','song-poetry','','[]','布衣所願極封留，佩印歸來正倦游。',64,'全唐诗/poet.song.193000.json','["布衣所願極封留，佩印歸來正倦游。", "汗馬無功開上郡，鑄龜有意顧中流。", "南巡空負黄圖恨，北望還興紫陌愁。", "王國不煩謀主父，自憐支子亦通侯。"]'),
('bc843182-c1b0-4a6e-998f-67b335da948b','十一月二十七日步自虎溪至西寺摩挲率更舊碑近覽前聞人故游有感而賦','岳珂','宋','宋诗','song-poetry','','[]','龜趺千丈屹岧嶢，古寺殘僧正寂寥。',64,'全唐诗/poet.song.193000.json','["龜趺千丈屹岧嶢，古寺殘僧正寂寥。", "律演金輪開印度，字遺石磴說隋朝。", "續題賸有名人蹟，接畛猶逃劫火燒。", "弔古未磨今古恨，又携筇策過前橋。"]'),
('09b38c61-1c6e-46a8-9d69-aad02e127b69','得閤門報以予班學士詔復賜衣带因懷初錫倏閲十年感恩紀事二首  其一','岳珂','宋','宋诗','song-poetry','','[]','憶昔除書下赤墀，賜鞶即日拜金閨。',64,'全唐诗/poet.song.193000.json','["憶昔除書下赤墀，賜鞶即日拜金閨。", "未容汗脚踏龍尾，先爲圍腰鑄褭蹏。", "紫詔一朝來蔀室，丹霄十載望躔奎。", "君恩一再知難報，誰賦維梁濡翼鵜。"]'),
('621cf817-125a-4726-8330-21f1860953f7','得閤門報以予班學士詔復賜衣带因懷初錫倏閲十年感恩紀事二首  其二','岳珂','宋','宋诗','song-poetry','','[]','老去茆簷只負暄，重煩冠綬到柴門。',64,'全唐诗/poet.song.193000.json','["老去茆簷只負暄，重煩冠綬到柴門。", "紆金何有功名望，束带豈堪賓客言。", "璀璨章身同錫馬，差池接翼愧廷鵷。", "折腰重起平生愧，諉曰何知鶴在軒。"]'),
('192d11ce-35e8-469d-bb5a-3d1ffaa5c259','謝趙季茂海錯二律  其一','岳珂','宋','宋诗','song-poetry','','[]','珍殽惟錯遠持將，頼有詩情合得嘗。',64,'全唐诗/poet.song.193000.json','["珍殽惟錯遠持將，頼有詩情合得嘗。", "明月擘蚶分瓦礱，晴霞浴鱟露珠房。", "鰂烏鮆白螺開靨，蚷紫蝦紅鰾挾腸。", "雁斷閩山歸未得，把杯猶憶少年場。"]'),
('0f2659de-96a7-4da6-9b2c-218718514f92','謝趙季茂海錯二律  其二','岳珂','宋','宋诗','song-poetry','','[]','苜槃朝日照蓬蒿，消得長吟賦老饕。',64,'全唐诗/poet.song.193000.json','["苜槃朝日照蓬蒿，消得長吟賦老饕。", "喜見監州有螃蟹，未須學士議車螯。", "案鮭三九漫青韭，斗酒十千無白醪。", "應爲近來詩思少，故將飲興發風騷。"]'),
('e88e7153-53ab-4a92-ac98-d1b11f42f682','己亥十二月十七日堂帖被召感恩二首  其一','岳珂','宋','宋诗','song-poetry','','[]','九天驛騎下弓招，葵日丹心識就堯。',64,'全唐诗/poet.song.193000.json','["九天驛騎下弓招，葵日丹心識就堯。", "鸞鳳正應在阿閣，鶢鶋何事享簫韶。", "丘園有分容逋客，海嶽無裨愧聖朝。", "老病不堪心力倦，甫田勿歎莠蕎蕎。"]'),
('d1ac7831-9fa3-465b-8f08-f51cfe5812fe','己亥十二月十七日堂帖被召感恩二首  其二','岳珂','宋','宋诗','song-poetry','','[]','歸來三徑脫塵鞿，兩拜除書下玉墀。',64,'全唐诗/poet.song.193000.json','["歸來三徑脫塵鞿，兩拜除書下玉墀。", "聖澤雲天何以報，臣心鐵石未全衰。", "馬蹄已負驅車願，鴻羽難勝漸陸儀。", "願把一犁祝膏澤，康衢擊壤樂清時。"]'),
('7516dafd-b35f-4f13-a4f0-bfb95b6286cb','二十七日復有旨除帥江西一旬之間兩奉除音再賦二首  其一','岳珂','宋','宋诗','song-poetry','','[]','披腹忱詞久未呈，浹旬兩詔下宸京。',64,'全唐诗/poet.song.193000.json','["披腹忱詞久未呈，浹旬兩詔下宸京。", "老臣何路通忱悃，聖主無私燭物情。", "鶴隴未渝耕隴志，牛衣空換錦衣榮。", "九重自是真知己，莫惜捐糜負此生。"]'),
('19eee38a-e125-4e81-a3b6-ff80b8bc9ea9','二十七日復有旨除帥江西一旬之間兩奉除音再賦二首  其二','岳珂','宋','宋诗','song-poetry','','[]','郊廛不隔馬牛風，枌梓環陰跬步通。',64,'全唐诗/poet.song.193000.json','["郊廛不隔馬牛風，枌梓環陰跬步通。", "湖带江襟邦畛接，雨簾雲棟物華同。", "未須豫計荒三徑，幸有需章達四聰。", "尚想東湖海棠閙，祇今未改舊時紅。"]'),
('075235f4-22ac-4c3c-a8e9-80918ee6c1d1','香蠃','岳珂','宋','宋诗','song-poetry','','[]','金相玉質介爲裳，一騎紅塵自遠方。',64,'全唐诗/poet.song.193000.json','["金相玉質介爲裳，一騎紅塵自遠方。", "籍掛衆香椒桂國，身居大海水雲鄉。", "丁蠃薦醢體猶具，甲煎流芬名未亡。", "舉酒便應酬一醉，尊前風味試平章。"]'),
('ee50ec37-5ea0-47f9-84ee-4d4ad2f342f4','昨訪箳篂聞有繡帨之讌回車戲呈季茂','岳珂','宋','宋诗','song-poetry','','[]','慣聞嬌小處，繞带覓銀魚。',48,'全唐诗/poet.song.193000.json','["慣聞嬌小處，繞带覓銀魚。", "授雁定同瑞，弄麞應誤書。", "生朝今日是，嘉讌早春初。", "無分陪湯餠，到門空返車。"]'),
('f8eabdc9-8108-4c95-870c-fd7f50b27fb4','病中未能訪鄧德載督參大監戲贈二首  其一','岳珂','宋','宋诗','song-poetry','','[]','昨朝華宴想清歡，今日床頭未整冠。',64,'全唐诗/poet.song.193000.json','["昨朝華宴想清歡，今日床頭未整冠。", "已恨酒腸孤夜醉，更驚病骨怯春寒。", "多情條脫參差是，一抹琵琶錯雜彈。", "老眼眵昏正無緒，爐薌燼冷對蒲團。"]'),
('f22eb9b0-bed4-45cd-86a1-413c58a7e82a','病中未能訪鄧德載督參大監戲贈二首  其二','岳珂','宋','宋诗','song-poetry','','[]','老來病是惡因緣，白晝明窗思悄然。',64,'全唐诗/poet.song.193000.json','["老來病是惡因緣，白晝明窗思悄然。", "欲住又傾連夕雨，半醒似醉困人天。", "近拈吟筆塵欺硯，遠想江樓浪拍船。", "滿院杏花紅欲放，何時長笛醉風前。"]'),
('6f65191d-3b32-4848-9b2d-bc4aa646d10d','春晴將游玉淵踐吳季謙待制馮可久武博山行之約先走長句','岳珂','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','康廬三萬丈，下有神龍淵。',288,'全唐诗/poet.song.193000.json','["康廬三萬丈，下有神龍淵。", "旁聯玉井並，仰溯銀河連。", "層崖積冰雪，斷岸藏風煙。", "崔隤五老峰，迸瀉三峽泉。", "鯨鯢碎紫霧，螮蝀開青天。", "脈疑海眼近，寒入山骨堅。", "澗草摇秋暉，谷花發春妍。", "其間地布金，到處題標璇。", "大哉象教尊，儼若螺髻仙。", "巍巍南宗栢，湛湛西方蓮。", "總持包萬法，卓犖棲羣賢。", "慈心鬼神仰，顯跡今古傳。", "遠令千聖境，容此一席顓。", "我昔宿命通，曾結它生緣。", "嘗聞祖師隠，上應帝釋躔。", "清宵珠石隕，白浪星湖邊。", "至今澎湃中，常欲光景燃。", "當時初卓錫，如昔睨采椽。", "浮雲常抗志，立雪思比肩。", "壯懷凌九疊，浩氣湧百川。", "山水爲高深，志節爭後先。", "永言縈俗累，茲游經幾年。", "猶想謝公屐，同整劉琨鞭。", "橋梁識昨經，歲月驚舊鎸。"]'),
('73abb5b5-8321-4a92-aa17-867edb1a2a9b','趙季茂以酒香蠃來適亦得京中遠致此品乃鮮者恨地遠不大佳擇十五殻爲贈','岳珂','宋','宋诗','song-poetry','','[]','海蠃風味冠東瀛，一種俱從香得名。',64,'全唐诗/poet.song.193000.json','["海蠃風味冠東瀛，一種俱從香得名。", "畢卓醉醒甕猶卧，左車生致鼎堪烹。", "受餐敢返盤持璧，執訊不妨詩報瓊。", "有命其言君聽取，一生一死見交情。"]'),
('5fc04dc6-56f4-4387-903c-759017b99265','奉賡趙季茂雪中感興二首  其一','岳珂','宋','宋诗','song-poetry','','[]','曉雪初明瓦，春雲密布空。',48,'全唐诗/poet.song.193000.json','["曉雪初明瓦，春雲密布空。", "酒驚蕃鶴遠，詩坐灞馿窮。", "訪戴無嘉客，和陶稱倦翁。", "應憐四十韻，衣带賀年豐。"]'),
('3cd376f3-5155-484e-91ea-f44190c1b4ca','奉賡趙季茂雪中感興二首  其二','岳珂','宋','宋诗','song-poetry','','[]','湓城一夜雪，處處飯籮空。',48,'全唐诗/poet.song.193000.json','["湓城一夜雪，處處飯籮空。", "青序回規運，蒼生比屋窮。", "傷心慨疆事，抱膝愧田翁。", "別乘應同志，憂時正願豐。"]'),
('2441018c-0f79-4df3-a8cb-d19f9b8e04ac','病中酬趙季茂','岳珂','宋','宋诗','song-poetry','','[]','雪窗病惱獨支頤，不解隨人舉酒巵。',64,'全唐诗/poet.song.193000.json','["雪窗病惱獨支頤，不解隨人舉酒巵。", "驚辨有時欺白羽，解圍無婦蔽青絲。", "驪珠滿袖勾吟興，鹿氅看山戀藥糜。", "莫訝牛腰聯未足，江州司馬例能詩。"]'),
('a0bfb15a-4f2b-4ebf-bcb0-fb72df5313d4','病中午後登山閒步遥見園亭有翠帟張欄處久而識之爲張孝顯成趣軒蓋與緹屏油幙高會予病不得衝宴悵惘移時因以中孚澤所網鮮鯿侑以棠漪家醖併成四絕呈在席諸人  其一','岳珂','宋','宋诗','song-poetry','','[]','九折登山倚瘦筇，杏蹊眼纈早冬烘。',32,'全唐诗/poet.song.193000.json','["九折登山倚瘦筇，杏蹊眼纈早冬烘。", "翠雲遮斷神仙客，不許其間著倦翁。"]'),
('f549ee7e-b43e-4ebb-b52a-90a9eeef8f39','病中午後登山閒步遥見園亭有翠帟張欄處久而識之爲張孝顯成趣軒蓋與緹屏油幙高會予病不得衝宴悵惘移時因以中孚澤所網鮮鯿侑以棠漪家醖併成四絕呈在席諸人  其二','岳珂','宋','宋诗','song-poetry','','[]','滿山桃李閙紅霞，曾約香山白鹿車。',32,'全唐诗/poet.song.193000.json','["滿山桃李閙紅霞，曾約香山白鹿車。", "堪笑東風欺病客，攙先且到別人家。"]'),
('fc5e46cc-ec26-4a30-8b49-495c14d26a09','病中午後登山閒步遥見園亭有翠帟張欄處久而識之爲張孝顯成趣軒蓋與緹屏油幙高會予病不得衝宴悵惘移時因以中孚澤所網鮮鯿侑以棠漪家醖併成四絕呈在席諸人  其三','岳珂','宋','宋诗','song-poetry','','[]','小池玉尺躍清波，病不開尊奈爾何。',32,'全唐诗/poet.song.193000.json','["小池玉尺躍清波，病不開尊奈爾何。", "更倩棠漪吹柳岸，爲君小發醉顔酡。"]'),
('12033bd4-a3dd-45da-bd09-1b6e2d6905f7','病中午後登山閒步遥見園亭有翠帟張欄處久而識之爲張孝顯成趣軒蓋與緹屏油幙高會予病不得衝宴悵惘移時因以中孚澤所網鮮鯿侑以棠漪家醖併成四絕呈在席諸人  其四','岳珂','宋','宋诗','song-poetry','','[]','衝席丞郎酒斛籌，不關無面見春鷗。',32,'全唐诗/poet.song.193000.json','["衝席丞郎酒斛籌，不關無面見春鷗。", "五鯖見說妨齋禁，留待明朝大白浮。"]'),
('10e90372-fd0c-47d3-90d2-d8cdefb14ebc','比聞趙季茂奉板輿行春甚樂予躍然效之是日乃值大風雨昏後倦歸則素月流天仍復晴矣自此連日春色尤濃杏已過雨紅英滿地悵然有作因寄','岳珂','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','棠湖有病客，破鼎支藥糜。',288,'全唐诗/poet.song.193000.json','["棠湖有病客，破鼎支藥糜。", "青陽動新晴，兀兀厭坐馳。", "靜聞簫鼓閙，翠幰行春堤。", "柔風吹簾旌，杲日浮屏緹。", "行厨依竹裏，繡幙聯江湄。", "爲問來者誰，板輿雙侍姬。", "光彩照路傍，拍舞襄陽兒。", "病翁禪定心，久矣沾絮泥。", "一念忽隨喜，聊復相追隨。", "家人治尊罍，夜漏覘晨晞。", "擁被起躍然，不知筋力痿。", "破曉始三弄，衝寒纔一巵。", "爚如滿天星，湛湛開青池。", "晨光透戶牖，纖塵寂不吹。", "倏焉雲頭催，隨以雨脚垂。", "汀蘋振淅瀝，岸柳驚紛披。", "度塘如度橋，跬步窘且危。", "往謁乘驛使，席間如鼓鼙。", "主賓無軟語，僮僕侵寒肌。", "一坐禮敬疎，四顧面色黧。", "亟就兒女曹，疾駕掀重帷。", "擁爐共炙手，悔游仍攢眉。", "須臾呼酒炙，稍覺春融怡。", "棠湖暫紓望，苜盤充療饑。"]'),
('07ef64b6-37af-4d51-bc38-fee38c872111','庚子正月彗見於室有詔求言因上己見有感作三唐律  其一','岳珂','宋','宋诗','song-poetry','','[]','天象占仁愛，宸心極戰兢。',48,'全唐诗/poet.song.193000.json','["天象占仁愛，宸心極戰兢。", "圖從甘石辨，言並禹湯興。", "有志酬消露，無詞贊履冰。", "至明昭萬里，先願燭西陵。"]'),
('1f1603de-9c15-49e2-a87a-2433527ef6e1','庚子正月彗見於室有詔求言因上己見有感作三唐律  其二','岳珂','宋','宋诗','song-poetry','','[]','美芹野人意，喬木世臣家。',48,'全唐诗/poet.song.193000.json','["美芹野人意，喬木世臣家。", "尺璧諒非寶，寸心元不遐。", "誰知劍門棧，已建鬰軍牙。", "所恨簫韶遠，不堪聞塞笳。"]'),
('249428ef-40ac-45a3-8a91-3af3e04d7ca5','庚子正月彗見於室有詔求言因上己見有感作三唐律  其三','岳珂','宋','宋诗','song-poetry','','[]','糧府久關慮，騎官方應占。',48,'全唐诗/poet.song.193000.json','["糧府久關慮，騎官方應占。", "天心昭可卜，人事備當嚴。", "一葦江難恃，三巴民已殲。", "閉關還早計，璿玉不須覘。"]'),
('a413747b-a00f-4ddc-b234-b747d03767de','戲作呈趙通判胡教授張總幹','岳珂','宋','宋诗','song-poetry','','[]','人言春游無不好，一日宴客三日飽。',352,'全唐诗/poet.song.193000.json','["人言春游無不好，一日宴客三日飽。", "翁言此語特未定，一日宴客三日病。", "人生所願筋力强，問花訪柳同壺觴。", "老夫豈無少年狂，胡爲兀兀坐一床。", "憶昔少時事賓友，常有清尊湛東牖。", "稍長便不論升斗，纔對白衣輒搔首。", "東來三輔西陪京，二十四橋誇廣陵。", "萬椽紅蠟槌畫鼓，醒處傳杯醉中舞。", "何嘗一日不春風，酒光花艷詩興濃。", "兔肩鹿䏶坐據熊，急雪打面看雕弓。", "笑談千古一吷中，眼底頓覺四海空。", "可憐芳草長邊路，年少堂堂背人去。", "歡筵徙廢管與絃，粥鼎相隨朝復暮。", "塞砧街鼓總愁聽，凉月花宵等虛度。", "前旬作意趁萬紅，沈霪積雨仍多風。", "中間一日稍晴意，藥裹關心復思睡。", "無氈坐上老相如，昔時依幕今題輿。", "三君笑談忽與俱，使我捨策忘其軀。", "須臾把酒舌底滑，席地幕天醉鄉闊。", "明朝奇祟那可言，閉院重尋舊生活。", "回思北海酒不空，料應多病過于儂。", "坐客常滿更可疑，華佗已死將誰醫。"]'),
('7d7829d6-0398-48b8-9b93-6e7960649e51','小園雙竹呈瑞二首  其一','岳珂','宋','宋诗','song-poetry','','[]','錦綳玉立紀雙清，瑞牒千年重得名。',64,'全唐诗/poet.song.193000.json','["錦綳玉立紀雙清，瑞牒千年重得名。", "龍竹高標儼元致，熊湘素節凜皇英。", "質同隴麥兩歧秀，奇並庭柯連理榮。", "却羨此君尤特立，虛心直道不孤生。"]'),
('7721e3e9-496a-4eea-a824-5feb596e6f55','小園雙竹呈瑞二首  其二','岳珂','宋','宋诗','song-poetry','','[]','曲檻紅闌小圃西，平池影浸碧玻璃。',64,'全唐诗/poet.song.193000.json','["曲檻紅闌小圃西，平池影浸碧玻璃。", "便同雙劍看龍化，未許孤奩舞鳳棲。", "連袂縱觀金谷妓，聯篇頻付錦囊奚。", "使符永擬章江去，且聽平安報帳犀。"]'),
('df67a036-35b0-4750-a1f5-1f69decb901a','豫庵三瑞詩 鵷竹','岳珂','宋','宋诗','song-poetry','','[]','雷雨新頭角，煙霄舊羽翰。',48,'全唐诗/poet.song.193000.json','["雷雨新頭角，煙霄舊羽翰。", "聯根方拔象，接翼更停鸞。", "紫錦雙翻籜，青銅並倚竿。", "摩穹端有待，聊復護雕闌。"]'),
('62d2ea95-4e1a-4356-95d0-8ade09ea5c11','豫庵三瑞詩 蟬竹','岳珂','宋','宋诗','song-poetry','','[]','氣並陰陽正，仁無雨露偏。',48,'全唐诗/poet.song.193000.json','["氣並陰陽正，仁無雨露偏。", "闔開知有地，奇耦自潜天。", "雖煥雙紋異，仍存一節堅。", "薰風動蟬腹，槐綠又鳴絃。"]'),
('8a387fe3-80d3-4f96-a3d5-1e16304a6692','豫庵三瑞詩 龍竹','岳珂','宋','宋诗','song-poetry','','[]','夭矯青池近，騰拏碧漢遥。',48,'全唐诗/poet.song.193000.json','["夭矯青池近，騰拏碧漢遥。", "微風鳴嶰管，輕霧映鮫綃。", "舞翠槐齊秀，蟠青松後凋。", "終須還直道，勁節自干霄。"]'),
('8068e8d5-090c-4e87-8f3b-d3084247a39c','庚子三月二十七日又易守當塗四月十一日發辭免之牘書懷成二唐律  其一','岳珂','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','九重旒冕真知己，幾度弓旌憶款門。',64,'全唐诗/poet.song.193000.json','["九重旒冕真知己，幾度弓旌憶款門。", "素志不爲溫飽計，赤心未報聖明恩。", "鶴汀雲雨暮應捲，牛渚風煙秋欲昏。", "休向長江問陳迹，浮梁孤塔不堪論。"]'),
('b514c076-0cd4-4a9d-83e1-86bd8d443ebe','庚子三月二十七日又易守當塗四月十一日發辭免之牘書懷成二唐律  其二','岳珂','宋','宋诗','song-poetry','','[]','去載西陲夏正初，首驚禹閣下除書。',64,'全唐诗/poet.song.193000.json','["去載西陲夏正初，首驚禹閣下除書。", "璇杓導旨方螭陛，珍圉迎釐又燕居。", "三見綸音傳詔璽，六看棨信到耕鋤。", "祇今又上公車奏，何日煙簑返老漁。"]'),
('e472ddc5-bf64-45d5-a6ce-d4cae2a3a327','十二日諏吉受通議大夫告再書述懷二首  其一','岳珂','宋','宋诗','song-poetry','','[]','聖代論思秩，中朝博議官。',48,'全唐诗/poet.song.193000.json','["聖代論思秩，中朝博議官。", "尚紆郡邸綬，空著侍臣冠。", "歲月驚馳隙，功名儘畫墁。", "髀銷今已復，半世愧狨鞍。"]'),
('d975af34-a295-4354-9b99-a54cc15b8afd','十二日諏吉受通議大夫告再書述懷二首  其二','岳珂','宋','宋诗','song-poetry','','[]','五雲瞻觀闕，百印寫綸絲。',48,'全唐诗/poet.song.193000.json','["五雲瞻觀闕，百印寫綸絲。", "有愧陪貂尾，何功復雁踦。", "精鏐肦紫磨，實匪咏緇宜。", "聖德知難報，規銅笑白髭。"]'),
('0869fd97-9de3-4534-ae24-0990227dd2fe','上高趙宰同叔遺以誠齋集開卷偶見答徐宋臣監丞書云來帖告訴門生排根嘗聞前輩謂受人之恩而不忘者爲子必孝爲臣必忠蓋推是心而信其人也又聞惟以怨報德者爲不可測蓋以有人之形者必有人之情也故盧杞之於顔公敏中之於文饒之奇之於永叔邢恕之於君實孰測其報恩一至此極哉昔孟嘗君有一客孟嘗遇之甚厚而客每毀孟嘗或問其故客曰人皆譽君而我獨毀人必以我爲小人而以君爲長者此吾所以報君也前五子者其意將無出於此歟至如逄蒙殺羿之事孟子不責蒙而責羿然則先生之與門生其責果誰在哉或掩卷有感因筆紀意復紬繹身履者以補其闕凡四十韻','岳珂','宋','宋诗','song-poetry','','[]','古人忠與孝，不在工報恩。',288,'全唐诗/poet.song.193000.json','["古人忠與孝，不在工報恩。", "如水日夜東，豈必同一源。", "堂堂顔魯公，舐血來平原。", "鬼質不知何，幾作絕吭魂。", "大中白丞相，昔躡衛國門。", "幻作萬羊夢，投畀朱崖村。", "奇謗及師友，躗言動君尊。", "匪但死不瞑，大是生無根。", "我嘗究初終，要亦無足論。", "或以裏言掇，或趣主意奔。", "或從談笑生，或即利欲昏。", "初亦未有心，末乃成至冤。", "青簡玷齒頰，至今猶啍啍。", "儻無魏闕戀，誰使舌莫捫。", "森淅起奉冊，片頃那容存。", "牀笫本無從，何物能輊軒。", "脂垢亦易辨，誰解洿璵璠。", "如彼孟嘗客，亦已悔而反。", "正比蕭相繫，慰拊聊春溫。", "五人皆有爲，評訂何必繁。", "之子獨嗟事，畫牢訊書爰。", "反覆蹈生死，呵噓變寒暄。", "秋毫無所取，可驗牘背翻。", "自言復自渝，洗垢亦不痕。"]'),
('9740d307-45fc-4204-a557-883d5824bd0c','睡起三絕  其一','岳珂','宋','宋诗','song-poetry','','[]','睡起東窗日已紅，扶頭宿酒未惺鬆。',32,'全唐诗/poet.song.193000.json','["睡起東窗日已紅，扶頭宿酒未惺鬆。", "南陽一夢何關醉，自愛終身作卧龍。"]'),
('e1d70cf0-0f50-4357-889b-4555fe9fc89d','睡起三絕  其二','岳珂','宋','宋诗','song-poetry','','[]','天色今晨已放晴，鳥烏亦覺有歡聲。',32,'全唐诗/poet.song.193000.json','["天色今晨已放晴，鳥烏亦覺有歡聲。", "幅巾自是便疎嬾，飯了花間取次行。"]'),
('fd538cd5-6311-4f50-aa9a-49ccdbd2c1ad','睡起三絕  其三','岳珂','宋','宋诗','song-poetry','','[]','五更展轉待晨光，到曉瞢騰入睡鄉。',32,'全唐诗/poet.song.193000.json','["五更展轉待晨光，到曉瞢騰入睡鄉。", "却是金門早朝客，千金不博枕中方。"]'),
('cc2171db-275f-4de7-a519-601d4ac0223a','自歲前逮夏初日始辭免有感而作','岳珂','宋','宋诗','song-poetry','','[]','憶昨除書賜召環，聯翩觚槧不曾閒。',64,'全唐诗/poet.song.193000.json','["憶昨除書賜召環，聯翩觚槧不曾閒。", "醉吟久負雞豚社，奏牘頻登虎豹關。", "求倦得忙三易地，自冬徂夏半年間。", "□□□□□□□，□□□□□□□。"]'),
('e6e7d928-bb3b-4b89-bdfe-222671b4f744','梳頭二首  其一','岳珂','宋','宋诗','song-poetry','','[]','白髮三千丈，斯言若未公。',48,'全唐诗/poet.song.193000.json','["白髮三千丈，斯言若未公。", "下梳驚落雪，倚檻且晞風。", "自笑雙蓬鬢，今成一禿翁。", "晨招幸無與，姑免誚頭童。"]'),
('8fea4474-c12d-46c0-bd98-e2efb995c786','梳頭二首  其二','岳珂','宋','宋诗','song-poetry','','[]','長記涪翁語，無塵有髮僧。',48,'全唐诗/poet.song.193000.json','["長記涪翁語，無塵有髮僧。", "無塵方願學，有髮亦何曾。", "學士年年樣，車門日日乘。", "二毛猶勝我，不必愧鬅鬙。"]'),
('00bbff1e-7549-4eef-a5f7-495240db8f0a','塔燈六言四絕  其一','岳珂','宋','宋诗','song-poetry','','[]','金輪示現清夜，火樹高騰碧虛。',28,'全唐诗/poet.song.193000.json','["金輪示現清夜，火樹高騰碧虛。", "說法未回坡應，冊勳先到鐘魚。"]'),
('362d3871-0a69-47b2-b6ac-d4a67722c38f','塔燈六言四絕  其二','岳珂','宋','宋诗','song-poetry','','[]','七層靈燄自照，萬里劫風不吹。',28,'全唐诗/poet.song.193000.json','["七層靈燄自照，萬里劫風不吹。", "烽信斷無澤國，神光恰似天池。"]'),
('0616d1cf-28d4-4b55-ac6b-87438d17b8d5','塔燈六言四絕  其三','岳珂','宋','宋诗','song-poetry','','[]','中天半倚寥泬，大帝高居鬰蕭。',28,'全唐诗/poet.song.193000.json','["中天半倚寥泬，大帝高居鬰蕭。", "已訝流鈴擲火，還疑絳節來朝。"]'),
('9e6a05dd-2456-4047-9618-ba748de4bbae','塔燈六言四絕  其四','岳珂','宋','宋诗','song-poetry','','[]','碧落星移象緯，紅光影射鮫宮。',28,'全唐诗/poet.song.193000.json','["碧落星移象緯，紅光影射鮫宮。", "甲煎千門初啟，明珠九曲先通。"]'),
('2dbe1eb8-806b-4e60-b9d6-490e5e7cfcc9','喜雨','岳珂','宋','宋诗','song-poetry','','[]','去年春旱種不移，後來雖雨那及時。',128,'全唐诗/poet.song.193000.json','["去年春旱種不移，後來雖雨那及時。", "至今田野有菜色，麥熟未救民啼饑。", "今年雨澤知時好，出水秧針隨處早。", "晴無十日雨輒隨，雨及一犁日還杲。", "天心一念本好生，去年今年何愛憎。", "古來藏室五千字，每歎凶年由大兵。", "祇今崆峒纔小熟，溝壑未甦猶五六。", "兵端倚伏詎可量，且願藩籬謹西蜀。"]'),
('9450ffe3-2d15-4f2a-bb89-6b2b94e82df8','四月二十日被以郡事入奏之命再賦二首  其一','岳珂','宋','宋诗','song-poetry','','[]','五雲堆裏望觚稜，二紀周南夢未曾。',64,'全唐诗/poet.song.193000.json','["五雲堆裏望觚稜，二紀周南夢未曾。", "四輩兩年勤詔札，九重一念乂黎蒸。", "烽臺雖有深秋燧，雁塔應無曩日僧。", "豫備正須如雍國，不妨德業頌高昇。"]'),
('66b8ee42-184a-476e-9f84-817960373162','四月二十日被以郡事入奏之命再賦二首  其二','岳珂','宋','宋诗','song-poetry','','[]','去年冬暮拜弓招，槐夏重承接畫朝。',64,'全唐诗/poet.song.193000.json','["去年冬暮拜弓招，槐夏重承接畫朝。", "錫馬敢期先雨露，冥鴻自愧點煙霄。", "沙墀有路瞻唐表，瓦缶何堪溷舜韶。", "歸郡定應遲六月，却從故迹問凌歊。"]'),
('e4b67062-878c-4a58-aae2-70a372f9fa64','予園泰堂之傍有奇石小有有洞箭括有門車箱有谷高廣雖不袤丈而嵌空之勢宛若飄動暇日獨坐對玩移晷因賦','岳珂','宋','宋诗','song-poetry','','[]','池邊歷平蹊，果下動游鞚。',240,'全唐诗/poet.song.193000.json','["池邊歷平蹊，果下動游鞚。", "一笑未心領，萬象徒目送。", "淵渟歷危檻，目景眩華棟。", "閒情晻不舒，倦思悄如瞢。", "忽驚鵲噪簷，恍類雞發甕。", "坐開蒼玉壁，平揖青瑶峒。", "疇昔果安在，奔走比嶽貢。", "仰觀箭括門，廣宇豁晴霧。", "右開車箱谷，盤道陟微衕。", "中天隠日月，遥海插螮蝀。", "居然袤丈間，有此具美衆。", "老夫生平嗜，酷好泉石弄。", "天巧謝斲削，人爲謾摶控。", "尚憶三神游，俛記十年夢。", "踞龜曾食蛤，騎鶴更笞鳳。", "覺來海山蒼，倏見雪竇空。", "便疑勢崷崒，獨欠波澒洞。", "捧罌喜對酌，岸幘發孤諷。", "此兄定絕奇，吾意當折衷。", "一笑問阿章，試與評伯仲。"]'),
('8289d0ab-0d84-410a-97e0-55a2830195a9','新荷出水','岳珂','宋','宋诗','song-poetry','','[]','貼水初翻紫玉團，忽驚矗立傍闌干。',64,'全唐诗/poet.song.193000.json','["貼水初翻紫玉團，忽驚矗立傍闌干。", "瑶池七日來青鳥，玉鑑孤奩舞翠鸞。", "曉露走槃珠顆瑩，晚風颭蓋雪衣寒。", "從今十丈開花面，太華峰頭更一看。"]'),
('db96abf3-b80d-4c68-8c60-776f45d885a6','舞鶴四絕  其一','岳珂','宋','宋诗','song-poetry','','[]','九臯仙子老芝田，小立清池阿那邊。',32,'全唐诗/poet.song.193000.json','["九臯仙子老芝田，小立清池阿那邊。", "忽作霓裳羽衣舞，天機未信祇魚鳶。"]'),
('1c8892c9-54ef-4405-b0a3-cce411722f3b','舞鶴四絕  其二','岳珂','宋','宋诗','song-poetry','','[]','曾見中庭舞素衣，夜涼桂殿玉笙吹。',32,'全唐诗/poet.song.193000.json','["曾見中庭舞素衣，夜涼桂殿玉笙吹。", "夢回一曲天風杳，正是華亭振萬時。"]'),
('86af81eb-4732-4384-aa41-46362bbfbaae','舞鶴四絕  其三','岳珂','宋','宋诗','song-poetry','','[]','臨臯亭下翩躚客，縞袂玄裳憶舊游。',32,'全唐诗/poet.song.193000.json','["臨臯亭下翩躚客，縞袂玄裳憶舊游。", "推戶惘然尋不見，笛聲猶認紫貂裘。"]'),
('45774a9f-8516-452f-810a-d48cc0df543a','舞鶴四絕  其四','岳珂','宋','宋诗','song-poetry','','[]','一川翠毯淺蕪平，上有鶑簧百囀聲。',32,'全唐诗/poet.song.193000.json','["一川翠毯淺蕪平，上有鶑簧百囀聲。", "萬里煙霄看鷺振，一池鼓吹謾蛙鳴。"]'),
('d629e61f-999c-43c4-8547-b223d695da2a','簡吳季謙堅他日柴桑之約時季謙有潭帥之命二首  其一','岳珂','宋','宋诗','song-poetry','','[]','幾年諸葛卧南陽，蠡澤春風詔趣裝。',64,'全唐诗/poet.song.193000.json','["幾年諸葛卧南陽，蠡澤春風詔趣裝。", "丹檢紫泥來四輩，碧油紅旆又三湘。", "不關富貴干旄戀，要看功名汗簡香。", "雪汁蓬婆漸秋水，好扶西極漢天長。"]'),
('dc176123-4afb-4931-94f1-94da996e8b84','簡吳季謙堅他日柴桑之約時季謙有潭帥之命二首  其二','岳珂','宋','宋诗','song-poetry','','[]','君今西上我東馳，一醉相從又幾時。',64,'全唐诗/poet.song.193000.json','["君今西上我東馳，一醉相從又幾時。", "星變十年占軫野，風寒兩地說江湄。", "憂時有慮慮須早，了事欲歸歸未遲。", "年齒官班略相似，伴閒頻記樂天詩。"]'),
('d7d81c5b-5e08-489f-8409-3ab25c955749','五月九日登舟聞迓卒鼓角發嚴','岳珂','宋','宋诗','song-poetry','','[]','古郡裁儀自太平，百艘初奏夜嚴聲。',64,'全唐诗/poet.song.193000.json','["古郡裁儀自太平，百艘初奏夜嚴聲。", "漁撾鼓史催三奏，龍角單于動五更。", "岸柳青煙留帳飲，堤蓮紅焰耿紗明。", "津亭獨坐逌然笑，不似池蛙兩部鳴。"]'),
('09a77b84-24f0-4749-8e38-84d5ea7df6be','將發琵琶亭','岳珂','宋','宋诗','song-poetry','','[]','前歲西泝鄂，今歲東入吳。',293,'全唐诗/poet.song.193000.json','["前歲西泝鄂，今歲東入吳。", "同一琵琶亭，行客各異塗。", "當時白傅恨，陳跡久榛蕪。", "豈特無遺音，榛蕪今亦無。", "突兀眼前屋，丹堊塗{木咨/木}櫨。", "廢興曾幾時，傳舍同蘧廬。", "已見兩折柳，於此餞老夫。", "昔持使者節，今發追鋒車。", "我則齊出處，世自分榮枯。", "而況天地間，萬變同須臾。", "我觀商婦者，瑣瑣豈足書。", "琵琶本常技，何地無此徒。", "夫販浮梁茶，婦即空舟居。", "長吏濕青衫，禮法毋乃疎。", "樂天子牟心，一念存江湖。", "詎關蝦蟆陵，維以懷故都。", "譬之澤畔吟，此語非寓歟。", "蓋嘗考遺集，一事曾同符。", "聞歌鸚鵡洲，尋聲得幼姝。", "倚檣泣明月，清淚垂真珠。", "夫君當此時，正屬典午初。", "不應奇謗後，無復思廉隅。", "六義有比興，觀洧傳洵盱。", "託物皆一理，實事那相須。"]'),
('1eb563bb-2b1d-4dbe-8b5f-a489befee21a','舟過庾樓','岳珂','宋','宋诗','song-poetry','','[]','得名元自庾西陽，秋夜何關舊踞床。',64,'全唐诗/poet.song.193000.json','["得名元自庾西陽，秋夜何關舊踞床。", "坐上參差雉橫堞，檻前來往燕歸檣。", "騷人雪月撩新句，游子風雲憶故鄉。", "何日君恩粗能報，苔磯從此濯滄浪。"]'),
('5e92b526-a38f-4f37-a8f5-5d7992a97420','白水浦懷王建寧','岳珂','宋','宋诗','song-poetry','','[]','南朝舊見王忠武，此地曾屯千萬兵。',64,'全唐诗/poet.song.193000.json','["南朝舊見王忠武，此地曾屯千萬兵。", "十里荒蹊秋兔健，千年陳迹暮鴻征。", "無衣空縕包胥志，遺幗終留諸葛名。", "落日英雄滿襟淚，鳳凰倚徙正孤城。"]'),
('d1ed68e4-0e9e-4f07-90aa-efea80fadee9','排灣遇風對岸即彭澤舊縣二首  其一','岳珂','宋','宋诗','song-poetry','','[]','隠約山藏霧，砰渹地起雷。',48,'全唐诗/poet.song.193000.json','["隠約山藏霧，砰渹地起雷。", "黑風吹海立，白雨過江來。", "齊樂正應爾，沛兒安在哉。", "雄雌誰與辨，試上楚王臺。"]'),
('b326346f-4b03-4ef6-8fd5-ec21f13cf757','排灣遇風對岸即彭澤舊縣二首  其二','岳珂','宋','宋诗','song-poetry','','[]','岸上蘆摇首，門前柳折腰。',48,'全唐诗/poet.song.193000.json','["岸上蘆摇首，門前柳折腰。", "千年已陳迹，四海又驚飈。", "宿翳何當浄，高風幸未遥。", "柴桑那可見，身世且漂摇。"]'),
('aa4aefd5-6586-44c4-894d-b1b3237c8d13','發排灣過小孤彭郎祠下遂宿馬當','岳珂','宋','宋诗','song-poetry','','[]','山小孤，磯彭郎，中納百谷吞三江。',393,'全唐诗/poet.song.193000.json','["山小孤，磯彭郎，中納百谷吞三江。", "江流澎湃不可當，勢比折木傾銀潢。", "渴龍一支走馬當，宛然天驥初騰驤，回韁矗立江中央。", "西從岷峨暨睢漳，南派五湖通三湘。", "後先奔走爭回翔，前驅怒氣軒且昂，倏然過此意消洋。", "儼然天子朝明堂，坐受萬國來氐羌。", "五瑞咸輯珪與璋，拜舞軒陛心俱降。", "我聞乾坤融結盤古開混茫，流峙異勢分輿方。", "巍巍神禹治水平懷襄，底乂一意先荆揚。", "此山綠字元弗詳，脫略丘垤登毫芒。", "後人考古徒縑緗，未覩此石天經地紀之維綱。", "君不見古馬當，今馬當，記牒雖漏處有常。", "上焉柱天植極扶三光，下焉立地作鎮安八荒。", "磅礴杳靄排穹蒼，削平澒洞壓鴻厖。", "萬熒棋布高蓋張，百靈臣伏絕影藏。", "坐使四海順流中古無濫觴，噫哦偉特那可量。", "我欲用世取所長，便當提作朱亥神椎椎獝狂。", "北絕大漠梟名王。", "何空更度金浮梁，一拯墊溺躋康莊。", "連山疊阜化囷倉，盡飽萬姓饑火腸。", "持此報上歌如岡，徧開壽域同畛疆。", "自今永永三十六萬歲，淳古比九皇。", "山岧岧兮江湯湯。"]'),
('c2bd80d2-06cd-429d-b813-fde501894eac','過雁汊','岳珂','宋','宋诗','song-poetry','','[]','駢集千艘岸，喧挐百吏聲。',48,'全唐诗/poet.song.193000.json','["駢集千艘岸，喧挐百吏聲。", "黄旗優仕賈，白奪困商程。", "吳楚方憂蹙，研桑謾計贏。", "坐觀還一笑，關市古無征。"]'),
('2aa1076f-7449-4787-a329-59544a03c13f','便風經雁汊宿荻港是日舟行四百里三首  其一','岳珂','宋','宋诗','song-poetry','','[]','近岸千帆閲，雄襟一昔舒。',48,'全唐诗/poet.song.193000.json','["近岸千帆閲，雄襟一昔舒。", "雲程排沸浪，風御翼澄虛。", "塊歷過都馬，波翻縱壑魚。", "經旬嘆淹滯，此理盍乘除。"]'),
('dea282e0-e821-436e-9d08-f7ca6c4577da','便風經雁汊宿荻港是日舟行四百里三首  其二','岳珂','宋','宋诗','song-poetry','','[]','羊角摶扶日，鴻毛迅順時。',48,'全唐诗/poet.song.193000.json','["羊角摶扶日，鴻毛迅順時。", "天心應有爲，吾道復何疑。", "岸燎開戎捷，磯神助好詞。", "倚檣聊一笑，且試楚襟披。"]'),
('8baed8e3-ba40-45e0-a4b0-1a5ad4989450','便風經雁汊宿荻港是日舟行四百里三首  其三','岳珂','宋','宋诗','song-poetry','','[]','瞬息四百里，經行三十年。',48,'全唐诗/poet.song.193000.json','["瞬息四百里，經行三十年。", "此時真縮地，當日信梯天。", "岸過人回首，山浮浪駕肩。", "望塵何足羨，禦寇正泠然。"]'),
('5027a343-d688-438e-87c2-e0cbc0336a72','入蕪湖港過吉祥寺','岳珂','宋','宋诗','song-poetry','','[]','昔時曾訪後山松，天道那令霸業窮。',64,'全唐诗/poet.song.193000.json','["昔時曾訪後山松，天道那令霸業窮。", "夾岸人觀新太守，擁門僧認舊詩翁。", "隠磯漫指六朝事，魯港嘗淹五宿風。", "從此片帆湖際去，只應日在瑞雲東。"]'),
('b6d006cc-004c-40ca-951d-e9841e82d7af','黄池','岳珂','宋','宋诗','song-poetry','','[]','易取日中市，陶居天下衝。',48,'全唐诗/poet.song.193000.json','["易取日中市，陶居天下衝。", "南琛下甌粵，西旅輯巴庸。", "四顧斷登壟，萬家塿聚蜂。", "寢丘端不類，何以洿吾封。"]'),
('2a3e100e-6d67-4a1b-8153-7b26081d94ef','曉過固城湖','岳珂','宋','宋诗','song-poetry','','[]','放船快度固城湖，十幅輕帆日未晡。',64,'全唐诗/poet.song.193000.json','["放船快度固城湖，十幅輕帆日未晡。", "東望金陵千嶂遠，南浮銀壩萬艫趨。", "歌聲隨地參吳楚，沮澤經春畏稗蒲。", "却認棠磯尋釣艇，只憐無影浸康廬。"]'),
('c1db2aee-6ecb-434d-9f50-2ac9f03965c3','銀堰','岳珂','宋','宋诗','song-poetry','','[]','舊說金爲土，今聞銀灌城。',48,'全唐诗/poet.song.193000.json','["舊說金爲土，今聞銀灌城。", "古人真作事，後世祇虛名。", "籌策雖曾立，厫倉竟未成。", "道旁誰築室，吾欲誦坻京。"]'),
('c9aa932b-41b6-4dd5-98cf-02b0f04262f0','久不雨裏河舟不可行戚橋平氏小舫在東壩予介紹假之以行','岳珂','宋','宋诗','song-poetry','','[]','裏河累月雨不時，河流一綫田拆龜。',64,'全唐诗/poet.song.193000.json','["裏河累月雨不時，河流一綫田拆龜。", "馮河無地訪一葦，有舫艤岸知爲誰。", "尺牋扣問真漫與，白頭雖新還亟許。", "從來遇合無古今，中流一壺真千金。"]'),
('d0d1967d-10eb-429e-9d33-0d47248c0e6f','夏旱三首  其一','岳珂','宋','宋诗','song-poetry','','[]','去年旱勢已殊常，今歲農家更可傷。',64,'全唐诗/poet.song.193000.json','["去年旱勢已殊常，今歲農家更可傷。", "支港鮒臣空涸轍，大田龜兆未移秧。", "祇今已是眼滴血，此後應無肉補瘡。", "蟣虱小臣惟痛哭，第憑宗社叫蒼蒼。"]'),
('73978552-7d02-4e6d-8f85-809d560f4fe9','夏旱三首  其二','岳珂','宋','宋诗','song-poetry','','[]','宣昇接境古高圩，多稼連雲號上腴。',64,'全唐诗/poet.song.193000.json','["宣昇接境古高圩，多稼連雲號上腴。", "水毀木饑猶解有，刀耕火耨故應無。", "瓠肥何計今糠覈，草竊空憂古葦苻。", "昨夜濃雲望東北，祇應雨脚在三吳。"]'),
('a7246e2d-c091-495a-ad65-fd5ddb90c895','夏旱三首  其三','岳珂','宋','宋诗','song-poetry','','[]','問津六輔到長安，滿目疲羸不忍觀。',64,'全唐诗/poet.song.193000.json','["問津六輔到長安，滿目疲羸不忍觀。", "耕耨又孤今歲飽，蓋藏尤比去年難。", "綺羅有目須令見，鐵石爲心方自寬。", "欲借玉階空悵望，救民無術愧空餐。"]'),
('fe20dd8e-0345-4f3e-bfeb-c53b7d31829a','東壩以裏沿岸人家皆對門植葦於小嶼不曉其旨漫成四絕  其一','岳珂','宋','宋诗','song-poetry','','[]','岸傍幾曲住人家，淺嶼排門種荻花。',32,'全唐诗/poet.song.193000.json','["岸傍幾曲住人家，淺嶼排門種荻花。", "縱使秋聲常索索，斷無司馬聽琵琶。"]'),
('70916197-ec21-40ea-8a32-e2c80de3d749','東壩以裏沿岸人家皆對門植葦於小嶼不曉其旨漫成四絕  其二','岳珂','宋','宋诗','song-poetry','','[]','萬里江濱長野蘆，西風元不費工夫。',32,'全唐诗/poet.song.193000.json','["萬里江濱長野蘆，西風元不費工夫。", "兩京薺菜論斤賣，耳目由來喜所無。"]'),
('649747eb-5a91-42c5-ad89-8c51daa4722a','東壩以裏沿岸人家皆對門植葦於小嶼不曉其旨漫成四絕  其三','岳珂','宋','宋诗','song-poetry','','[]','北都舊産無淇竹，見說園池蘆葦多。',32,'全唐诗/poet.song.193000.json','["北都舊産無淇竹，見說園池蘆葦多。", "漲綠不妨夜來雨，更須別浦聽鳴荷。"]'),
('0dfec4f9-0cd9-4806-abb9-381d52e6bc41','東壩以裏沿岸人家皆對門植葦於小嶼不曉其旨漫成四絕  其四','岳珂','宋','宋诗','song-poetry','','[]','曲江西畔鎖離宮，細柳新蒲日日風。',32,'全唐诗/poet.song.193000.json','["曲江西畔鎖離宮，細柳新蒲日日風。", "想見千門映春綠，君王未見碧成叢。"]'),
('25194bc2-4263-46b2-921a-ef78f1ef9c4b','三塔渰圩下二首  其一','岳珂','宋','宋诗','song-poetry','','[]','暑風空戰荻蕭蕭，盡日舟行淖沒腰。',64,'全唐诗/poet.song.193000.json','["暑風空戰荻蕭蕭，盡日舟行淖沒腰。", "曾見決堤憂螘漏，未聞涸轍縱鰍跳。", "成渠致利今無鄭，具備先時古有堯。", "安得圩圖比安上，憂時如俠奏清朝。"]'),
('faa21932-f754-4f49-b4d1-971fe9aca0be','三塔渰圩下二首  其二','岳珂','宋','宋诗','song-poetry','','[]','深不堪桴淺不浮，百艘鱗戢賈胡留。',64,'全唐诗/poet.song.193000.json','["深不堪桴淺不浮，百艘鱗戢賈胡留。", "如泥乘橇禹行水，以力嬰天奡盪舟。", "生息便疑吹野馬，陂陀正恐見淵虬。", "君行遲速何須問，且爲斯民恥內溝。"]'),
('c191afd1-c78f-42ea-a26a-714fa9f01c54','三塔寺寒光亭張于湖書詞寺柱吳毅夫命名後軒二首  其一','岳珂','宋','宋诗','song-poetry','','[]','竹裏逢僧院，殘碑不記年。',48,'全唐诗/poet.song.193000.json','["竹裏逢僧院，殘碑不記年。", "雁題三崒堵，龍化兩魁躔。", "寶正號應紀，元豐墨尚鮮。", "寒光定何似，誰放五湖船。"]'),
('d8ca4346-24ec-4a54-9278-dc167dc64453','三塔寺寒光亭張于湖書詞寺柱吳毅夫命名後軒二首  其二','岳珂','宋','宋诗','song-poetry','','[]','雲煙千嶂遠，風月四時新。',48,'全唐诗/poet.song.193000.json','["雲煙千嶂遠，風月四時新。", "笠澤昔魯望，鏡明今季真。", "何時脫塵絆，來此寄垂綸。", "一艇葦間宿，寒光長是鄰。"]'),
('c55e8814-fde1-477a-961f-2dfa236f2ada','渰中水淺輿從下水肩舟二首  其一','岳珂','宋','宋诗','song-poetry','','[]','揚塵驚淺瀨，平陸比通津。',48,'全唐诗/poet.song.193000.json','["揚塵驚淺瀨，平陸比通津。", "絕臏正扛鼎，化身如轉輪。", "未輿譏代畜，不狩媿懸鶉。", "誰借商巖手，一篙煙水春。"]'),
('7a7cb1d8-caee-46f9-8249-75515565cd62','渰中水淺輿從下水肩舟二首  其二','岳珂','宋','宋诗','song-poetry','','[]','水面平如砥，湖心淺不波。',48,'全唐诗/poet.song.193000.json','["水面平如砥，湖心淺不波。", "駕肩同作楫，袖手莫談河。", "不見成橋鵲，空傳度磧駝。", "勞生正應爾，空愧白鷗莎。"]'),
('f148296e-bc88-42d9-835a-0f82d89f1800','嘉定丁卯余守槜李召還郡人見餞於三塔灣偶至此寺因名有感','岳珂','宋','宋诗','song-poetry','','[]','往年曾佩雙湖組，古剎猶題三塔灣。',64,'全唐诗/poet.song.193000.json','["往年曾佩雙湖組，古剎猶題三塔灣。", "墮雁重尋湖浩渺，斷虹渾記水回環。", "兩州隔涉名無改，二紀棲遲老復還。", "病衲雖無分別想，經行莫作少年看。"]'),
('d654c267-3958-4fd2-85ed-f248d315ae59','去歲五月二十八日發雪錦亭以六月旦謁富池而行是夜始望見廬山今歲以此日正在湖渰中念歲月之倏忽驚道途之勞勩回首感歎二首  其一','岳珂','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','雪錦亭前夕照紅，興唐寺下曉聞鐘。',64,'全唐诗/poet.song.193000.json','["雪錦亭前夕照紅，興唐寺下曉聞鐘。", "傷心楚水又經歲，回首吳雲知幾重。", "萬里同盟祇鷗鷺，三江嘯浪憶魚龍。", "如今且對湖光裏，八九重開夢澤胸。"]'),
('b6f8f81d-bada-43e6-9d83-46b5dff56259','去歲五月二十八日發雪錦亭以六月旦謁富池而行是夜始望見廬山今歲以此日正在湖渰中念歲月之倏忽驚道途之勞勩回首感歎二首  其二','岳珂','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','去年今日富池頭，浩蕩風煙卷雪樓。',64,'全唐诗/poet.song.193000.json','["去年今日富池頭，浩蕩風煙卷雪樓。", "湖海百年雙鬢老，荆揚兩地一萍浮。", "河斜左界流清夜，雲密西郊望有秋。", "通塞隨時何必問，明朝又放溧陽舟。"]'),
('0ccf32f9-e464-4581-b370-fb5c3e314480','火雲','岳珂','宋','宋诗','song-poetry','','[]','清晨洗月露，雲色已如血。',120,'全唐诗/poet.song.193000.json','["清晨洗月露，雲色已如血。", "惟憂農畝枯，敢嘆征途熱。", "瀕湖十萬戶，旦旦望霓切。", "龍骨夾岸鳴，盡暮不暇歇。", "祇今牛犁地，已作龜兆裂。", "平湖三十里，泱漭幾盡竭。", "矧此一綫渠，而不比涸轍。", "天閽高莫叫，歲事漸無說。", "如予方懷章，何以救餘孑。", "回首望堯雲，憑風哀涕雪。"]'),
('c74615ff-f674-493f-bf3d-209f8a99b9b3','病虎行','岳珂','宋','宋诗','song-poetry','','[]','長風吹谷白日暗，曠野人稀雲黯澹。',259,'全唐诗/poet.song.193000.json','["長風吹谷白日暗，曠野人稀雲黯澹。", "狐狸嘯舞豺狼嘷，病虎妥尾行蓬蒿。", "天寒泉凍山骨高，皮枯髀痒霜爪搔。", "紛紛晴雪爮落毛，垂頭帖耳身腥臊。", "羣鴉槎牙噪古木，燐火半青新鬼哭。", "走麕過前不能逐，目視眈眈蹲樸𣙙。", "毛風血雨天地肅，何日跳踉看食肉。", "天生萬物有盛時，當年一嘯天助威。", "坐看雲起行引兒，當塗寧復論老羆。", "一朝老去守巖竇，落葉滿山冰雪後。", "壯心空在筋力疲，寂寞長饑眠白晝。", "古來豪傑多沈淪，不用爲鼠皆若人。", "范雎折脅西入秦，內史長嘆田甲嗔。", "可憐百獸爲披靡，轉顧不如圈中豕。", "男兒奮跲亦渠似，肯復虛爲倚崖死。", "君不見南山白額曾報恩，牆頭金枕投何人。"]'),
('ae51ed5d-a667-47a4-8369-1524036f8f9a','浩歌行','岳珂','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','浩然一氣古到今，古人無愧惟此心。',398,'全唐诗/poet.song.193000.json','["浩然一氣古到今，古人無愧惟此心。", "青天爲幕地爲席，醉裏聊作烏烏吟。", "君不見人生所重獨名謚，一代簡書耀青史。", "當時命名偶然耳，跖聖丘愚果誰是。", "又不見人生所願在貴豪，汾陽鐘鼎顔簞瓢。", "祇今等是一堆土，寧識生前時所遭。", "或言惟勢可凌物，旦作參軍暮蒼鶻。", "富方煉炭貧牛衣，上下升沈總飄忽。", "又言有才堪動人，文章不過紙上塵。", "卿雲復生鮑謝作，我亦不識知誰真。", "書函闔開古所患，萬札千緘漫堆案。", "當年京洛驛走塵，未見遠官救劉晏。", "人情炎涼今所同，鞠𦜕却篲壽迺公。", "小兒坐睡觸屏風，亦復諂語無所容。", "回思一拙勝百巧，囊粟侏儒先亦飽。", "纔從埽軌學𢾅門，邊上鋤犁不相保。", "又思三窟寄一身，東來入淛南入閩。", "已慚下車馮婦笑，又恐顧影癡兒嗔。", "一壺一鍤醒復醉，便作劉伶藉糟計。", "易園蓊蔚棠湖清，席上老兵未渠異。", "一花一柳春復秋，更效凝式東西游。", "池荷漸衰棗紅近，卹緯那免孤嫠憂。", "噫嚱人生萬事大似繭抽縷，百緒千端無物不如許。", "歸歟一曲浩浩歌，堯舜揖遜湯武興干戈。"]'),
('01afeaba-592e-4a46-b08c-df4f560ec9c6','玉唾壺','岳珂','宋','宋诗','song-poetry','','[]','古來玉唾壺，歌罷壺爲缺。',200,'全唐诗/poet.song.193000.json','["古來玉唾壺，歌罷壺爲缺。", "憂時一片心，常惜志士烈。", "鸊鵜瑩出昆吾刀，截肪溫潤如切膏。", "悲歌聲動行雲高，何愛一闋稱世豪。", "馬生冀州北，未省能伏櫪。", "骨拳鬃禿刓四蹄，鳳膺赭汗人不知。", "夕陽芳草顧影嘶，猶憶振鬣天山西。", "可憐歲華暮，萬里瑶池路。", "鹽車轆轆踰太行，夜然枯草晝服箱。", "上天振策無王良，徒有此志今未忘。", "荆山韞明月，良工斲不徹。", "抱璞昔三刖，曾泣卞和血。", "既斲復毀不可磨，尊前對酒聽浩歌。", "唾壺雖缺璞更多，騏驥不生奈老何。"]'),
('2ee555ad-ee7b-405c-b2f6-f4cf25b811c8','中橋二首  其一','岳珂','宋','宋诗','song-poetry','','[]','過了平湖又小溪，却從蕪徑訪多歧。',64,'全唐诗/poet.song.193000.json','["過了平湖又小溪，却從蕪徑訪多歧。", "如何江上乘風鷁，化作泥中曳尾龜。", "誰遣旌旟行沮洳，定知鼓吹宅漣漪。", "中橋咫尺末由到，且作吳兒玩水嬉。"]'),
('8228c8e9-09f3-4f7b-bcb7-4298e94fd982','中橋二首  其二','岳珂','宋','宋诗','song-poetry','','[]','澤國何村不著橋，中橋跬步即雲霄。',64,'全唐诗/poet.song.193000.json','["澤國何村不著橋，中橋跬步即雲霄。", "青帘望市雷鳴腹，黄帽推船水沒腰。", "六月彤雲摇旱火，一潮清浪捲晴飈。", "平生未慣舟行陸，鐵石心腸也合消。"]'),
('dbb3ce26-028f-4382-873d-e079bf15e813','泥行終日至晡始抵中橋六絕  其一','岳珂','宋','宋诗','song-poetry','','[]','終日泥行足半胝，中橋望見已多時。',32,'全唐诗/poet.song.193000.json','["終日泥行足半胝，中橋望見已多時。", "一篙不得風漪力，早被青帘聖得知。"]'),
('ba65c248-c6cb-4080-977d-e33afc373c29','泥行終日至晡始抵中橋六絕  其二','岳珂','宋','宋诗','song-poetry','','[]','平川煙草碧如煙，曲摺琉璃翡翠田。',32,'全唐诗/poet.song.193000.json','["平川煙草碧如煙，曲摺琉璃翡翠田。", "一水分明度舟檝，如何平陸却推船。"]'),
('a3b57e33-0ca6-4598-a8ea-4112b57c0366','泥行終日至晡始抵中橋六絕  其三','岳珂','宋','宋诗','song-poetry','','[]','農家未補眼前瘡，却種湖田作旱糧。',32,'全唐诗/poet.song.193000.json','["農家未補眼前瘡，却種湖田作旱糧。", "別浦誰家夜鳴艣，踐殘一半不成秧。"]'),
('32d4357f-0b45-46ee-bcf7-2041150fccbf','泥行終日至晡始抵中橋六絕  其四','岳珂','宋','宋诗','song-poetry','','[]','兩岸黄苗半跬深，媷餘短髮更傷心。',32,'全唐诗/poet.song.193000.json','["兩岸黄苗半跬深，媷餘短髮更傷心。", "莫疑一點無生意，盡是田家眼內針。"]'),
('0a8bd5fe-9988-4f87-816b-6264b1fb753e','泥行終日至晡始抵中橋六絕  其五','岳珂','宋','宋诗','song-poetry','','[]','歷盡清灣日已晡，斷虹吹浪過平湖。',32,'全唐诗/poet.song.193000.json','["歷盡清灣日已晡，斷虹吹浪過平湖。", "兒癡不識中橋影，問道前山有雨無。"]'),
('5351b61e-d7e6-4b53-9453-d8a7efaceb72','泥行終日至晡始抵中橋六絕  其六','岳珂','宋','宋诗','song-poetry','','[]','到得中橋一徑斜，岸傍沽酒兩三家。',32,'全唐诗/poet.song.193000.json','["到得中橋一徑斜，岸傍沽酒兩三家。", "長年醉卧桑陰下，鼓吹猶煩兩岸蛙。"]'),
('66f85f35-b22d-4b0a-b7e1-0f9bab429154','夜宿橋岸','岳珂','宋','宋诗','song-poetry','','[]','裊纜宿前灣，平蕪泱漭間。',48,'全唐诗/poet.song.193000.json','["裊纜宿前灣，平蕪泱漭間。", "舫移星在戶，岸迥斗藏山。", "淺瀨不勝揭，浮生何日閒。", "夜深聞過艣，知自溧陽還。"]'),
('19f078b7-c9ad-4dbf-8ba6-682908738100','問道宜興二首  其一','岳珂','宋','宋诗','song-poetry','','[]','買田陽羨說東坡，想見溪山勝槩多。',64,'全唐诗/poet.song.193000.json','["買田陽羨說東坡，想見溪山勝槩多。", "曾是中營誇繡帽，尚傳遺廟鎖雕戈。", "斬蛟義槩人猶記，化蝠仙蹤事易訛。", "我欲問津先訪古，古靈題蹟試摩挲。"]'),
('580c3469-3838-4c97-8bf6-c9601f85bb49','問道宜興二首  其二','岳珂','宋','宋诗','song-poetry','','[]','粹儀夾綻盛花鈿，人說先朝祀玉仙。',64,'全唐诗/poet.song.193000.json','["粹儀夾綻盛花鈿，人說先朝祀玉仙。", "罨畫有溪春不老，煉丹無竈古空傳。", "乞靈賸擬羞蘋藻，養性何勞學汞鉛。", "書閤蒼龍應不遠，爲君重寫白雲篇。"]'),
('f86576d5-3f61-4e2c-a356-c00847edd8ce','過謝䃮渰','岳珂','宋','宋诗','song-poetry','','[]','蒹葭曼衍浪縈回，波面雖平路不開。',64,'全唐诗/poet.song.193000.json','["蒹葭曼衍浪縈回，波面雖平路不開。", "溝瀆行舟休剡木，坳堂浮芥欲膠杯。", "人如鳬雁俱游耳，江有魚龍安在哉。", "但說渰名吾亦畏，輔渠有路莫重來。"]'),
('00fe2363-1576-47f8-bdb8-57ed0a03e372','遇順風','岳珂','宋','宋诗','song-poetry','','[]','身世漂摇似轉蓬，歷湖經渰任西東。',64,'全唐诗/poet.song.193000.json','["身世漂摇似轉蓬，歷湖經渰任西東。", "凌波小試檜松楫，宿露飽親葭葦叢。", "兩岸居然驚脫兔，一帆從此迅冥鴻。", "到頭天意君須會，吾道區區端未窮。"]'),
('e0e95697-f53a-4314-bd8b-faf47b7d30f9','楊梅','岳珂','宋','宋诗','song-poetry','','[]','渰歷三家市，梅垂萬顆酸。',48,'全唐诗/poet.song.193000.json','["渰歷三家市，梅垂萬顆酸。", "烽池看火樹，嶁室試金丹。", "風露盈籃重，冰霜透齒寒。", "它楊應不類，留與子雲看。"]'),
('4b49f236-3eec-4074-81a8-7b8896e0d7f4','六月二日乙丑濫溪大雷雨','岳珂','宋','宋诗','song-poetry','','[]','人言夏月雨甲子，赤地千里真旱祥。',320,'全唐诗/poet.song.193000.json','["人言夏月雨甲子，赤地千里真旱祥。", "今年六月天久亢，平疇龜坼田禾秧。", "農夫慟哭眼滴血，郡邑奔走焚巫尪。", "油雲勃興杳無際，涸轍渴想惟西江。", "誰能逆計休與咎，且願炎熱澆清涼。", "凌晨望霓到日暮，屯膏雖施了未光。", "萬夫喁訴百澮竭，風伯一埽還穹蒼。", "那知天意極仁愛，爲民之慮尤周詳。", "摇光一夕動北斗，濃霾五夜迷東望。", "赫曦再見耀亭午，童謠忽憶歌商羊。", "快哉雄風起蘋末，玉女嚂笑叫阿香。", "盡傾天瓢灑甘露，五丁仗劍分銀潢。", "桑麻油油粟旆旆，稻苗鬰鬰溪湯湯。", "葭蘆起舞岸柳揖，農家欣喜幾欲狂。", "向來羣心已誤見，俱謂時數無金穰。", "詎知瞬息變呼吸，頓使空廩還千箱。", "彼管窺天蠡測海，妄以時日肆度量。", "亦復委曲致避就，聊徇世俗拘陰陽。", "天於萬物乃如此，大造生意何可忘。", "嗟乎得隴仍望蜀，更乞一剪田中蝗。"]'),
('d63d8327-934f-49fd-92e5-7ee9188574f2','道中思廬山','岳珂','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山三百里，巨浸壓宮亭。',240,'全唐诗/poet.song.193000.json','["廬山三百里，巨浸壓宮亭。", "勢接九江匯，峰連萬古青。", "淵源開道術，哤幻雜仙靈。", "厚地蟠奇秀，雄標動杳冥。", "濃嵐晨歷歷，流水夜泠泠。", "雪擁瓊瑶障，花繁錦繡屏。", "吾居嘗靜對，親處異空聆。", "瀑布手自酌，斜川身所經。", "龍淵敲短策，鳥道絕危陘。", "正派尊涵泳，高山有典型。", "揭來三涉徑，知閲幾周星。", "白傅松猶在，陶潜菊未零。", "堅高思並轍，今古共忘形。", "便擬安圭竇，終期老澗坰。", "忽嚴大君詔，言駕小侯軿。", "一別門垂柳，重觀階換蓂。", "出山羞小草，浮海又流萍。", "頗覺登山屐，翻成泛宅舲。", "回頭看豹霧，望眼隔鸞汀。", "縱抱知還志，何時振倦翎。"]'),
('ae0003c1-bafd-4ca5-b1ed-df6ab8dfa6a5','寄江州趙倅季茂二首時過溧陽舟中正遇順風張帆  其一','岳珂','宋','宋诗','song-poetry','','[]','扁舟初下投金瀨，忽憶湓江趙治中。',64,'全唐诗/poet.song.193000.json','["扁舟初下投金瀨，忽憶湓江趙治中。", "才氣當年凡事別，詩盟近日與誰同。", "何當解印乘歸興，想見隨橋亦順風。", "茶竈筆床淡生活，一帆先借老龜蒙。"]'),
('814b135e-46df-48d4-a00b-9691101b6234','寄江州趙倅季茂二首時過溧陽舟中正遇順風張帆  其二','岳珂','宋','宋诗','song-poetry','','[]','庾公樓上憑欄時，一片歸雲費夢思。',64,'全唐诗/poet.song.193000.json','["庾公樓上憑欄時，一片歸雲費夢思。", "鄉國情懷應念我，江山風月定分誰。", "青衫休爲墓陵濕，紫氣先尋牛渚期。", "好是初秋藕花候，蛾眉尊酒正相宜。"]'),
('aa83c4ae-1dc7-4a9a-a9f1-7e0bcf0b36c9','寄胡教授二首  其一','岳珂','宋','宋诗','song-poetry','','[]','西風送我溧陽溪，終日篷窗祇有詩。',64,'全唐诗/poet.song.193000.json','["西風送我溧陽溪，終日篷窗祇有詩。", "黄篾未妨床著筆，青緺不管鬢成絲。", "雁隨去訊勞君問，鷗憶同盟尚我隨。", "想見歸舟不多日，一樽牛渚訪秋期。"]'),
('406de783-8b57-4e29-a157-3544f43a5aca','寄胡教授二首  其二','岳珂','宋','宋诗','song-poetry','','[]','潯陽江上無氈客，別後音書杳未通。',64,'全唐诗/poet.song.193000.json','["潯陽江上無氈客，別後音書杳未通。", "蕉鹿定應隣左計，蓴鱸端是待西風。", "謾懷離思人猶遠，欲寓吟情句未工。", "朝列鵷鴻問消息，一牋莫靳寄詩筩。"]'),
('fba24536-96db-43eb-b832-1e84018d2ba6','寄高建寧尚書二首  其一','岳珂','宋','宋诗','song-poetry','','[]','鶴書幾到闔廬城，見說君王憶姓名。',64,'全唐诗/poet.song.193000.json','["鶴書幾到闔廬城，見說君王憶姓名。", "衡嶽雲開傳諫草，考亭月冷見文盟。", "不從金馬登丞輔，却托銅菟煩客卿。", "天意未應無定據，管教吾道致升平。"]'),
('69736938-b70c-4e1b-b81f-64cb09c57515','寄高建寧尚書二首  其二','岳珂','宋','宋诗','song-poetry','','[]','已分耕畦老一犁，天風吹夢入枯溪。',64,'全唐诗/poet.song.193000.json','["已分耕畦老一犁，天風吹夢入枯溪。", "誰憐北垞騎牛背，又踏東華放馬蹄。", "槐綠不妨穿禁漏，棗紅便覺動邊鼙。", "歸途願請平戎策，政恐曹裝趁詔泥。"]'),
('2934c4fc-8915-493b-9b62-6f9e36bd2c22','天申萬壽宮','岳珂','宋','宋诗','song-poetry','','[]','湖㳇溪邊春草青，張公洞下泉泠泠。',320,'全唐诗/poet.song.193000.json','["湖㳇溪邊春草青，張公洞下泉泠泠。", "兩行松檜列旌纛，中有金堂開福庭。", "壯哉神力出杳冥，樓觀矗立排巖扃。", "焜煌金碧儼相照，刻石猶紀唐朝銘。", "中興天子授舜禪，壽宮晨候祠官星。", "紫衣敕使易霞袂，白茅羽士迎雲軿。", "頗聞當日動乾象，二十八宿摇天經。", "奎鈎寫題月兔泣，昭回雲漢爭晶熒。", "至今榮光猶炳耀，百爾呵護煩山靈。", "玉仙紵像羅珓卜，昭應奎寶模牌形。", "朅來正值天六月，栢城將泫秋露零。", "芝輿望幸已絕覬，蒿悽觸感徒靡寧。", "岫雲無心出而雨，谷風振響流爲霆。", "石堪礪齒定何似，流欲洗耳將誰聽。", "嗟哉行役久勞勩，如鳥知倦纔振翎。", "燒香臺邊聊倚策，煉丹竈上方絕陘。", "由下瞻仰始知悔，扶力已竭那可停。", "衆皆徇目且徇耳，我謂獨往非獨醒。", "從初秘祝本何益，中休端自明德馨。", "周家克敬綿萬億，自今葉葉皆堯齡。"]'),
('3c5c5f71-ada8-4f7b-bfda-04d849dc3297','張公洞二首  其一','岳珂','宋','宋诗','song-poetry','','[]','祚紀千齡運，名標二代仙。',48,'全唐诗/poet.song.193000.json','["祚紀千齡運，名標二代仙。", "鵲鳴應徙地，蝠化已先天。", "風洞疑無底，丹爐信有緣。", "祇應巖下弈，爲我一跫然。"]'),
('609dc71a-fada-4731-95dc-b90d08b5d10f','張公洞二首  其二','岳珂','宋','宋诗','song-poetry','','[]','馿跡驚初踐，鷹盤若有靈。',48,'全唐诗/poet.song.193000.json','["馿跡驚初踐，鷹盤若有靈。", "石橋通便戶，金鑰鎖硃庭。", "滴乳看成像，登臺仍刻銘。", "更憐國山字，真欲比云亭。"]'),
('44a52aa6-7a4d-44d9-b329-272dd8ddf647','晨日湖㳇至青口有數老父携筐筥拜道旁問之則山居之民紹定中嘗以摘山爲香蘭寨兵所擾予時將指淮東爲直之適見騶從聞予之姓曰是姓稀必吾官也以新茗爲贄予笑遣去遮道不已因感其意却而謝之有賦','岳珂','宋','宋诗','song-poetry','','[]','路傍迎拜正紛紛，尚憶鋤山話事因。',64,'全唐诗/poet.song.193000.json','["路傍迎拜正紛紛，尚憶鋤山話事因。", "老去可憐心尚在，姓稀猶是耳曾聞。", "驛追少日傳行客，犬吠多年絕過軍。", "慚媿一錢無以稱，殷勤寄語若耶雲。"]'),
('19284190-8242-48f6-962f-875f21088cba','過啄木嶺暑暍憩道傍移時始行三首  其一','岳珂','宋','宋诗','song-poetry','','[]','啄木侵雲起，流金正日中。',48,'全唐诗/poet.song.193000.json','["啄木侵雲起，流金正日中。", "澗深猶斷港，山崦略無風。", "自是人來去，何關暑藴隆。", "羲皇正高卧，多媿北窗翁。"]'),
('8c5bf3f3-81d6-47f1-b49c-c79348b826ff','過啄木嶺暑暍憩道傍移時始行三首  其二','岳珂','宋','宋诗','song-poetry','','[]','憑軾汗如雨，低簷氣若炊。',48,'全唐诗/poet.song.193000.json','["憑軾汗如雨，低簷氣若炊。", "垂頭疑大病，駐足便多時。", "輿隸爭陰樾，家人薦藥糜。", "吾生黨行道，暑暍亦奚爲。"]'),
('15b79181-d8c9-4c43-a432-e609cb794796','過啄木嶺暑暍憩道傍移時始行三首  其三','岳珂','宋','宋诗','song-poetry','','[]','鳥道度嶮絕，禽名通古今。',48,'全唐诗/poet.song.193000.json','["鳥道度嶮絕，禽名通古今。", "築亭聊駐馬，息木未成陰。", "路峻天應近，崖幽霧更深。", "畏途猶避熱，坐有躡雲心。"]'),
('06529c73-c5d8-4a12-862d-c54687d96ba4','望北關門','岳珂','宋','宋诗','song-poetry','','[]','萬里雲開瑞日明，雕甍遥接九重城。',64,'全唐诗/poet.song.193000.json','["萬里雲開瑞日明，雕甍遥接九重城。", "觚連丹鳳紅雲繞，關度青牛紫氣迎。", "新第千門俱改觀，舊溪二紀漫關情。", "今宵且向橋頭宿，又聽鼕鼕打六更。"]'),
('63e8ed9f-7cf4-43a7-b907-8eea22566b2d','六月二十一日內引賜對緝熙殿玉音宣問漏下數刻將退賜金幣香茗有差既而御筆除長地官將旨八路復賜一札兼鎮姑孰敬紀感遇以昭恩榮四首  其一','岳珂','宋','宋诗','song-poetry','','[]','曲廊青瑣午陰遲，一朶紅雲擁緝熙。',64,'全唐诗/poet.song.193000.json','["曲廊青瑣午陰遲，一朶紅雲擁緝熙。", "便座詢猷親帝問，近璫承詔引朝儀。", "小臣曾是鵷鴻舊，夙幸還瞻龍鳳姿。", "出殿陛郎驚漏下，兩行簾日影參差。"]'),
('07782af6-0494-4e09-b8ff-cf12907dd6f2','六月二十一日內引賜對緝熙殿玉音宣問漏下數刻將退賜金幣香茗有差既而御筆除長地官將旨八路復賜一札兼鎮姑孰敬紀感遇以昭恩榮四首  其二','岳珂','宋','宋诗','song-poetry','','[]','二紀身陪獻納班，今朝始得拜金鑾。',64,'全唐诗/poet.song.193000.json','["二紀身陪獻納班，今朝始得拜金鑾。", "褭蹄范鑄分天馥，鮫織開奩薦月團。", "奎壁近霑琅鈕濕，斗牛直射寶光寒。", "糜捐雖有平生志，自覺君恩報稱難。"]'),
('8380f12e-ef4c-41ec-ba20-bf35257bc500','六月二十一日內引賜對緝熙殿玉音宣問漏下數刻將退賜金幣香茗有差既而御筆除長地官將旨八路復賜一札兼鎮姑孰敬紀感遇以昭恩榮四首  其三','岳珂','宋','宋诗','song-poetry','','[]','曾窺遺制辨中朝，更帖驍游八座貂。',64,'全唐诗/poet.song.193000.json','["曾窺遺制辨中朝，更帖驍游八座貂。", "空有丹心酬雨露，詎應赤脚踏煙霄。", "人繇汲汲知堯舜，我豈區區事管蕭。", "不是鸞臺勤再詔，狂言何以發芻蕘。"]'),
('b524b1fc-8bf0-4792-a0ec-fdb301313609','六月二十一日內引賜對緝熙殿玉音宣問漏下數刻將退賜金幣香茗有差既而御筆除長地官將旨八路復賜一札兼鎮姑孰敬紀感遇以昭恩榮四首  其四','岳珂','宋','宋诗','song-poetry','','[]','單軺從此歷湖陰，自愧便蕃聖澤深。',64,'全唐诗/poet.song.193000.json','["單軺從此歷湖陰，自愧便蕃聖澤深。", "贈策不煩秦士歎，埋輪聊見漢臣心。", "主憂未解誠知辱，民瘵猶思力不任。", "表語拳拳懷美報，用中聊以當虞箴。"]'),
('12ed34a1-2670-412e-82b8-020fd9839093','中秋夜宿旌德觀無月','岳珂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','滿看金盆湧碧流，西湖從古愜中秋。',64,'全唐诗/poet.song.193000.json','["滿看金盆湧碧流，西湖從古愜中秋。", "清班正自重闉隔，塵鞅難從近甸游。", "自是四并偏我靳，從知一笑豈人謀。", "望霓得月良非急，且願西風送雨休。"]'),
('966c2a2d-a6cf-4e96-b339-527b23df0d2d','水樂洞','岳珂','宋','宋诗','song-poetry','','[]','天下水樂洞，今歸四姓家。',48,'全唐诗/poet.song.193000.json','["天下水樂洞，今歸四姓家。", "臺池閒日月，泉石痼煙霞。", "誰挈游人榼，還尋奉使楂。", "明朝重回首，清夢隔京華。"]'),
('c527d0be-4e43-4c03-944c-32bff3c481cf','趙山二絕  其一','岳珂','宋','宋诗','song-poetry','','[]','驅車結束趁晨暾，水樂簾前共一尊。',32,'全唐诗/poet.song.193000.json','["驅車結束趁晨暾，水樂簾前共一尊。", "二十二年如掣電，軟紅依舊暗脩門。"]'),
('156693c9-ff76-48f7-8959-48922403f484','趙山二絕  其二','岳珂','宋','宋诗','song-poetry','','[]','江南閒殺老尚書，自是承平一事無。',32,'全唐诗/poet.song.193000.json','["江南閒殺老尚書，自是承平一事無。", "送客折腰書脫腕，試從駝巘看登塗。"]'),
('f7310c04-acb5-4fd2-b26c-c6ecba624aab','洞霄宮','岳珂','宋','宋诗','song-poetry','','[]','岧嶢樓觀鎖新宮，十里清溪一徑松。',64,'全唐诗/poet.song.193000.json','["岧嶢樓觀鎖新宮，十里清溪一徑松。", "金榜奎章紅日照，石崖仙影白雲封。", "香殘半掩凝塵榻，路轉猶聞隔澗鐘。", "四牡經行真不枉，玉淵初識洞霄龍。"]'),
('9685e574-9966-4a79-867d-5a8df4e8b9d9','洞霄宮良泓孫副宮二首  其一','岳珂','宋','宋诗','song-poetry','','[]','山比復泓澄，幽房取次行。',48,'全唐诗/poet.song.193000.json','["山比復泓澄，幽房取次行。", "萬峰隨眼換，一勺照心清。", "墜露涵秋氣，斜暉度晚晴。", "逌然還自笑，見易未經名。"]'),
('b6db50eb-4b9f-4326-b573-9d9e7fe62e76','洞霄宮良泓孫副宮二首  其二','岳珂','宋','宋诗','song-poetry','','[]','養生須及早，器破輒難全。',48,'全唐诗/poet.song.193000.json','["養生須及早，器破輒難全。", "鑑止存心地，涵虛詠性天。", "寓言隨㶁㶁，至理本淵淵。", "玩物先觀象，如師況少年。"]'),
('b21da053-0a2a-487d-a52c-b6f3fa60a6b1','試廬陵賀發竹絲筆','岳珂','宋','宋诗','song-poetry','','[]','此君素以直節名，延風揖月標韻清。',64,'全唐诗/poet.song.193000.json','["此君素以直節名，延風揖月標韻清。", "何人心匠出天巧，縷析毫分勻且輕。", "居然束縛復其始，即墨紆朱封管城。", "世門官爵豈必計，且幸一家同汗青。"]'),
('a1a1de45-a4df-477a-91d4-fef25311f889','九月八日桐川道中二絕  其一','岳珂','宋','宋诗','song-poetry','','[]','斷雲輕素抹山腰，山下人家野水橋。',32,'全唐诗/poet.song.193000.json','["斷雲輕素抹山腰，山下人家野水橋。", "小隊旌旗空獵獵，不教閒趁酒旗招。"]'),
('739a3733-dcbb-4286-b8ba-8ea4f2c87ef6','九月八日桐川道中二絕  其二','岳珂','宋','宋诗','song-poetry','','[]','依稀九日明朝是，三徑情知不到家。',32,'全唐诗/poet.song.193000.json','["依稀九日明朝是，三徑情知不到家。", "隨分秋光關節物，桐川道上看黄花。"]'),
('f0d728c4-8ef1-45d0-96b2-4535af8d2c00','九日發廣德至建平感事有作','岳珂','宋','宋诗','song-poetry','','[]','西風吹著白髭鬚，嘉節催儂老道塗。',64,'全唐诗/poet.song.193000.json','["西風吹著白髭鬚，嘉節催儂老道塗。", "無菊傍籬真漫與，有松掃逕故應蕪。", "登龍路近心誰賞，戲馬臺成足已瘏。", "悵望杜陵正搔首，一枝不得賜茱萸。"]'),
('394ba2da-03e2-4a2c-8be0-263860d934fa','是日迎送之車屬道戲成','岳珂','宋','宋诗','song-poetry','','[]','老仗相如節，佳時負酒尊。',48,'全唐诗/poet.song.193000.json','["老仗相如節，佳時負酒尊。", "人誰羞俠轂，我自媿乘軒。", "塵土欺貂袖，功名付犢褌。", "令君休負矢，予不詫王孫。"]'),
('005d27c0-cec7-48aa-9f4f-2637e61dc2b7','宵征','岳珂','宋','宋诗','song-poetry','','[]','炬火一川明，前驅聽鼓鉦。',48,'全唐诗/poet.song.193000.json','["炬火一川明，前驅聽鼓鉦。", "指途期縣驛，問道趣王程。", "不爲栢人怯，聊尋葵戍盟。", "征夫免泥淖，何忍喜天晴。"]'),
('84ea2e7b-d43a-49e1-816a-d7525c036920','夢尚留三橋旅邸','岳珂','宋','宋诗','song-poetry','','[]','天上歸來打六更，夢回搔首正瞢騰。',64,'全唐诗/poet.song.193000.json','["天上歸來打六更，夢回搔首正瞢騰。", "玉霜初上三更月，絳綵猶明九市燈。", "聲徹銅魚催勘箭，影斜金鵲在觚稜。", "帝鄉東望重回首，佳氣何時到五陵。"]'),
('fd409d72-535e-4168-bf86-ea9f19637c04','病中試張觀筆','岳珂','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','淮上霜濃衰草黄，阿㕙健走何如獐。',144,'全唐诗/poet.song.193000.json','["淮上霜濃衰草黄，阿㕙健走何如獐。", "不知聚族加束縛，妙手乃有明山張。", "生來阿㕙素狡獪，何術聚致如驅羊。", "拔豪擷穎不敢惜，一一順聽伏且僵。", "人生切勿恃一技，善走古有執蓋郎。", "不惟平地傅兩翼，仍以俘馘浮長江。", "一朝發憤遼東岸，逝水亦復隨浮梁。", "只今紅綃瑩玉管，何人解發千古光。", "明張眼前第一手，嗟嗟阿㕙孰能走。"]'),
('39d7db6c-c852-4bd5-b4a2-379da4565586','十月廿五日有詔以予班六卿賜對衣金带鞍馬二首  其一','岳珂','宋','宋诗','song-poetry','','[]','綴蹟中朝十四春，精鏐兩錫带圍新。',64,'全唐诗/poet.song.193000.json','["綴蹟中朝十四春，精鏐兩錫带圍新。", "賜袍又見光蹏褭，沃轡不妨翔苑麟。", "有馬可乘存史闕，無衣謾賦感君仁。", "輕肥豈是平生志，髀肉何堪豢此身。"]'),
('75d8170c-0b94-40c1-9c06-4a0b7f094784','十月廿五日有詔以予班六卿賜對衣金带鞍馬二首  其二','岳珂','宋','宋诗','song-poetry','','[]','非念蹉跎馬少游，幾年田野任沈浮。',64,'全唐诗/poet.song.193000.json','["非念蹉跎馬少游，幾年田野任沈浮。", "衣章不稱麒麟楦，袍縕誰慙狐貉儔。", "試問囁嚅常束带，何如款段自經丘。", "感恩一念惟憂國，莫笑隠居金絡頭。"]'),
('e3f6895a-af6d-4d95-a83f-0e59203f7bca','當塗勸駕詩','岳珂','宋','宋诗','song-poetry','','[]','禮行鳴鹿盛侯邦，企慕纔因既見降。',64,'全唐诗/poet.song.193000.json','["禮行鳴鹿盛侯邦，企慕纔因既見降。", "詔下菑川今第一，才如成紀古無雙。", "雷聲龍化標應奪，筆力牛迥鼎易扛。", "老守殷勤折津柳，相期鼓吹輅春江。"]'),
('97b1c09a-352c-409a-b575-b8898d6a7a69','鹿鳴宴中走筆呈林教授','岳珂','宋','宋诗','song-poetry','','[]','三級催龍浪，朋來盛鹿賓。',48,'全唐诗/poet.song.193000.json','["三級催龍浪，朋來盛鹿賓。", "淵源識餘潤，騰踏已通津。", "融帳知方盛，陸莊應未貧。", "成功豈無日，況復值詞人。"]'),
('968f0910-9dc7-462d-be7e-f4a5d8d64762','碧雲亭晚眺二首  其一','岳珂','宋','宋诗','song-poetry','','[]','閒步碧雲亭，寒郊弄晚晴。',48,'全唐诗/poet.song.193000.json','["閒步碧雲亭，寒郊弄晚晴。", "牛羊分暝色，禽鳥有春聲。", "城柳風猶勁，溪梅冰共清。", "屋梁正殘照，西望憶長庚。"]'),
('72977233-15c4-40b5-a53a-f040b75ac1a3','碧雲亭晚眺二首  其二','岳珂','宋','宋诗','song-poetry','','[]','歲華方冉冉，耕畝自閒閒。',48,'全唐诗/poet.song.193000.json','["歲華方冉冉，耕畝自閒閒。", "日落青楓浦，雲平白苧山。", "夜城嚴警柝，昏鼓動層關。", "風露汀洲冷，驚鴻自往還。"]'),
('ba83b490-b97c-4953-b0a5-39fac21099ee','題王諶潛泉蛙吹二首  其一','岳珂','宋','宋诗','song-poetry','','[]','開編看句律，著意寫題辭。',48,'全唐诗/poet.song.193000.json','["開編看句律，著意寫題辭。", "業以能潜大，泉如始達時。", "一謙聊託物，六義可言詩。", "有問君須答，爲公還爲私。"]'),
('d4208fe0-df5c-46bf-9f98-fb8f52d3a6a1','題王諶潛泉蛙吹二首  其二','岳珂','宋','宋诗','song-poetry','','[]','楓落吳江冷，曾聞五字傳。',48,'全唐诗/poet.song.193000.json','["楓落吳江冷，曾聞五字傳。", "懸知鷙累百，何待己能千。", "清氣溪山宅，閒情月露篇。", "六經須鼓吹，吾子盍先鞭。"]'),
('2a8c236a-1750-4116-9df7-1a82ac82eb64','閏月之臘詔賜銀合臘藥三首  其一','岳珂','宋','宋诗','song-poetry','','[]','驛使錦連乾，傳宣下九天。',48,'全唐诗/poet.song.193000.json','["驛使錦連乾，傳宣下九天。", "緘題瞻賜璽，走送聽鳴鞭。", "意溢兼金外，恩從玉陛前。", "更憐戍邊客，一騎入秦川。"]'),
('6662fc2f-bd9e-4556-80f5-096bfee93557','閏月之臘詔賜銀合臘藥三首  其二','岳珂','宋','宋诗','song-poetry','','[]','式賜十一種，分馳數百程。',48,'全唐诗/poet.song.193000.json','["式賜十一種，分馳數百程。", "虎符多俊傑，貂帽比恩榮。", "老矣何能役，居然忝此名。", "聖情天樣闊，美報誓餘生。"]'),
('b423ff94-fe80-4fd3-96cd-8e6998c06198','閏月之臘詔賜銀合臘藥三首  其三','岳珂','宋','宋诗','song-poetry','','[]','無功應自念，有賜盍先嘗。',48,'全唐诗/poet.song.193000.json','["無功應自念，有賜盍先嘗。", "病作餘生累，恩頒上劑良。", "願覘齊國證，小效越人方。", "采菲儻留意，須先元氣防。"]'),
('31a5aa9d-bf67-4042-ab7c-e03f62ad28b1','嘉熙四年九月奉詔改明年元爲淳祐閏十二月降德音','岳珂','宋','宋诗','song-poetry','','[]','我生淳熙間，今復見淳祐。',288,'全唐诗/poet.song.193000.json','["我生淳熙間，今復見淳祐。", "粵從髮覆額，及此已衰耇。", "恭惟孝皇聖，是時方在宥。", "兩宮俱萬年，薄海同一候。", "四時無札癘，仍歲稱大有。", "布政具方策，詒謀謹封守。", "中更繼代三，更閲改年九。", "帝心思止當，休命侈誕受。", "夫何邇年來，譴告頗輻湊。", "災流雨雹行，星以妖彗奏。", "烏暘爍天地，蝗害徧田畝。", "饑氓腹□□，遺穗莽如帚。", "莫量天降疵，但見證書咎。", "嗟予斗升□，濫此符竹剖。", "眼看人穽崖，心愧吳父母。", "忽傳一札下，取法四宗舊。", "既叶天人助，復期風俗厚。", "熙陵道化盛，仁祖歷年久。", "華旦盛太平，中天開永阜。", "願言緝熙襲，還見泰和又。", "三春霈雷雨，一洗徧宇宙。", "桁楊空滯冤，緡庾釋逋負。", "無文祀咸秩，有纇網皆漏。", "果聞精祲合，悔禍屈伸肘。"]'),
('45339073-f961-452d-8776-53b44c8c3a2b','宮詞一百首  其一','岳珂','宋','宋诗','song-poetry','','[]','五色雲煙覆帝城，御溝流水接金明。',32,'全唐诗/poet.song.193000.json','["五色雲煙覆帝城，御溝流水接金明。", "曉來珂繖沙堤閙，萬歲聲中賀太平。"]'),
('66e63579-0aa4-4c92-a6f1-a1b26359367a','宮詞一百首  其二','岳珂','宋','宋诗','song-poetry','','[]','一朶祥雲捧赭袍，九天春色醉仙桃。',32,'全唐诗/poet.song.193000.json','["一朶祥雲捧赭袍，九天春色醉仙桃。", "教坊度曲聲嗺酒，折檻雙瞻舞袖高。"]'),
('93d314da-bd12-4738-9811-ee53aec7bc29','宮詞一百首  其三','岳珂','宋','宋诗','song-poetry','','[]','天街御膳寫臣封，隨例朝朝進六宮。',32,'全唐诗/poet.song.193000.json','["天街御膳寫臣封，隨例朝朝進六宮。", "後苑日高催泛索，茶牀擎出繡雲龍。"]'),
('f2acf3d8-c547-436b-91e4-765f742e2183','宮詞一百首  其四','岳珂','宋','宋诗','song-poetry','','[]','五夜鍾聲上直時，焚香重熨早朝衣。',32,'全唐诗/poet.song.193000.json','["五夜鍾聲上直時，焚香重熨早朝衣。", "裹頭殿直催排立，等候君王出木圍。"]'),
('64a4b6d9-c7ec-415f-b400-e6a5d8232648','宮詞一百首  其五','岳珂','宋','宋诗','song-poetry','','[]','雉扇雙分識聖顔，紫宸上閤正催班。',32,'全唐诗/poet.song.193000.json','["雉扇雙分識聖顔，紫宸上閤正催班。", "退朝花底紛歸騎，春在金門萬柳間。"]'),
('840d807b-7f55-4a85-af18-0fa5dd3398ee','宮詞一百首  其六','岳珂','宋','宋诗','song-poetry','','[]','內省催班立御廊，紫宸朝退侍君王。',32,'全唐诗/poet.song.193000.json','["內省催班立御廊，紫宸朝退侍君王。", "尚宮直筆呈章奏，一縷金猊繞殿香。"]'),
('bda11d57-31d2-491f-8da9-0c06d70f86e2','宮詞一百首  其七','岳珂','宋','宋诗','song-poetry','','[]','黎明新火下龍墀，御柳青煙冷食時。',32,'全唐诗/poet.song.193000.json','["黎明新火下龍墀，御柳青煙冷食時。", "別殿焚香催賜宴，傳宣教進謝恩詩。"]'),
('4a91c6c6-53de-42d8-9f88-536d4c8f4529','宮詞一百首  其八','岳珂','宋','宋诗','song-poetry','','[]','端辰帖子縷黄金，詞苑題來禁籞深。',32,'全唐诗/poet.song.193000.json','["端辰帖子縷黄金，詞苑題來禁籞深。", "共道萬方欣解慍，南風已奏舜鳴琴。"]'),
('75d3d3ac-2a12-439c-af5e-5b7c215fb618','宮詞一百首  其九','岳珂','宋','宋诗','song-poetry','','[]','太液沉雲冷寖菰，宮簾卷月掛珊瑚。',32,'全唐诗/poet.song.193000.json','["太液沉雲冷寖菰，宮簾卷月掛珊瑚。", "插天樓殿凉如洗，好是承平七夕圖。"]'),
('d98effd6-d654-47e2-a0f5-0ba1ecf810f5','宮詞一百首  其一○','岳珂','宋','宋诗','song-poetry','','[]','銀罌翠筦恰冬時，近臘金門賜口脂。',32,'全唐诗/poet.song.193000.json','["銀罌翠筦恰冬時，近臘金門賜口脂。", "無數槐籠擎積雪，日華漸上萬年枝。"]'),
('75968fd1-d360-46cb-8e98-1659c1fbfbcc','宮詞一百首  其一一','岳珂','宋','宋诗','song-poetry','','[]','上黨王師未凱旋，鸞旗黄鉞正行邊。',32,'全唐诗/poet.song.193000.json','["上黨王師未凱旋，鸞旗黄鉞正行邊。", "紅塵一騎傳天使，爲送宮中則劇錢。"]'),
('9376f807-64f7-474e-b320-54b8fda6cffa','宮詞一百首  其一二','岳珂','宋','宋诗','song-poetry','','[]','六師夜撤廣陵圍，積甲蕪城一樣齊。',32,'全唐诗/poet.song.193000.json','["六師夜撤廣陵圍，積甲蕪城一樣齊。", "淮海祇今清徹底，更留京觀築鯨鯢。"]'),
('cb3c5af5-7b1e-43c0-88c3-815a136e0067','宮詞一百首  其一三','岳珂','宋','宋诗','song-poetry','','[]','夜深雪壓內門前，一榻還驚四璧天。',32,'全唐诗/poet.song.193000.json','["夜深雪壓內門前，一榻還驚四璧天。", "上相傳觴妻擁炭，歸來鼾息頓安眠。"]'),
('d417625b-d7fd-4e31-b3d9-0c5000b1f958','宮詞一百首  其一四','岳珂','宋','宋诗','song-poetry','','[]','闕門雙鳳鑄黄金，柳色宮溝轉綠陰。',32,'全唐诗/poet.song.193000.json','["闕門雙鳳鑄黄金，柳色宮溝轉綠陰。", "闢盡四門繩樣直，萬方同見一人心。"]'),
('27aa1218-c4da-40c1-8d62-2e1b40852ee4','宮詞一百首  其一五','岳珂','宋','宋诗','song-poetry','','[]','驥騄雙馳挽六鈞，一枝花蘂委紅塵。',32,'全唐诗/poet.song.193000.json','["驥騄雙馳挽六鈞，一枝花蘂委紅塵。", "相輝樓下空排馬，徒見寧王奉太真。"]'),
('8d32c32d-7bc9-4d85-8b35-b52b2c1a03d5','宮詞一百首  其一六','岳珂','宋','宋诗','song-poetry','','[]','奎躔五緯驗連珠，瑞紀人文啟聖符。',32,'全唐诗/poet.song.193000.json','["奎躔五緯驗連珠，瑞紀人文啟聖符。", "一札鐵衣天下誦，千山黑處起金烏。"]'),
