('a7ba3547-f273-4a0b-b114-3a6c01943d92','宮詞一百首  其一○○','岳珂','宋','宋诗','song-poetry','','[]','鬰葱佳氣藹南都，共識彊華赤伏符。',32,'全唐诗/poet.song.193000.json','["鬰葱佳氣藹南都，共識彊華赤伏符。", "地紀已占江渡馬，天心定見屋流烏。"]'),
('b0f83aa4-3726-458a-9982-30a0d2049142','太宗皇帝處分手札御書贊','岳珂','宋','宋诗','song-poetry','','[]','於赫炎圖，真主勃興，人文其昌。',331,'全唐诗/poet.song.193000.json','["於赫炎圖，真主勃興，人文其昌。", "天開神機，海嶽洗氛，龜龍發祥。", "明明廟謨，麾指變更，著于宸章。", "十行之頒，六合驛行，動罔不臧。", "片幅所傳，神護鬼呵，積于縑緗。", "筆縱墨濃，奇正迭參，芸閣之藏。", "臣傳此札，字體靜嚴，意態齋莊。", "或指以疑，臣謂不然，各適所當。", "前朝大臣，帝心所祗，理異尋常。", "豈以軍書，龍戰鷹揚，而可比方。", "或敬而咨，或召而親，都俞巖廊。", "帝心所形，帝札所存，默寓弛張。", "璆琅鳴琚，佩玉以趨，韜鋒歛鋩。", "闢闔坤乾，風霆雲烟，萬世所望。", "意其當時，左右拱承，日思贊襄。", "君臣同心，始于一堂，以達八荒。", "後三百年，來瞻奎躔，猶知激昂。", "有偉副車，承平之儲，印以含光。", "劫火洞昏，玉躞金題，猶識褾裝。", "於昭帝圖，詔于後昆，不愆不忘。", "惟天縱之能，惟心之亨，惟斷之剛。", "臣得其真，寶以昭之，冠于百王。"]'),
('ded7ed32-0ff5-4406-9d2e-4e9882f78591','太宗皇帝古詩御書贊','岳珂','宋','宋诗','song-poetry','','[]','乾德之五星，旋于降婁，開文祥兮。',95,'全唐诗/poet.song.193000.json','["乾德之五星，旋于降婁，開文祥兮。", "太常之英姿，跨頡歷籀，開大荒兮。", "游藝之神，𨏼古轢今，奚鍾王兮。", "維副車之題，在承平時，謹瑟藏兮。", "維北宮之璽，施于中興，傳帝皇兮。", "維臣其得之，錦弢瓊函，絢宸章兮。"]'),
('573ab053-439c-41b2-b810-c448f9644973','太宗皇帝南牙謝熊白狀贊','岳珂','宋','宋诗','song-poetry','','[]','鼎食之珍，義比美芹，致者何人，姓名之已湮。',132,'全唐诗/poet.song.193000.json','["鼎食之珍，義比美芹，致者何人，姓名之已湮。", "天筆之存，龍跡紛縕，暗于風塵，拱護之有神。", "字取其均，揩取其陳，質勝于文，繄風俗之淳。", "鑄印以新，繫姓以親，昭哉天倫，繄友悌之真。", "嗚呼，有典有則，詒厥子孫，此帖之傳，奚止乎關石之與和均。", "臣繫以詩，式著厥因。", "聖制不磨，考于斯文。"]'),
('49ad5dac-35c0-4ee1-8a5d-c76d046c9ee3','真宗皇帝御製朱表御書贊','岳珂','宋','宋诗','song-poetry','','[]','宋德茂三世，祥符闓九清。',192,'全唐诗/poet.song.193000.json','["宋德茂三世，祥符闓九清。", "兢業帝道登，陟降王心寧。", "龍鸞夜染翰，虎豹晨抽扃。", "宸心勤惕憂，精思入杳冥。", "慶陰雲裔裔，飆景風泠泠。", "朱表動淵監，蒼旻聞德馨。", "岧嶢瞻天章，邃穆環禁庭。", "昭回河漢隔，澒洞山河腥。", "流傳幾百年，撝呵猶六丁。", "金牋炯玉字，蜀带要吳綾。", "大名標北都，寶慶恢中興。", "邊塵失甌脫，趙璧歸連城。", "百年神蹟晦，再拜感涕零。", "探驪方得雋，負馬仍騰英。", "天心正昌唐，文軌將收京。", "願言豁氛霾，長仰奎星明。"]'),
('0ad404e2-2c51-49c6-bf10-d89b8d472309','真宗皇帝南牙謝訪狀贊','岳珂','宋','宋诗','song-poetry','','[]','自虎闈之教廢，分絕堂陛。',115,'全唐诗/poet.song.193000.json','["自虎闈之教廢，分絕堂陛。", "偉聖皇之訂禮，得古意于胄齒。", "南牙既啟，有煜朱邸。", "鏘鏘佩履，謁刺填委。", "不愛尺紙，錫以雲體。", "天光之下，彼藹然主器。", "不居其貴，此其所以詒天禧之謀，垂治平之制。", "臣贊而藏，昭示物軌，以續洪氏之秘。", "尚寶勿替，式示萬世。"]'),
('5852681d-5b06-4602-af8d-1d58292c777d','仁宗皇帝二詩御漢體書贊','岳珂','宋','宋诗','song-poetry','','[]','鴻荒有開，昉頡鳥跡。',200,'全唐诗/poet.song.193000.json','["鴻荒有開，昉頡鳥跡。", "字學之興，亦既象物。", "漢有議郎，曰臣蔡邕。", "帛書發奇，出淳古蹤。", "千齡寥寥，嗣響逾邈。", "貞觀御牀，淳化秘閣。", "雲漢之章，施于仁皇。", "厥維天葩，源宋跨唐。", "萬幾燕閒，成是肆筆。", "弛張異用，游戲如一。", "士俗之成，玄默自躬。", "見于首篇，尚絅之風。", "安不忘危，尤示注意。", "筆墨之餘，又形拊髀。", "慶曆之治，太平極功。", "帝心所存，天地與同。", "春朝鳴珂，秋塞沈柝。", "一視之仁，昭此聖學。", "海嶽八極，羲娥九霄。", "媲于寶藏，萬世見堯。"]'),
('9b30accd-ed2f-4b36-bf8a-f19e6a815651','仁宗皇帝濃風二字御書贊','岳珂','宋','宋诗','song-poetry','','[]','維聖肆筆根于天，神蹤合作皆自然。',96,'全唐诗/poet.song.193000.json','["維聖肆筆根于天，神蹤合作皆自然。", "勁腴華實無以偏，春秋雖富力已全。", "天禧資善環琦園，隻字落紙時爭傳。", "煌煌翰墨二百年，傳家曾是金鑾仙。", "渡江文獻仍中原，繄臣何人望奎躔。", "欲知付受須瞻前，印以忠孝錢家錢。"]'),
('7b825499-b065-4251-a51d-ec4920f56599','英宗皇帝寧字御漢體書贊','岳珂','宋','宋诗','song-poetry','','[]','惟漢體書，筆法之變。',240,'全唐诗/poet.song.193000.json','["惟漢體書，筆法之變。", "于帝王中，亦有羲獻。", "有煜昭陵，蒸雲激電。", "品冠一神，中寓萬善。", "于惟治平，問安視膳。", "葩奇自然，得于目見。", "傅英染華，躬侍筆硯。", "既習既觀，弗咤弗眩。", "心法斯授，體勢亦擅。", "故于游戲，如墨裙練。", "惟帝之聖，統接堯禪。", "追懷羹牆，謀謹詒燕。", "武存止戈，威寓不戰。", "五餌匈奴，三登海縣。", "耆髫茹粹，支夏解辮。", "寧人之功，是履是踐。", "帝心敢知，畔援歆羨。", "妙則已具，奎文式絢。", "揭于座隅，以示警勤。", "仁皇之仁，惟聖時憲。", "猗與此寧，尸居龍見。", "苞桑其存，伐柯不遠。", "事陋規隨，戒存藥眩。", "有籤維瑶，有軸維鈿。"]'),
('bac36f6c-d059-4dd2-8258-18584be95390','神宗皇帝龍字御漢體書贊','岳珂','宋','宋诗','song-poetry','','[]','應龍之神兮。',115,'全唐诗/poet.song.193000.json','["應龍之神兮。", "休命之申兮。", "利見大人兮。", "四聖之傳兮。", "有筆如椽兮。", "得龍之全兮。", "時以乘兮。", "世之熙寧兮。", "騫騰兮。", "天衢之亨兮。", "與物維新兮。", "驅雷滃雲兮。", "澤沛無垠兮。", "旋坤轉乾兮。", "聲氣自然兮。", "其合以天兮。", "嗟兮。", "龍兮。", "凜兮。", "遺蹤兮。", "歸來兮。", "漢之宮兮。"]'),
('1934d9df-e70c-4fbe-bc64-b509d1010e64','徽宗皇帝臨右軍蘭亭序御書贊','岳珂','宋','宋诗','song-poetry','','[]','太霄帝君升壽丘，夢中靈篆垂鸞虯。',208,'全唐诗/poet.song.193000.json','["太霄帝君升壽丘，夢中靈篆垂鸞虯。", "翩然下作八極游，赤符羽蓋臨中州。", "神機天縱凌□□，日□月□孕□□。", "□□殿前卷罳罘，□□□□侍衛休。", "昭回雲漢光正浮，萬象不足供雕鎪。", "蘭亭當日禊事修，筆力一挽回千牛。", "不特字健文亦遒，蕭統作選棄不收。", "藿羹詎識羅珍羞，掎摭碔砆遺琳球。", "帝謂□□予欲□，巨筆霞練扶斗輈。", "寫成斜月輝瓊樓，群真鵠立光射眸。", "六丁雷電不可求，倏忽一瞬三千秋。", "長安千門曲江頭，柳色曾繫金□□。", "天涯恭覽涕泗流，蒼梧叫□□□愁。"]'),
('2beaa358-bfcb-48b2-9450-8bb9a62c2abd','徽宗皇帝詩聯扇面御書贊','岳珂','宋','宋诗','song-poetry','','[]','四海如春，時維帝心。',40,'全唐诗/poet.song.193000.json','["四海如春，時維帝心。", "遇物而感，其傳至今。", "宮扇之存，有此神翰。", "願揚仁風，慰彼塗炭。"]'),
('8fc0586d-a593-4421-9889-03460d91ea08','徽宗皇帝秋賦御書贊','岳珂','宋','宋诗','song-poetry','','[]','帝宣和之太平兮，忻朝野之多娛。',281,'全唐诗/poet.song.193000.json','["帝宣和之太平兮，忻朝野之多娛。", "偉楚臣之託辭兮，侈肆筆之特書。", "猗百工之精能兮，璨玳軸而金朱。", "宛百年其如砥兮，方日卷而霞舒。", "維宸筆之天縱兮，臣固不得而議也。", "若一藝之必極其致兮，亦盛時之細也。", "彼舞衣與竹矢兮，猶三代之秘也。", "知苟且之爲無兮，亦可觀其治也。", "在本始與地節兮，漢室稱爲中興。", "豈尚方之工萃兮，反有愧于西京。", "紛天葩其在前兮，晃銀海其欲眩。", "縷黄金以爲飾兮，駭萬態而千變。", "雙龍宛其在軸兮，森毛髮以骨寒。", "歷溽潤與埃塵兮，曾不可乎犯干。", "巫咸下招兮，天門詄蕩。", "臣得而藏兮，徒慨歎以興想。", "鸞翔龍翥兮，太平之蹤。", "神睒鬼哭兮，太平之工。", "五陵松柏兮，蕭蕭秋風。", "此賦之傳兮，與天無窮。"]'),
('d3cd2cc9-e266-40bf-a198-d6f818999b91','徽宗皇帝讀閣支降御筆贊','岳珂','宋','宋诗','song-poetry','','[]','昭回之秘天所示，風行雷厲動一世。',160,'全唐诗/poet.song.193000.json','["昭回之秘天所示，風行雷厲動一世。", "獨持八柄昭馭貴，馭貴馭富抑其細。", "百年史牒記金匱，木脚東廊果何地。", "誰從六閣得幅紙，朱書旁行儼如此。", "貴璫日月書紙尾，宛如宣和見宣底。", "參稽天筆良不類，恭覽比方三歎喟。", "王蔡諸臣真可罪，區區球補蟣蝨耳。", "汴都徬徨塵未洗，此帖間行來萬里。", "大書尊堯詆王氏，責以格君法當爾。", "奸諛直筆誅既死，願以所書裨太史。"]'),
('f9486e01-e75b-43dd-ade3-47c12df0e4ef','高宗皇帝舞劍賦御書贊','岳珂','宋','宋诗','song-poetry','','[]','維中興，焯人文。',132,'全唐诗/poet.song.193000.json','["維中興，焯人文。", "燀皇靈，即清燕。", "垂翰墨，光日星。", "揖怒蛙，市駿骨。", "期混并，寫古作。", "示休寵，作豪英。", "臣有劍，淬三河。", "包兩京，舞絕世。", "抉浮雲，開太清。", "帝有訓，誓臣節。", "式欽承，誰掣肘。", "起奮袖，憤裂纓。", "鬰干將，在寶匣，長悲鳴。", "後百年，血郅支，鍔尚腥。", "刻斯贊，表帝心，傳龍庭。"]'),
('68197c66-a218-4f74-904a-f70bcb8dd957','高宗皇帝韋杜三詩御書贊','岳珂','宋','宋诗','song-poetry','','[]','古者賦詩，惟以言志。',240,'全唐诗/poet.song.193000.json','["古者賦詩，惟以言志。", "或陳卒章，或摭首意。", "惟聖秉籙，啟于多艱。", "北鄉之悲，鑾輿未還。", "歲時顧瞻，雪涕凝竚。", "宸毫寄心，亦或有取。", "惟唐二臣，一唱一酬。", "節物感懷，下筆不休。", "西清燕閒，念此夐隔。", "鬰乎居南，凄其望北。", "璧跗琅鈕，舒卷龍牋。", "白雲其翔，契闊十年。", "臣之管窺，嘗讀國史。", "曹勛衣襟，洪皓幅紙。", "或慟或泣，或命以官。", "或間持書，或使問安。", "玉音琅琅，具記青汗。", "宜其注思，感此歸雁。", "三詩之作，迭寫杜韋。", "社日二篇，獨書前詩。", "昭哉聖情，如古之賦。", "迄其弗償，徒切舜慕。", "霜露之履，誰無此哀。", "止或尼之，謂之何哉。"]'),
('d7850e37-754a-42ce-af42-2d36d09ae97c','高宗皇帝蹙龍手札御書贊','岳珂','宋','宋诗','song-poetry','','[]','辛伯有言，並后亂本。',40,'全唐诗/poet.song.193000.json','["辛伯有言，並后亂本。", "惟聖齊家，知益知損。", "臣得此書，反其三隅。", "一卷之藏，于昭宸謨。"]'),
('f6b6b90e-3975-43bc-98f9-9c83f17e141b','高宗皇帝御筆臨吳皇象如鷹帖贊','岳珂','宋','宋诗','song-poetry','','[]','書法淳古，遡晉而上。',60,'全唐诗/poet.song.193000.json','["書法淳古，遡晉而上。", "于上品中，則有皇象。", "漢歌大風，思士之壯。", "帝臨此書，獵渭懷望。", "於昭詒謀，倚重惟將。", "豈象之臨，亦意之尚。"]'),
('64a997a0-c1cf-4512-9cd6-053b09f7db88','孝宗皇帝杜甫夜宴左氏莊詩御書贊','岳珂','宋','宋诗','song-poetry','','[]','帝淳熙兮重華，燦璧跗以秀荂。',175,'全唐诗/poet.song.193000.json','["帝淳熙兮重華，燦璧跗以秀荂。", "根六藝兮正以葩，蔽一言兮思無邪。", "噫後人兮誰耶，有臣甫兮不浮以夸。", "窮不詘兮之死靡他，志不忘君兮于天之涯。", "九淵兮鯨牙，洶怒兮奔拏。", "閲三百年兮鼓吹群蛙，皦如英韶兮屏淫斥哇。", "搴月兔兮泛靈槎，登鈞天兮泰皇家。", "御墨兮驚鴉，十行兮整斜。", "紫電兮丹霞，因風兮塵沙。", "臣有扁舟兮牀筆竈茶，願託寶墨兮水雲蒹葭。", "恍清夢兮隨鑾車，臣身江湖兮臣心不遐。"]'),
('e1abcf73-95c0-4647-ba6d-ac7266199d32','孝宗皇帝杜甫萬丈潭詩御書贊','岳珂','宋','宋诗','song-poetry','','[]','於戲中興，駐蹕東南。',246,'全唐诗/poet.song.193000.json','["於戲中興，駐蹕東南。", "江沱之安，匪帝所堪。", "飆起霆驅，沛澤以甘。", "慰于望霓，意則可探。", "念昔臣甫，賦萬丈潭。", "謂彼應龍，潛雺隠嵐。", "豈嵌竇是即，豈泉石是耽。", "救民一心，大造實參。", "方陽初驕，民憂未惔。", "彼界此疆，飲瓢粟甔。", "遵養必時，畢毓畢涵。", "亦既太甚，炎威孔燂。", "播奏之艱，□□孰餤。", "必其來蘇，以溉以覃。", "帝惟明習，詎不我諳。", "升自天衢，時乘其驂。", "視此沸鑪，而忍弗戡。", "維寧親是先，匪樂之酣。", "維復讎是懷，匪垢之含。", "鬰鬰久居，若古有談。", "毋功之幸成，而德之或慚。", "臣謂此心，與天地三。", "龍變難諶，龍髯已毿。", "心畫之昭，賁于寶函。"]'),
('9b668a3b-caf9-4c89-a4e5-dbd1e5d74bdf','孝宗皇帝御製春詞御書贊','岳珂','宋','宋诗','song-poetry','','[]','春賦之作，八荒是同。',40,'全唐诗/poet.song.193000.json','["春賦之作，八荒是同。", "掞詞寄情，則其餘功。", "德異玩人，理存觀妙。", "臣藏其真，以見電笑。"]'),
('30550df4-70ca-4772-aa7f-64b729d0b37e','光宗皇帝夏竦雙頭牡丹賦御書贊','岳珂','宋','宋诗','song-poetry','','[]','聖孝動天，瑞則應之。',240,'全唐诗/poet.song.193000.json','["聖孝動天，瑞則應之。", "帝開紹熙，天實命之。", "三宮燕娛，愛且敬之。", "禁籞翠華，時聯幸之。", "萬葩其春，綵服映之。", "玉色怡愉，霞巵醟之。", "豈樂行都，民物盛之。", "乾坤同歡，康衢咏之。", "于牣靈沼，魚鳥泳之。", "天光下臨，邦家慶之。", "煌煌牡丹，奇産並之。", "帝王稱觴，親捧迎之。", "巍巍太皇，萬壽稱之。", "一德隆興，聖益聖之。", "維太平臣，嘗比興之。", "國英竦名，夏則姓之。", "穠纖艷殊，美則評之。", "仁皇之祥，今亦訂之。", "堯父舜子，本天性之。", "龍樓雞鳴，久溫凊之。", "晦明節宣，臣或諍之。", "瑜瑕未昭，事則鏡之。", "宸毫所傳，神具聽之。", "後三十年，臣則勝之。"]'),
('24ab5cb7-01a5-4008-9ac9-2b44c2a939a3','光宗皇帝待月詩御書贊','岳珂','宋','宋诗','song-poetry','','[]','疏篁陰陰，長松矯矯。',40,'全唐诗/poet.song.193000.json','["疏篁陰陰，長松矯矯。", "苔靜雲閒，山清月皎。", "樂以心會，興因天隨。", "以詩觀詩，是謂管窺。"]'),
('3cea9f14-9239-40ca-9637-8392ab22a60e','寧宗皇帝詩卷耳篇御書贊','岳珂','宋','宋诗','song-poetry','','[]','偉王人之典學，本天縱之多能。',308,'全唐诗/poet.song.193000.json','["偉王人之典學，本天縱之多能。", "續六藝之絕業，環諸儒而講明。", "璧跗蔚其流芳，瓊字煥其騰英。", "居蠖濩而儲精，炳龜龍而效靈。", "歲嘉定之辛巳，歷九閏而時乘。", "旦孜孜而忘倦，志兢兢而靡矜。", "詩三百有五篇，沃帝心而日聆。", "儼露門之未竟，已雲章之滿籝。", "繄是詩之四章，首二南而儀刑。", "凡家齊而國治，本大學之爲經。", "自求賢而審官，見濟濟之以寧。", "越染翰之雖同，茲注意之實形。", "昔德壽之在御，嘗史漢之留情。", "傳復古之奇蹟，亦流輝于古荆。", "有詞臣曰萬里，亟再拜而震驚。", "謂縫掖之所難，而帝王之躬行。", "今寶章之誕賁，知祖武之克繩。", "殆家法之相似，聯自檢于宮庭。", "眇周行之下走，方虺隤而于征。", "竦昭回之景光，愧抱槧之餘生。", "覽盈咫之昭華，想繹純于九成。", "得猗那而藏焉，尚廟瑟之餘聲。"]'),
('65d228d8-c27d-4e10-aa75-e4d9a66621d7','王獻之洛神賦帖贊','岳珂','宋','宋诗','song-poetry','','[]','慶雲絢彩，河漢縈之。',240,'全唐诗/poet.song.193000.json','["慶雲絢彩，河漢縈之。", "列星垂天，日月明之。", "先民授能，維聖成之。", "英英後先，疇其勝之。", "有晉大令，父而兄之。", "一門擅奇，世共稱之。", "小楷之傳，抑更精之。", "芝靈葩奇，杳莫名之。", "賜書官奴，既準繩之。", "洛神出藍，而復青之。", "閲幾何年，劫火經之。", "鬼神護持，莫憑凌之。", "煌煌炎圖，帝中興之。", "嚴除清廂，又南榮之。", "翰權墨衡，千古程之。", "神覽睿藻，二難并之。", "一真既藏，大訓形之。", "流秘下方，萬目驚之。", "或軼或傳，式經營之。", "十閲歲華，迄克膺之。", "竭橐以酬，尚或矜之。", "恍然舊觀，緘且縢之。", "有煒廟瑟，天球鳴之。", "鄙俚混淆，敢曰聲之。"]'),
('7f6e13f1-f018-4e8e-89b6-3a060f22b76f','王操之舊京帖贊','岳珂','宋','宋诗','song-poetry','','[]','永嘉戎馬摇乾坤，渡江一馬黄屋奔。',224,'全唐诗/poet.song.193000.json','["永嘉戎馬摇乾坤，渡江一馬黄屋奔。", "中原文獻無復存，僅有筆陣興王門。", "猗歟大令趾右軍，幾年埒美名金昆。", "片紙斷爛如瑶琨，鸞蛟蛇蚓置勿論。", "爲問此帖當何人，豺狼父子蟻君臣。", "綱常肇自清濁分，孰能自植無君恩。", "是時咸洛塵霾昏，阡原變徙陵谷翻。", "家人丘隴何足言，痛裂乃爾摧心肝。", "義熙九土封函關，遺氓遮道挽息真。", "矢口止誦公家墳，人心大義端不泯。", "誰其主議畫淮濆，伊瀍王氣空膏屯。", "悠悠千載有此臣，委質無乃慚州民。", "感歎遺墨氣涌山，我欲請劍同朱雲。", "收亭楸檟方成阡，大呼爲叫九天閽。"]'),
('de3fd5af-413b-4747-863a-b6b6dfb0b66f','王洽永嘉帖贊','岳珂','宋','宋诗','song-poetry','','[]','瑞牛出谷，既秉金籙。',60,'全唐诗/poet.song.193000.json','["瑞牛出谷，既秉金籙。", "短轅逐犢，池鳳是續。", "棲梧食竹，葩奇韵馥。", "在此寶軸，手不可觸。", "神觀玉立，宛若在目。", "恍其展讀，烏衣之曲。"]'),
('56679120-d718-461a-8b1b-f9bcb290948c','梁阮研宰相帖贊','岳珂','宋','宋诗','song-poetry','','[]','巨濟取帖，斷于李唐。',66,'全唐诗/poet.song.193000.json','["巨濟取帖，斷于李唐。", "而予何人，波及于梁。", "然而考硬黄之流別，辨緗素之古香。", "並之以淳化秘閣之蹟，印之以紹興御府之章。", "於戲斯文，不忝厥藏。"]'),
('8122fd45-a634-4319-ae64-19031024cae8','陳僧智永歸田賦帖贊','岳珂','宋','宋诗','song-poetry','','[]','平子作賦，六一著錄。',48,'全唐诗/poet.song.193000.json','["平子作賦，六一著錄。", "前乎一千年，既傳于草堂之手。", "後乎四百載，仍託以稗官之目。", "衡製永述，修題珂續。"]'),
('bf519775-407e-4762-8d0b-98cd02c4b8c1','歐陽詢陰符經帖贊','岳珂','宋','宋诗','song-poetry','','[]','內史書如率令，善奴秀比官奴。',28,'全唐诗/poet.song.193000.json','["內史書如率令，善奴秀比官奴。", "千古會稽楷則，于今重見陰符。"]'),
('a65c29f5-dbfd-4c1d-adef-57dca80fc6e1','陳子昂無端帖贊','岳珂','宋','宋诗','song-poetry','','[]','麟臺正字垂拱臣，手持鴻筆扶金輪。',64,'全唐诗/poet.song.193000.json','["麟臺正字垂拱臣，手持鴻筆扶金輪。", "喔咿自擬教牝晨，尚欲圭璧全其身。", "筆精墨妙雖有神，千載乃作無端人。", "以人廢言古所聞，尚可展卷書吾紳。"]'),
('61ec2025-1612-40f5-8387-dd3c8de2f622','崔融荷華帖贊','岳珂','宋','宋诗','song-poetry','','[]','六郎之風姿，秀于清池。',45,'全唐诗/poet.song.193000.json','["六郎之風姿，秀于清池。", "初日之華蕤，流景發暉。", "種玩之誰宜。", "有美人兮，掞胸中之奇，筆下其似之。"]'),
('2e47c7ce-8b3c-4969-b70a-55d1ff34ad49','顔真卿朝迴帖贊','岳珂','宋','宋诗','song-poetry','','[]','公之素守，日烈霜嚴。',100,'全唐诗/poet.song.193000.json','["公之素守，日烈霜嚴。", "公之大節，斗揭巖瞻。", "筆勢所存，心畫可占。", "八法具體，匪柔匪銛。", "庶彙流形，如鶱如潛。", "坱圠是似，端倪孰覘。", "人以藝進，公以德兼。", "凜其高風，氣壓萬籤。", "公神在天，公書在奩。", "繫贊以藏，震于壬憸。"]'),
('76e9de25-a9ac-4fd0-a6c6-335919c1d89b','徐浩謝賜書帖贊','岳珂','宋','宋诗','song-poetry','','[]','南陽素書，浩之素珍。',72,'全唐诗/poet.song.193000.json','["南陽素書，浩之素珍。", "而本朝觀浩之書，又皆以爲絕倫。", "今視諸賢之跋，凡十有三人。", "歲月幾何，又不能彷彿其清塵。", "書意日新，而迹日陳。", "白首之攻，庶幾信今。"]'),
('21984c41-758f-465c-8f72-3ab60cfd2e9f','張長史春草三帖贊','岳珂','宋','宋诗','song-poetry','','[]','夔作八音，莖韺咸雲。',93,'全唐诗/poet.song.193000.json','["夔作八音，莖韺咸雲。", "婁辨五色，朱紫玄纁。", "偉絕藝之天成，隨所施而冠群。", "既運斤而薦巧，亦端委而長身。", "或有若而闕里，或蔡邕而虎賁。", "是其同者體，而不同者神。", "藻繪既後素，笙鏞無奪倫，夫是之謂寶真。"]'),
('501aa920-9727-475e-baca-aa2768b5883b','張長史秋深帖贊','岳珂','宋','宋诗','song-poetry','','[]','煒五帖兮迨今，信第一兮秋深。',56,'全唐诗/poet.song.193000.json','["煒五帖兮迨今，信第一兮秋深。", "彼伯高兮書淫，人爭取兮千金。", "考步武兮可尋，付纖穠兮何心。", "媲關沈兮鳴琴，尚海岳兮知音。"]'),
('7dd8a920-f3d5-4be2-88ad-2bd981f2516e','懷素千文帖贊','岳珂','宋','宋诗','song-poetry','','[]','鵾鵬徙海，龍蛇起陸。',40,'全唐诗/poet.song.193000.json','["鵾鵬徙海，龍蛇起陸。", "思妙天隨，神鍾鬼哭。", "垂露在手，非烟眩目。", "錦紱瓊機，光我韞櫝。"]'),
('3b6e62f3-c207-4745-8a6a-ed72197178c5','懷素秋風帖贊','岳珂','宋','宋诗','song-poetry','','[]','憭慄之秋，騷人所悲。',40,'全唐诗/poet.song.193000.json','["憭慄之秋，騷人所悲。", "彼僧何爲，乃寫以辭。", "絕藝出塵，亦寄焉耳。", "雲烟蒼茫，在此幅紙。"]'),
('1a606066-8c27-404f-bfc8-b575e70db7f5','懷素律公帖贊','岳珂','宋','宋诗','song-poetry','','[]','噫懷素，善草書。',32,'全唐诗/poet.song.193000.json','["噫懷素，善草書。", "雜真行，世所無。", "妙之臻，理不殊。", "盍反觀，同其初。"]'),
('9e6dccc6-36b1-4e13-8619-9402c19c68bb','裴素明日帖贊','岳珂','宋','宋诗','song-poetry','','[]','有王茂宏之筆勢，予非取其麗。',30,'全唐诗/poet.song.193000.json','["有王茂宏之筆勢，予非取其麗。", "從容而大肆，巧者以愧，尚庶古意。"]'),
('8da39afe-339b-4ba7-bb15-05d792434c17','唐史惟則篆千文帖贊','岳珂','宋','宋诗','song-poetry','','[]','籀學在唐，陽冰一夔。',40,'全唐诗/poet.song.193000.json','["籀學在唐，陽冰一夔。", "彼秩八音，各有工師。", "斯帖之奇，體微而具。", "何以譬之，磬襄鼗武。"]'),
('5ccdec64-7634-4518-b2d2-350a7105a13b','唐許渾烏絲欄詩真蹟贊','岳珂','宋','宋诗','song-poetry','','[]','玉𥫽詩府旌陽仙，驂鸞翳鳳珊瑚鞭。',176,'全唐诗/poet.song.193000.json','["玉𥫽詩府旌陽仙，驂鸞翳鳳珊瑚鞭。", "羽裳雲錦朝帝垣，天鳳戛佩披瑯玕。", "瑶階十二琪樹連，珠暉璧魄環非烟。", "手按碧蕊丹葩鮮，崑閬七七爭芳妍。", "翩焉來下探九淵，攫頷驚起龍正眠。", "茫茫塵劫今幾年，北斗柄爛東海田。", "袖中琲琲輝且圓，琤琮落筆如流泉。", "烏欄錦褾餘百篇，獄寶上燭牛斗躔。", "御題小璽今宛然，已散復合庸非天。", "鯨魚東去雲浪翻，晴晝昳蕩開虎關。", "紫金浮玉月滿川，大招爲賦乘槎騫。"]'),
('0ae236e8-c3ac-4ebb-8729-41c11203cfc3','崔遠送瘙利詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','唐而乾寧，果何時。',37,'全唐诗/poet.song.193000.json','["唐而乾寧，果何時。", "作書及詩，且恬以嬉。", "淪胥之不知，而拳拳于一緇。", "吁其可悲。"]'),
('048fbcae-91ed-4db1-baf1-de9fed81fc92','衛恒往來帖贊','岳珂','宋','宋诗','song-poetry','','[]','書既造妙，摹者惟欲取其肖。',48,'全唐诗/poet.song.193000.json','["書既造妙，摹者惟欲取其肖。", "摹既逼真，題者不必託諸人。", "以實傳信，萬古一晉。", "無目睫之徇，視御府之印。"]'),
('af6ba3c0-0d1f-4c48-af1a-68c28bf94569','王廙問安王秋二帖贊','岳珂','宋','宋诗','song-poetry','','[]','摹法之精，必驗以真。',40,'全唐诗/poet.song.193000.json','["摹法之精，必驗以真。", "我見棗刻，已同似人。", "啟以楷書，告以章草。", "情敬之分，于此焉考。"]'),
('00191be6-f03f-4879-95ae-eb345e280aa8','王導懷感帖贊','岳珂','宋','宋诗','song-poetry','','[]','王門之書祖始興，他帖閣本皆洞精。',64,'全唐诗/poet.song.193000.json','["王門之書祖始興，他帖閣本皆洞精。", "獨餘此帖難强名，妙處頓使俗眼驚。", "唐人硬黄昔流聲，紙古墨暗如晨星。", "兒曹緘口勿浪評，更看羲獻森階庭。"]'),
('9b43da6a-acd1-4a28-b08e-f69bb8cfeca6','郗恢授衣帖贊','岳珂','宋','宋诗','song-poetry','','[]','郗姓三傳而至恢，晉代七革而爲唐。',65,'全唐诗/poet.song.193000.json','["郗姓三傳而至恢，晉代七革而爲唐。", "書以世而能，摹以久而彰。", "予將因高平之奕葉，而擷千古之遺芳。", "於戲道徽，尚其不亡，茲其足以侈摹帖之藏。"]'),
('bba1298b-2497-40c2-80d0-ed31e011d454','馮承素蘭亭敘帖贊','岳珂','宋','宋诗','song-poetry','','[]','猗應龍，蟠九嵕。',32,'全唐诗/poet.song.193000.json','["猗應龍，蟠九嵕。", "抱驪珠，閟含風。", "見似人，喜若跫。", "作者誰，臣姓馮。"]'),
('bf32a736-7906-472c-9e28-0c81511daa50','吳通微臨蘭亭敘帖贊','岳珂','宋','宋诗','song-poetry','','[]','禊帖之亡，坏土其朽。',40,'全唐诗/poet.song.193000.json','["禊帖之亡，坏土其朽。", "至于貞元，夫豈一手。", "彷彿之傳，爛如晨星。", "尚勝定武，以石得名。"]'),
('7e909bfc-a48d-4a89-9672-e2aff2ad156c','右軍初月帖贊','岳珂','宋','宋诗','song-poetry','','[]','唐摹之傳取奇古，彷彿硬黄疑此楮。',32,'全唐诗/poet.song.193000.json','["唐摹之傳取奇古，彷彿硬黄疑此楮。", "我從眼力別瑶珷，安得庸奴字如許。"]'),
('b43be008-dade-405f-9074-ffbc89588233','右軍遣信帖贊','岳珂','宋','宋诗','song-poetry','','[]','筆健而奇，而紙素猶近時。',33,'全唐诗/poet.song.193000.json','["筆健而奇，而紙素猶近時。", "彼摹者吾不能知其爲誰。", "忘筌與蹄，庶幾得之。"]'),
('84ad6d5d-7900-4f22-9a36-6396c0c088c6','右軍留女帖贊','岳珂','宋','宋诗','song-poetry','','[]','或真或摹，斯焉取諸，是出于偃月之儲。',34,'全唐诗/poet.song.193000.json','["或真或摹，斯焉取諸，是出于偃月之儲。", "垂胄同仇，于門之魚，予將比乎邾。"]'),
('88577c88-d1fe-4c57-95bb-f42368e3c02f','右軍復尅二書帖贊','岳珂','宋','宋诗','song-poetry','','[]','書摹于唐，故不當印以貞觀。',63,'全唐诗/poet.song.193000.json','["書摹于唐，故不當印以貞觀。", "然而涸筆天成，書名雲爛，殆不止于真之亂。", "彼無別者，徒欲侈其真而汩以贋。", "石汰玉出，涇分渭判，尚考予贊。"]'),
('2d496713-3844-4977-98f3-cc58efb1b728','右軍尚書帖贊','岳珂','宋','宋诗','song-poetry','','[]','宣和御府皆法書，珍藏直及鍾王初。',64,'全唐诗/poet.song.193000.json','["宣和御府皆法書，珍藏直及鍾王初。", "徒緣絹素少晉儲，著定聊復稱唐摹。", "氣全神王斷裂餘，更有數體同官奴。", "百年風塵閲穹廬，回首六閣懷東都。"]'),
('73c472bc-a96e-4731-8fcd-0947e79636f3','右軍安問帖贊','岳珂','宋','宋诗','song-poetry','','[]','唐人善書者，晨夕臨鵝池。',48,'全唐诗/poet.song.193000.json','["唐人善書者，晨夕臨鵝池。", "生平安問帖，千古乃見之。", "蕭齋今爲誰，米姓猶可窺。", "摹筆得活法，一卷當得師。"]'),
('a5e2668f-6ffa-4ad9-a101-19668a04fce0','右軍轉勝帖贊','岳珂','宋','宋诗','song-poetry','','[]','唐人摹帖多自喜，千古換鵝誰趾美。',64,'全唐诗/poet.song.193000.json','["唐人摹帖多自喜，千古換鵝誰趾美。", "順塗鹿夢豈真寐，畫餠兒癡出饞水。", "詎憐成安獲張耳，泜上鼓旗那可致。", "銅丸碧衣誰證爾，重說偈言煩小米。"]'),
('5a92ca37-e325-4e02-947f-b5d1ddb384c9','右軍得示帖贊','岳珂','宋','宋诗','song-poetry','','[]','淳古有真味，不特見于結子。',62,'全唐诗/poet.song.193000.json','["淳古有真味，不特見于結子。", "茲帖之名得示，縱摹倣於唐世，隠然猶有西晉之遺意。", "彼昌黎者，或肆譏議。", "謂以俗書趁姿媚，予未敢以爲是。"]'),
('6c384c92-e418-4bbf-a16a-3e42c641bc41','孫過庭摹洛神賦贊','岳珂','宋','宋诗','song-poetry','','[]','大令好書洛神賦，後人猶襲邯鄲步。',64,'全唐诗/poet.song.193000.json','["大令好書洛神賦，後人猶襲邯鄲步。", "夫君草聖洞千古，筆下縱橫敏風雨。", "凌波杳杳去無所，半幅尚能追媚嫵。", "幾年唐印閲振武，誰其別之視書譜。"]'),
('df240558-b54b-4ee4-b6dc-32a769b3cfcc','洪元眘行業讚集王右軍書帖贊','岳珂','宋','宋诗','song-poetry','','[]','天津織女瓊爲梭，的皪八體輝明河。',96,'全唐诗/poet.song.193000.json','["天津織女瓊爲梭，的皪八體輝明河。", "雲章玉字炯不磨，一洗秦籀麾周科。", "人世剪割同綺羅，百衲尚可睨伐柯。", "告身莫易矧換鵝，浙江轟豗老伏波。", "龍象駭慄嚴撝訶，玉函金鑰神畀珂。", "一洗海岳遺恨多，千巖唐晉春嵯峨。"]'),
('15c3ce98-c1cf-4b05-aef2-5aa0efbb36bc','萬歲通天帖贊','岳珂','宋','宋诗','song-poetry','','[]','洛石赤心，以出寶圖。',60,'全唐诗/poet.song.193000.json','["洛石赤心，以出寶圖。", "燕涎雞晨，即瑞製書。", "有奕王門，南土華腴。", "獻其家珍，陳于玉除。", "筆法之神，匪臨伊摹。", "史館之儲，尚其不誣。"]'),
('ca6e3ff5-786a-4abc-a7f5-0718c6658198','智永千文真草帖贊','岳珂','宋','宋诗','song-poetry','','[]','興嗣次韵成一家，作者更書遍河沙。',64,'全唐诗/poet.song.193000.json','["興嗣次韵成一家，作者更書遍河沙。", "幾年真草分正葩，變現要作千體誇。", "誰知筆椽出袈裟，如摧犀角抽龍牙。", "墨池摹倣紛天華，尚想字母真摩耶。"]'),
('b11af7e1-290d-41d5-9c4a-45a19665d1c2','諸遂良枯樹賦帖贊','岳珂','宋','宋诗','song-poetry','','[]','開禧之元，予仕軍庾。',190,'全唐诗/poet.song.193000.json','["開禧之元，予仕軍庾。", "偕朋命駕，嘗即甘露。", "慨懷海岳，賦詩弔古。", "朅予再來，乘軺茲土。", "復登多景，乃得斯賦。", "江山几案，風月樽俎。", "俯仰迹陳，卧臨意寓。", "維賦之作，自庾開府。", "殷歎婆婆，桓懷雄據。", "染翰行墨，自唐摹褚。", "蘇印儲錄，魏藏米譜。", "後百餘載，見我詩句。", "又二十年，真蹟斯睹。", "地有顯閟，物遂散聚。", "抑人與對，非鑒奚取。", "獨慚予者，莫踵遐武。", "誰其後先，傳此縑素。", "朝猿暮鶴，秋霓春霧。", "是書其存，尚想吞吐。"]'),
('e7596074-4f0d-48aa-983c-d48ca55f100a','薛稷夏熱帖贊','岳珂','宋','宋诗','song-poetry','','[]','帖中月字用武后書體，因其時也。',109,'全唐诗/poet.song.193000.json','["帖中月字用武后書體，因其時也。", "魏字紛如葩葉之當風，轉而奇也。", "遡晉千年，如極如馳也。", "既宜于今，而于古亦師也。", "既變于己，而于人亦資也。", "米芾有言，功名不如翰墨。", "抗少保而躋之，謂五王其卑也。", "予固從而貴其帖，而亦未暇辨其是非也。"]'),
('da2ab150-bb38-4c17-a6ca-e9f47be1400d','顔魯公祭文帖贊','岳珂','宋','宋诗','song-poetry','','[]','當天寶之季歲，騰紫宮之長彗。',231,'全唐诗/poet.song.193000.json','["當天寶之季歲，騰紫宮之長彗。", "駭漁陽之駃騠，將道洛以飲渭。", "以十五萬衆鼓行之勇，涉二十四郡無人之地。", "偉顔門之競爽，獨舍生而取義。", "有常山以爲之兄，有魯公以爲之弟。", "合群從而死難，慟三軍而雪涕。", "蓋將豁百世而開聵矇，澄六合而蕩氛翳。", "手締絕紐，躬支橫潰。", "射羿日之並出，扶杞天于將墜。", "斯文也，所謂質之鬼神而無疑，建諸天地而不悖。", "又豈止于區區之一酹。", "於虖，誤主有人，效忠何罪。", "胡大僇之正不致于林甫之流，而所遭之慘乃及于泉明之輩。", "予持此評，氣洶心痗。", "豈徒贊八體之書，抑以代千載之誄。"]'),
('01d41845-96e2-4703-9101-39c03fc54072','李邕光八郎帖贊','岳珂','宋','宋诗','song-poetry','','[]','北海書名亢其宗，雖摹猶足傳奇蹤。',64,'全唐诗/poet.song.193000.json','["北海書名亢其宗，雖摹猶足傳奇蹤。", "已鳴褚籥調歐鏞，更拔永戟摧羲鋒。", "平生鑒賞襄陽公，二寶相避如燕鴻。", "青氈閲世儻可逢，定見重合延平龍。"]'),
('7524f704-359e-4f57-b10a-0bbe708add51','李玄胄清慎帖贊','岳珂','宋','宋诗','song-poetry','','[]','洗箕山之耳，緘周廟之口。',44,'全唐诗/poet.song.193000.json','["洗箕山之耳，緘周廟之口。", "雷孤竹之腹，策六馬之手。", "清乎慎乎，有餘縕乎。", "二者之間，吾其隠乎。"]'),
('da4064e4-100f-426d-af69-1964b8b1a351','楞伽經注帖贊','岳珂','宋','宋诗','song-poetry','','[]','貝多之葉來金仙，益以注釋非忘言。',64,'全唐诗/poet.song.193000.json','["貝多之葉來金仙，益以注釋非忘言。", "楞伽著在西域編，名雖或訛經則傳。", "唐世經生筆力便，茲文流布今幾年。", "河南題字恐未然，留與末世觀蹄筌。"]'),
('2022d4a7-2729-4898-8977-d9328c79ed01','奉禮帖贊','岳珂','宋','宋诗','song-poetry','','[]','群賢修禊，書法遂東。',40,'全唐诗/poet.song.193000.json','["群賢修禊，書法遂東。", "永欣之傳，盛于越中。", "褚雖莫留，猶有遠公。", "至今千巖，颯然清風。"]'),
('b3da22fb-33d3-4451-ab4f-ba3ef513ff84','青峰詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','心潛書法，神造詩境。',40,'全唐诗/poet.song.193000.json','["心潛書法，神造詩境。", "予意是時，萬念俱屏。", "樂非外騖，自得雋永。", "坐令塵埃，頓發深省。"]'),
('3f80d759-201e-478c-b31d-949e811012c5','吳越三王判牘帖贊','岳珂','宋','宋诗','song-poetry','','[]','玉冊之樓壓吳杭，三川錦繡開故鄉。',128,'全唐诗/poet.song.193000.json','["玉冊之樓壓吳杭，三川錦繡開故鄉。", "英姿颯颯熊虎相，紅袍金印交煒煌。", "百年霸府儀物龐，山判近出功臣堂。", "鳳宅畫諾鵲抵章，五雲八體嚴且莊。", "流傳世世民弗忘，鬼神呵護謹毖藏。", "題染猶带猊爐香，卷端藻墨十二行。", "紫橐曾是天台房，我寶此帖隨縑緗。", "匪徒嗜古思耿光，大誼猶可占尊王。"]'),
('279a0862-0d29-4d4b-a831-d5215af4fdca','豆盧革田園帖贊','岳珂','宋','宋诗','song-poetry','','[]','書名之訛，創自韋陟。',60,'全唐诗/poet.song.193000.json','["書名之訛，創自韋陟。", "季襲其風，始見書尺。", "狙冠豺綬，乃唐之賊。", "相不加誅，而反畏惕。", "禮度盡壞，王綱倒植。", "存此謂何，覽者太息。"]'),
('4b668595-7bc7-4960-bf76-96e56a4bf43e','徐鉉小篆千文帖贊','岳珂','宋','宋诗','song-poetry','','[]','於惟騎省，神藝造古。',140,'全唐诗/poet.song.193000.json','["於惟騎省，神藝造古。", "獮兔璇窟，吸蜍銀浦。", "千文爰襲，百體具舉。", "慶雲澄靄，清風垂露。", "鳥跡觀象，魚書辨魯。", "倉創籀述，嶧夸咸詛。", "如周金版，如岐石鼓。", "製比邈健，勢窮斯嫵。", "游史遜妍，冰書挈度。", "悠悠千載，孰是去取。", "寥寥幾人，他莫比數。", "世遺趙璧，寶及康瓠。", "矉心何尚，徵睫何睹。", "表而出之，光我書府。"]'),
('1db7a292-21cf-4de4-b887-42db0e8097c1','徐鉉篆五柳傳帖贊','岳珂','宋','宋诗','song-poetry','','[]','晉有逸民，樂天不憂。',83,'全唐诗/poet.song.193000.json','["晉有逸民，樂天不憂。", "唐有遺臣，嗜古好修。", "或夷惠之擬倫，或斯冰之與儔。", "炯松姿而筠操，又鐵畫而銀鈎。", "集二妙之全美，接千載之風流。", "載酒拂石，尋壑經丘。", "吾將抱此而爲栗里之游。"]'),
('b8db5ef1-73cc-4b4e-b92b-6dce91700658','李西臺啟詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','予于是帖，有感者四。',207,'全唐诗/poet.song.193000.json','["予于是帖，有感者四。", "館職在外，于學士不繫細銜，于带職者皆曰同院，意親情洽，所以見前輩之篤風誼也。", "內賜金魚，蓋出新寵，带職者乃從學士轉致，又雜以他寄焉，所以見上恩交情俱無內外也。", "謝學士以啟，而用楷法，寄同院同年以詩，而用行書，又以見待人處己，雖小節皆有體也。", "承平幕府，得一佳帖，相聚以觀，又以見時清事簡，雖邊圉亦得以從容于文藝也。", "於虖，詩文之傳，幾人于茲。", "獨于此書，有感有思。", "流風之存，妙墨之遺。", "什襲是宜，維以詩之。"]'),
('9e7b24db-e658-4476-827c-52e1760a2cf3','李西臺退居詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','以退藏心，邀丘壑老。',40,'全唐诗/poet.song.193000.json','["以退藏心，邀丘壑老。", "唱酬之間，意已足考。", "我以倦翼，故應知還。", "高躅凜然，庶幾是攀。"]'),
('03356c86-751d-494b-ad1e-5c3eb297d358','宋素臣惜別詩帖','岳珂','宋','宋诗','song-poetry','','[]','桂州之帥，予莫知其爲誰也。',80,'全唐诗/poet.song.193000.json','["桂州之帥，予莫知其爲誰也。", "盍簪得朋，其必有以稱此詩也。", "黄卷之苦心，意其樂之真足以忘疲也。", "若夫屈伸則有時也，而豈以是爲富貴之資也。", "得路之終期，予固未免猶置夫疑也。"]'),
('f3666329-bd65-4666-82dc-81ef77fed862','張文懿珍果帖贊','岳珂','宋','宋诗','song-poetry','','[]','以帝傅，從赤松。',64,'全唐诗/poet.song.193000.json','["以帝傅，從赤松。", "有榮名，華厥躬。", "超二疏，列三公。", "瞻中臺，祖上東。", "煥衮舄，樂鼓鍾。", "壽九袠，天報豐。", "思其人，想清通。", "觀筆法，猶雍容。"]'),
('864df53f-b863-483a-b3c7-0ce572fc59bc','呂文靖亭候帖贊','岳珂','宋','宋诗','song-poetry','','[]','嘉定乙亥，珂丞軍器，居于寶蓮。',240,'全唐诗/poet.song.193000.json','["嘉定乙亥，珂丞軍器，居于寶蓮。", "鄰有善士，曰范擇能，實祖太史。", "百年相承，文獻攸萃。", "暇日啟鑰，抉奇出秘。", "有三軸者，實公程藝。", "捧玩再拜，始識公字。", "丁丑禾興，刻置官寺。", "棗肥失態，莫盡體勢。", "粵來維揚，歲在癸未。", "客出公帖，相示歎喟。", "如昔所見，毫髮畢似。", "于翰墨間，更著風誼。", "客謂此書，伐木無愧。", "亟以歸我，備名臣體。", "瓊函錦繰，明窗棐几。", "時一展玩，若鏘劍佩。", "是歲七月，日維乙巳，淮海堂下，清陰蔽芾。", "我時受藏，午暑猶熾。", "月紀歲合，時又其位。", "于日之吉，與初覽對。", "載見載識，若合符契。", "豈非天耶，尚勿失墜。"]'),
('e4f89bd4-8104-40e0-8c97-f32f9359a96f','范文正問醫帖贊','岳珂','宋','宋诗','song-poetry','','[]','元氣在天，日星繫焉。',90,'全唐诗/poet.song.193000.json','["元氣在天，日星繫焉。", "骨骾在身，四體恃焉。", "王國之幹，公實似焉。", "有煒翰墨，抑其細焉。", "是書之傳，自尹氏焉。", "歷年雖多，人爭毖焉。", "彼名家者，衆或棄焉。", "脅肩夏畦，亦何利焉。", "一卷之師，覽者愧焉。"]'),
('496e8ddc-71b0-4d97-a0f1-836c7a0006e6','蔡忠惠書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','凌雲成而楷遂絕，太極建而書仍存。',166,'全唐诗/poet.song.193000.json','["凌雲成而楷遂絕，太極建而書仍存。", "藝不足以名世，士亦貴于自珍。", "彼其之子以賤待其身，而又安能以重望夫人。", "偉四諫之直聲，並翰墨而流芬。", "方其作元舅之碑以伸天子之孝，拒佞倖之請而杜褻取之門。", "則片言隻字之落人間者，世固待之以褚顔之節，而豈復儕之于芝繇之倫。", "後二百年珂得而藏其真，是蓋不特寶其書而楷模其縱筆之妙思，又將因其字而彷彿其絕世之清塵也。"]'),
('26b9a771-3cbb-4e52-b5a0-5203c60477f4','蔡忠惠趙氏風度帖贊','岳珂','宋','宋诗','song-poetry','','[]','前朝之名臣，承平之王孫。',37,'全唐诗/poet.song.193000.json','["前朝之名臣，承平之王孫。", "筆妙而跋真，一旦而並臻。", "此蓋不特適千里而喜似人也。"]'),
('f9a70f44-6b48-4424-aae0-5604b511cc1b','蔡忠惠家書帖贊','岳珂','宋','宋诗','song-poetry','','[]','家書正所以寄情之真，徒得觀筆力之神，又以見公之褆身。',36,'全唐诗/poet.song.193000.json','["家書正所以寄情之真，徒得觀筆力之神，又以見公之褆身。", "予彙而藏，以警夫人。"]'),
('baeeaa74-45e8-47ab-b16f-8249e891f145','宋景文言志帖贊','岳珂','宋','宋诗','song-poetry','','[]','既有史才，又得墨妙。',40,'全唐诗/poet.song.193000.json','["既有史才，又得墨妙。", "今古言辭，事功談笑。", "蜀人之藏，曰維甘棠。", "我時其傳，以著不忘。"]'),
('be584202-f444-4616-8b1d-639d9ce2acd6','龐莊敏魁柄帖贊','岳珂','宋','宋诗','song-poetry','','[]','漢有德公天下士，皇祐相國實其裔。',64,'全唐诗/poet.song.193000.json','["漢有德公天下士，皇祐相國實其裔。", "雖云出處有同異，今古龐宗開顯晦。", "我觀清風勵百世，未若太平以身致。", "鹿門遺墨不可覬，聊寶此書貴行志。"]'),
('245f62a6-eb67-475b-a829-f6b603cebf25','韓忠獻北道京邑二帖贊','岳珂','宋','宋诗','song-poetry','','[]','扶桑擎日，厥幹萬尺，以爲公筆。',151,'全唐诗/poet.song.193000.json','["扶桑擎日，厥幹萬尺，以爲公筆。", "天壽平格，元圭昭錫，以爲公墨。", "陰陽闔闢，鰲柱立極，見此偉特。", "太山絕壁，九河碣石，莫動筆力。", "有雲五色，曾著瑞籍，多士辟易。", "繄天實啟迪，豈以詡飾，如彼韋陟。", "公騎鵬翼，歸侍帝側，有是遺蹟。", "榮光交射，星月珠璧，終古不忒。", "維珂之得，再拜歎息，坱圠孰測。", "几几赤舄，尚想公德，永鎮下國。"]'),
('31b97028-ed88-4b57-b9f1-241a24f2531b','韓忠獻早夏衆春二詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','五言簡嚴而意不迫，七言丰腴而體不忒。',82,'全唐诗/poet.song.193000.json','["五言簡嚴而意不迫，七言丰腴而體不忒。", "意公彷徉于景物之間所謂造化生意者，蓋亦畢寫于翰墨。", "如彼纖巧，旬鍛月鍊，又焉得以踐其閫閾。", "春萌夏假，默具帝力。", "公詩自然，于以觀德。"]'),
('cc6c7eaf-e9f2-4c18-af09-b32d92a76b1d','富文忠出身帖贊','岳珂','宋','宋诗','song-poetry','','[]','其溫而惠，有青州救荒之意。',87,'全唐诗/poet.song.193000.json','["其溫而惠，有青州救荒之意。", "其勁而竦，有北庭抗議之勇。", "其湍而直，有鎮撫百度之績。", "萃是三德，發爲遺墨。", "蓋靜而正者公之心，而用而變者公之迹。", "端委搢紳，言孚意親。", "我思若人，古社稷臣。"]'),
('95473947-79a6-4f9a-9638-002838f79ee2','文忠烈治裝帖贊','岳珂','宋','宋诗','song-poetry','','[]','德威堂中有漢相，衮繡晝扶靈壽杖。',64,'全唐诗/poet.song.193000.json','["德威堂中有漢相，衮繡晝扶靈壽杖。", "龐眉鮐背猶克壯，手展炎圖開治象。", "虹蜺椽筆光萬丈，落紙珠璣爭獻狀。", "凜然手澤端可仰，三復崧高慰瞻想。"]'),
('d36468b5-1b2d-4912-a198-c6eff3109f79','杜正獻與歐公書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','厚德如祁公，黄鐘大鏞，和樂且雍。',148,'全唐诗/poet.song.193000.json','["厚德如祁公，黄鐘大鏞，和樂且雍。", "尊賢如六一，朱絃疏越，三歎廟瑟。", "道比志叶，不膠而漆。", "顧中外之雖異，猶同堂而合席。", "思遺蹟而不可見，幸二賢之爲時出。", "所以前乎此則致太平之明效，後乎此則贊受遺之定冊。", "既以廣元氣之運，亦以壽斯文之脈。", "然則湍瀨無縱鱗，風枝無寧翼。", "涵養成就，見此輔弼，故後世尤得以歸功慶曆也。"]'),
('eba07118-9abe-4208-9c20-05ddf0c3bf77','孫威敏及物帖贊','岳珂','宋','宋诗','song-poetry','','[]','有文事，有武備，公之筆札蔚然可占也。',104,'全唐诗/poet.song.193000.json','["有文事，有武備，公之筆札蔚然可占也。", "兵凶器，戰危事，公之此事非直一謙也。", "以公之才，持必勝之策，而于顧慮獨如此其嚴也。", "嗟今之人，萬一不逮，談伊吾，望天山，乃抵掌而奮髯也。", "爾言則輕，民之殲也。", "好謀而成，視吾奩也。"]'),
('53e68c34-73d8-44f9-b531-10e69b4bfe1b','歐陽文忠索碑遣居二帖贊','岳珂','宋','宋诗','song-poetry','','[]','公于率更，每稱吾家。',80,'全唐诗/poet.song.193000.json','["公于率更，每稱吾家。", "是書之傳，似耶非耶。", "書出于心，既勁且方。", "世多公書，行或未藏。", "易方而圓，飄飄若仙。", "楷以其人，行以其天。", "堂堂斯文，維軻與雄。", "我觀二書，如或見公。"]'),
('06a93c45-5b62-419e-ac3d-1e1f1d6954d3','唐彥猷談奉得達二帖贊','岳珂','宋','宋诗','song-poetry','','[]','公于國史，以好硯稱。',40,'全唐诗/poet.song.193000.json','["公于國史，以好硯稱。", "石焉取斯，蓋協其能。", "遒媚之觀，在此尺紙。", "善工利器，予鑒如此。"]'),
('1afe43f1-6fa1-4540-b7da-63cf3766bd19','曾宣靖類見帖贊','岳珂','宋','宋诗','song-poetry','','[]','公在嘉祐，輔政受遺如畢公高，勳烈堂堂，奉同而隮也。',116,'全唐诗/poet.song.193000.json','["公在嘉祐，輔政受遺如畢公高，勳烈堂堂，奉同而隮也。", "公在治平，清浄畫一如曹相國，德心休休，比規之隨也。", "公在熙寧，功成身退如裴中令，壽雋番考，樂以全其歸也。", "帖字宛然，既莊而復奇也。", "周密無間，筆法繇此推也。", "予得而藏，尚可以想麒麟之英姿也。"]'),
('4645f267-7d9a-4815-8faa-1c1c43d0cd79','趙清獻勤潔帖贊','岳珂','宋','宋诗','song-poetry','','[]','爲御史而稱其鐵面，宜筆力之健。',48,'全唐诗/poet.song.193000.json','["爲御史而稱其鐵面，宜筆力之健。", "尹成都而琴鶴以行，宜字體之清。", "書法何出，心即其物，可以比魏公之笏。"]'),
('a7c75998-ed7b-4d63-8eba-c65629dbadeb','王文公赴官修學二帖贊','岳珂','宋','宋诗','song-poetry','','[]','態騰踔而多疎，意軒昂而多趣。',153,'全唐诗/poet.song.193000.json','["態騰踔而多疎，意軒昂而多趣。", "倏焉如籋電之駒，沛然如縱壑之魚。", "使之爲山澤之癯，抱是道以自娛，聞清風而興起，望膏澤之沾濡，膚寸所形，粃糠金朱，豈不毅然大丈夫。", "然而律之以芝繇之法度，考之以羲獻之範模，媲行楷而已變，質隸草而多拘。", "顧欲以之擅八體，教六書，合天下同軌之車，而不容有一轍之殊，茲其所以僨于康莊之衢。", "吁。"]'),
('424b8dd1-433f-4cd8-8920-1419ba81c7b3','呂參政示諭帖贊','岳珂','宋','宋诗','song-poetry','','[]','發知己之私書，謂其自隠于齊年。',73,'全唐诗/poet.song.193000.json','["發知己之私書，謂其自隠于齊年。", "彼云云者，使或人亦指以詭秘之迹，夫孰曰不然。", "事君有義，本無黨偏。", "當熙寧側席以求賢，惜公之所芘頼，求諸人而不求諸天也。"]'),
('d30def03-a56a-4a28-a083-79f7640edae8','韓獻肅古法書詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','韓氏之寶軸，文獻相續，蔚其盈屋。',129,'全唐诗/poet.song.193000.json','["韓氏之寶軸，文獻相續，蔚其盈屋。", "曷知夫高賢之何以見取，忠義之孰爲並錄。", "遺篇之若褚若柳，手筆之或顧或陸，想其錦繡在篚，璵璠韞櫝，名蹟爭麗，榮光相屬。", "既追懷古今之不朽，見嗜好酸鹹之可卜。", "是故詩者題品之攸寓，贊者歌詠之不足。", "即此帖之藏于寶真，殆所謂同工而異曲者兮。"]'),
('47506cc0-e06a-4e9d-b860-91bb55e6a235','吳參政炎溽帖贊','岳珂','宋','宋诗','song-poetry','','[]','公以四□，近事三朝。',41,'全唐诗/poet.song.193000.json','["公以四□，近事三朝。", "絕識巖嶢，心畫以昭。", "帖出于近世撫臣之家，又得以記先友于嘗僚也。"]'),
('1dc3ee90-df96-44fd-8bea-0d9c22af25e4','沈叡達書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','夢溪筆談載公之論書曰：書之神韵雖得于心，書之法度必資于學。',137,'全唐诗/poet.song.193000.json','["夢溪筆談載公之論書曰：書之神韵雖得于心，書之法度必資于學。", "分制有法，均停相若，三四合體，上下齊脚，多寡不牽，乃異世作。", "今視其帖，信乎其嗜之專而見之卓也。", "雖然，藝在當家，習亦有源，存中瞻前，文通比肩。", "顧翰墨文章之不殊，而俱未若公之知言。", "知言伊何，以神合天。", "古人之良，意在筆前。"]'),
('64041804-2d8c-4faf-ae08-7482ccc13940','沈叡達昭君詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','玉徽十三，維以寓聲。',40,'全唐诗/poet.song.193000.json','["玉徽十三，維以寓聲。", "支郎何心，寫脂粉情。", "漢冢春青，塞霜曉白。", "千年之悲，表此遺墨。"]'),
('fa9b2aff-dbad-45f6-9d98-18b8137dcc89','張子野詩稿帖贊','岳珂','宋','宋诗','song-poetry','','[]','觀水以心，本于知者之樂。',75,'全唐诗/poet.song.193000.json','["觀水以心，本于知者之樂。", "取射以藝，譬諸巧者之中。", "時雖後先之不同，意或迭取而互用。", "句葩體莊，字謹心縱。", "是曰仁祖太平之詞人，遺帖之存，固宜後世之知所重也。"]'),
('de4cdae0-4b41-4b79-b59d-0e7d35ccc69d','王文公易漕帖贊','岳珂','宋','宋诗','song-poetry','','[]','以文致身，以恭奉上。',92,'全唐诗/poet.song.193000.json','["以文致身，以恭奉上。", "錙銖筆態，矩矱心匠。", "論其鈎格則得紆餘曲致之體，考其縱逸則妙雍容不迫之狀。", "儼佩玉之度，肇官儀之創。", "百辟班見，大廷宏敞。", "方觚穎之發揮，蓋已具此氣象。", "曰誰之書，元豐首相。"]'),
('c17dc704-d758-4f80-98ff-2dd485357c6f','吳正憲歲端帖贊','岳珂','宋','宋诗','song-poetry','','[]','濃如夏木森葱蒨，淡若秋波橫組練。',64,'全唐诗/poet.song.193000.json','["濃如夏木森葱蒨，淡若秋波橫組練。", "端方亭亭復妍婉，有肉不俗骨不軟。", "情真字楷意蕭散，如在竹宮樂閒燕。", "九光玉籍觀文殿，字曰沖卿謚正憲。"]'),
('95531c17-b34f-404f-b946-0f7652f047b3','司馬文正公集序帖贊','岳珂','宋','宋诗','song-poetry','','[]','道本于身，真積乃全。',200,'全唐诗/poet.song.194000.json','["道本于身，真積乃全。", "貫以一誠，雖人實天。", "元祐之初，帝賚良弼。", "匪康其躬，爲民而出。", "龍起于洛，雲興于嵩。", "有澤其膏，四海之豐。", "方其未驤，一念下土。", "九關雖扃，編此守虎。", "及其既用，草偃維風。", "群賢鱗差，滃然而從。", "天以誠開，民以誠格。", "混融流通，何索何獲。", "有崇南山，太平之基。", "巖巖具瞻，維公宜之。", "平生不欺，涵泳浹洽。", "心畫之作，爲天下法。", "取人以直，持己以謙。", "豈徒幅箋，二德之兼。", "榮光屬天，公書在櫝。", "有德有言，溫其如玉。"]'),
('21bd4b92-5ecc-41d7-87f9-43d42203645f','蘇文忠公書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','雲濤稽天，睨而陸之。',60,'全唐诗/poet.song.194000.json','["雲濤稽天，睨而陸之。", "神龍在淵，頷而觸之。", "一世諞諞，稚而畜之。", "節堅氣全，墨卿卜之。", "淳古簡嚴，芝繇僕之。", "勁直不然，䖃鮓目之。"]'),
('ff72f6ab-cba5-4177-a67f-5eacad1a8fa5','蘇文忠歸潁帖贊','岳珂','宋','宋诗','song-poetry','','[]','事師之情，期以百世。',40,'全唐诗/poet.song.194000.json','["事師之情，期以百世。", "言雖不多，意則獨至。", "識以歲月，越王之孫。", "式時覽觀，用考大倫。"]'),
('d53ffc28-16a4-4fe8-83ed-14e792b19499','蘇文忠潘墨詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','懷絕世之清音，歎媸妍之難諶。',252,'全唐诗/poet.song.194000.json','["懷絕世之清音，歎媸妍之難諶。", "慨丸墨之未改，挹古人而寄心。", "褐黯黯以如漆，笏琅琅而抵金。", "貯冰壺其自如，渺一塵之弗侵。", "彼遠臭以何歸，謾花柳之繁陰。", "姓昧昧以污人，雖千年而亦瘖。", "予得此詩，跫然長吟。", "想先生之清標，契謫仙于同襟。", "凌九垓而神會，豈入海之可尋。", "方將抱月乘風，携壺命琴。", "短墨帝于玄圃，挾客卿于翰林。", "快騎鯨而翳鳳，遂登高而俯深。", "執此卷而撰杖，筮得朋于盍簪。", "秋露其滴，玉蜍自斟。", "捧詩硯之如箕，淬詞鋒之發鐔。", "付張李于一吷，視滄溟于蹄𨁊。", "逸興天游，浩無古今。", "斗杓回光，曦車發晨。", "承謦欬于緒言，猶足以投微機于芥針也。"]'),
('0bf235f6-4943-4d66-8fba-60b58b8f84ac','蘇文忠西湖聽琴觀月詩帖贊','岳珂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖之名，杭潁異轍。',117,'全唐诗/poet.song.194000.json','["西湖之名，杭潁異轍。", "然皆足以寄七絃之清調，而共千里之明月。", "方指地而辨訛，客鬨堂而纓絕。", "迄五日之考據，驗注編于一閲。", "是詩之來，予目所別。", "昔也傳觀，今焉秘笈。", "歎人事之易變，何凋零之飄忽。", "然則記歲月于所見，而逸名氏于可闕，亦予之所不忍恝也。"]'),
('b142f21d-567e-4c12-a076-d639e005d278','蘇文忠二詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','物隨春而欣榮，詩之偶成，何間乎虎跑之與女城。',78,'全唐诗/poet.song.194000.json','["物隨春而欣榮，詩之偶成，何間乎虎跑之與女城。", "縱筆而書，冰谷梅英。", "凡是歲月之與所因，予皆不必强評。", "惟當即先生雜出之書，以考先生所寄之情，其何以異乎孤山之清也。"]'),
('d7499082-f7d5-4998-9a15-6d5b7c0d7e65','蘇文忠大字詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','小字鵠引騫而翔，大字虎卧靖且莊。',64,'全唐诗/poet.song.194000.json','["小字鵠引騫而翔，大字虎卧靖且莊。", "我藏遺帖雖盈箱，尚歎鉅刻無滌黄。", "誰憐神物開混茫，想見醉墨猶淋浪。", "此題要補束晳亡，更恐有詩書雪堂。"]'),
('1a217365-0956-4830-b1ef-908ed3d7954d','蘇文忠蕭丞相樓二詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','登高而賦，維以思古。',40,'全唐诗/poet.song.194000.json','["登高而賦，維以思古。", "二難之風，意健句嫵。", "黯然塵楮，筆勢軒翥。", "真兮不諼，我懷陟岵。"]'),
('04368284-06a4-44ec-8fdd-84272471913c','蘇文忠羅漢偈帖贊','岳珂','宋','宋诗','song-poetry','','[]','佛法離住相，色相本非實。',144,'全唐诗/poet.song.194000.json','["佛法離住相，色相本非實。", "云何阿羅漢，可以色相求。", "居士宰官身，祇園夙親近。", "會發宏願深，現此廣長舌。", "于後像法世，讚歎說偈言。", "筆力涵虛空，三昧出胸臆。", "撞開癡愚網，透出大千界。", "我昔睹殊勝，會聞諸佛說。", "以音聲求我，不能見如來。", "偈語復云何，能離音聲見。", "今當解佛意，一切有爲法。", "非偈亦非贊，應作如此觀。"]'),
('2df47711-8c88-49b2-b20f-1dc6bbe76db8','蘇文定衙前至京湖三口帖贊','岳珂','宋','宋诗','song-poetry','','[]','周禾同穎，趙玉連璧。',86,'全唐诗/poet.song.194000.json','["周禾同穎，趙玉連璧。", "層見間出，又其偉特。", "有美潁濱，味道自得。", "既相師于父子，又齋驅于翰墨。", "吾評其人，概猶可識。", "蓋嚴重端肅者老泉之教，而淳勁邁往者長公之德。", "謂余不信，視此手澤。"]'),
('2aca3454-331b-4260-ac70-f47b3b170493','二蘇文登趨闕二帖贊','岳珂','宋','宋诗','song-poetry','','[]','文字之祥，厥有原委。',80,'全唐诗/poet.song.194000.json','["文字之祥，厥有原委。", "父師昆弟，以及諸子。", "文兮斜川，道兮潁水。", "以文貫道，一家濟美。", "施及翰林，特游戲耳。", "于風味中，亦復是似。", "以坡爲骨，以潁爲髓。", "蘇門之英，來者視此。"]'),
('f0de6e41-995c-4fc3-85a6-d942d0a09de8','薛道祖書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','崇觀太平，博雅彙征，秀出簪纓。',121,'全唐诗/poet.song.194000.json','["崇觀太平，博雅彙征，秀出簪纓。", "楚羋蜀劉，三英并輈，道祖其儔。", "沈浸深醇，薰陶見聞，厥藝以振。", "方旅蘭芝，水清獻奇，發千古機。", "擷其所長，韜鋒斂鋩，類曲水之觴。", "即權合經，不特製名，雅韵盡呈。", "涇芾已仙，是書之傳，孰探其天。", "風期九垓，黄鵠下來，然予言哉。"]'),
('c7ac9079-98e1-47b6-9598-f39c35aacf01','薛道祖鵓鴣帖贊','岳珂','宋','宋诗','song-poetry','','[]','朋友之宿草未黄，眷眷于舊藏。',64,'全唐诗/poet.song.194000.json','["朋友之宿草未黄，眷眷于舊藏。", "畫史之詆訾未忘，齗齗乎弗償。", "鳩搶枋而下垂，鶴唳天而高翔。", "誰能游九垓以問太虛，其必有以別二子之短長也。"]'),
('170c53a7-5af8-4d45-9783-6d0cea6ee6d5','薛道祖書簡重本三帖贊','岳珂','宋','宋诗','song-poetry','','[]','帖之疑也，非取而并不足以爲證，非視其印不足以爲信。',66,'全唐诗/poet.song.194000.json','["帖之疑也，非取而并不足以爲證，非視其印不足以爲信。", "既信矣，又何加焉，曰一以訂吾友之言，一以貽吾家之傳。", "傷彼苟且，祗益可憐。", "於虖昔賢。"]'),
('f7e35521-9118-4042-9ba9-9c46493db95e','薛道祖秘閣詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','中秘法書之積，自淳化至于崇觀富矣，而未加別也。',129,'全唐诗/poet.song.194000.json','["中秘法書之積，自淳化至于崇觀富矣，而未加別也。", "翰墨博雅之能，自劉米逮于道祖著矣，而未多閲也。", "伯牙之珍，百世知音。", "偉奇能之表表，本和樂之愔愔。", "予嘗歎太平之盛際，士大夫可以盡其好尚之心，盤薄時清，彷徉書淫。", "彼何預于帝力，殆有類乎魚鳶之在天淵，各自得以遂其高深也。"]'),
('a09471ce-a97d-463d-9908-94a86efea5ee','薛道祖清閟閣詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','此君之清閟，昌黎所憩，何啻得其細。',108,'全唐诗/poet.song.194000.json','["此君之清閟，昌黎所憩，何啻得其細。", "三鳳之呈瑞，非實不餌，亦姑即其意。", "予陋且蔽，嘗竊歎喟，謂必見其真與境契，而後可以處絕塵之地。", "歸而對，出而棄，十寒而一暴，久暌而暫慰，則亦何足以得二者之味。", "詩乎竹乎，予將求其所以無愧。"]'),
('b5b0e79d-2b56-445b-bcfd-6baa088fc3b4','薛道祖二花詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','菊粲粲兮東籬，蓮的的兮西風。',56,'全唐诗/poet.song.194000.json','["菊粲粲兮東籬，蓮的的兮西風。", "是皆不受夫一塵之染，而特立于九秋之中。", "予固喜其潔清而自全，亦以觀其筆之妙而句之工也。"]'),
('704ba0bd-d8b7-466a-9b98-ed1d1e5753ec','薛道祖寄黄魯直詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','詩以情寄，而拳拳乎子姪之示。',30,'全唐诗/poet.song.194000.json','["詩以情寄，而拳拳乎子姪之示。", "又使之寶而勿棄，亦足以見其得意。"]'),
('c379d571-4f38-437d-8c99-37937a1b132e','薛道祖白石潭詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','畫以有聲著，詩以無聲名。',37,'全唐诗/poet.song.194000.json','["畫以有聲著，詩以無聲名。", "有聲者道祖之所已知，無聲者道祖之所欲爲而未能者也。"]'),
('58b8476a-6969-4b93-84f0-40c32250fbce','薛道祖荼䕷詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','夾路濃陰野興長，荼䕷想見競年芳。',32,'全唐诗/poet.song.194000.json','["夾路濃陰野興長，荼䕷想見競年芳。", "至今四月花如雪，猶带河東翰墨香。"]'),
('e939de6d-d7e9-4a17-aea5-4a058ece45b5','薛道祖經行詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','仲氏既不能定其名，經行又不能指其地。',50,'全唐诗/poet.song.194000.json','["仲氏既不能定其名，經行又不能指其地。", "睹奇逸于筆勢，想溪山于詩意，瞭然景物之皆備，又何必吾身之親至也。"]'),
('d2af44ba-bcee-4288-aba4-c6b4d81004f9','黄魯直書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','詩至江西，始別宗派。',40,'全唐诗/poet.song.194000.json','["詩至江西，始別宗派。", "字豈無祖，人其有待。", "鶴瘠鸞鎩，松寒石怪。", "彼有髮僧，尚聞謦欬。"]'),
('c8e0be8d-3593-485e-88ce-fd666fa0788f','黄魯直先王賜帖贊','岳珂','宋','宋诗','song-poetry','','[]','賜帖不知其幾，而今獲其一。',72,'全唐诗/poet.song.194000.json','["賜帖不知其幾，而今獲其一。", "四印之錯出，百年之湮鬰，神呵鬼護，見此遺物。", "嗚呼，此固先德之所寓，而匪止于絕世之名筆。", "既軼而獲此繡質，子孫守之謹勿失。"]'),
('723bac30-dfef-4c60-8706-8a3355c6c419','黄魯直覺民讀書帖贊','岳珂','宋','宋诗','song-poetry','','[]','學以進乎道，不止於决科也。',86,'全唐诗/poet.song.194000.json','["學以進乎道，不止於决科也。", "厭飫優柔，貴精不貴多也。", "得失奇偶，固末如之何也。", "指端而言，所以勉其切磋也。", "三致意于丁寧，式爾心之訛也。", "因私淑以儆諸後學，又有以見前輩用心之不頗也。"]'),
('72785cae-c175-4e94-a42d-cd0ceb4d9536','黄魯直食麵帖贊','岳珂','宋','宋诗','song-poetry','','[]','山谷書法，本于天才。',100,'全唐诗/poet.song.194000.json','["山谷書法，本于天才。", "變而成家，如萬壑崖。", "骨瘦氣清，霜寒籟哀。", "故其言曰，法安出哉。", "我師我心，奚彼之儕。", "今觀此書，自葉而荄。", "斂其角圭，以復成才。", "規矩崛奇，關機闔開。", "故其跋曰，自本心來。", "誰其知言，嘻噫絜齋。"]'),
('f4601d2c-6eee-432d-8c04-5fb2a6e87207','黄魯直一笑帖贊','岳珂','宋','宋诗','song-poetry','','[]','帖字三十蹟如濕，弔古其逢驚啜泣。',80,'全唐诗/poet.song.194000.json','["帖字三十蹟如濕，弔古其逢驚啜泣。", "公來姑孰甫翔集，書翰從容豈遑及。", "此帖之獲雖此邑，時猶可疑蠹誰葺。", "至寶道旁世收拾，乃以齧殘棄緗笈。", "五湖浪卷四海立，墨風雨中起蛟蟄。"]'),
('3fcb17fe-3c01-4090-bd8d-e0d3e1dc5ddf','黄魯直湯方蔬法帖贊','岳珂','宋','宋诗','song-poetry','','[]','湯以濡唇，蔬以適口。',62,'全唐诗/poet.song.194000.json','["湯以濡唇，蔬以適口。", "撫藜腸而自驚，奚龍腦之猶取。", "予方筍蕨是茹，蘗荼是友。", "發遺帖而一笑，正恐楊妃之百驛，未足以比庾郎之三韭也。"]'),
('89a29bb0-6fa5-44ae-bc8f-22850931a3a6','黄魯直煎茶賦帖贊','岳珂','宋','宋诗','song-poetry','','[]','茶雖以藥煎，斯失正味。',69,'全唐诗/poet.song.194000.json','["茶雖以藥煎，斯失正味。", "字託以筆試，斯失正體。", "以先生而比王定國，抑未知其何似。", "于賦之尾，與他本異，又莫詳其孰是。", "要皆知乎識者之議，敬藏以俟。"]'),
('bfa5e2ed-a726-4c87-982f-6038e971a129','蘇文忠歸潁帖贊','岳珂','宋','宋诗','song-poetry','','[]','事師之情，期以百世。',40,'全唐诗/poet.song.194000.json','["事師之情，期以百世。", "言雖不多，意則獨至。", "識以歲月，越王之孫。", "式時覽觀，用考大倫。"]'),
('3c7705e6-1a28-4b06-b5c1-d9cdd6c1fe7b','黄魯直真一酒詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','以蜜爲酒，昉于東坡，託詩以傳，百世不磨。',92,'全唐诗/poet.song.194000.json','["以蜜爲酒，昉于東坡，託詩以傳，百世不磨。", "然而濁爲賢而清爲聖，泛爲醪而盎爲酇。", "自古以降，厥名孔多，要皆不以甜稱，惟少陵昌黎始有如蜜若飴之歌。", "豈時人酸鹹之嗜大概略同，予固未辨其趣之如何也。"]'),
('7e91ae53-e602-415c-8779-0dc7e74e6b35','黄魯直詩稿帖贊','岳珂','宋','宋诗','song-poetry','','[]','句法之奇，日鍊月鍛。',69,'全唐诗/poet.song.194000.json','["句法之奇，日鍊月鍛。", "鳥輕之過疾詎穩，馿上之推敲未判。", "長吉之心欲嘔，彌明之息猶鼾。", "天巧呈露，風期汗漫。", "予方遡詩派而未能，所以掩斯卷而三歎也。"]'),
('a99c48b6-dbae-4365-b10d-5f3797c3c185','黄魯直催繡詞帖贊','岳珂','宋','宋诗','song-poetry','','[]','詞以寓意，何適非理。',40,'全唐诗/poet.song.194000.json','["詞以寓意，何適非理。", "游戲翰墨，亦或張弛。", "此篇所傳，觀蜡之比。", "樂而不淫，庶幾在此。"]'),
('5e6aa62a-2918-43a0-9e5e-2354433ab7d1','蘇魏公到鎮出京二帖贊','岳珂','宋','宋诗','song-poetry','','[]','德量維昔該乾坤，藝成而下道乃尊。',64,'全唐诗/poet.song.194000.json','["德量維昔該乾坤，藝成而下道乃尊。", "堂堂魏公古大臣，劫火同燬靈光存。", "直躬致主無間言，餘事翰墨何足論。", "百年劍佩紛如雲，不於其書於其人。"]'),
('08d3f91c-9f03-4149-9b67-412cfe0317db','范忠宣南都帖贊','岳珂','宋','宋诗','song-poetry','','[]','符祐戰，九河溢，砥柱植兮。',89,'全唐诗/poet.song.194000.json','["符祐戰，九河溢，砥柱植兮。", "珪確競，天地昏，清風滌兮。", "大中之道，關百聖而不熄兮。", "用之不失其時，公獨得兮。", "公筆之不倚，而字之不泐兮。", "公意之不偏，而態之不迫兮。", "我觀此書，公心尚可覿兮。"]'),
('eba6e935-bd3b-4cb1-8b2e-b8fa97aa51b2','劉忠定書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','公心如鐵，萬仞壁立。',40,'全唐诗/poet.song.194000.json','["公心如鐵，萬仞壁立。", "聲名百年，翰墨十襲。", "絕景獨睨，奔塵莫及。", "曰誰爲之，目不妄入。"]'),
('a67d247a-cd20-48e8-bffe-b9ebda7c8958','李公擇嘉裕帖贊','岳珂','宋','宋诗','song-poetry','','[]','予登五老峰，其下蓋有山房焉。',87,'全唐诗/poet.song.194000.json','["予登五老峰，其下蓋有山房焉。", "繚閣層廊，疏松秀篁，泉璆夜鳴，谷繡晨張。", "公方讀書其間，蓋已會此趣于胸中之藏。", "然則摛墨池之華，擷綵筆之芳，發其緒餘，書尺七襄，固知其自然雲錦之章也。"]'),
('9261bfb6-535d-440b-a637-d05caea51d93','孫莘老報狀帖贊','岳珂','宋','宋诗','song-poetry','','[]','遺墨之四行，煜其如晨星之爛。',59,'全唐诗/poet.song.194000.json','["遺墨之四行，煜其如晨星之爛。", "是曰元祐之名臣，所當考而申之以贊。", "久藏弗治，客見而歎，持並所携，毫髮無間，予是以知其非贋。"]'),
('9c254828-65bb-483d-af1e-ed71c770aa7b','范正獻書畢帖贊','岳珂','宋','宋诗','song-poetry','','[]','士之以道義相從，豈計其功，而况乎公。',154,'全唐诗/poet.song.194000.json','["士之以道義相從，豈計其功，而况乎公。", "當其任紬繹唐事之寄，所以極簡編之從容。", "亦既上成書于邇英，而公猶得以三百年之鑑，信其遺風。", "則是一紀之淹，乃所以就百世之功。", "石渠蘭臺，片言帝聰，考槃弗爲，皦然初終，尤以見公之于元豐。", "蓋盡其魏闕之心，而裕陵之于溫國，未嘗不知其畎畝之忠也。", "此帖之存，公心天通。", "詆斥之誣，吁嗟麟窮。"]'),
('33deab8b-df18-49c1-a953-9eec86532a6d','范正獻奏議帖贊','岳珂','宋','宋诗','song-poetry','','[]','思魏徵之棠，不如列疏屏之十漸。',113,'全唐诗/poet.song.194000.json','["思魏徵之棠，不如列疏屏之十漸。", "愛衛公之柏，不如存丹扆之五箴。", "諫說豈騰口，格君當以心。", "想引筆而行墨，方危冠而正襟。", "追古事以比迹，見忠臣之慮深。", "是雖不足契當時之感悟，不猶可以鏡方來之佞壬。", "此左氏所以憤乾谿之痛，而三歎于祈招之德音。"]'),
('76d15e51-9e53-4406-94dc-6ea853be87eb','張文潛九華帖贊','岳珂','宋','宋诗','song-poetry','','[]','結字小而密，氣放以逸。',67,'全唐诗/poet.song.194000.json','["結字小而密，氣放以逸。", "措意婉而妍，神閉以全。", "公固不以書名，蓋無一而非天。", "然則汪洋澹泊，一倡三歎，考之東坡先生之言，蓋不特公之文爲然也。"]'),
('2fdd9f98-ec8f-4767-8e57-0ce68807951e','秦少游書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','昔江淹夢五色筆，而不以能書稱。',96,'全唐诗/poet.song.194000.json','["昔江淹夢五色筆，而不以能書稱。", "天昌其文，字偕以行，如公辭章，淹豈能京。", "既已禪長公之文籙，奚必夸大令之墨精。", "託敬賢之盛心，尚遺蹟之可憑。", "然則我得其詩，手之而不釋。", "予方將借荆國之書，以爲此帖之評。"]'),
('651e4cbd-0cdd-4c69-a390-bcb192bccdb9','李端叔命駕神仙二帖','岳珂','宋','宋诗','song-poetry','','[]','姑溪之水清且漪，青山之源衍而汰。',54,'全唐诗/poet.song.194000.json','["姑溪之水清且漪，青山之源衍而汰。", "鍾此奇士，亦一雋快。", "風義磅礴，筆鋒嶮怪。", "蓋已具書體之五雲，不但得發遣之三昧。"]'),
('e298095e-da27-44db-aa7c-bf9e70c69052','范資政早饌帖贊','岳珂','宋','宋诗','song-poetry','','[]','元祐多世臣。',30,'全唐诗/poet.song.194000.json','["元祐多世臣。", "公之德，由忠文。", "岷有阜，江有源。", "傳是帖，存名門。"]'),
('96b6aca3-170e-454a-b815-4e397321dacd','錢文肅家書三帖贊','岳珂','宋','宋诗','song-poetry','','[]','代言無讇辭，居約見素守。',48,'全唐诗/poet.song.194000.json','["代言無讇辭，居約見素守。", "元無刀劈口，乃若神運肘。", "立身本孤直，落筆已耐久。", "家聲到于今，此帖儻不朽。"]'),
('dda28c3c-8e21-410f-8b0b-05039fd3688a','林文節定力帖贊','岳珂','宋','宋诗','song-poetry','','[]','公以好古兼博識，固宜著聲于翰墨。',61,'全唐诗/poet.song.194000.json','["公以好古兼博識，固宜著聲于翰墨。", "予觀此帖，實在京師之定力，是時蓋初掃元祐之迹。", "使其不爲三子之累，則後日之筆當不至于輕擲也。"]'),
('55ceafd4-7a09-4a2c-9c28-7c7f6f9bcbde','林文節參候帖贊','岳珂','宋','宋诗','song-poetry','','[]','平甫之與荆公，蓋當同而異，而公則當異而同者也。',71,'全唐诗/poet.song.194000.json','["平甫之與荆公，蓋當同而異，而公則當異而同者也。", "當刺謁之相從，以朋友之切磋，極兄弟之友恭。", "使合同異之見，而惟是之歸，予知其必有以助善政于熙豐也。"]'),
('ca7e7786-0a16-438b-a7d4-9e02067b0ac0','林文節贈賈收詩稿二詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','歐稱醉翁，公稱醒老。',40,'全唐诗/poet.song.194000.json','["歐稱醉翁，公稱醒老。", "尚論平生，豈以詩考。", "慶曆之滁，元祐之湖。", "醒歟醉歟，醉歟醒歟。"]'),
('8497503a-8856-4a71-abf4-a9ba599ee5a9','林文節元祐日記帖贊','岳珂','宋','宋诗','song-poetry','','[]','漢大中大夫東方曼倩之對孝武曰：誠得天下賢士公卿在位，咸得其序。',400,'全唐诗/poet.song.194000.json','["漢大中大夫東方曼倩之對孝武曰：誠得天下賢士公卿在位，咸得其序。", "譬如以周召爲丞相，仲尼居御史府，畢公高備拾遺，蘧伯玉爲太傅，博士則以顔閔，執金吾以季路，衛尉以卞嚴子，光祿以仲山甫，郡守以子産，詹事以孔父，史魚司直，申伯爲御，下至旄頭式候亦羿萬之伍，則唐虞之隆，成康之際，陳功比德，自無以喻。", "武帝爲之大笑，蓋甚言其難遇也。", "今視元祐之時，彼固何足慕哉。", "群賢拔茅，大奸脫距。", "如確如惠，必斥必去。", "師保萬民，維溫維潞。", "大老既歸，百揆時序。", "師表以韓，押麻以呂。", "班廷謝門，紛鵷振鷺。", "守正如王，博聞如顧。", "錢劉曾孔，滃雲蒸霧。", "其未登于錄者又不可一二數。", "宣制正衙，天人交助，翕然閭巷，曰司馬雨。", "公蓋異時攘臂于代言之間，而染指于同省之賂，顧猶有是語。", "則是非之公，蓋未嘗不具也。", "然則插齒吐吻，擢項結股。", "委蛇其跡，偊旅其步。", "雖辨知閎達溢于文辭，而詼諧者猶皆不之與，後之君子其必知所去取矣。", "幅紙之得，正邪以寓。", "式闚厥衷，逸史是補。"]'),
('876df76a-4293-4573-8938-cef628ae709e','林文節紹聖日記前帖贊','岳珂','宋','宋诗','song-poetry','','[]','史本乎公，不厭於複。',263,'全唐诗/poet.song.194000.json','["史本乎公，不厭於複。", "重觀紹聖以來之記述，初無及于鄭雍。", "非親札之具存，雖欲考之而孰從。", "如王誼李祉之實迹，徧考史錄，皆無預乎此案之中。", "酈保姓名，亦各不同。", "至于韓忠彥力諫興獄，直乞陛下且與含容。", "安燾面析章惇，以爲鄉風。", "此皆繫其人之大節，而金匱之汗青，皆泯泯于二人之忠。", "凡此帖紙之所具，以同時附會白帖子之人，猶能秉直以寫其衷。", "抑可以見人心之是非，本無所蔽蒙也。", "然于此時，凡六人者皆有所抗論，獨雍首尾噤然若不預者。", "佩玉端委，接武夔龍，又何其無一言之獻替，廣于四聰耶。", "迎合于始，循默于終，而迄不免于黨籍之歸，此枉道事人之所以不勝於直躬也。"]'),
('c09fe763-b2bd-476a-ba50-48a533c92f43','林文節紹聖日記後帖贊','岳珂','宋','宋诗','song-poetry','','[]','進築之法，自古兵法所未有，而始于本朝。',127,'全唐诗/poet.song.194000.json','["進築之法，自古兵法所未有，而始于本朝。", "予意其欲毀齒而兒不知，所以爲是漸取而漸摇。", "曾不虞乎兵分力疲，反足以啟戎心之驕。", "方聖主之側身，凜天變之未消。", "章呂合謀，惟敵是挑。", "豈知夫璿璣七政之必齊，而舞干兩階之自足以格有苗哉。", "我鼓其鼛，我弓其弨，此帖之存，聖心是昭。"]'),
('32c8d4a8-2c91-4191-9158-0784087db7d2','李伯時醉卧圖詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','猗龍眠，本書仙。',32,'全唐诗/poet.song.194000.json','["猗龍眠，本書仙。", "工而妍，畫亦然。", "醉之趣，醒不傳。", "題此詩，比逃禪。"]'),
('591fbca7-f42a-4abc-8dff-93da1aa7b86b','文周翰盛暑帖贊','岳珂','宋','宋诗','song-poetry','','[]','同文之獄，諸賢非一族。',39,'全唐诗/poet.song.194000.json','["同文之獄，諸賢非一族。", "殄瘁之悲，獨及于禹玉。", "豈一人之言，自爲之反復。", "傷哉利祿。"]'),
('f4bef790-55ae-4654-b6ca-5b6c3ed48f79','曾文昭時寒帖贊','岳珂','宋','宋诗','song-poetry','','[]','祖孫百年，兄弟一世。',40,'全唐诗/poet.song.194000.json','["祖孫百年，兄弟一世。", "歸乎其全，抑有公議。", "遺墨散軼，得自名裔。", "人其監茲，豈必名位。"]'),
('68c8df20-2299-4b39-b7ce-33c5b8567469','晁无咎金山詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','我登吞海，而帖適至。',160,'全唐诗/poet.song.194000.json','["我登吞海，而帖適至。", "事雖偶然，不啻有意。", "彼江山者，秀無古今。", "丘壑市朝，則二其必。", "阿大中郎，煌煌虎節。", "金閨卷懷，亦既殊轍。", "同此登覽，而趣不同。", "雲霄並翔，翬翟冥鴻。", "矢詞胸襟，浩蕩萬里。", "比興所存，二疏是企。", "清詩勝景，何地無之。", "不縶不維，景則我隨。", "征塵障天，我亦倦翼，遺墨未渝，微躬奚息。", "南零之波，上派于湓。", "詩其警予，以諗侯門。"]'),
('46d59f24-b8b4-4cd1-a779-d4d9821e2b62','陳忠肅書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','士有直躬，夷險靡易。',40,'全唐诗/poet.song.194000.json','["士有直躬，夷險靡易。", "事君以堯，距詖如墨。", "筆力勁挺，德聲昭植。", "不倚不流，是謂心畫。"]'),
('306ccaad-d7d8-4b61-b842-451c981c3754','蔣觀文錢塘天府二帖贊','岳珂','宋','宋诗','song-poetry','','[]','尺瑜寸瑕，工所不棄。',130,'全唐诗/poet.song.194000.json','["尺瑜寸瑕，工所不棄。", "如公平生，抑有清議。", "雖翰墨之僅存，亦世俗之共毖。", "予獨區區于別白，是亦或出于有意。", "昔鄒忠公以言得罪，士皆縮頸以避去。", "公乃折簡以自麗，由是而去，蓋已無懟。", "然則操觚刻槧，片言幅紙，其知所以行己也必矣。", "以字達識，以識行字，舉一知二，茲帖之所以可貴。"]'),
('4197af33-d498-4756-b877-b7f30e01a114','佛印清勝帖贊','岳珂','宋','宋诗','song-poetry','','[]','欲溯其洄，先涉其流。',68,'全唐诗/poet.song.194000.json','["欲溯其洄，先涉其流。", "欲觀其人，先視其與游。", "東坡之名，在昌黎武威之間。", "而師之能，亦文暢秘演之儔。", "德必有鄰，而人焉廋。", "世于是可以察予之去留。"]'),
('20991ca7-e8e7-41c6-960a-b0ca4bc87010','參寥新秋帖贊','岳珂','宋','宋诗','song-poetry','','[]','帖中書督字，法當爲篤，世間豈有不識字參寥子耶。',45,'全唐诗/poet.song.194000.json','["帖中書督字，法當爲篤，世間豈有不識字參寥子耶。", "應世以文，特師之粗，于此乎何拘，維以觀其書。"]'),
('c1caace2-6f6b-4045-b2c4-82237c02878f','米元章書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','論書自晉始，蓋因其風俗之清而流之于妍。',256,'全唐诗/poet.song.194000.json','["論書自晉始，蓋因其風俗之清而流之于妍。", "降而六代，又以其習尚之篤而溺之于專。", "維唐設科，身判書言。", "作成自初，歐褚爭先，薛靚張顛，顔真迎便。", "中世而後，雖經生楷隸，猶得以揚鑣而鳴鞭。", "五季日卑，吾宋興焉。", "士以德進，捨藝之偏。", "既窒其進取之塗，故世之以書名家者，皆不雜以人而純乎天。", "更八葉之豫豐，乃設學而詳延。", "有芾者出，集其大全。", "蓋繇羲獻而來，遡崇觀而前，或營萃以拔棘，或宮牆而及肩，或小醇而大疵，或舍正而取權。", "六書之統，殆所謂芾之死不得其傳也。", "巘巘喬嶽，洋洋大川，草木風雲，波濤蛟黿。", "我繫此評，其然豈然。", "較三十里，後八百年。"]'),
('6140100f-6ff2-4af8-b490-9515945734bd','米元章靈峰行記帖贊','岳珂','宋','宋诗','song-poetry','','[]','永和之蘭亭，列序時人。',46,'全唐诗/poet.song.194000.json','["永和之蘭亭，列序時人。", "文字之不磨，千載莫鄰。", "彼睎顔之徒雖未足倫，觀其所傳，亦庶幾彷彿乎清塵。"]'),
('463931ec-0c06-473b-a75a-16808cc70462','米元章獲硯帖贊','岳珂','宋','宋诗','song-poetry','','[]','公謂是硯，生平之所無。',41,'全唐诗/poet.song.194000.json','["公謂是硯，生平之所無。", "彼美硯山，乃易其所居。", "既舍其所寶，聊假以自娛，其亦人之情歟。"]'),
('db0df264-3dda-4f17-95b3-13749374186b','米元章四大字帖贊','岳珂','宋','宋诗','song-poetry','','[]','昔大令書壁，作方丈大字，觀者至數百人。',78,'全唐诗/poet.song.194000.json','["昔大令書壁，作方丈大字，觀者至數百人。", "蓋能書家嘗以收斂觀楷則，而以縱放觀精神。", "予觀此書，大不失倫。", "蓋自智而慧者筆下有天真之悟，而惟清與凈者胸中無一點之塵也。"]'),
('cd41310a-a046-4b15-8339-4cc755ce7474','米元章曹子建應詔詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','呼嗟乎丕，摧幹弱支。',44,'全唐诗/poet.song.194000.json','["呼嗟乎丕，摧幹弱支。", "予讀此詩，何異乎煮豆而燃萁。", "弔古以詩，觀帖以奇。", "瑶鈿銀泥，以侈厥題。"]'),
('0d601827-61b7-48b9-9e1e-cfc0697b1a45','米元章蠶賦帖贊','岳珂','宋','宋诗','song-poetry','','[]','桑柘之利被天下，而不足以芘一女。',69,'全唐诗/poet.song.194000.json','["桑柘之利被天下，而不足以芘一女。", "鬢蓬手筥，而身不縷。", "雲織霧組，便疏曲戶。", "世之類此者，又何可勝數。", "是將誰尤，曰本是務。", "彼棄我取，維終以無窶。"]'),
('196362ba-7dad-4d08-a54a-ee8769185d7a','米元章黄龍帖贊','岳珂','宋','宋诗','song-poetry','','[]','華胄遥遥楚國，宗風的的曹溪。',28,'全唐诗/poet.song.194000.json','["華胄遥遥楚國，宗風的的曹溪。", "喚起爭名米老，奎光長照珍題。"]'),
('28b604fa-5d98-419a-aa8b-5c7f6df53ba4','米元章獄空行帖贊','岳珂','宋','宋诗','song-poetry','','[]','事上官當以信。',55,'全唐诗/poet.song.194000.json','["事上官當以信。", "溢美而言，是謂私徇。", "唐君果何人，而得此于寶晉。", "予蓋于是三歎，則前朝之得士，而未暇及筆法之神雋也。"]'),
('f26a3475-0523-40f0-b407-f9e20a401de4','米元章四大字詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','四詩之作，句新而詞伉。',142,'全唐诗/poet.song.194000.json','["四詩之作，句新而詞伉。", "兩軸之書，意軒而神王。", "合此名蹟，奇變萬狀。", "予得此詩，季春既望。", "風激海而濺霧，月穿雲而崩浪。", "開函卷舒于小萬有之上，作而歎曰，是可以領略山川之清壯矣。", "予方望紫烟之岫，具黄篾之舫，友二妙于百載，寓三歎于一倡。", "正使持此而列衡門之素壁，亦足對雲錦之九疊，而夸瀑布之千丈也。"]'),
('37b1c75f-ca84-427b-aac1-32908a49dfb1','米元章海嶽詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','海嶽之東西，見于印而驗于碑。',69,'全唐诗/poet.song.194000.json','["海嶽之東西，見于印而驗于碑。", "觀乎此詩，景與物隨。", "於虖噫嚱，此皆是也，夫豈復有今是而昨非。", "江湯湯其不移，山窿窿其不虧。", "登兮覽兮，予言其如之。"]'),
('aad4e4b5-f133-42ab-957d-2cb4e5ed3714','米元章硯山詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','壺嶺九華，營是一枝，何異乎持琬琰以易羊皮。',62,'全唐诗/poet.song.194000.json','["壺嶺九華，營是一枝，何異乎持琬琰以易羊皮。", "硯之不存，而寶此詩，抑類乎舍魚兔而守筌蹄。", "不我後先，得于斯是，几席江山，庶幾見之。"]'),
('b9473cd8-3691-45b8-8725-70b9c3f236c2','米元章甘露詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','公嘗有凈名之詩曰：殷勤顧景物，爲爾老南徐。',123,'全唐诗/poet.song.194000.json','["公嘗有凈名之詩曰：殷勤顧景物，爲爾老南徐。", "考乎此篇，則出無晴雨之待，觀無陰霽之殊。", "晝呼竹輿，暮詠歸塗。", "既不舍于斯須，其必邇于海嶽之故廬。", "如曰易硯山之寶儲，登樓平章，維王及蘇，自西徂東，乃獲奠居。", "此所謂舍其舊而新是圖，予固因以驗予記與跋之皆不誣也。"]'),
('4ddfed44-3c5d-4ecc-8e26-267c9cee0f3f','米元章寶月觀詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','月之行空，四海清輝，豈獨于一觀見之。',39,'全唐诗/poet.song.194000.json','["月之行空，四海清輝，豈獨于一觀見之。", "覽層宇之翬，地高而天隨，而後可以觀公之詩。"]'),
('7f60a832-ee05-498a-a191-123633a20ab4','米元章鑑遠前詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','登覽之勝，隨寓有感。',54,'全唐诗/poet.song.194000.json','["登覽之勝，隨寓有感。", "野燒之觀，玉石俱慘。", "逞志一快，忘彼物情。", "是以老氏惡夫佳兵。", "觀乎觀乎，彼以爲觀而予以爲懲。"]'),
('04c4dd1c-bb34-4b0d-9986-d45e658324b4','米元章鑑遠後詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','野燒之觀，予嘗以爲歎。',39,'全唐诗/poet.song.194000.json','["野燒之觀，予嘗以爲歎。", "此詩之存，予又以爲欣。", "一鑑遠耳，而戚休之以身，天乎非人。"]'),
('0229e9d4-90c3-4784-9f54-5e06f9340794','米元章催租詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','賑濟者何人，催租者何司。',36,'全唐诗/poet.song.194000.json','["賑濟者何人，催租者何司。", "有令如斯，而無救于背馳。", "此古人所以設官以採詩也。"]'),
('963c5bf4-41c3-4e64-99dd-f393b5fc26ef','米元章槐前竹後詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','槐竹之與居，栩栩乎華胥。',53,'全唐诗/poet.song.194000.json','["槐竹之與居，栩栩乎華胥。", "予方發韓滉之連艫，午陰之繁維，以驅原隰之車。", "蓋健羨乎一身之閑，所以縱玩乎八體之書。"]'),
('a970bd3e-2511-4638-b76d-3fa97076942f','米元章壯觀前詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','北山之麓有奇觀，景絕人奇乃無間。',64,'全唐诗/poet.song.194000.json','["北山之麓有奇觀，景絕人奇乃無間。", "賦非雕蟲句有眼，千古雄姿想蕭散。", "我觀此卷字老懶，猶似古彝親數頮。", "借公舊詩聊永歎，跪閲墨皇三復返。"]'),
('a3d18979-3d01-424d-a65a-569e317f9a6d','米元章壯觀後帖贊','岳珂','宋','宋诗','song-poetry','','[]','四朞之不到，雪與日杲。',45,'全唐诗/poet.song.194000.json','["四朞之不到，雪與日杲。", "停舟不棹，無嫌乎衝冒。", "出此詩畫，摹寫天巧。", "觀之壯，思之老，詩乎可考。"]'),
('e9213339-0206-4536-bbcd-e29f9b71a62a','米元章姑孰詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','天上文章一酒星，生平只欠換鵝經。',32,'全唐诗/poet.song.194000.json','["天上文章一酒星，生平只欠換鵝經。", "奇才逸思通千古，留待南宮眼爲青。"]'),
('15cee5c8-eec5-498b-a3a1-c4ba31ec4603','米元章道林詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','道林之名，予不得而知。',111,'全唐诗/poet.song.194000.json','["道林之名，予不得而知。", "雲泉松石之勝寫于漣漪，必其地之景物足以稱其詩也。", "今其陳跡杳然，已無復遺。", "予蓋嘗登瑞墨之基，渺一境之陂陀，皆平蕪與荒畦，又惡睹所謂畢世相忘之奇。", "泉陊雲歸，松橋斧隨，世固多有之。", "而予獨于此奇其北向之悲也。"]'),
('73548383-4a73-4774-9003-37fcece8dce1','米元章賞心詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','金陵之賞心，天下之奇觀，真足以當南宮之詩翰。',60,'全唐诗/poet.song.194000.json','["金陵之賞心，天下之奇觀，真足以當南宮之詩翰。", "予之持節登覽非一旦，而得此詩八年之泮奐。", "吁嗟公兮，豈料百年而售此詩于三萬兮。"]'),
('7b7322c7-4d7f-4fe9-913a-0ce37101bec6','米元章壽時宰詞帖贊','岳珂','宋','宋诗','song-poetry','','[]','太平得協于夢卜，濃墨大軸，予未知其誰祝。',36,'全唐诗/poet.song.194000.json','["太平得協于夢卜，濃墨大軸，予未知其誰祝。", "韓呂之穀，王蔡之辱，尚四海之欲。"]'),
('6c02af0f-a25d-4927-b6b3-1f5be7d4d05d','米元章墓誌帖贊','岳珂','宋','宋诗','song-poetry','','[]','予觀柳少師，在唐以能書聞。',59,'全唐诗/poet.song.194000.json','["予觀柳少師，在唐以能書聞。", "當時碑誌或非其筆，則人以不孝議其子孫。", "噫嚱，陳君之傳，夫豈以其文。", "如寶晉省，亦庶幾乎其人矣。"]'),
('6954dcc2-80ed-42a3-81b2-402cfc0ee5a6','米元章書山谷大悲憕贊帖贊','岳珂','宋','宋诗','song-poetry','','[]','我佛住世，大開方便。',270,'全唐诗/poet.song.194000.json','["我佛住世，大開方便。", "有大士者，現自在身。", "以千手眼，一一接引。", "指示群迷，照破諸妄。", "如是我聞，佛說了義。", "諸鈴杵鐸，寶塔經卷。", "輪拂瓔珞，種種所執。", "凡所執者，俱非有相。", "智慧清凈，肉眼慧眼，佛法天眼，種種所見。", "凡所見者，俱非有著。", "以無相故，釋諸纏縛，一切衆生，得大解脫。", "以無著故，具足圓明，一切衆生，得大知見。", "佛尚無相，何况于讚。", "佛身常住，即心是佛。", "稻麻竹葦，無限劑數。", "彼頂戴者，皆真實相。", "百千萬億，何况於身。", "涪皤說法，如標月指。", "標本在手，何者爲月。", "寶晉寫讚，如轉輪王。", "運轉隨人，終不成道。", "我不見憕，我不執筆。", "非見非□，手眼皆具。", "稽首大士，大慈悲故。"]'),
('8708a420-926d-4573-905b-25ba830bf053','米元章臨晉武帝大水帖贊','岳珂','宋','宋诗','song-poetry','','[]','論帖至晉，書法之祖。',40,'全唐诗/poet.song.194000.json','["論帖至晉，書法之祖。", "遡晉而西，又舉一武。", "撲散質寓，意妍態魯。", "禁臠之藏，尚覿真古。"]'),
('a1db971b-710e-4e6e-b286-39fd6ea3bbf2','米元章臨謝安八月帖贊','岳珂','宋','宋诗','song-poetry','','[]','八月一帖，無爲寶晉之刻，則其初也。',173,'全唐诗/poet.song.194000.json','["八月一帖，無爲寶晉之刻，則其初也。", "兵燬而後重取而鎸，遺其精而得其粗也。", "京口供軍之碑，紹興所傳，芾之書也。", "此帖亦其同時，同出于尚方之儲也。", "芾之嗜帖，所謂麻紙十萬，足以驗其平生之工夫也。", "字與跋皆不同，蓋所臨雖出一手，而其所得之時日則殊也。", "供軍帖字之所以寡，出于率意之真，而此二帖則皆臨而非摹也。", "京口海嶽，芾所居也。", "兩臨本之並傳，尚可以見其人之緒餘也。"]'),
('73b0214c-51ff-4345-9511-9f06d2813dfc','米元章臨智永千文真草帖贊','岳珂','宋','宋诗','song-poetry','','[]','永之法，妍而婉。',65,'全唐诗/poet.song.194000.json','["永之法，妍而婉。", "芾之體，峭以健。", "馬牛其風，神合志通。", "彼妍我峭，惟神克肖。", "故曰袒裼不浼，夜戶不啟。", "善學柳下惠，莫如魯男子，芾其知此。"]'),
('e1c6641c-0c2e-4a86-a771-93ffa9c60258','米元章臨右軍四帖贊','岳珂','宋','宋诗','song-poetry','','[]','東淮餉府供軍堂，壁有龕石鸞鵠翔。',224,'全唐诗/poet.song.194000.json','["東淮餉府供軍堂，壁有龕石鸞鵠翔。", "問之何石摹破羌，曾傍雲漢分天章，廷陵刻此侈寵光。", "後四十年猶煒煌，我持搨本謹毖藏。", "三年徙倚玩未央，客來袖出雲一張。", "曾染復古隃麋香，珠璣別出十九行。", "驚喜比並走且僵，摛華絢彩交相望。", "宛然並粲如英皇，幾年絕識高君王。", "尚取鑒定煩諸郎，半歸左畹半尚方。", "駕言駰隰留餘芳，今夕何夕獲干將。", "鏌鋣未睹龍已驤，吳侯攀髯歸帝鄉。", "秋虹挾月常貫窗，誰能籋雲開斗房。", "携書伴我老柴桑，要隨神物恢混茫，更斲此石封苔蒼。", "六丁雷電未可量，會見難起初平羊。"]'),
('b1c35d64-c3f7-46f7-9b02-44110fe977ff','米元章臨右軍玉潤帖贊','岳珂','宋','宋诗','song-poetry','','[]','熠煜客星，顒逵之伍乎。',66,'全唐诗/poet.song.194000.json','["熠煜客星，顒逵之伍乎。", "軒冕相禪，泉石之嫵乎。", "美疢惡石，天所痼乎。", "情之所鍾，同此趣乎。", "排九閶之雲，巫咸之訴乎。", "後千年有人，垤澤之呼乎。"]'),
('1fb2a3c1-cd47-4126-adf9-230834fc70bf','米元章臨筆精日寒二帖贊','岳珂','宋','宋诗','song-poetry','','[]','義獻之蹟，臨者米也。',40,'全唐诗/poet.song.194000.json','["義獻之蹟，臨者米也。", "遡觀欣書，乃二體也。", "隨珠卞璧，萃此紙也。", "以鑒得之，亦可紀也。"]'),
('2a0eb6b6-bfed-4db0-8e57-472a4d4b0ef6','米元章臨王獻之臺符帖贊','岳珂','宋','宋诗','song-poetry','','[]','芾贊謝安帖，而嘉其得太帝之翰墨。',66,'全唐诗/poet.song.194000.json','["芾贊謝安帖，而嘉其得太帝之翰墨。", "龍跡震驚，言猶未泐，豈知其身被帝澤也哉。", "士患不能，不患不知。", "百世俟聖，乃今見之，予將以之爲行己之師。"]'),
('fe9894d3-2886-4bdc-9a9f-9b71455809fb','米元章臨王獻之東問帖贊','岳珂','宋','宋诗','song-poetry','','[]','字有十五，如月當戶。',40,'全唐诗/poet.song.194000.json','["字有十五，如月當戶。", "騰輝以望，靡忒今古。", "匪獻莫具，匪芾莫祖。", "誰其修之，有玉其斧。"]'),
('1f70f4a4-e504-4f9c-9127-5cd2adc862ea','米元章臨顔真卿放生池帖贊','岳珂','宋','宋诗','song-poetry','','[]','楷正而端方，維顔之長。',94,'全唐诗/poet.song.194000.json','["楷正而端方，維顔之長。", "軒昂而自善，維米之體。", "多嗜而博愛，故能有其態。", "略迹而取神，故不沒其真。", "是曰唐放生之碑。", "作者書之，能者摹之。", "江陰之王，畀我儲之。", "五御既調，又日驅之。", "於虖後生，誰能如之。"]'),
('a258597f-e225-4ef4-b550-17717fc13359','邵仲恭展晤省見二帖贊','岳珂','宋','宋诗','song-poetry','','[]','寶晉大字之刻，嘗同公遊。',68,'全唐诗/poet.song.194000.json','["寶晉大字之刻，嘗同公遊。", "必嗜好之素同，故忘情乎尋壑之與經丘。", "予嘗陋貞觀慰問之不收。", "得此帖于鄉，考百年之風流。", "識者文曰：此吾宋之邵蘇州也。"]'),
('fe98197e-a39e-4e1b-838b-cf1235dc8d96','龔深父南康帖贊','岳珂','宋','宋诗','song-poetry','','[]','公用王氏學術，終始不易。',44,'全唐诗/poet.song.194000.json','["公用王氏學術，終始不易。", "雖有歉于識，然亦足以知其自信之力。", "一偏之溺，異端之惑，視此手蹟。"]'),
('ddceb9e2-ba6e-4448-b446-ba58dbbcdb2f','張文忠至都帖贊','岳珂','宋','宋诗','song-poetry','','[]','無盡之學，出入孔釋。',109,'全唐诗/poet.song.194000.json','["無盡之學，出入孔釋。", "故其筆法倜儻斜直，于跌宕中時入繩墨。", "亦猶即紹聖以侮元祐之正，用大觀以反崇寧之譎。", "凡是心之所藴，已畢寓于聲畫。", "雖曰自蓋，斷猶可識。", "使其知根荄之物則，而推以芟葛藤之蒙闃。", "如是帖者，亦可以爲傳世之名蹟矣。"]'),
('fe124b0a-38fd-4eeb-8b13-285dcdced5e9','張文忠草書韓退之桃源詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','太平宰相張天覺，草聖之神何卓犖。',64,'全唐诗/poet.song.194000.json','["太平宰相張天覺，草聖之神何卓犖。", "幾年嘉禾識奇作，餘事猶令墨池涸。", "仙源三月桃雨落，雲黑洞深風色惡。", "夢回滿紙字如昨，喚起龍蛇見頭角。"]'),
('7d86b562-4c83-415c-a4cb-e9d70b46417f','趙清憲挽辭帖贊','岳珂','宋','宋诗','song-poetry','','[]','公爲中司，排擊元祐故臣，而猶拳拳于伊洛之門人。',81,'全唐诗/poet.song.194000.json','["公爲中司，排擊元祐故臣，而猶拳拳于伊洛之門人。", "豈奏疏陳事或爲世資而詘，而作詩懷友固不害于私情之伸耶。", "於虖，是私情也，而實出于公言。", "此吾之所以重歎，而列之于斯文也。"]'),
('b126fc44-8f60-4976-8fb3-49a31f23f2d9','吳開府前日帖贊','岳珂','宋','宋诗','song-poetry','','[]','豫章之東湖，有公之居。',36,'全唐诗/poet.song.194000.json','["豫章之東湖，有公之居。", "西山薦圖，咮鳳滴蜍。", "伊波之餘，而無以昌其書。", "嗚呼。"]'),
('d4ec0b7b-19e9-4c59-bc5a-b3aa90230a75','章申公屏居帖贊','岳珂','宋','宋诗','song-poetry','','[]','張無盡嘗謂公奇男子，夢中劇談若或見之。',60,'全唐诗/poet.song.194000.json','["張無盡嘗謂公奇男子，夢中劇談若或見之。", "矧予于手蹟之遺，猶足以睹百年之風姿。", "仕繫于時，才高用違，覽者未嘗不三歎息于斯。", "嘻。"]'),
('f79d1fff-af8e-47a1-b872-53548b846e30','薛黄門春聚帖贊','岳珂','宋','宋诗','song-poetry','','[]','九字在紙，落落晨星。',40,'全唐诗/poet.song.194000.json','["九字在紙，落落晨星。", "此帖之傳，猶及太平。", "意象軒昂，足稱其名。", "作此贊焉，惟字之評。"]'),
('6e38ad4e-4e29-4b5b-923e-88e9876bccc8','晁之道促裝帖贊','岳珂','宋','宋诗','song-poetry','','[]','仕以行義，有時乎爲貧也。',108,'全唐诗/poet.song.194000.json','["仕以行義，有時乎爲貧也。", "兄弟之間，情事貴乎真也。", "公起異科，事不患不伸也。", "囊封叩閽，因以警夫君也。", "忠既弗售，反以痼終身也。", "扶持之難，曷敢尤夫人也。", "今觀斯帖，凜乎其若存也。", "於虖文元，有以教子孫也。", "德之不孤，吾知必有鄰也。"]'),
('58ef063e-590c-48e8-90b0-f9f0969c04d8','霍仁仲指教帖贊','岳珂','宋','宋诗','song-poetry','','[]','金斗之魁祥，爛兮流光。',44,'全唐诗/poet.song.194000.json','["金斗之魁祥，爛兮流光。", "玉墀之西廂，頎兮荷囊。", "寶墨之淋浪，蔚兮遺芳。", "百年之巾緗，宜兮毖藏。"]'),
('a479eaea-93b4-49b2-b242-30d0720cc1bc','葛文康書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','辭以情達，義以氣激。',40,'全唐诗/poet.song.194000.json','["辭以情達，義以氣激。", "以素心期，託名手筆。", "都曹之獲，中寓其一。", "尚想風流，太平人物。"]'),
('08bdf62e-14f8-4a8c-a084-28710d0e0e7b','二蔡陪輔展晤二帖贊','岳珂','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','王氏之鬻他帖也，有紙繅其間。',139,'全唐诗/poet.song.194000.json','["王氏之鬻他帖也，有紙繅其間。", "予見其粉墨闌珊，既磨而殘。", "而考其氏名，輒長愾而永歎。", "曰予聞之叢談，是與忠惠者若是班乎。", "今驗其字體，則豪放而具骨力，激越而競波瀾。", "使名節足以齊馳，亦何羨乎二難。", "然而所立所趨，其視忠惠，何啻汙池之于泰山。", "故雖鬻駔尚得而唾棄之，世之以藝稱者，斯亦足以觀矣。"]'),
('60a9dacc-dfcf-408e-98bc-4183d2e86930','徐明叔競向熱傳達二帖贊','岳珂','宋','宋诗','song-poetry','','[]','書名之行，始于東夷。',40,'全唐诗/poet.song.194000.json','["書名之行，始于東夷。", "歸而範模，則有餘師。", "中興幾人，存此絕技。", "太平之風，尚想漸被。"]'),
('190702ba-40a5-4073-836d-e5372813c228','周美成友議帖贊','岳珂','宋','宋诗','song-poetry','','[]','左太沖賦三都十年，門牆藩溷皆著紙筆。',135,'全唐诗/poet.song.194000.json','["左太沖賦三都十年，門牆藩溷皆著紙筆。", "予意其因以寓墨池模倣之妙，而未必徒以詫記事備言之述。", "不然則亦焉用是物也。", "如公書法，或者得太沖之彷彿乎。", "有鳳樓之手，以侈其標度。", "有香奩之澤，以醖其風骨。", "體具態全，夫豈一日。", "清真之名，公所自出。", "世不當徒以考公之詞賦，尚可因是著公之翰墨也。"]'),
('d135ba6c-870d-47b0-951a-c0d82724f06e','翁端朝輕利帖贊','岳珂','宋','宋诗','song-poetry','','[]','結字清而峻，用筆精而穩。',48,'全唐诗/poet.song.194000.json','["結字清而峻，用筆精而穩。", "雖牋以粉，而墨蹟猶未損。", "公之功名，予固未暇論。", "而所謂書法，要必有所本矣。"]'),
('ddf0b126-a687-48dc-b3d0-ba0785455eec','吳王造見應命二帖贊','岳珂','宋','宋诗','song-poetry','','[]','所書如此，而事如彼。',40,'全唐诗/poet.song.194000.json','["所書如此，而事如彼。", "既悅我目，亦冷我齒。", "我錄此事，與郗超比。", "名焉不刊，帖亦奚毀。"]'),
('66a88e80-43fd-4a70-86ac-301a22a3ca6d','耿黄門讀易帖贊','岳珂','宋','宋诗','song-poetry','','[]','堅冰履霜，誨盜慢藏。',79,'全唐诗/poet.song.194000.json','["堅冰履霜，誨盜慢藏。", "戒隳乎復隍，亡繫乎苞桑。", "一乎柔以御剛，確其信于殊方。", "以是謀國，迄于靖康。", "則讀易之無一得，蓋公之所愧，殆非空言以成報章。", "尚其監茲，前事不忘。"]'),
('e3bede14-72a3-4610-9677-783342791123','汪忠定栗冽帖贊','岳珂','宋','宋诗','song-poetry','','[]','黄霸爲相，功名減于治郡。',47,'全唐诗/poet.song.194000.json','["黄霸爲相，功名減于治郡。", "尺或不足，而有餘于寸。", "文翰聲跡，百年一瞬。", "遺帖得于其家，殆亦足以傳信。"]'),
('d655b6b5-f56c-4213-a940-a83dc5ddacfd','朱忠靖按巡郡寄邸報三帖贊','岳珂','宋','宋诗','song-poetry','','[]','士孰不排難，貴乎安以徐。',76,'全唐诗/poet.song.194000.json','["士孰不排難，貴乎安以徐。", "士孰不立節，貴乎平以舒。", "既家國之兼全，亦身名之裕如。", "是與夫激切奮跲，纓冠曼胡者，蓋已同功而殊塗。", "我思其人，猶及屋烏，而况乎遺書。"]'),
('0bed441d-ad79-4f1d-abb1-c1e1df21e5da','滕資政山中帖贊','岳珂','宋','宋诗','song-poetry','','[]','沮徒民于中原，廣好生于帝堯。',49,'全唐诗/poet.song.194000.json','["沮徒民于中原，廣好生于帝堯。", "亦既三已，歸而漁樵。", "而書尺之間，造次不忘乎本朝。", "此所以爲中興之大僚也。"]'),
('bc828f72-71a2-4e5b-bda2-36b4c0e5eba2','趙伯山寶鍊帖贊','岳珂','宋','宋诗','song-poetry','','[]','以公姓之麟定，執登壇之牛耳。',56,'全唐诗/poet.song.194000.json','["以公姓之麟定，執登壇之牛耳。", "即信厚以爲俊奇，蓋一家之自爲體。", "以道對時，居夷何愧。", "此鑑堂之所以處己，而予察之于此。"]'),
('aa0a3ca5-984b-4a24-a0f1-1a722d7fd0da','劉資政符寶帖贊','岳珂','宋','宋诗','song-poetry','','[]','公兩登西掖，前後抗論數十疏，可謂剛且勁。',67,'全唐诗/poet.song.194000.json','["公兩登西掖，前後抗論數十疏，可謂剛且勁。", "而扈衛江右，遭時不競。", "斯亦可以言命矣。", "夫遺學所傳，雖未足以盡乎平生，而亦足以見其行己之簡敬也。"]'),
('f02b354a-3d83-47f6-9c89-99124ec925f2','葉左丞同升遂意二帖贊','岳珂','宋','宋诗','song-poetry','','[]','早登金扉踏仙鰲，晚陪大政歸擁旄。',64,'全唐诗/poet.song.194000.json','["早登金扉踏仙鰲，晚陪大政歸擁旄。", "石林風月出處高，清心妙寄同揮毫。", "麗如雲錦披宮袍，橫走健態霜鶻捎。", "萬里筆陣誰能鏖，摧鋒今識真孟勞。"]'),
('9a3fac0c-98f9-40bd-bbe9-e5ca688aed35','沈忠敏勞軍帖贊','岳珂','宋','宋诗','song-poetry','','[]','仕同時也，志同歸也。',40,'全唐诗/poet.song.194000.json','["仕同時也，志同歸也。", "相與以心，無町畦也。", "職位接踵，亦相齊也。", "噫嚱此帖，比傳衣也。"]'),
('81c6a79c-e757-4ab7-a30e-b938d6271a9d','宗忠簡留守司二劄家書吾友三帖贊','岳珂','宋','宋诗','song-poetry','','[]','人心大義，不作不奮。',240,'全唐诗/poet.song.194000.json','["人心大義，不作不奮。", "楚漢之間，較者尺寸。", "翼翼京邑，九聖所都。", "時方多艱，天下之樞。", "勢進則張，狙詐作使。", "聚而遺毒，不人則己。", "一退則衄，彼莫我宗。", "于敵弗施，各逞其鋒。", "天方授吾，狼貪如罕。", "使乘其弊，隻輪不返。", "機失于昨，何救匪今。", "方憤之人，未弱之心。", "京國有君，河外有統。", "如彼見關，孰不鼓勇。", "犖犖忠簡，蓍數龜陳。", "瞭其胸中，七十之身。", "黄汪何知，愛以姑息。", "捐之中原，俾自爲敵。", "謂不可敵，公方渡河。", "連壁百萬，馬騰士歌。", "公心何愛，憤至于死。", "紐不在上，雖締易弛。", "滎陽勿守，漢業豈高。", "屠狗販儈，何吠不嘈。"]'),
('2e9eb3f8-5022-4076-896f-1421dfb14b24','宗忠簡贈陳秀才詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','赫蹏之紙，幅不盈咫。',40,'全唐诗/poet.song.194000.json','["赫蹏之紙，幅不盈咫。", "字雜衆體，詩具二美。", "不軼不毀，相維天只。", "意質功偉，有志視此。"]'),
('e6f49a3e-5984-4b12-a94b-bad6bde96d85','孫仲益和議帖贊','岳珂','宋','宋诗','song-poetry','','[]','事君有大義，彼國家之不計，而惟顧乎妻子之避地。',51,'全唐诗/poet.song.194000.json','["事君有大義，彼國家之不計，而惟顧乎妻子之避地。", "則執筆舐痔，惟苟活是視，岸然不愧，固其素志。", "于予乎何議。"]'),
('990f8dd6-141a-4e83-aa8d-819041641ec5','蘇養直書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','其作字得東坡之骨，而加以平實。',109,'全唐诗/poet.song.194000.json','["其作字得東坡之骨，而加以平實。", "得山谷之體，而去其越軼。", "其應世接物得馬少游之善，而持以卑詘。", "故先生者施之長上，居士者待其儔匹，兄之又所以示其親且密。", "意厚詞悉，情真制質。", "列之籤帙，神采坌溢。", "雖不識者，亦將曰此隠君子之筆也。"]'),
('52b135b5-ae93-42ea-a49d-48335f49cd14','蘇養直與四僧書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','彼黄四娘，詩于杜陵。',40,'全唐诗/poet.song.194000.json','["彼黄四娘，詩于杜陵。", "先南懷芝，果何等僧。", "視其與游，尚或可喜。", "于帖之存，以識驥尾。"]'),
('3a3fc72a-f13a-40d3-8a3b-3598d560a2e6','蘇養直留客詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','予在京江，蓋慣識江南之秋。',27,'全唐诗/poet.song.194000.json','["予在京江，蓋慣識江南之秋。", "一成之去，而虛作十年之留也。"]'),
('3e417a02-937d-46ff-afaf-2e4f59e783db','朱希真書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','洛陽耆英，淪于朔塵。',43,'全唐诗/poet.song.194000.json','["洛陽耆英，淪于朔塵。", "三十年有人，典型之存。", "炙手絕倫，一日之伸。", "梅花兮繽紛，孤山兮片雲。"]'),
('54410022-d61e-4518-b7e4-629b32cccebe','葛常之犀表帖贊','岳珂','宋','宋诗','song-poetry','','[]','文康之學導其源，文定之學濬其流。',45,'全唐诗/poet.song.194000.json','["文康之學導其源，文定之學濬其流。", "三世之帖俱傳于予家，其亦足以見植槐之志，而占良冶之裘也歟。"]'),
('45876b67-80e1-4aaa-9840-ec75671aecd4','蔣宣卿書簡帖贊','岳珂','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山之下仙佛之廬，多公題扁，予熟其體矣。',73,'全唐诗/poet.song.194000.json','["廬山之下仙佛之廬，多公題扁，予熟其體矣。", "而今見其帖，大抵小則遒而大則婉。", "豈所施有異，而筆法亦隨以變。", "遒而不流于介，婉而不失其健，予猶愧乎知書之淺。"]'),
('94685000-4983-408d-b4e7-7ac87c9b0f89','劉季高書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','用情之真，視古庶幾。',35,'全唐诗/poet.song.194000.json','["用情之真，視古庶幾。", "他帖雖不能盡知，筆法皆清而奇。", "我標淳風，以戒言詭。"]'),
('9d4b35d1-762c-4e7f-866e-34105cc9b4ca','劉行簡前日帖贊','岳珂','宋','宋诗','song-poetry','','[]','情叶事之宜，筆力亦稱之。',30,'全唐诗/poet.song.194000.json','["情叶事之宜，筆力亦稱之。", "雖得于歙水之湄，然望而識其爲苕溪也。"]'),
('be5fa1b6-780a-45ee-921c-57ca952bc5fb','劉忠武書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','以勁筆力，作往來帖。',40,'全唐诗/poet.song.194000.json','["以勁筆力，作往來帖。", "婉有餘妍，莊不可狎。", "古者文武，初非二流。", "繫於卿士，予其從周。"]'),
('e3079963-1075-445b-9734-19794db3fdf8','劉忠武五詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','予表此詩，蓋欲天下知將帥未嘗無人。',48,'全唐诗/poet.song.194000.json','["予表此詩，蓋欲天下知將帥未嘗無人。", "夫豈必弧矢之棄而筆硯之親。", "合之一，歧之分。", "噫嚱斯藏，何忝于文。"]'),
('d8a92b61-b036-4cb9-94f9-49cb6bca138e','楊文靖早間帖贊','岳珂','宋','宋诗','song-poetry','','[]','道之在人，日用皆其事也。',48,'全唐诗/poet.song.194000.json','["道之在人，日用皆其事也。", "待物必誠，所以達乎義也。", "延平之津，伊洛之涯涘也。", "筆端波瀾，亦可想其似也。"]'),
('d7c7d55d-ec1c-496e-8d37-8e998430822f','吳傳朋書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','小書楷則本晉人，降而唐世體益真。',48,'全唐诗/poet.song.194000.json','["小書楷則本晉人，降而唐世體益真。", "妙趨要識筆有神，行行清妍雜奇偉。", "奇爲精神楷爲體，吳君筆力備諸此。"]'),
('6eda3db8-e529-492e-a017-768bf6005bbc','吳傳朋游絲書飲中八仙歌帖贊','岳珂','宋','宋诗','song-poetry','','[]','天絲兮舞空，春光兮怡融。',64,'全唐诗/poet.song.194000.json','["天絲兮舞空，春光兮怡融。", "杲麗日兮柔風，想八仙兮飲中。", "倒景兮騎虹，落紙兮游龍。", "俱上下兮西東，笑春歸兮無蹤。", "墨皇兮化工，留玩兮何窮。"]'),
('af1a3bc2-8522-435b-80e7-a9319328d83b','趙忠簡送春詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','陶陶孟春，草木莽只。',251,'全唐诗/poet.song.194000.json','["陶陶孟春，草木莽只。", "白日昭昭，照下土只。", "瘴烟浩淫，雜海霧只。", "憔悴行吟，閴島嶼只。", "公乎歸徠，無嫪此詩句只。", "黎母之居，家炎陬只。", "崒嵂盤鬰，蔽雲浮只。", "蝮虺鰅鱅，蜒僻幽只。", "人跡闃絕，魑魅仇只。", "公乎歸徠，空山不可以久游只。", "鳴鳶跕跕，墮滄溟只。", "蛟蜃噀雨，晝冥冥只。", "折肱見沫，瞻斗星只。", "夕照黄濁，波濤腥只。", "公乎歸徠，落景不可以久停只。", "茅葦叢薄，桃李囚只。", "韶容駘蕩，異中州只。", "陽龢弗舒，金石流只。", "短狐秘蜮，起蟄坏只。", "公乎歸徠，春不可留只。", "卉服椎髻，駢蜓艕只。", "咿嚘啁哳，言莫諒只。", "烹蛇茹蠱，食且恙只。", "眇其愁予，雖迥曠只。"]'),
('4f271736-1326-4cba-adda-48618da5d199','范元長觀梅詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','范本蜀望，世仍忠嘉。',210,'全唐诗/poet.song.194000.json','["范本蜀望，世仍忠嘉。", "南渡而來，人門莫加。", "帝咨典型，詔起幽遐。", "翊媺銅龍，執經金華。", "筆取端重，而兼奇葩。", "儒先所推，奚待詡夸。", "有偉豐公，如璧不瑕。", "卷懷樞庭，寓賞梅花。", "公從北方，共之天涯。", "均德比誼，而兼葭莩。", "寒谷將春，輕陰不遮。", "潔樽斯從，寄驛匪賒。", "倡汝和予，屏淫斥哇。", "託彼陰晴，以寫正邪。", "愛君之心，對越靡差。", "一瞬百年，遺墨驚鴉。", "臭兮同蘭，好兮投瓜。", "二公其仙，星箕漢槎。", "如此帖者，可復得耶。", "清並玉雪，秀同綺霞。", "矢辭以藏，庸識名家。"]'),
('93cceb22-14d2-47bd-a905-dbf0beacf834','陳參政簡易帖贊','岳珂','宋','宋诗','song-poetry','','[]','眼底中興日月，手中建筆虹霓。',28,'全唐诗/poet.song.194000.json','["眼底中興日月，手中建筆虹霓。", "造化功成秋兔，先生原有新詩。"]'),
('12abb524-8bd1-45bc-a217-4feb6d79b03d','張忠獻時義誠力二帖贊','岳珂','宋','宋诗','song-poetry','','[]','至誠動天，中貫三極。',200,'全唐诗/poet.song.194000.json','["至誠動天，中貫三極。", "堂堂南陽，繼以魏國。", "山嶽鼎震，江河釜溢。", "群生失寧，乃見人傑。", "大義既信，人紀復植。", "于晦冥中，揭以日月。", "操固漢賊，敵禍宋祏。", "萬段之磔，吾耻未滌。", "不共戴履，矧肯屈膝。", "祁山屢却，淮隴迭出。", "非不拙沮，之死靡易。", "我觀史冊，二公與匹。", "功雖不同，心則如一。", "隆興至今，耳目尚及。", "遺墨之寶，已若尺璧。", "造次皆忠，言猶未泐。", "天維可絕，地軸可折。", "公心之磨，此理則熄。", "兩朝開濟，萬古闔闢。", "繫此詩之，以媲廟柏。"]'),
('bdce08cd-dfd1-4f8d-a860-92f3532b332d','李莊簡三字帖贊','岳珂','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','秦禍滔天，鯨洶九淵。',84,'全唐诗/poet.song.194000.json','["秦禍滔天，鯨洶九淵。", "淪胥以顛，而我謂不然。", "如公之賢，泰山巋然。", "奔流百川，何傷乎一卷。", "野史所編，人心之傳。", "匪石則遷，誰爲之燎原。", "兩家之先，義比仲連。", "覽此卷焉，不知其涕漣。"]'),
('f20d7c96-5188-40b8-a65c-986e5b197d3d','王敏節歡喜帖贊','岳珂','宋','宋诗','song-poetry','','[]','秦火燎原，衣冠塗炭。',40,'全唐诗/poet.song.194000.json','["秦火燎原，衣冠塗炭。", "繞指之柔，出乎百鍛。", "如公之剛，猶死憂患。", "時歟命歟，一覽三歎。"]'),
('af08b20f-74e5-451e-b029-fa704118b893','翟忠惠秋杪帖贊','岳珂','宋','宋诗','song-poetry','','[]','態跌宕而奇偉，姿高明而通詭。',29,'全唐诗/poet.song.194000.json','["態跌宕而奇偉，姿高明而通詭。", "此書得于其里，茲可想見其人矣。"]'),
('650d462d-3418-42f7-8cef-9f6f3f2150cc','折樞密子友帖贊','岳珂','宋','宋诗','song-poetry','','[]','陝服之俗重于義。',49,'全唐诗/poet.song.194000.json','["陝服之俗重于義。", "公家府谷，殆且百世，予不能知子友之兄弟。", "爲謀而如己，交情之不替，亦足以見前修之志。"]'),
('a678a12b-e9d9-47c2-9341-c3d99324a9c7','孫參政知命帖贊','岳珂','宋','宋诗','song-poetry','','[]','古稱君相不言命。',37,'全唐诗/poet.song.194000.json','["古稱君相不言命。", "執國大政，而猶拳拳于富貴功名之競。", "其言雖獨應，予猶以爲病。"]'),
('51482717-7392-4438-9448-f5b36fe40f30','何恭敏料理帖贊','岳珂','宋','宋诗','song-poetry','','[]','虐焰熏天，而公以勺水欲救其燎原。',66,'全唐诗/poet.song.194000.json','["虐焰熏天，而公以勺水欲救其燎原。", "觀公之帖，雖久別之一見，亦將以歸之時數之自然。", "胸中所處者素定，宜其敢于攖豺虺之鋒，而吐天下之公言也。"]'),
('a12a31ef-505b-4d85-a125-832f86dcca23','張章簡康寧帖贊','岳珂','宋','宋诗','song-poetry','','[]','予官京口，前後十年，接公之枌榆兮。',65,'全唐诗/poet.song.194000.json','["予官京口，前後十年，接公之枌榆兮。", "讀耆舊傳，慨想其人，莫覿其居兮。", "維帖之得，題標失真，幾以迷其初兮。", "覺民跋證莫近斯，于以識公書兮。"]'),
('3bc6ceeb-a08c-4574-aa40-48da218c06a3','趙德麟召還詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','昔東晉王茂弘諸人，登新亭，望長淮，自謂風景不殊，舉目有山河之異。',163,'全唐诗/poet.song.194000.json','["昔東晉王茂弘諸人，登新亭，望長淮，自謂風景不殊，舉目有山河之異。", "至今想之，猶鬰乎其有餘哀。", "矧預瑶牒，登玉階，而寄宗國之懷者耶。", "王業偏安于海瀕，故都久棄于蒿萊。", "主議者方貪天之功，而肆其雄猜。", "朝士沉空，不復向來。", "率兆乎滔天之讒，而迄乎和議之開。", "此有志者所以歎于嗟之麟，而思當道之豺也。", "嗚呼，鍾簴百年，邊塵尚霾。", "悠悠蒼天，彼何人哉。"]'),
('a9c7d63f-d1e8-4a3c-8ac0-8d5ab3179c6d','周少隠留春詞帖贊','岳珂','宋','宋诗','song-poetry','','[]','絃管之流聲，景物之感情。',73,'全唐诗/poet.song.194000.json','["絃管之流聲，景物之感情。", "激徵含商，舒華發英。", "固所以合融怡于自然，而惜流轉之不停。", "亦猶夫見穿花之蛺蝶，賦點水之蜻蜓。", "思盡醉于風光，而典春衣于杜陵也。"]'),
('99c91d89-76d0-479b-9cd2-7b5779a64a21','張文忠奉告晴快二帖贊','岳珂','宋','宋诗','song-poetry','','[]','上嗣服之初載，首以忠之一字，褒顯邦之臣二人。',96,'全唐诗/poet.song.194000.json','["上嗣服之初載，首以忠之一字，褒顯邦之臣二人。", "亦既表百年之宗儒，遂復開千社之舊勳。", "嗚呼，英衛善用兵，房杜濟以文。", "惜先生之位弗克究，故先世之志亦終莫之伸也。", "遺帖之存，手墨如新。", "我藏孔宜，對于褒綸。"]'),
('abd8d1f2-c975-4d57-aead-82081bf154f9','米玄暉書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','父子而善書，自羲獻而始也。',85,'全唐诗/poet.song.194000.json','["父子而善書，自羲獻而始也。", "寥寥千載，固已莫之擬也。", "至于我朝，有楚國之羋也。", "不隕其名，雖未濟厥美也。", "其讀父書，亦非括之比也。", "瞠乎望洋，混混猶此水也。", "此帖之觀，尚可見其體也。"]'),
('5be24d3f-d534-4424-b668-fcb30cbc8cad','米玄暉秀軒詩帖','岳珂','宋','宋诗','song-poetry','','[]','山氣之微明，湖光之清浚。',61,'全唐诗/poet.song.194000.json','["山氣之微明，湖光之清浚。", "軒中之人秀而隠，予固未之論。", "獨是一篇之題，自是于古無所與遜。", "知益知損，予意猶有儷乎孔門爲國之哂也。"]'),
('27e7b39b-db5e-40aa-9d24-9a32050f6102','米玄暉陽春詞帖贊','岳珂','宋','宋诗','song-poetry','','[]','予家有山林集，觀寶晉自製之詞，每不逮乎平日之文。',119,'全唐诗/poet.song.194000.json','["予家有山林集，觀寶晉自製之詞，每不逮乎平日之文。", "豈句律之未工，疑用志之或分。", "偉筆力之扛鼎，得過庭之異聞。", "陶冶性情，自爲陽春。", "既寓意于館甥，亦秘笈而自珍。", "予嘗商略函書，彷彿梁塵，規矩合作，勺簫奪倫。", "竊以爲夫君金縷之衣，亦未足以換墨練之裙也。"]'),
('b814eeb0-7e21-4ce3-b6e3-3f8cde0a8133','潘子賤改月帖贊','岳珂','宋','宋诗','song-poetry','','[]','公立柱下，直聲凜如。',40,'全唐诗/poet.song.194000.json','["公立柱下，直聲凜如。", "氣則不餒，而况于書。", "待人以情，真意浹洽。", "于嗟前修，動則可法。"]'),
('c7856cb1-539d-4ded-bdb6-65c3ede0518d','胡已茂鶚章帖贊','岳珂','宋','宋诗','song-poetry','','[]','矰繳之冥鴻，人心所同。',46,'全唐诗/poet.song.194000.json','["矰繳之冥鴻，人心所同。", "是內舉者何足以害其公。", "世道之趨，或汙或隆。", "此帖之存，所以愧今日之憧憧。"]'),
('ad33ad9e-e9d9-46e4-8089-4e66af540442','向伯恭旁午帖贊','岳珂','宋','宋诗','song-poetry','','[]','塗水漣漪未改，薌林風月如新。',28,'全唐诗/poet.song.194000.json','["塗水漣漪未改，薌林風月如新。", "一紙重觀遺蹟，百年無復斯人。"]'),
('5a0c48a1-37aa-446d-be6f-6e45ef512952','劉彥修江岸帖贊','岳珂','宋','宋诗','song-poetry','','[]','其忠足以繼忠顯，其教足以傳西樞。',46,'全唐诗/poet.song.194000.json','["其忠足以繼忠顯，其教足以傳西樞。", "其略足以佐魏公，其識足以知二吳。", "於虖，斯亦足以列寶真之儲矣。"]'),
('f856d55d-2326-4633-b244-f42bf8865124','梁仲謀去月帖贊','岳珂','宋','宋诗','song-poetry','','[]','當邊境之多虞，士君子出而備馳驅，見于盈咫之書。',90,'全唐诗/poet.song.194000.json','["當邊境之多虞，士君子出而備馳驅，見于盈咫之書。", "觀其六鑾之行，雖擇日亦不可以少須，其時爲何如。", "燀燀出車，投袂以趨。", "毋寧以家而忘此匈奴，豈其私是圖。", "此敵愾之士，必即是以察忠臣之區區也。"]'),
('bc850991-b06c-4663-a309-b05af374ec63','魏邦達聖訓帖贊','岳珂','宋','宋诗','song-poetry','','[]','意有不可，束带之立弗與也。',75,'全唐诗/poet.song.194000.json','["意有不可，束带之立弗與也。", "事所當盡，杭葦之急弗顧也。", "詩不云乎，駪駪征夫，每懷靡及。", "覽此遺墨，斯足以觀君子之于役，而考古義于原隰矣。", "再拜什襲，噫吾何執。"]'),
('0d8756a2-5c29-4b1a-841b-859d2b1c5706','汪彥章譽望求賢薦書三帖贊','岳珂','宋','宋诗','song-poetry','','[]','納交以道，不殊乎丘園。',86,'全唐诗/poet.song.194000.json','["納交以道，不殊乎丘園。", "觀政以人，歎息于求賢。", "言情以真，無事乎脅肩。", "此前輩之流風，今不復見者幾百年矣。", "使覽者跫然曰：古道之存，存乎尺箋，盍思乎勉旃。", "則如寶真者，亦將預有榮焉。"]'),
('7df73d27-f679-45a6-89df-ee1e1abe4254','朱文靖報稱帖贊','岳珂','宋','宋诗','song-poetry','','[]','勁而柔，端而遒。',32,'全唐诗/poet.song.194000.json','["勁而柔，端而遒。", "奔八驥，回九牛。", "功玉鉉，名金甌。", "藏此書，識前修。"]'),
('231e7935-bb29-46a3-97a9-11765d41f031','劉無言餉茶帖贊','岳珂','宋','宋诗','song-poetry','','[]','筆勢之偉，筆意之詣，筆法之粹，是三者固足以名家而無愧矣。',75,'全唐诗/poet.song.194000.json','["筆勢之偉，筆意之詣，筆法之粹，是三者固足以名家而無愧矣。", "於虖，祐陵天縱八體，公蒙識拔，獨在初歲，亦宜有此具美也。", "寶此幅紙，以見太平之游藝，惟秘閣是視。"]'),
('5eff1aac-9e6f-4e22-8fe9-9dc8a378c1ca','劉無言輞川詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','輞川之勝，新詩之詠，所以適性也。',54,'全唐诗/poet.song.194000.json','["輞川之勝，新詩之詠，所以適性也。", "繭紙之瑩，筆力之勁，所以寫興也。", "維詩與筆，景物交映也。", "並于唐圖，于是爲稱也。"]'),
('a0482d7b-aa11-4cc9-83c5-100b3088c020','呂居仁瞻仰收召二帖贊','岳珂','宋','宋诗','song-poetry','','[]','呂氏一門，我朝韋平。',240,'全唐诗/poet.song.194000.json','["呂氏一門，我朝韋平。", "衣冠既南，孰爲典型。", "猗歟北扉，翰墨騰英。", "難進之風，藹于心聲。", "其進維何，風雷隠砰。", "賤霸尊王，萬古作程。", "天將開之，以豁聵盲。", "孰遏其萌，維盜實憎。", "觀公初心，何止懲羹。", "親朋斯升，方喜彙征。", "私書之詒，猶欲却行。", "豈願空言，與乳臭爭。", "道之將宏，非人所能。", "俯首事讎，衆方若酲。", "詎知禍胎，自漢公卿。", "淪胥一談，大呂爲輕。", "綸音一頒，四海竦聆。", "臧宮鳴劍，賈誼請纓。", "書下奉天，已識中興。", "曲筆誰歟，反肆譏評。", "陰險何知，雲收霧明。", "公帖初獲，我心未寧。", "謂彼噂沓，臆度以情。", "是或鼠腐，猶疑鴻冥。"]'),
('44e5b3de-9745-4f78-950a-e9be8371e945','李商老酬答詩帖','岳珂','宋','宋诗','song-poetry','','[]','九派之沕潏，注于溟渤，寓此詩筆。',47,'全唐诗/poet.song.194000.json','["九派之沕潏，注于溟渤，寓此詩筆。", "烟霞之痼疾，園涉以日，紓寫盤鬰。", "予于西江，搜抉遺軼，備體之一。"]'),
('8b4b8a14-6bfe-4f24-90f3-be721a1b1fb8','陳文正黄庭帖贊','岳珂','宋','宋诗','song-poetry','','[]','隆興聖主臨盛朝，元臣堂堂冠蟬貂。',128,'全唐诗/poet.song.194000.json','["隆興聖主臨盛朝，元臣堂堂冠蟬貂。", "鎮撫百度服天驕，九鼎安固屹莫摇。", "凜然遺墨松後凋，美錦不裼璞不雕。", "百年攸熺均童妖，惜我喬木屈艾蕭。", "圍棋賭墅意自消，後來偉蹟何岧嶢。", "我來郿塢鳥焚巢，乃見拱璧污脂膋。", "卷藏再拜刻琰瑶，百花藩溷隨飄飄。", "願續洛譜從午橋，不問處所知春饒。"]'),
('30f89775-8b31-48f3-b68e-b76e7d8c1d5b','史忠定蚤作帖贊','岳珂','宋','宋诗','song-poetry','','[]','危微精一，傳之在心。',240,'全唐诗/poet.song.194000.json','["危微精一，傳之在心。", "二典勳華，光于有臨。", "大原自天，端倪孰尋。", "豈無疇咨，培高浚深。", "寢明以昌，舉元難壬。", "烝哉明良，嗣此德音。", "匪鑑而諷，匪鑑而箴。", "啟迪在初，有開宸襟。", "巖廊南風，袗衣鼓琴。", "淵躍籋雲，匣鉶發鐔。", "達其已充，澤彼蒼黔。", "王度之恢，如玉如金。", "進而虞淵，賓暘發霠。", "坱圠機衡，開闔陽陰。", "九韶其諧，萬奏皆瘖。", "退而卷懷，藝圃書林。", "出入歐顔，而加𣂏斟。", "湛湛秋江，岧岧春岑。", "如彼德人，危冠整簪。", "不伐不矜，森嚴深沉。", "我考問學，惟心靡諶。", "端平自我，何用弗欽。", "重抵九鼎，價踰萬琛。", "惟帖可觀，爲世砭鍼。"]'),
('b6ffbf43-12b5-4001-b5cd-91e36593a8b9','洪文惠盍簪帖贊','岳珂','宋','宋诗','song-poetry','','[]','公作隸古，與先漢侔。',100,'全唐诗/poet.song.194000.json','["公作隸古，與先漢侔。", "發爲書翰，順塗挾輈。", "公相孝宗，曾不少留。", "歸安一丘，始終休休。", "我護淮餉，祖公前修。", "登華信亭，步得江樓。", "摩挲石題，瞻睇銀鈎。", "風靜鵲巢，月明沙鷗。", "意公其來，偕造物游。", "蹟則不磨，心兮焉求。"]'),
('b3be92eb-29e3-4dc9-be71-0024ca34f3f2','蔣丞相得男帖贊','岳珂','宋','宋诗','song-poetry','','[]','仕遭時，相真主。',32,'全唐诗/poet.song.194000.json','["仕遭時，相真主。", "材之充，澤斯普。", "以端逸，御妍嫵。", "諒予言，法當取。"]'),
('6f5c8ddc-8db3-49cc-8c63-307a9927ea4f','虞忠肅萬里帖贊','岳珂','宋','宋诗','song-poetry','','[]','方長鯨之干誅，駭百川之騰浪。',330,'全唐诗/poet.song.194000.json','["方長鯨之干誅，駭百川之騰浪。", "撼坤軸其欲裂，有雍公之忠壯。", "策數船之奇勳，射天狼于北向。", "既旄頭之夜殞，窘紛披而投仗。", "歎微管其左衽，曾垂褒于素王。", "凜百年而若存，耿英氣于江上。", "攬遺帖以在手，並風雲而獻壯。", "斂胸中之倔奇，爲筆下之豪放。", "念舊交于漕輓，寓執訊之還往。", "慨寶傳之至今，猶足慰夫馳想。", "予嘗考史牒之終始，論餘功于翼亮。", "觀其位上宰以秉成，猶未忘大義之獨唱。", "謂取秦而下燕，可拊背而扼吭。", "軒墀靡慕于金鉉，節斧乃頒于玉帳。", "當王業溺于積安之久，而人心頓有振起之望。", "迨時數之未偶，墜妖星于五丈。", "故議者不見于異時之所就，而得以寘疑于當日之自將。", "何鴆毒之難瘳，本亡秦之蠱喪。", "嗟群情習見于苟且，宜隻手莫支于締創。", "予所以抱遺槧于五紀，悼成心于一相。", "既什襲以致其尊慕，又三歎而繼之惆悵也。"]'),
('c428a7fd-7896-4238-a129-5e33de10ad3a','曾丞相臨平帖贊','岳珂','宋','宋诗','song-poetry','','[]','書尺之作趨簡便，情之所託斯可見。',64,'全唐诗/poet.song.194000.json','["書尺之作趨簡便，情之所託斯可見。", "志雖少貶言猶婉，體雖少拙敬猶簡。", "堂堂相國緇衣彥，明哲自將亦通願。", "竦然述贊覽遺卷，我欲以之參世變。"]'),
('c2596021-accd-4ee3-981b-2f1840e937bb','張安國書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','漢輕法言，耳目所忽。',40,'全唐诗/poet.song.194000.json','["漢輕法言，耳目所忽。", "予藏于湖，亦近世物。", "氣並華劍，烈同段笏。", "匪尚其容，亦尚其骨。"]'),
('bff7c1e0-410f-4106-905f-5cb9c7d8fd77','張安國寫坡詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','玉妃粲粲怯詩瘦，秦艷蘇腴略先後。',32,'全唐诗/poet.song.194000.json','["玉妃粲粲怯詩瘦，秦艷蘇腴略先後。", "于湖筆力並奇秀，手執遺篇欲三嗅。"]'),
('a43cfce0-cde5-4261-93b0-b82ba165ebbd','張安國東坡三養帖贊','岳珂','宋','宋诗','song-poetry','','[]','在易之頤，飲食以節。',100,'全唐诗/poet.song.194000.json','["在易之頤，飲食以節。", "推而廣之，有是三說。", "蒸壺發羃，衰髮滿幘。", "機赤乳白，未死神泣。", "萬金之璧，護一蟻缺。", "彼過分者，于我何得。", "昔傳者詩，今見者帖。", "昔以事戒，今以理悅。", "吁嗟先生，何學非易。", "稱此翰墨，是謂知德。"]'),
('fb46bf37-57f2-49d7-a1d1-90517cef9822','陳正獻權攝帖贊','岳珂','宋','宋诗','song-poetry','','[]','英宰翼天縡，治象開淳熙。',48,'全唐诗/poet.song.194000.json','["英宰翼天縡，治象開淳熙。", "雖云簡牘間，已具梁棟資。", "瀛海渺且清，壺山秀而滋。", "膚寸起膏澤，筆意儻可知。"]'),
('dbc7e4b2-804f-4f9e-b71a-5f0cfaa950f5','梁文靖南安漳巖泉福三帖贊','岳珂','宋','宋诗','song-poetry','','[]','詞真意浹，不屈不狎，端重有法。',41,'全唐诗/poet.song.194000.json','["詞真意浹，不屈不狎，端重有法。", "此近世名臣之帖。", "承平流風，尚或可接，予欲以此觀相業。"]'),
('e69f2db4-fd97-4dd0-9aa4-25a64ff3aa4a','范參政行臺兩司常州成都四帖贊','岳珂','宋','宋诗','song-poetry','','[]','縱之而矩不逾，歛之而鋒無餘。',65,'全唐诗/poet.song.194000.json','["縱之而矩不逾，歛之而鋒無餘。", "實藴而華敷，雲爛而霞舒。", "雖曰近世之書，亦足以爲軒几之娛。", "久而信，信而傳，其殆留而爲後世之須。", "噫嚱石湖。"]'),
('d8c5614a-b83b-41e8-928b-a8919acf6251','范參政書懷詩帖贊','岳珂','宋','宋诗','song-poetry','','[]','當平世而概想齋壇之國士，因送客而遂及陽關之舊知。',70,'全唐诗/poet.song.194000.json','["當平世而概想齋壇之國士，因送客而遂及陽關之舊知。", "蓋拊髀之思，在上弗替。", "故淳熙之士夫，亦不敢一日而忘可將之奇。", "斯帖之傳，固未易例以近世之詩也。"]'),
('b2f05686-0a73-4b63-b91c-3241966a2d0b','王文定省中要津二帖贊','岳珂','宋','宋诗','song-poetry','','[]','謹嚴而穩愜，一筆之涉，足寓心法。',50,'全唐诗/poet.song.194000.json','["謹嚴而穩愜，一筆之涉，足寓心法。", "淳熙之相業，動守檢押。", "耳目猶接，列于書籍，百體不乏。", "是曰王魯公之帖。"]'),
('a56360d5-9184-42f2-83c7-d227745244ec','周文忠寶眷帖贊','岳珂','宋','宋诗','song-poetry','','[]','廬陵之文忠，前歐而後周。',73,'全唐诗/poet.song.194000.json','["廬陵之文忠，前歐而後周。", "筆法之可稽，歐勁而周柔。", "苟內心之是似，豈外蹟之能求。", "予嘗遡平原之津，望二典之樓。", "想公從容子墨客卿間，猶足以接六一之風流也。"]'),
('022e26ef-aeb4-4d3a-95ce-600373b629ae','張宣公書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','紫巖之傳，原委一忠。',140,'全唐诗/poet.song.194000.json','["紫巖之傳，原委一忠。", "遡而伊濂，根本一中。", "事君致身，其用則同。", "自我淑人，派于五峰。", "力久積真，至公而充。", "淳熙之間，天下爲公。", "守道彬彬，洙泗之風。", "公于是時，不下禹功。", "據德游藝，言立志通。", "故其遺書，筆意俱工。", "我得而藏，敢忘所宗。", "淵淵其心，皜皜其容。", "學冠穹壤，名儕岱嵩。", "萬世仰之，曰人中龍。"]'),
('f28329bf-9b61-4844-b9e8-6f7decdb9ffd','陸文安書稿泛舟二帖贊','岳珂','宋','宋诗','song-poetry','','[]','自吾道之既南，閩浙湘潭，鼎立而三。',119,'全唐诗/poet.song.194000.json','["自吾道之既南，閩浙湘潭，鼎立而三。", "聖塗康莊，先生蓋與之揚鑣而並驂矣。", "觀其家人唯諾之際，惟理義是探，惟人物是耽，惟世道是參。", "公取飽諳，包羅渾涵，舍是弗譚。", "其亦如夫任重道遠，必求其所謂合人己而無慚者耶。", "璧瑴珠駢，有此尺函。", "式嚴厥藏，勿蠹勿蟫。"]'),
('b182017c-e509-4133-8858-4033d1268f79','呂成公寬平通鑑佚老三帖贊','岳珂','宋','宋诗','song-poetry','','[]','治粹于隆古，元凱之懿，根于篤誠。',317,'全唐诗/poet.song.194000.json','["治粹于隆古，元凱之懿，根于篤誠。", "世澤未傾，英髦代興。", "非不卓犖，絕乎逕庭。", "而斯道之正，獨未有以韋平之家，而繼孟荀之鳴者。", "豈天心之昌我朝，固得其人而後行耶。", "儒服獨立，出于簪纓。", "百聖微言，闡我金籝。", "使萬世而下，洙泗有所繫，伊濂有所承。", "正傳未墜而迄續，絕學將晦而復明。", "所謂派徐歷許，沿申遡榮。", "簣覆基峙，源澄流清。", "殆匪一日之積，偶然而生。", "至于道以身立，忠以死爭。", "斡泰否之機，開剝復之萌。", "其昆弟剛毅之操，家庭講貫之精，又何其集義之不餒，而爲人之難能也。", "我讀五帖，言言典型。", "文史潘吳，詩書邵程。", "望群賢于忠讜，驗本體于寬平。", "則雖小而見諸簡牘之接物，亦奚以異于塤箎之同聲。", "晻若前陳，如龜之明。", "仁遠德輶，欲舉曷勝。", "於戲二難，古誰與京。", "倡與和與，展也其成。"]'),
('dab4f5cd-ec1d-4c6c-853d-5da4ad1e1699','范元卿中秋詞帖贊','岳珂','宋','宋诗','song-poetry','','[]','猗望舒，盛三五。',32,'全唐诗/poet.song.194000.json','["猗望舒，盛三五。", "光璇儀，韵金縷。", "偉健筆，作奇語。", "誰知音，傳樂府。"]'),
('653d2b77-e458-47eb-992e-fa82b165ac45','葛文定關外帖贊','岳珂','宋','宋诗','song-poetry','','[]','以文籙傳家，以相業濟時。',48,'全唐诗/poet.song.194000.json','["以文籙傳家，以相業濟時。", "貂冠絳裳，予猶及見其丰儀。", "簡牘所傳，是以爲近世之奇。", "一瞬卅年，贊而藏之。"]'),
('4bf15e53-7c1b-42f9-bf8a-9f843d7e1f6a','朱文公離騷經贊','岳珂','宋','宋诗','song-poetry','','[]','偉茲帖之奇瑰兮，羌筆力之有神。',318,'全唐诗/poet.song.194000.json','["偉茲帖之奇瑰兮，羌筆力之有神。", "走緘縢之來詔兮，並垂棘而足珍。", "從鯉庭而載求兮，得陳亢之異聞。", "書三閭之孤忠兮，將爭光兮儀鄰。", "予嘗竊寘疑兮，謂意或有在也。", "方淳熙之繼明兮，德如天其大也。", "挈道統而在上兮，固無嫉邪之害也。", "先生之溯伊濂兮，又非沅湘之派也。", "寓物以寫興兮，自前世以固然。", "豈先生之適正兮，乃獨取于沉淵。", "行或過乎中庸兮，雖爲法而不可。", "其忠君愛國之誠兮，亦不虞乎後日之禍。", "彼不學兮，周公仲尼。", "知莊士與醇儒兮，或羞稱之。", "律風雅之末流兮，若未免于或變。", "使交有所發兮，亦足以迪天性民彝之善。", "以今日之書兮，固非出于感時。", "則異時之集注兮，亦何病乎俗人之悕。", "原屈原之心兮，宗國之楚。", "作春秋兮，固安在乎黜周而王魯。", "先儒之心兮，百聖之矩。", "藏此帖兮，昭于今古。"]'),
('64158039-ecd4-442c-a9b6-6e6006c427f7','朱文公儲議帖贊','岳珂','宋','宋诗','song-poetry','','[]','道統之傳，洙泗濂伊。',145,'全唐诗/poet.song.194000.json','["道統之傳，洙泗濂伊。", "公于淳熙，萬古一時。", "言名之輿，世泯其轍。", "皎皎綱常，首載先烈。", "粵古大臣，以國爲身。", "浚源培根，茲爲愛君。", "總干徂征，拜疏輒發。", "外寧內憂，間不容髮。", "復讎大義，不振不隨。", "易安于危，本則先之。", "先王之忠，與萊公對。", "讒夫孔多，百欽若輩。", "彼姑息者，大義一毛。", "謂我徒勞，群吠以嘈。", "事是蹟訛。"]'),
('b8ab815f-4d4c-42c7-b05e-fb592ab32786','趙忠定濠梁帖贊','岳珂','宋','宋诗','song-poetry','','[]','真宰之出，維天降才。',240,'全唐诗/poet.song.194000.json','["真宰之出，維天降才。", "既玉于成，勳名九垓。", "山川出雲，時雨必至。", "道之將行，公揭魁瑞。", "問學已正，淵源已充。", "險夷一塗，奚有于躬。", "紹熙季年，國勢𣕕杌。", "手扶重輪，公爲時出。", "屹若九鼎，不震不摇。", "公秉國成，端委以朝。", "拔茅斯征，苞桑斯戒。", "匪兕之時，乘否于泰。", "有棐至誠，雲開于衡。", "顧不能排，噂𠴲背憎。", "公能者天，豈曰臧氏。", "汗青萬年，則有公議。", "我昔齔齒，拜公江干。", "公顧而奇，信乎庭蘭。", "三十八年，始得遺帖。", "憂邊謹微，抑寓相業。", "字端而莊，德謙而光。", "于閒暇時，憲型四方。", "書藏在奩，百世如對。", "尚想公儀，灑掃進退。"]'),
('a531c980-6c3f-44ad-82c6-066900f253d1','余忠肅典贍益辨二帖贊','岳珂','宋','宋诗','song-poetry','','[]','珥貂佩玉之舒徐兮。',37,'全唐诗/poet.song.194000.json','["珥貂佩玉之舒徐兮。", "引筆行墨之豐腴兮。", "閲世論人以其書兮。", "尚可以想慶元之初兮。"]'),
('10673d57-047d-4be0-ab2a-8db695594ceb','鄂忠武王出師疏帖贊','岳珂','宋','宋诗','song-poetry','','[]','於惟紹興，扶危支傾。',225,'全唐诗/poet.song.194000.json','["於惟紹興，扶危支傾。", "揠校涖戎，不識一丁。", "先王奮呼，起自諸生。", "經通誼明，筆妙墨精。", "翠微之詩，五嶽之盟。", "祁陽整旅，東松紀行。", "蹟徧九州，氣凌三精。", "粵時出師，首茲抗旌。", "規模弗愆，忠憤莫攖。", "上心載嘉，奎章式形。", "謂朕何憂，惟爾責成。", "以百萬師，觀我甲兵。", "僅四十里，復我舊京。", "日郤陽侯，星隕中營。", "萇血遂碧，狐史漫青。", "天不誘衷，曷其底寧。", "傷哉離騷，坐此修能，冰鏤芷馨。", "惟帝鑒忠，惟人與誠。", "烈並褒鄂，志恢幽并。", "有奕龍跡，遹昭駿聲。", "遺墨既刊，大猷是經。", "對于廟祧，豈惟雲仍。"]'),
('f3a38cb4-7a1d-4b89-a42a-ef39ca099494','鄂忠武王書簡帖贊','岳珂','宋','宋诗','song-poetry','','[]','昔李西平之在鳳翔，嘗以直道致主。',151,'全唐诗/poet.song.194000.json','["昔李西平之在鳳翔，嘗以直道致主。", "慕魏鄭公，雖叔度之進言，猶毅然而不從。", "謂幸備于將相，詎愛身而苟容。", "猗歟先王，亦師文忠。", "凡引筆而行墨，皆刻志而比蹤。", "今觀碑刻之在天下，雖小大真行之異工，視此帖之所傳，蓋不約而皆同。", "然則有犯無隠，挺焉直躬。", "唾當道之豺狼，嬰九淵之神龍。", "蓋當心摹手追之時，已有之死不顧之遺風矣。"]'),
('6e102c54-8e0b-444e-bd89-813bbffce94d','銀青制劄帖贊','岳珂','宋','宋诗','song-poetry','','[]','先王筆法源于蘇，奕然世體繇庭趨。',64,'全唐诗/poet.song.194000.json','["先王筆法源于蘇，奕然世體繇庭趨。", "奩中手澤他豈無，義與事比當特書。", "巨編剪取刪繁蕪，盛心端可傳遺孤。", "百年小楷照乘珠，爲問汗青誰董狐。"]'),
('da161f68-ffa6-4261-a797-3e7c33984088','銀青清白頌語贊','岳珂','宋','宋诗','song-poetry','','[]','嗚呼死生，如一旦暮。',71,'全唐诗/poet.song.194000.json','["嗚呼死生，如一旦暮。", "達觀其大，等視來去。", "如古之聖賢，所謂曳杖山木之歌，啟手淵冰之語，其皆超然知所處矣。", "手澤之存，慨其孺慕。", "贊詩不文，以配陟岵。"]'),
('01092e42-2e4d-435c-87c4-dea706d7d944','大寧夫人二書贊','岳珂','宋','宋诗','song-poetry','','[]','釋老之異，佞者惟酷喜，排者惟疾觝。',87,'全唐诗/poet.song.194000.json','["釋老之異，佞者惟酷喜，排者惟疾觝。", "死生之大，達者晦其理，昧者尚其詭。", "喪祭之正，徇古者失于泥，行今者溺于鄙。", "如遺訓者，亦可以守而勿墜矣。", "我懷緒言，杯棬之比。", "子孫傳家，真蹟在此。"]'),
('3731c2b0-9a3e-456c-b949-8f5e2d106618','吏部二詞帖贊','岳珂','宋','宋诗','song-poetry','','[]','薛在近世，意莊體葩。',40,'全唐诗/poet.song.194000.json','["薛在近世，意莊體葩。", "倣而肖耶，偶其好耶。", "筆動聖鑒，藝兼詞華。", "繫詩而藏，維以傳家。"]'),
('815ec474-3ae6-4e33-8418-2d9fb4ac1777','經進百韻詩','岳珂','宋','宋诗','song-poetry','','[]','永祐當臨御，重熙極泰亨。',288,'全唐诗/poet.song.194000.json','["永祐當臨御，重熙極泰亨。", "物窮隍土復，地大蘗牙萌。", "蕞爾瀛懦國，違吾海上盟。", "烽烟昏九土，氛霧塞三精。", "於赫中興主，初專九伯征。", "赤符觀炳炳，嘉兆得庚庚。", "四七膺休運，三千協一誠。", "乾坤恢闢闔，日月洗明清。", "天授睢壇筴，風興渭水英。", "維時臣大父，摇迹聖廛氓。", "寶匣鳴長劍，雄冠彯曼纓。", "衣裘供羿射，燈火近韓檠。", "聖世方求駿，明神豈舍騂。", "始從魚鑰守，小㭊羽林兵。", "嘗敵無車乘，麾軍不鼓鉦。", "熏門摧彥政，汜水從閭勍。", "馹召班龍節，犀軍下雀桁。", "王師俱蓄縮，游騎愈縱橫。", "馬渡朝迎敵，鍾山夜駐營。", "狂瀾身砥柱，大厦手支撐。", "敵焰猶繁熾，吳都忽震驚。", "東巡傳警蹕，右袒半公卿。", "憤起宜興旅，追收建業城。", "大江誰飲馬，五嶽更刑牲。"]'),
('942b8069-ab81-4829-be94-309c1248b664','玉蕊花','岳珂','宋','宋诗','song-poetry','','[]','路入平山萬木清，松蘿薈蔚接烟甍。',64,'全唐诗/poet.song.194000.json','["路入平山萬木清，松蘿薈蔚接烟甍。", "鹿跑泉眼涵秋影，雁带雲容度晚晴。", "花徑有時傳相國，蘚碑無字紀昭明。", "六朝金粉今何處，贏得十年蕙帳名。"]'),
('b37d87b0-d18d-490d-9c4f-35495dedf287','布袋和尚頌','岳珂','宋','宋诗','song-poetry','','[]','行也布袋，坐也布袋。',20,'全唐诗/poet.song.194000.json','["行也布袋，坐也布袋。", "放下布袋，多少自在。"]'),
('a1a21a3d-2f30-41b0-b965-768fc69325ff','思賢堂','岳珂','宋','宋诗','song-poetry','','[]','傑宇翬聯接孔牆，盛朝人物仰堂堂。',64,'全唐诗/poet.song.194000.json','["傑宇翬聯接孔牆，盛朝人物仰堂堂。", "憑熊曾識棠陰芾，睎驥何堪粃政揚。", "配祀有人存折檻，奉祠無路愧題梁。", "平山遺像猶多闕，幸趁春風薦羽觴。"]'),
('531dc90b-3c7d-40a3-9b4e-eb163714544c','偶題','岳珂','宋','宋诗','song-poetry','','[]','下簾宴坐自焚香，酒力醒時冬夜長。',32,'全唐诗/poet.song.194000.json','["下簾宴坐自焚香，酒力醒時冬夜長。", "憂國寸心應未爐，夜深頻起看天狼。"]'),
('7578d0d4-f820-4943-8156-634bcd0ab63c','東松庵','岳珂','宋','宋诗','song-poetry','','[]','東松一建幾經春，景物清幽匪俗鄰。',64,'全唐诗/poet.song.194000.json','["東松一建幾經春，景物清幽匪俗鄰。", "曾識當年駐金節，尚存遺墨勒堅珉。", "晚生不復究前烈，所幸猶來拂壁塵。", "市虎欺天疇敢爾，東風回首一霑巾。"]'),
('454a2e12-514b-413f-b5ec-e755d46fdda6','鶴林寺','岳珂','宋','宋诗','song-poetry','','[]','秋枕竹鳴屋，晝棋松掩關。',48,'全唐诗/poet.song.194000.json','["秋枕竹鳴屋，晝棋松掩關。", "雨晴猶濕徑，雲薄不藏山。", "未洗中原恨，誰消永日閑。", "西風動征隰，空愧鬢毛斑。"]'),
('d9fc6f31-23e4-4fd1-95ed-395eae2cce9d','句  其一','岳珂','宋','宋诗','song-poetry','','[]','動指不須占染鼎，去毛切莫拗蒸壺。',16,'全唐诗/poet.song.194000.json','["動指不須占染鼎，去毛切莫拗蒸壺。"]'),
('b3d6ef1e-2558-4304-a7ae-351e772a9b75','句  其二','岳珂','宋','宋诗','song-poetry','','[]','片雲出岫猶知倦，流水吟湘肯伴牢。',16,'全唐诗/poet.song.194000.json','["片雲出岫猶知倦，流水吟湘肯伴牢。"]'),
('eda71c87-e1f8-43ac-84c3-3558d4ec538c','句  其三','岳珂','宋','宋诗','song-poetry','','[]','尚有奏篇煩狗盜，肯辭馳傳爲駹臣。',16,'全唐诗/poet.song.194000.json','["尚有奏篇煩狗盜，肯辭馳傳爲駹臣。"]'),
('2ab2b911-8a78-4ac2-9f82-ec06866838e3','擬九頌  其一','程公許','宋','宋诗','song-poetry','','[]','龍吟兮九淵，鶴唳兮九天。',185,'全唐诗/poet.song.194000.json','["龍吟兮九淵，鶴唳兮九天。", "飛僊兮下寥闊，鶴可馭兮龍可鞭。", "白雲兮坌谷，飛泉兮鳴筑。", "掇瑶草兮帝庭，搴瓊林兮木末。", "問老僊兮何爲，珠庭宴兮悅怡。", "啟瓊笈兮探道帙，盼靈童兮往授之。", "粲僊李兮芳奕葉，主斯文兮千歲期。", "維嵩嶽兮峻極，繄甫申兮孕質。", "彼圩頂兮尼丘，非毓聖兮何述。", "偉茲山兮萬仞，獨載英兮一家。", "下培塿兮何有，上帝閽兮可排。", "龍奮髯兮翔騫，鶴整翮兮褊褼。", "灑瓢滴兮澤苗槁，何蕙帳兮吾久淹。"]'),
('dd67577a-c7e5-4dcb-8d0e-c12f860b18e0','擬九頌  其二','程公許','宋','宋诗','song-poetry','','[]','馳余馬兮南北，慨永懷兮故國。',183,'全唐诗/poet.song.194000.json','["馳余馬兮南北，慨永懷兮故國。", "豈喬木兮吾敬，繄世臣兮取則。", "許史兮金張，煜煜兮煌煌。", "薰天兮富貴，達觀兮粃糠。", "水有源兮木有本，傳不傳兮天若吝。", "彼高密兮崇門，後何稱兮子孫。", "維指李兮蟠根，光萬丈兮斯文。", "父子兮昆弟，面命兮叮嚀。", "闖戶兮車不停軌，滿堂兮烜朱與紫。", "顧所重兮未然，寧以彼兮易此。", "佩禮義兮服詩書，保厥美兮久不渝。", "百世兮嗣守，張赫奕兮吾閭。", "守一經兮範金石，寧鄭公兮專通儒。"]'),
('f81b90c7-4566-4850-a60e-6844f28f2c83','擬九頌  其三','程公許','宋','宋诗','song-poetry','','[]','修眉兮連娟，曼翠靄兮麻源。',156,'全唐诗/poet.song.194000.json','["修眉兮連娟，曼翠靄兮麻源。", "君門獰兮九虎，蹇予留兮三年。", "三峨之山兮遠萬里，見似人兮胡不喜。", "半輪秋兮促公歸，空高徑兮班屐齒。", "蹈夷險兮一心，既何戚兮何欣。", "忍較功兮曲突，莽蒼狗兮白雲。", "清風颯兮綺疏，明月耿兮庭徐。", "紛縹帙兮插架，尚青衿兮來趨。", "渺天涯兮延佇，時與拂兮蠹魚。", "雪堂兮躬耕，萬古兮芳馨。", "匪天窮兮人厄，九鼎重兮斯文。"]'),
('988fffe9-e210-4063-a36b-84042f45b511','擬九頌  其四','程公許','宋','宋诗','song-poetry','','[]','水平湖兮溶溶，鴈鳴秋兮雝雝。',146,'全唐诗/poet.song.194000.json','["水平湖兮溶溶，鴈鳴秋兮雝雝。", "氣相求兮聲相應，渺萬里兮葭葺叢。", "晴雲淡兮天宇清，行不亂兮字縱橫。", "伊美人兮心和平，韻塤箎兮錦繡文。", "湖光澹兮酒溫巵，鑑湖影兮燭鬚眉。", "縱百坡兮何聚散，如此水兮湼不緇。", "彼弋人兮奚慕，何南北兮定處。", "嫋嫋兮秋風，瀟瀟兮夜雨。", "飛鳴兮向陽，何心兮稻粱。", "望層空兮接羽，友鴻鵠兮高翔。"]'),
('c6753eca-c6d8-4759-9e0e-150058224924','擬九頌  其五','程公許','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','貌棱層兮心潔貞，玉韞質兮金作聲。',163,'全唐诗/poet.song.194000.json','["貌棱層兮心潔貞，玉韞質兮金作聲。", "芙蓉冠兮獨立，佩寶璐兮繽紛。", "胡拳拳兮石友，期歲晚兮相守。", "瞠俗眼兮老醜，自心知兮堅久。", "彼平泉兮森離立，紛品第兮羅甲乙。", "吾何嗜兮狷介，寧與汝兮同癖。", "琴書兮左右，龜鶴兮前後。", "覿面兮崢嶸，忘言兮一笑。", "泰山兮非大，拳石兮非小。", "體無不具兮，性何不有。", "喦喦兮層霄，藹膚寸兮澤九州。", "時卷舒兮爲世，亙古今兮獨超。"]'),
('d0a3f52d-6a14-4d41-92e1-ba53a1d1eb8b','擬九頌  其六','程公許','宋','宋诗','song-poetry','','[]','葵傾心兮向陽，車導迷兮指南。',179,'全唐诗/poet.song.194000.json','["葵傾心兮向陽，車導迷兮指南。", "彼赫曦兮麗晝，奚信耳兮銅盤。", "路通行兮九軌，奚窘步兮媻姍。", "理有窒兮必通，物無幽兮不闡。", "懿君子兮姱修，曾何心兮獨善。", "曼余目兮流觀，瞻咫尺兮威顔。", "慨冥行兮一世，撫余衷兮獨安。", "惟納約兮自牖，苟牆面兮孰誘。", "擁前旒兮余察，昏擿埴兮余考。", "周道兮如砥，君子兮所履。", "彼矇叟兮何知，跬步兮千里。", "倚檻兮永歌，君門九重兮奈何。", "倚皇明兮寤鑒，蹈前修兮不頗。"]'),
('19614547-279b-4882-ac5b-2e32089aeb2a','擬九頌  其七','程公許','宋','宋诗','song-poetry','','[]','滄海兮渺瀰，杳莫見兮津涯。',186,'全唐诗/poet.song.194000.json','["滄海兮渺瀰，杳莫見兮津涯。", "愕風濤兮澒洞，問靈皇兮何之。", "天蒼蒼兮正色，水混混兮相接。", "何人心兮過險，陡平陸兮震懾。", "維水流兮不盈，縱涉險兮心亨。", "亦可載兮可溺，毋以弱兮意輕。", "兀漏舟兮彭湃，矧維楫兮不戒。", "羌左重兮右輕，曾何恃兮弗敗。", "引余袂兮褰余裳，整余柂兮屹余檣。", "舟中人兮乃心一，險可濟兮患可防。", "乘流兮上下，如平武兮康莊。", "思古人兮莫我遌，志尊堯兮慨以慷。", "固天命兮有當，繄人謀兮允臧。"]'),
('5fa5b929-6da8-4305-8a70-b180e8d561b8','擬九頌  其八','程公許','宋','宋诗','song-poetry','','[]','東方兮煌煌，烜吾目兮晨光。',167,'全唐诗/poet.song.194000.json','["東方兮煌煌，烜吾目兮晨光。", "耳翰音兮三唱，屏羣英兮遠藏。", "攬衣兮起起，危檻兮徙倚。", "寧餐華兮學僊，何炙背兮誇美。", "衆鼾睡兮昏莫知，我心惻兮獨徘徊。", "胡羲馭兮不少尼，恐君行兮迫崦嵫。", "晞余髮兮扶桑，騁余乘兮暘谷。", "翫咸池兮洗光，佇閶闔兮開鑰。", "建采旄兮飛虹，駕蜿蜒兮八龍。", "鸞鳳兮前導，靈鳥兮後從。", "於微閭兮發軔，景未仄兮帝宮。", "及曜靈兮未晏，尚察余兮從容。"]'),
('e988f5da-268e-43eb-b515-d57bac5fb1ce','擬九頌  其九','程公許','宋','宋诗','song-poetry','','[]','桑枝綠兮麥齊腰，醴泉山下兮春和柔。',223,'全唐诗/poet.song.194000.json','["桑枝綠兮麥齊腰，醴泉山下兮春和柔。", "有美一人兮山之曲，薜荔屋兮蕙裯。", "溪流兮清瀏，嵐靄兮穠秀。", "鳥語韻兮清風，花氣馥兮晴晝。", "山中人兮衮繡衣，汎濫游兮憺忘歸。", "溉千頃兮芳茝，藝百畝兮留夷。", "歲暮兮華實，折以遺兮所思。", "懷渺渺兮何極，時不可兮再得。", "丹鳳兮飛飛，何兩美兮未合。", "山中人兮忍淹留，皇渴佇兮石田秋。", "樂行兮憂違，余心兮焉求。", "草萋碧兮日婉娩，炯四目兮余袂挽。", "披霞縕兮紬瓊編，倚僊翁兮與周旋。", "樂莫樂兮醴泉之墅，役薪水兮公忍余棄。", "凌汎景兮從之遊，渺下顧兮一稊米。"]'),
('8ebf70e0-c956-40f9-8db0-1df2a8368982','述九頌  其一','程公許','宋','宋诗','song-poetry','','[]','五氣兮順行，萬彙兮嘉生。',191,'全唐诗/poet.song.194000.json','["五氣兮順行，萬彙兮嘉生。", "繄人兮有異，毓其秀兮最靈。", "紛總總兮橫目，何一濁兮一清。", "豈后皇兮爾私，命曰賢兮粹精。", "雖才品兮靡易，匪先覺兮曷程。", "誕空桑兮開有殷，崧嶽降兮周之禎。", "矧皇運兮配天，作之輔兮差肩。", "藹遺芳兮簡編，屹柱石兮多賢。", "眷指李兮嫡裔，祖柱下兮老僊。", "扶輿兮瑞霧，溶洩兮非煙。", "鞭鸞兮馭鶴，抉雲漢兮來九天。", "粲文瑞兮郁郁，帝所賫兮坤軸。", "經天兮日星，緯地兮嶽瀆。", "綿萬禩兮不泯，爲生民兮耳目。"]'),
('d738036a-c0b5-4cf1-b0ff-4d9b491efef3','述九頌  其二','程公許','宋','宋诗','song-poetry','','[]','岷山兮五嶽丈人，大江兮四瀆之尊。',194,'全唐诗/poet.song.194000.json','["岷山兮五嶽丈人，大江兮四瀆之尊。", "羌鬰積兮佳氣，固人物兮載英。", "環兩川兮千里，何江鄉兮專媺。", "匯千頃兮玻瓈，龍與鶴兮集止。", "山之隠者聃耳孫，子正見兮楊氏女。", "乘汎景兮軼罡風，藹僊蹤兮山之趾。", "稟帝命兮叢霄，聊世人兮游戲。", "五男子兮翹英，今嶢嶢兮鼎峙。", "彼談遷兮世史官，悵有歉兮晜及季。", "真人兮高翔，盼塵寰兮粃糠。", "憫俗兮惛瞀，蹇余佩兮熒煌。", "老翁泉兮龍鶴之雲，前蘇後李兮藹芳馨。", "岷可礪兮江可竭，不可沫兮英與靈。"]'),
('0d1813fc-a9e8-489a-9fd0-83b4e72636a0','述九頌  其三','程公許','宋','宋诗','song-poetry','','[]','天不椓兮斯文，寄命脈兮哲人。',232,'全唐诗/poet.song.194000.json','["天不椓兮斯文，寄命脈兮哲人。", "爛咸陽兮焰虐，不可燬兮六經。", "苟日月兮可晦，何天地兮長存。", "言不文兮行不遠，義欲正兮詞欲贍。", "學之荒兮氣之浮，匪艱深兮必蹇淺。", "公昔來兮帝旁，佩瓊蕤兮雲錦裳。", "六龍兮伏軫，從之兮彩凰。", "愍世兮溷濁，下掃兮不祥。", "屈宋兮導前，卿雲兮翼後。", "韓柳兮並馳，杜李兮齊驟。", "建安七子兮隨行，江左諸謝兮羅左右。", "抗吾旃兮典籍場，軼吾轂兮風雅囿。", "探金匱兮秘圖，掞國華兮冊書。", "範金石兮揚律呂，散人世兮猶緒餘。", "民之生兮有司命，彼指南兮亦有車。", "秉斯印兮千萬壽，後有覺兮余楷模。"]'),
('0db228a6-0989-4eeb-9763-d0e50a8c954b','述九頌  其四','程公許','宋','宋诗','song-poetry','','[]','郊見帝兮琮璜，瑟彼瓚兮流斯黄。',196,'全唐诗/poet.song.194000.json','["郊見帝兮琮璜，瑟彼瓚兮流斯黄。", "物有專兮靈粹，寧糅雜兮尋常。", "懿君子兮毓德，可蠡測兮藴藏。", "稟堪輿兮間氣，學遠紹兮皇王。", "探墜緒兮鄒魯，集臯夔兮衆芳。", "俗薆薆兮要艾，紛余佩兮蘭纕。", "衆襜襜兮冶服，爛余裳兮織襄。", "石渠兮紫橐，斗樞兮萬閣。", "持衆美兮效君，寧濡跡兮康國。", "世惛惛兮莫吾與，矯茲媚兮私處。", "畦於閭兮珣琪，藝瓊蔬兮玄圃。", "暖晴旭兮養和，霏瑞霧兮來下。", "苟昭質兮莫虧，猶可遺兮遠者。", "及羲鞭兮未晏，導帝之兮軌路。"]'),
('ff5641a6-97e4-4c61-ac59-fd8bc5751063','述九頌  其五','程公許','宋','宋诗','song-poetry','','[]','蘿門兮薜戶，宛其姝兮靜女。',195,'全唐诗/poet.song.194000.json','["蘿門兮薜戶，宛其姝兮靜女。", "撫瑶瑟兮清歌，歌不絕兮如縷。", "事君子兮歲幾何，薺非甘兮蘗非苦。", "金石兮貞心，恩深兮雨露。", "豔半額兮姱倡，豈娥眉兮能嫵。", "山之顛兮虎豹嗥，波洶洶兮蛟龍饕。", "君欲行兮孰導，隠余思兮鬰陶。", "願一列兮無從，首倦櫛兮頻搔。", "寶輅兮瑶轍，道阻兮積雪。", "君何志兮遠遊，危斷綏兮惙惙。", "歲冉冉兮將遒，蹇奚淹兮山椒。", "愕噦鳳兮戾止，曰有詔兮汝謀。", "日有食兮仍曜，景有晏兮復朝。", "苟蓀薆兮弗諼，聊延佇兮中洲。"]'),
('5cdda83d-726e-4d5f-98d3-7fafd673f0a9','述九頌  其六','程公許','宋','宋诗','song-poetry','','[]','蚩尤旗兮飛炱，天狗墮兮隠雷。',244,'全唐诗/poet.song.194000.json','["蚩尤旗兮飛炱，天狗墮兮隠雷。", "天運兮日蹙，目漲兮氛埃。", "一失兮一得，孰强兮孰弱。", "莽三垂兮骨縱橫，恣强敵兮橫奔突。", "天萬里兮杳莫知，何一朝兮飛羽愕。", "皇乃眷兮西顧，愴赤子兮何負。", "白駒兮來思，忍空谷兮逸豫。", "有俶兮東方，千騎兮煌煌。", "淑旂兮綏章，往欽兮汝臧。", "膏余車兮秣余馬，遲汝不來兮盍整余駕。", "忽霧塞兮飈回，梗綠林兮轔藉。", "不我後兮我前，幸劫災兮天假。", "怒轍兮徒勞，鼎魚兮焉逃。", "民生兮何尤，膏火兮煎熬。", "蛟涎兮脫禍，父母兮鞠我。", "集鴈兮中洲，作之屏兮蜀之左。", "內訌兮外阻，誰禦兮誰拒。", "膚寸兮鬰遥岑，先一州兮後天下。"]'),
('39f9fe06-48cc-4b40-9486-c4660c95e214','述九頌  其七','程公許','宋','宋诗','song-poetry','','[]','奫淪兮澤有水，渺莫窺兮涯涘。',241,'全唐诗/poet.song.194000.json','["奫淪兮澤有水，渺莫窺兮涯涘。", "鼓之雷兮噓之風，沛萬里兮流莫止。", "潏濤瀾兮汎東洋，張乾綱兮翕坤紀。", "渺觀兮古今，賢運兮齊軌。", "狼跋兮其胡，赤舄兮几几。", "東征兮遲遲，滔滔兮不歸。", "歸來兮何時，繡裳兮衮衣。", "美人兮嫮好，思不見兮令人老。", "昔與余兮成言，忍棄之兮異道。", "九疑兮緬哉，重華兮宴娭。", "蒼龍兮峙闕，岧嶢兮帝臺。", "蕙裯兮芷幄，從之兮九垓。", "麾青虬兮以梁，驂孔鸞兮以駕。", "靄雲旃兮繽紛，恍松喬兮來御。", "步咫尺兮帝軒，帝一笑兮何言。", "恍流盼兮下土，掃埃氛兮九埏。", "余左兮汝右，余先兮汝後。", "汝作朕兮股肱，拜稽首兮皇萬壽。"]'),
('0c93e673-c50f-4e7d-adfb-1dfb8939f744','述九頌  其八','程公許','宋','宋诗','song-poetry','','[]','一之日兮周正，建子兮良辰。',225,'全唐诗/poet.song.194000.json','["一之日兮周正，建子兮良辰。", "黄鐘兮起律，魯臺兮望雲。", "氣機兮翕闢，往來兮不停。", "皇揆予兮初度，秉幼志兮潔貞。", "延日月兮察幽，睎雨露兮瀹氛。", "蓀拳拳兮余愛，何險艱兮弛勤。", "與蓀違兮星紀，思專專兮曷已。", "九折臂兮成醫，信情質兮可恃。", "端策兮以占，有孚兮韋編。", "陰極兮陽復，豈賢運兮不然。", "矧甲子兮一周，測天度兮循環。", "丹臺兮定錄，壽紀兮日延。", "理無窒兮不亨，物去故兮就新。", "蠖屈兮求信，根之歸兮再榮。", "彼涸陰兮毓質，亦忍俟兮陽春。", "洪鈞兮密庸，播物兮無垠。", "開八荒兮壽域，如華胥兮大庭。"]'),
('2206110b-aee9-4577-bbcf-74e47cc74f8b','述九頌  其九','程公許','宋','宋诗','song-poetry','','[]','天門開兮九重，爛鈎陳兮紫宮。',206,'全唐诗/poet.song.194000.json','["天門開兮九重，爛鈎陳兮紫宮。", "烜舜瞳兮萬里，穆五絃兮從容。", "予唱兮孰和，勞心兮𢥞𢥞。", "渺煙塵兮蕭瑟，慨世途兮荆棘。", "上帝兮孔仁，賫予兮良弼。", "金碧波兮漲漪淪，妖氛洗兮景氣新。", "皇軫思兮六合，佇公來兮經營。", "天蒼兮地厚，日月兮悠久。", "民命兮以延，國脈兮以壽。", "雲鬅鬙兮僊者家，瑶之臺兮戶瓊玖。", "飯寶屑兮醴玄霜，脯擘麟兮果梨棗。", "馭鶴兮鞭龍，故山兮春風。", "吾誰侶兮赤松，匪上玄兮曷從。", "撫塵劫兮浩蕩，燕鈞天兮樂融。", "長接引兮羣品，與龍漢兮無窮。"]'),
('9d56562d-02a0-4be0-bda7-4f662aed613b','亨泉詞','程公許','宋','宋诗','song-poetry','','[]','有閟兮寒泉，運而往兮幾何年。',353,'全唐诗/poet.song.194000.json','["有閟兮寒泉，運而往兮幾何年。", "地靈兮啟秀，不我後兮不我先。", "川媚珠兮圓折，蓮吐岫兮便娟。", "坤文郁兮瑞世，所思邈兮西都之虞淵。", "芳至今兮未沫，世載英兮昌維。", "其已考槃兮山之阿，龜何以兮食只。", "築之垣兮登登，忽而凹兮窈而深。", "累甓兮尋丈，刳木兮虛心。", "木爲仁兮仁者靜，水閡險兮中不失信。", "矧生數兮土以培，固受命兮獨也正。", "孰牖兮孰窒，孰導兮觱沸。", "否傾以亨兮繄所遭，余何喪兮何得。", "美人兮委蛇，泂酌兮永歌。", "昔泥不食兮匪我吝，今渫可汲兮湛不波。", "韋絕編兮堂上，晤三聖兮惝怳。", "有孚兮坎習，不窮兮井養。", "消息兮盈虛，道之體兮易之象。", "沛吾輈兮八荒，志拯溺兮靡遑。", "雞鳴喈喈兮霜月曉，紛紜歸夢兮殷轆轤之下銀床。", "萬家兮渴飲，渺千里兮相望。", "猿奚悲兮鶴奚怨，旱欲霖兮川欲航。", "功成兮不居，媲彼泉兮有常。", "纓可濯兮滄浪，鯉可羞兮漢之姜。", "修綆兮汲古，涴新學兮肺腸。"]'),
('36a2041e-f111-4f7b-a09d-a0c45380c3c4','仙谷詞送別西憲楊少卿奉祠東歸','程公許','宋','宋诗','song-poetry','','[]','攬飛雲兮遐思，軼迅飈兮流目。',205,'全唐诗/poet.song.194000.json','["攬飛雲兮遐思，軼迅飈兮流目。", "涪之水兮渺瀰，祕殊境兮仙谷。", "彼僊谷兮何有，辟埃氛兮泬寥。", "森幽篁兮擁翠，蓊嘉栢兮相樛。", "路窈窕兮山盤紆，田可稼兮谿可漁。", "谷中人兮歸何時，霧冥冥兮雨霏霏。", "人心洪濤兮衝君航，世途羊腸兮隤君馬。", "盍舍策兮停橈，聊相羊兮田野。", "蘭室兮蕙裯，鶴舞兮猿嗥。", "君歸來兮何樂，澹無取兮焉求。", "敷床兮千萬軸，問何如兮嶽之麓。", "慨視世兮搶攘，忍潔身兮幽獨。", "谷中人兮無淹留，靄膚寸兮澤九州。", "芳菲菲兮未沫，期歲晚兮逍遥。"]'),
('a5a13b1f-acfc-468a-94c5-0921a4f4875b','撰先伯桂隠先生哀詞','程公許','宋','宋诗','song-poetry','','[]','丹山之巖兮阻且深，丹山之雲兮閟其霖。',227,'全唐诗/poet.song.194000.json','["丹山之巖兮阻且深，丹山之雲兮閟其霖。", "中有姝兮靜處，冠岌峨兮瑶簪。", "方轍兮坎滯，聊返轡兮穹林。", "辛夷兮爲屋，芷幄兮蘭衾。", "世與我兮異好，不可揉兮精金。", "信有味兮恬漠，亦何怨兮寡朋。", "猿嗥兮鶴憤，鳥悲兮蛟吟。", "忽西崦兮墮日，急響絕兮玉琴。", "載營魄兮焉逝，空桂枝兮蕭森。", "朔風兮陵厲，白晝兮多陰。", "素車兮丹旐，曷返兮遥岑。", "天高兮地厚，古往兮來今。", "彼達觀兮超曠，奚死生兮愛憎。", "四方兮上下，杳眇兮莫尋。", "鶴歸兮何日，瑶草碧兮勞我心。", "涕浪浪兮霑襟，君無滯兮遠淫。", "歸來兮娛樂，故山兮崚嶒。"]'),
('e3716a78-d332-4611-9cd4-a15e551914d1','安人趙氏哀詞','程公許','宋','宋诗','song-poetry','','[]','商飈之蕭瑟兮，百草莽其披離。',334,'全唐诗/poet.song.194000.json','["商飈之蕭瑟兮，百草莽其披離。", "何深林之敷蕙兮，藹芳華其不虧。", "物有生而專媺兮，豈伊人而不然。", "閴濬房其窈窕兮，非從夫將孰稱賢。", "媚璇源之駛瀏兮，四僊之峰其𡽱嶪。", "衮衣藹其碩膚兮，笄珈配之煒曄。", "有齋季女淑且明兮，天作之對奚苟求。", "懿玉屏之有孫兮，嗣寬閒之潔修。", "面嘉命其必敬戒兮，庶幾君子之好逑。", "歌福履之將兮，詠室家之宜。", "敝屣珠玉吾何有兮，佩禮義而服書詩。", "顧俗好之騖榮兮，得則盈而失則沮。", "媺君子其獨不羣兮，期百歲而偕處。", "夫何孤鸞一朝而舞鏡兮，悼亡賦而鬢霜。", "念天秩之有典兮，幽明離隔其忍忘。", "冷辟邪而燼絕兮，疊旁行其蛛蟊。", "耿松岡之夜月兮，尚欣欣以從舅姑之遊。", "悼人命其孰司兮，參大衍其非夭。", "信流芳之未沫兮，豈獨華髮而曰壽。", "苟天理之可恃兮，君子之步其丹霄。", "湯沐大國日可冀兮，尚足慰芳魂於一丘。"]'),
('6265b054-adac-4ed4-85b0-4fddaa15eba3','明禋進戒詩','程公許','宋','宋诗','song-poetry','','[]','於赫圓宰，視聽自民。',240,'全唐诗/poet.song.194000.json','["於赫圓宰，視聽自民。", "惟聖能饗，非德莫親。", "乃眷炎宋，受命以仁。", "十有三葉，涵海毓春。", "德厚流光，施及吾君。", "歷數有歸，兆協大橫。", "性篤孝恭，天縱睿神。", "思皇帝統，積累艱勤。", "譬彼菑田，是播是耘。", "遺大朕躬，曷其敢寧。", "嗣訓九年，端拱嚴宸。", "權綱復歸，如日宣精。", "姦憸投荒，耆哲揚廷。", "與物更始，三載惟寅。", "宗祀戒期，歷吉中辛。", "孚號萬方，以肅先庚。", "飭我玉幣，潔我粢盛。", "秋霖淫泆，俄浹六旬。", "法宮祗懼，虔祈百靈。", "爐沉未燼，如谷應聲。", "飈籟號起，霧祲歛昏。", "凡百執事，肄習彬彬。", "戊辰齋居，彌竭精純。", "昧旦盛服，天仗肅陳。"]'),
('d89731bf-9924-4b38-866b-8cba07ea4797','遊靈隠寺','程公許','宋','宋诗','song-poetry','','[]','夙好在巖壑，强持縛纓簪。',240,'全唐诗/poet.song.194000.json','["夙好在巖壑，强持縛纓簪。", "野性當奈何，惝恍如驚麕。", "京華百萬家，𧥄𧥄瓦疊鱗。", "海氣蕩煩暑，作威凌轢人。", "湖山招我來，九里松風清。", "稽首靈鷲山，西瞻目若營。", "云何一峰碧，飛來如羽輕。", "俗見囿畛域，達觀渺沙塵。", "不見毗耶離，示病老浄名。", "古掌斷世界，猶如陶家輪。", "竺慧去不返，雪猿呼莫聞。", "斯言誰與證，萬壑空烟雲。", "老禪法龍象，談麈紛縱橫。", "萍蓬萬里外，繾綣猶鄉情。", "齋盂乳鋪玉，茗椀花糝瓊。", "兩腋扶清風，取意巖壑行。", "冷泉掬清泚，五峰凌崢嶸。", "真賞味無味，內觀湛空明。", "可能一枝筇，雲水自由身。", "永愧隠峰老，勇決拂衣巾。"]'),
('c2dcb3bb-06a7-48c9-9107-500216af5a03','連日快晴登金華菴觀大面諸峰','程公許','宋','宋诗','song-poetry','','[]','齋心謁殊庭，異境目力眩。',288,'全唐诗/poet.song.194000.json','["齋心謁殊庭，異境目力眩。", "積陰疑漏天，媧石誰與鍊。", "列仙喜我至，一笑晴景現。", "絮雲斂太空，螺翠敞大面。", "正位儼宸極，羣峰拱星弁。", "烟雲互吐吞，草木鬰葱蒨。", "錯磨金碧麗，襞積霞綺絢。", "平生飫看山，及茲頗創見。", "常聞西城君，承詔通明殿。", "玉虬層空來，寶室仙境擅。", "真侶萬五千，朝夕侍游燕。", "凝神杳渺間，稽首瓣香薦。", "倏看碧瑶岑，坌起白雲片。", "溟涬含一氣，瞬息閲千變。", "意恐大隗迷，或作巨鼇抃。", "仙者奚異人，豈忍爲獨善。", "利欲膏火熬，是非蠻觸戰。", "持是以求仙，何異沙作膳。", "吾身信浮漚，世事如掣電。", "本來一晶明，初不假方便。", "隨緣聊爾耳，可使爲物轉。", "寸田須鋤耘，老屋亟營繕。", "行迷及未遠，補過以無倦。", "飈游如有聞，印我本誓願。"]'),
('e5f5c6d6-b12f-4382-8946-6c967c04ac70','古碑塔寺改律爲禪鄉大夫招凌雲智禪師主法席規模就整侯丞用晦爲賦揭章和者成軸書來索和','程公許','宋','宋诗','song-poetry','','[]','智禪生峩下，稚齒希空門。',264,'全唐诗/poet.song.194000.json','["智禪生峩下，稚齒希空門。", "落髮受具戒，持鉢巡諸村。", "有如摩尼珠，烱然古井渾。", "又若大明鏡，不受塵垢昏。", "衰世不見理，窺天於覆盆。", "誓將昌祖道，特用報佛恩。", "得法歸燕社，閉口不復論。", "眷言古叢城，往事空劍痕。", "誰規此浮屠，峻極壓厚坤。", "意令五濁海，親見兩足尊。", "末法裨販盛，遺教髣髴存。", "破律會十方，有詔下九閽。", "法席遴厥選，爐香冷復溫。", "豎拂集龍象，催粥吼鯨鯤。", "能使幽衢暝，豁開若木暾。", "空花眩俗眼，孰辦牢脚跟。", "斯道許津梁，如天柱崑崙。", "施金方山積，巧匠猶水奔。", "請以六度法，爲拔六欲根。", "諸君快說偈，羣魔驚褫魂。", "何時共峻陟，層霄疑可捫。", "勿謂蟹井小，可敵鯨海吞。"]'),
('73fe42f0-012c-4460-920f-b1d8d70136da','投龍寶室洞天過延慶觀訪王倅共父劍峰精舍','程公許','宋','宋诗','song-poetry','','[]','璧簡薦寶室，襟裾馥旃檀。',180,'全唐诗/poet.song.194000.json','["璧簡薦寶室，襟裾馥旃檀。", "眷言石交舊，可憚脚力酸。", "層崖一劍裂，陰壑千古寒。", "數椽棲泬寥，小樓面巑岏。", "風穴激虎嘯，石洞掀龍蟠。", "是日朔吹慘，舞空雪花漫。", "開尊聊暖熱，芼蔬勸加餐。", "心事喜我同，晤言藹清歡。", "欲去有餘戀，小駐搜奇觀。", "評畫過神品，誓鬼猶故壇。", "君家古叢城，甲第十畝寬。", "胡獨嗜幽寂，而樂茲考槃。", "戍邱漸相迫，住山殊未安。", "春風動倅馬，雲霄插雙翰。", "儻念猿鶴怨，無多貪熱官。"]'),
('932f0bec-a832-49d4-9651-7b50b617a15b','羅仙宮道士留午飯後遍覽山中佳景三十六峰羅列几席夜雨達旦客枕甚清','程公許','宋','宋诗','song-poetry','','[]','老樹萬安驛，古井羅真山。',264,'全唐诗/poet.song.194000.json','["老樹萬安驛，古井羅真山。", "玉虬五雲車，仙翁此往還。", "雲蹤久不刓，汎景疑可攀。", "憶昔摛藻頖，題詩揭松關。", "抱琴唐昌來，快晴春物妍。", "截竹倚伶俜，引袂飛褊褼。", "歷階一稽首，爲我展笑顔。", "善救無棄物，廣度隨有緣。", "殊庭遥相望，異關非浪傳。", "道士多野朴，山肴親潔蠲。", "披榛爲前導，𣂏酒勤款延。", "墨池鑑寒藻，書臺滃非烟。", "所著何隠帙，乃忍慳不傳。", "空餘六六峰，可想格筆椽。", "最憐覆盂亭，秀出層巒顛。", "周遭碧霞嶂，莽蒼雲海連。", "酒囤擬泂酌，花坪夐連娟。", "暝色阻窮探，夜雨得佳眠。", "塵緣一相誤，凡骨何當仙。", "雲霞豈不戀，簡書當趣旋。", "神丹夜澗火，青藜洞中天。", "仙翁如點頭，未忍甘棄捐。"]'),
('6a1d4d72-dfc6-451c-9247-7519dca9601f','過金堂迂路登三學山李八百仙人道場','程公許','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','失脚塵土窄，謁歸旬朔暫。',252,'全唐诗/poet.song.194000.json','["失脚塵土窄，謁歸旬朔暫。", "迂徑款名山，攀險得幽翫。", "平川開靄杳，長江遠疏散。", "驅車松柏陰，闖戶風日淡。", "樓居規制古，殿壁丹青暗。", "仙翁李八百，曾舉陟霄漢。", "遺跡古未陳，見我若笑粲。", "靈液噴幽喦，枯楠茁新幹。", "黄冠肅延勞，綠茗勸澆灌。", "饑腸殷雷蟄，塵慮忽冰泮。", "碑閲唐隸遒，詩爲處士歎。", "三生學精苦，一日升汗漫。", "我豈無宿緣，心猶憫世難。", "思見甲兵洗，永息氈毳悍。", "王度式金玉，民勞拔塗炭。", "翛然一儒腐，不自省疏緩。", "强令事馳驅，終覺窘羈絆。", "何當脫屣去，託跡烟霞伴。", "宮洞吟步虛，丹經嚴靜觀。", "太初以爲鄰，巧歷那可算。", "松風天末來，爲我發永歎。"]'),
('66d400b1-100e-4c4f-9409-1e6c89ef503d','擬古二章  其一','程公許','宋','宋诗','song-poetry','','[]','剛風軼飛浮，叢霄隠寥闊。',168,'全唐诗/poet.song.194000.json','["剛風軼飛浮，叢霄隠寥闊。", "其上仙者家，俯世塵漠漠。", "慨我志遠遊，幽思無與豁。", "披雲一長嘯，曾舉騎轇轕。", "整袂謁靈君，授我一丸藥。", "侍宴旬始宮，從遊紫虛閣。", "琅函閟道帙，許我抽玉鑰。", "玄期記三生，廣度有夙諾。", "世氛日澒洞，帝念慘不樂。", "願借萬里風，從君駕鸞鶴。", "鞭雷揮斗柄，夔罔併縶縛。", "掃清六合塵，景象囘閶闔。", "帝命不可稽，侍晨司校錄。", "永劫保澄明，何問癡仙愕。"]'),
('febe16ac-298f-418a-876f-3f5b09d0ff46','擬古二章  其二','程公許','宋','宋诗','song-poetry','','[]','霜英濾雲母，月華吐幽魄。',168,'全唐诗/poet.song.194000.json','["霜英濾雲母，月華吐幽魄。", "濬房鎖葳蕤，弄杼夜咿軋。", "天寒日苦短，篋不貯寸帛。", "嬋娟空自妍，襟袖無乃窄。", "停機掩孤嚬，欲歌心已咽。", "積此萬縷工，織成苧羅白。", "蹇修來何時，復關滯塗轍。", "女無終不嫁，謹勿昧所擇。", "忍寒青瑣窗，熏麝翠羅幙。", "粲粲雙明璫，團團雙白璧。", "稚齒昔所娛，翫之不能斁。", "春風蕩繁囿，觸眼會良匹。", "擷芳索幽占，兩美斯有合。", "及茲歲未晏，爲君媚芳澤。"]'),
('82b36d74-e38a-4c5d-b6b0-388296c13404','人頭山肅謁石壁清源真君像','程公許','宋','宋诗','song-poetry','','[]','人頭接劍門，濯濯危髻綰。',120,'全唐诗/poet.song.194000.json','["人頭接劍門，濯濯危髻綰。", "一峰表獨立，層崖平若剷。", "有一偉丈夫，遠莫辨眉眼。", "異聞驗清源，奇質自天産。", "三生舊緣契，邂逅一笑莞。", "江流怒未平，父功子其僝。", "坐令老蛙縛，笑看離堆鏟。", "陸海擅兩川，利百倍灞滻。", "神聖杳難詰，事或載編簡。", "明德遠矣哉，椒漿酌盈琖。"]'),
('b5797d3f-7565-45d0-abb9-d585d3e6495a','鹽亭登高山廟','程公許','宋','宋诗','song-poetry','','[]','曉馳光祿坂，暑憩鹽亭縣。',72,'全唐诗/poet.song.194000.json','["曉馳光祿坂，暑憩鹽亭縣。", "嵯峨山疊雲，窈窕溪橫練。", "長憐少陵叟，浪走天涯徧。", "耿然憂國心，甘作忍饑面。", "世難今略平，軍行余後殿。", "憑高慨往哲，欲去有餘戀。"]'),
('338a5be5-33c2-4f23-a7b1-32f387a4866b','景行堂','程公許','宋','宋诗','song-poetry','','[]','斯文一綫流，伊川師弟子。',48,'全唐诗/poet.song.194000.json','["斯文一綫流，伊川師弟子。", "萍梗記經行，丹青肖容止。", "升堂如有聞，虛心探厥旨。", "毋與時俗競，溺心於口耳。"]'),
('4be1115f-71a5-4a50-a959-52573ea783e1','貫道堂','程公許','宋','宋诗','song-poetry','','[]','道秘不可傳，非文無以貫。',48,'全唐诗/poet.song.194000.json','["道秘不可傳，非文無以貫。", "君看聖畫易，風行水上渙。", "誰令鞶帨工，能使雅鄭亂。", "六經日麗天，諸子雲霧散。"]'),
('1206a555-9f6e-4e5f-8c88-c37c720f7380','逢源堂','程公許','宋','宋诗','song-poetry','','[]','務學有彝訓，左右逢其原。',48,'全唐诗/poet.song.194000.json','["務學有彝訓，左右逢其原。", "後生巧穿鑿，末派迷本源。", "世不有先覺，誰當警羣昏。", "佩衿來于于，千古師道尊。"]'),
('40503d5e-fd58-4856-986b-288211751f98','卧龍亭','程公許','宋','宋诗','song-poetry','','[]','隆中抱膝吟，意豈慕聞達。',48,'全唐诗/poet.song.194000.json','["隆中抱膝吟，意豈慕聞達。", "翻然起潛蟄，了不愆宿諾。", "廢興渠有命，忠直理難奪。", "出處士所重，羞死荀文若。"]'),
('32775bd8-ce1e-48a0-81d8-3046f729530f','小亭','程公許','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','道義日羣居，閒暇一游息。',48,'全唐诗/poet.song.194000.json','["道義日羣居，閒暇一游息。", "小亭擁芳榮，長江鑑空碧。", "風雩不盡春，庭草有生色。", "習學自孔氏，深體而默識。"]'),
('d60dabd8-8269-47e7-b830-a7336f19ff8c','題枕带雙流閣','程公許','宋','宋诗','song-poetry','','[]','層樓架蒲牢，其下表奇觀。',48,'全唐诗/poet.song.194000.json','["層樓架蒲牢，其下表奇觀。", "江連內外流，山列遠近案。", "烽火日平安，烟霞奉娛翫。", "蔽芾南國棠，挺特九秋幹。"]'),
('3870321e-2d77-449f-884c-8de72995ae23','圓嶠','程公許','宋','宋诗','song-poetry','','[]','羣峰最高處，一席如鏡平。',48,'全唐诗/poet.song.194000.json','["羣峰最高處，一席如鏡平。", "烟霞敞松牖，風月棲茅楹。", "仙姑紫綺裘，飛步白玉京。", "揮手一長嘯，四海風塵清。"]'),
('4b4c85ae-2021-4313-8fc4-4bc362526d08','水雲天','程公許','宋','宋诗','song-poetry','','[]','樓臺錯圖畫，高低各雲烟。',48,'全唐诗/poet.song.194000.json','["樓臺錯圖畫，高低各雲烟。", "小車倦登覽，危欄且囘旋。", "滄波納暝色，溟濛同一天。", "此中有真賞，題詩謝雕鎸。"]'),
('9fe8d0ab-c50a-4481-baef-1d6bb5cf8e58','解纜凌雲快晴','程公許','宋','宋诗','song-poetry','','[]','淫雨三月賒，點篷今夕止。',60,'全唐诗/poet.song.194000.json','["淫雨三月賒，點篷今夕止。", "蕭晨企璇漢，微雲散霞綺。", "鴨綠澹不波，軟翠浄如洗。", "吾行及端月，餘寒未云已。", "何以寫幽情，無多佳句子。"]'),
('d77e9aa7-ef27-42bc-9315-29fd0ade9a71','舟行過昭化望遠山秀色柬幕中諸丈','程公許','宋','宋诗','song-poetry','','[]','劍北山巑岏，刺眼亂矛戟。',48,'全唐诗/poet.song.194000.json','["劍北山巑岏，刺眼亂矛戟。", "烟雲借光景，稍覺含秀色。", "倚檣寄遐瞻，慨我三友益。", "有懷無與晤，搔首暮雲碧。"]'),
('b1600ea4-08ee-4b20-b749-f5cb2c061664','重陽陪諸鄉丈遊水樂洞過風篁嶺龍井張飲觀兩蘇仙辯才法師像晚憩楊家梅園歸路小雨','程公許','宋','宋诗','song-poetry','','[]','凜秋天氣佳，令節天賜沐。',288,'全唐诗/poet.song.194000.json','["凜秋天氣佳，令節天賜沐。", "客居意莫展，勝賞諾已宿。", "風澹湖不波，霧斂山更簇。", "畫舫厭囂喧，筍輿恣追逐。", "閒尋水樂洞，嵌空韻琴筑。", "烟雲互吞吐，臺館適涼燠。", "非無人力勝，亦自天巧足。", "側步滑青苔，醉面爽飛瀑。", "風篁轉幽徑，龍井鑑寒玉。", "默堂定未起，清風誰與續。", "四海兩仙翁，三生緣契熟。", "定知明月夜，屐響答空谷。", "歸路取名園，移尊屢更僕。", "凍雨不成泥，騶騎未須趣。", "峨岷渺何在，萬里勞遠目。", "安得天瓢翻，盡把邊塵沃。", "文昌德宏毅，承旨氣肅穆。", "溫雅奉常卿，忠憤膠庠博。", "宮講靜有儀，正字竭忠告。", "而我贅其間，自省羞樸樕。", "明堂索桴棟，底用采卷曲。", "平生邱壑姿，本不耐羈束。", "撫事長鬰陶，臨觴轉顰顣。", "故園俯大江，繞屋藝嘉木。"]'),
('218fe0a8-50e6-4bde-9576-0bd04be6b11f','同王萬里山行','程公許','宋','宋诗','song-poetry','','[]','邂逅非宿期，意行得奇眺。',108,'全唐诗/poet.song.194000.json','["邂逅非宿期，意行得奇眺。", "三生湖山緣，青眼不改舊。", "飛榜漾湖光，躡屐梯雲嶠。", "玉立緱嶺仙，灑落我同調。", "沖懷寄寥闊，塵外恣吟嘯。", "瞇目東華塵，誰識此中妙。", "吾儕骯髒資，如痼不可療。", "溷溷渠得知，不自恥牛後。", "已矣毋復言，恐貽水仙笑。"]'),
('d0a90188-3a16-403e-953e-7a96a9433913','次李晉仲同遊南巖韻','程公許','宋','宋诗','song-poetry','','[]','風林舞霜葉，野水收寒溪。',108,'全唐诗/poet.song.194000.json','["風林舞霜葉，野水收寒溪。", "旭日愛清美，良友欣招携。", "近遊南巖麓，遠躡樵人蹊。", "世未變野處，地已呈榱題。", "鍊石既有穴，補天亦餘梯。", "仰睇磴可涉，窮擇日從低。", "窅深有神護，險絕令心悽。", "我歸期再出，後會豈終暌。", "第膺三接寵，未許尋高棲。"]'),
('6682da41-ba1b-4cf4-a6b4-a31cfa7fb9ed','晉仲文學淵邃方爲朝陽鳴鳳僕所次前韻及之而洊賜佳章招隠敢再次韻以反之以資他日重會一笑','程公許','宋','宋诗','song-poetry','','[]','丈夫爲世用，釣築辭巖溪。',108,'全唐诗/poet.song.194000.json','["丈夫爲世用，釣築辭巖溪。", "不用身徇道，固可卷而携。", "侃侃紫陽翁，不踐桃李蹊。", "淳熙用不終，歸途此留題。", "坐令南巖高，萬丈誰能梯。", "倘止論茲山，僅亦培塿低。", "今如峴首碑，千載令人悽。", "我輩何適莫，但觀道合暌。", "鳥獸不可羣，仲尼非棲棲。"]'),
('f04454c4-cfff-47dd-92fb-939e6d3c5045','遊涪州北巖','程公許','宋','宋诗','song-poetry','','[]','恭惟同出自，斯文其在茲。',156,'全唐诗/poet.song.194000.json','["恭惟同出自，斯文其在茲。", "白衣帝王師，古聞今所疑。", "慘澹涪江濱，烟雨寒無炊。", "一編洗心易，後學之蓍龜。", "學禪譙夫子，窺牆胡不麾。", "茲道貫三極，何曾限籓籬。", "柱史接武來，相望幾何時。", "舊隠勤汛掃，大書挺雄奇。", "江山著羈臣，千古同一悲。", "渠自氣浩然，何成復何虧。", "高堂儼遺像，寶墨鎸豐碑。", "往者不可作，搔首空涕洟。", "蕭蕭北巖松，悠悠我之思。"]'),
('b38af1e8-d79c-48b1-a17f-3353ad042cf4','和江平叔遊無爲山詩韻','程公許','宋','宋诗','song-poetry','','[]','夙嗜一邱壑，誓言苦難踐。',120,'全唐诗/poet.song.194000.json','["夙嗜一邱壑，誓言苦難踐。", "夢踏西山雲，陟降原復巘。", "世紛不可耐，道根日以淺。", "永愧龕中定，三歎涕如霰。", "君從柯山來，行盡蜀山險。", "不憚屐齒蠟，恣襞蘭亭繭。", "毫端花五色，優曇時一現。", "翛翛塵外趣，歷歷眼中見。", "人生歡會少，摶沙隨手散。", "何以慰瞻思，英詞展黄絹。"]'),
('79d6f3da-287f-4b1c-8fd7-c37b6502595b','自道場山至何山讀故人洪舜俞內翰詩刻追和','程公許','宋','宋诗','song-poetry','','[]','褊性不諧俗，泛梗歸無家。',264,'全唐诗/poet.song.194000.json','["褊性不諧俗，泛梗歸無家。", "故人右扶風，雙旌擁崇牙。", "款門及暇日，褰裳躡飛霞。", "維南古道場，諸天集毗耶。", "巍撐鳳鶱舞，岌起龍騰拏。", "坡仙舊詩刻，清芬郁天葩。", "雲表塔標峻，具區帆影賒。", "萬象森湊泊，窮探忽谽谺。", "金輿度窈窕，翠幄巧蔽遮。", "昔賢此幽棲，禪扉寂無譁。", "蕭爽萬竿竹，芬甘一甌茶。", "清泉茁蘭茗，黄粉飄松花。", "意疑人境外，身漾天漢槎。", "浮生能幾何，騖智那有涯。", "神龜寶巾笥，曳尾寧坳漥。", "所嗜在閒曠，何心事雄夸。", "洪崖石交舊，歲晚蔗境佳。", "心源秋水澹，藝苑春容奢。", "冢上木遽拱，海山棗如瓜。", "今古一轉燭，聚散猶摶沙。", "暮江趣浮鷁，城樹喧棲鴉。", "願言借一窗，爐香繙楞伽。"]'),
('1c105132-097d-47ec-93dd-3feca9be8165','連日駐白帝城懷古感事閲陸放翁詩集追和其韻','程公許','宋','宋诗','song-poetry','','[]','益以搤爲國，前後闢兩門。',192,'全唐诗/poet.song.194000.json','["益以搤爲國，前後闢兩門。", "劍棧徑偪側，峽江浪崩奔。", "盤礴六十州，奠位西南坤。", "天險豈輕設，參旗寧易捫。", "我行當嚴冬，岸沙高漲痕。", "絕壁走猱玃，深潭伏鼉黿。", "東逝注滄海，西來非一源。", "相傳石筍三，下接灧澦根。", "長懷草廬公，受遺龍準孫。", "志節局不展，德義深可尊。", "矧伊躍馬壯，得與同日論。", "形勢今猶昔，世故難爲言。", "撫事重感慨，遐瞻莽塵昏。", "空餘瀼西東，未泯冰雪魂。", "臘殘春意動，清波躍河豚。", "撾鼓趣下峽，渚宮同一尊。"]'),
('ba49a8eb-be18-43df-9d02-4888dd0a7dfc','中元節日登舟赴官巴西兄姪偕親友追送三十里乃別相顧悽黯舟行得此詩以寄','程公許','宋','宋诗','song-poetry','','[]','隨牒倦塵土，歸夢長紛紜。',180,'全唐诗/poet.song.194000.json','["隨牒倦塵土，歸夢長紛紜。", "及歸歲阻饑，負米良艱勤。", "細摹食粥帖，長歌送窮文。", "忽捧毛生檄，往擷魯宮芹。", "元方與猶子，念我當離羣。", "折柬期諸彥，褰裳集江濆。", "追送三十里，酒炙羅繽紛。", "夜航語達旦，摻袂俄夕曛。", "汀蘆黯囘首，風萍悵輕分。", "時危事遠役，所遇無一欣。", "元戎調新律，笑談靜邊氛。", "容我坐無氈，峩冠誦皇墳。", "采蘭勸加餐，伐木友多聞。", "諸君志姱修，未可恬耕耘。", "努力崇令猷，時來皆青雲。"]'),
('2981dc65-e8e8-4b1d-8280-029ccbc12994','弔齊齋先生尚書文節倪公  其一','程公許','宋','宋诗','song-poetry','','[]','披襟白蘋風，蕩槳碧瀾月。',72,'全唐诗/poet.song.194000.json','["披襟白蘋風，蕩槳碧瀾月。", "若下酒可斟，顧渚茗堪啜。", "茲遊足娛翫，所遇皆勝絕。", "四海齊齋翁，清風傳奕葉。", "平生心本朝，峩冠蓬怒髮。", "子皮五湖棹，烟波時出沒。"]'),
('3e8082fe-6568-4f45-8e75-7f0c899bc0b5','弔齊齋先生尚書文節倪公  其二','程公許','宋','宋诗','song-poetry','','[]','仕道昔有訓，退處非爲名。',72,'全唐诗/poet.song.194000.json','["仕道昔有訓，退處非爲名。", "齊竽醉聒耳，虞絃自希聲。", "清波貫霅苕，空翠浮弁衡。", "圖史足怡悅，風月無將迎。", "生世我已後，景行寧忘情。", "昂昂雞羣鶴，慰我雙眼明。"]'),
('1a46bf94-2222-431f-98d1-015d21fbc9df','弔齊齋先生尚書文節倪公  其三','程公許','宋','宋诗','song-poetry','','[]','萬頃湖浪碧，一點浮玉青。',72,'全唐诗/poet.song.194000.json','["萬頃湖浪碧，一點浮玉青。", "先生此考槃，有道甘沉冥。", "植柳蔭水檻，栽蓮繞風亭。", "感慨手遺奏，精神超列星。", "鴻鵠既層舉，鴞鴆爭刷翎。", "克家類季子，隧碑新刻銘。"]'),
('fe8e7c87-5a2d-462a-8a8c-4171aae5dc76','弔齊齋先生尚書文節倪公  其四','程公許','宋','宋诗','song-poetry','','[]','風塵日騷屑，耆哲晨星稀。',72,'全唐诗/poet.song.194000.json','["風塵日騷屑，耆哲晨星稀。", "九原不可作，斯文今誰歸。", "臨風想孤標，把酒哦落暉。", "扁刻見尚友，雪堂密傳衣。", "歸帆拂蘋波，晴烟抹松扉。", "滿篋貯寶刻，展誦省昨非。"]'),
('f8d854cd-1c14-4017-ab82-20b68a6904dd','劉園','程公許','宋','宋诗','song-poetry','','[]','陰沍閟陽和，快晴差愜意。',84,'全唐诗/poet.song.194000.json','["陰沍閟陽和，快晴差愜意。", "怒飈妬心賞，清遊殊鮮味。", "繫船枯葦叢，悶損兀坐睡。", "斷港麴塵波，見引著勝地。", "逕梅佇攬結，堤柳是才思。", "尤憐石交舊，勸我取一醉。", "異事詫白詩，偶同二月二。"]'),
('587402f3-62b6-4aa3-a534-82983e2d8b4b','贈修水黄君子行','程公許','宋','宋诗','song-poetry','','[]','雨潤莘野犁，水給漢陰甕。',288,'全唐诗/poet.song.194000.json','["雨潤莘野犁，水給漢陰甕。", "一爲大烹鼎，玉食此焉供。", "一如朽木偶，肯受關索弄。", "顯晦勢則然，達觀等一夢。", "可憐蓬甕生，萬卷皆成誦。", "靜退一何勇，本不借慫慂。", "使孔孟復起，必能與折衷。", "世道日以隘，古心誰與共。", "君家太史公，以文瑞吾宋。", "崛奇莊騷語，雅淡商周頌。", "學力探窅深，天巧妙機綜。", "風流被諸孫，璆琳富包貢。", "若若綬滿朝，傱傱清燕奉。", "那知一畝宮，有士苦吟諷。", "寐語甘自怡，經綸付時棟。", "伊余曩在列，竊自恥陰拱。", "斥去職蕃宣，翫愒糜廩俸。", "何階繆推激，爲我破愚憃。", "由唐及國朝，作者亦已衆。", "元氣所融會，諒亦勞藝種。", "苦心欲其工，何者適於用。", "當知正始音，若睹治世鳳。", "覽輝千仞岡，一洗羣目瞢。", "諛聞我自知，可能相引重。"]'),
('e87a63b2-018e-4a7b-bb3f-56016ca67a6d','和景韓贈子敬末章韻','程公許','宋','宋诗','song-poetry','','[]','艷冶昭陽妃，嬌好浣紗女。',288,'全唐诗/poet.song.194000.json','["艷冶昭陽妃，嬌好浣紗女。", "盛時一轉盼，零落委黄土。", "彼姝秋胡婦，真節甘獨守。", "煒煒編簡上，芳聲乃持久。", "我欲呼緒風，酹以一觴酒。", "君看澗底松，閲世幾寒暑。", "丈夫要如此，千載可尚友。", "鬼蜮玩阿瞞，何妨摻撾鼓。", "平生書五車，一字不堪煮。", "愾我左右手，雙顧石棱紫。", "忍窮學師道，覓句迫徐俯。", "橫陳味嚼蠟，下筆迅流水。", "憶昨涪江濱，對吟夜床雨。", "胡爲輕判袂，愁凭烏皮几。", "人生如飛蓬，飄落無定所。", "那知錦官城，尊酒又同舉。", "草玄幾垂絲，筆力造化補。", "自我交斯人，短翅思決起。", "不因得趣同，那覺同心苦。", "至今浮山夢，歷歷西窗語。", "齋厨厭苜蓿，塵甑窘禾稆。", "忍饑搜枯腸，數息保氣母。", "何當陪勝賞，一醉詩分取。", "終恐吃期期，輸君白玉麈。"]'),
('9d116ebb-73f5-4969-9389-eaf65ba18bb5','唐文權郡見前作和韻見教乃賦詩三首以答之  其一','程公許','宋','宋诗','song-poetry','','[]','陰陽無停機，寒暑迭更代。',48,'全唐诗/poet.song.194000.json','["陰陽無停機，寒暑迭更代。", "迅商俄慄憀，炎官亟斂退。", "巖壑有餘妍，雨晴皆可愛。", "迫迮紅塵海，適喜翠屏對。"]'),
('df450a76-8ae5-468b-9e44-f4b55995637f','唐文權郡見前作和韻見教乃賦詩三首以答之  其二','程公許','宋','宋诗','song-poetry','','[]','魯國久仙去，詩偕芙蓉秋。',48,'全唐诗/poet.song.194000.json','["魯國久仙去，詩偕芙蓉秋。", "淵淵韻金石，往往餘巖丘。", "象賢來題輿，同聲應鳴璆。", "清渭發源遠，濁涇難混流。"]'),
('2da0999f-f506-44d4-880d-348da3d410f5','唐文權郡見前作和韻見教乃賦詩三首以答之  其三','程公許','宋','宋诗','song-poetry','','[]','贊房容久愒，遊子奚所嘆。',48,'全唐诗/poet.song.194000.json','["贊房容久愒，遊子奚所嘆。", "樹老晝常寂，雲埋宵易寒。", "龕燈對青熒，手箑失白團。", "撫運忽有感，秋防趣三單。"]'),
('dab3f69d-d0ea-4b02-a797-d1eb807aeda8','宗博宮講何丈以諸賢所賦清賦堂詩軸示教借和元韻附軸尾','程公許','宋','宋诗','song-poetry','','[]','避影惡木陰，忍渴貪泉水。',240,'全唐诗/poet.song.194000.json','["避影惡木陰，忍渴貪泉水。", "君看象渡河，步步須徹底。", "士當秉特操，盛行貴知止。", "佳境著蔗根，苦或起瓜蔕。", "上尊錫方進，萬事咨伯始。", "孰能超然觀，貫之以一理。", "瓢飲有餘樂，我自味無味。", "憶登君子堂，積雪幾沒趾。", "雙鶴舞前除，穟烟縈素几。", "疊石肖嶮崿，俯檻鑑清泚。", "旌招還此來，歸夢曷能已。", "紅塵交轡語，新律吐瓊蕊。", "千載友元亮，顧未忍違世。", "將壇建鼓旗，許我陪末至。", "政恐如濁涇，難以汩清渭。", "俗氛日轇轕，菉茨亂蓀芷。", "爲君歌停雲，倦翮思决起。", "念歸悵無家，素食心所恥。", "安得三間茅，託身安穩地。", "一編岫雲吟，枯腸或能擬。"]'),
('ebbca1e8-99fe-4336-99dd-25fbc2d5d620','題夾江馮臨父玉山莊圖','程公許','宋','宋诗','song-poetry','','[]','天下最佳處，惟二室三川。',252,'全唐诗/poet.song.194000.json','["天下最佳處，惟二室三川。", "一氣所融結，何地無雲烟。", "憶遊古南安，倦憩大觀前。", "十洲與三島，渺莽雲水連。", "追隨子邵子，飛步山房巔。", "醉歸迷夕靄，笑歌呼渡船。", "至今詩篋中，秀色餘芳鮮。", "永願借一壑，抱耒耕石田。", "不學谷口隠，姓名京師傳。", "邂逅大馮君，爲我開愁邊。", "烟霞粲畫本，風月起筆椽。", "上有玉山莊，遥挹峩峰妍。", "士爲聲利役，何如擁腫全。", "脫粟幸可飽，苦茶宜活煎。", "畫計不用決，與山終薄緣。", "三間苟完矣，萬松想蒼然。", "羊腸摧君輈，問君歸何年。", "早逐山房翁，江郊掉吟鞭。", "往來成二老，日醉壺中天。", "對峙五言城，寫之七絲絃。", "勿遣俗士駕，汙我青苔錢。"]'),
('028e97a9-5e55-4617-b696-b21353c7d9af','今日良宴會','程公許','宋','宋诗','song-poetry','','[]','良辰不可久，飛幰會華館。',84,'全唐诗/poet.song.194000.json','["良辰不可久，飛幰會華館。", "雕俎粲陳前，羽觴勸引滿。", "危柱瑟難和，急軫琴失按。", "含思以亮激，響入凌霄漢。", "四坐聽我歌，歌罷倚長歎。", "勿遣歌聲悲，悲多聽者慘。", "振轡騰康莊，及此歲未晏。"]'),
('ca8e4bbd-ee7b-4d94-8a0a-f6ba02200a25','春事無幾端居蕭索追懷成都舊遊慨然有賦','程公許','宋','宋诗','song-poetry','','[]','憶昔吏錦城，寄隠雲水鄉。',240,'全唐诗/poet.song.194000.json','["憶昔吏錦城，寄隠雲水鄉。", "蕭散不任事，上官容我狂。", "短篷漾空明，舞棹歌滄浪。", "會心多勝友，一舉累十觴。", "芳春樂事饒，飛幰集寶坊。", "意行無定在，有花即相羊。", "馬蹄穿夜市，奚奴背詩囊。", "三年一炊黍，舊遊想微茫。", "誰知涪江濱，側翅不得翔。", "醉飲無與和，三歎熱中腸。", "雨晴好風景，輕輿便晚涼。", "亂絮撲晚靄，牡丹泫殘粧。", "春物能幾何，營巢燕飛忙。", "茶事迫榆火，餳膠催粥香。", "我本樂烟霞，失身縛簪裳。", "官曹幸云冷，詩債可不償。", "錦城未即去，十景茲難忘。", "安能窘邊幅，低頭甘鎖韁。", "升沈自天分，矯情恐有妨。", "借我白玉壺，爲君歌慨慷。"]'),
('1e2a25d8-a690-4760-a896-7b9d7564d51f','餞寄菴居士龔彥質','程公許','宋','宋诗','song-poetry','','[]','煌煌帝王都，列第喧絲竹。',240,'全唐诗/poet.song.194000.json','["煌煌帝王都，列第喧絲竹。", "林園競選勝，四匝湖山曲。", "誰知南屏下，老叟甘幽獨。", "憶從古栝來，紅頰鬢鬢綠。", "王侯爭倒屣，交友爲屬目。", "引觴百壺倒，授簡千穎禿。", "功名良誤人，日月如轉轂。", "侵尋四十年，一往不可復。", "浮雲玩身世，投老寄僧屋。", "堅忍不苟求，趺坐淡無欲。", "人生固幻夢，要須有歸宿。", "買山豈不念，探囊一捧腹。", "舊交上連璧，情未忘伐木。", "蘇臺香正凝，寶婺駕已夙。", "談笑百金揮，拮据三間足。", "何妨山水窟，就訊高燥卜。", "行矣不可遲，片帆浪花蹙。", "歸來督工師，涓選亟營築。", "開軒納雲水，繞檻藝松菊。", "身閒心自平，長把黄庭讀。"]'),
('e9a250aa-b0b3-4bf3-87e0-df393b8f0ab9','三伏中積雨如秋','程公許','宋','宋诗','song-poetry','','[]','峨眉三日雨，客館六月秋。',132,'全唐诗/poet.song.194000.json','["峨眉三日雨，客館六月秋。", "幽懷無與娛，欹枕清夜遊。", "炎官失聲勢，萬木皆商謳。", "一涼德我厚，耿耿何隠憂。", "憂多白人頭，頭白可復休。", "積陰忤正氣，潢流冒崇邱。", "世故莽難期，病根寧易瘳。", "履霜不知戒，堅冰諒難尤。", "天運不停機，明當火西流。", "勿以餘熱在，而忘晚歲謀。", "家貧迫短晷，及時戒衣裘。"]'),
('d2084463-f4d4-4ab9-85c4-4550edc65a5f','縣圃蓮花方開同時木犀吐芳劉光遠仙尉賦詩爲和韻','程公許','宋','宋诗','song-poetry','','[]','季夏苦積陰，泥逕殊窘步。',120,'全唐诗/poet.song.194000.json','["季夏苦積陰，泥逕殊窘步。", "彼姝水花紅，媚此晴色暮。", "邂逅小山桂，纔洗仙掌露。", "相携齋閣來，不著丹鉛污。", "杲之與黄香，胡爲此同聚。", "向來古錦九，散落不知數。", "吟腸久荒澁，幽賞但默喻。", "殷勤吳市仙，能供巖壑趣。", "詩味淡愈佳，交情凝有素。", "我願同蔦蘿，得與長松附。"]'),
('bbd75981-d343-4226-a92a-e525dbc2a489','十四日同張伯修羅堅甫大智賞月探韻即事感興殊激懦衷翌日會保福辱詩示教借張大韻同賦','程公許','宋','宋诗','song-poetry','','[]','涉秋苦多陰，嬋娟喜見乍。',228,'全唐诗/poet.song.194000.json','["涉秋苦多陰，嬋娟喜見乍。", "天巧竟作難，借此三五夜。", "屯雲滃四面，如騖俗士駕。", "寶坊盍朋簪，尊酒共清話。", "諸君讀書眼，明不失纖罅。", "天眼物昏之，誰爲彎弓射。", "連宵耿孤吟，虛窗自高挂。", "竹風靜逾爽，露葉燦可畫。", "夢踏市橋去，醉眠僧榻借。", "陰晴且勿言，幽賞可能罷。", "恨欠截老龍，三弄倚風榭。", "酒酣歌慨慷，四坐勿渠詫。", "邊塵日澒洞，志士惜閒暇。", "君看古聖賢，憂樂以天下。", "持此閲人多，何但如傳舍。", "短氣吐復吞，欲言恐遭駡。", "徑思投紱去，甘老漁樵社。", "世論熟脂韋，人物歎衰謝。", "相期崇令猷，蘭鮑觀所化。"]'),
('03dae60c-77a1-4645-8dfc-0fb014e74bf4','重陽後一日親友會飲於滄洲以初九未成旬重陽即此辰探韻得初未二字  其一','程公許','宋','宋诗','song-poetry','','[]','雅志厭闤闠，考槃樂郊墟。',156,'全唐诗/poet.song.194000.json','["雅志厭闤闠，考槃樂郊墟。", "言歸憩桑梓，不憚躬拮据。", "歲晚此棲宿，佳氣鬰扶輿。", "淫雨度陽節，晴雲吐月梳。", "獨酌良亦佳，所思在羣居。", "晨興喜復晴，草具何可徐。", "黄花有餘馥，白酒無多儲。", "清灘蟄雷吼，輕霞綵幄舒。", "翳然林水間，舒嘯天籟虛。", "雪髯醉先起，衆賓且躊躇。", "人生有定分，適意不願餘。", "衣食粗能給，吾當賦遂初。", "相期晚節堅，結社同樵漁。"]'),
('d09b913a-7d97-405f-b3db-6d8024d2eb76','重陽後一日親友會飲於滄洲以初九未成旬重陽即此辰探韻得初未二字  其二','程公許','宋','宋诗','song-poetry','','[]','風露澹秋容，汀洲肅秋氣。',156,'全唐诗/poet.song.194000.json','["風露澹秋容，汀洲肅秋氣。", "吾廬倚高寒，遊目周品彙。", "既空買山資，恨欠除堂費。", "醪觴漾籬菊，淺酌殊有味。", "蜜餌雜園蔬，何妨食之既。", "興酣一憑眺，情感怱累愾。", "裔夷恃天驕，邊關猶鼎沸。", "殺氣纏慘澹，將材乏沈毅。", "吁嗟楚芡荒，遑恤頃筐暨。", "腐儒拙料事，積憂漫如蝟。", "伊昔賢哲人，用智奔流未。", "駟隙詎容追，蟻潰可不畏。", "索裘已較晚，寒機密經緯。"]'),
('b8cc5d85-5db7-4e26-a89c-ae664f6124b0','過房公湖臨發廣文載酒登南樓聽隠士陳希逸彈琴讀鴈湖先生詩及悅齋先生賦','程公許','宋','宋诗','song-poetry','','[]','湖蕩匝城府，堤柳一徑通。',240,'全唐诗/poet.song.194000.json','["湖蕩匝城府，堤柳一徑通。", "森戟晝漏永，闃如墟野中。", "掣鈴三日留，鬰鬰殊寡悰。", "登埤展遐眺，盪我磊磈胸。", "溝畦磨衲麗，烟蕪圖采工。", "廣文一尊酒，邂逅清賞同。", "慨昔石林老，小駐雙旌紅。", "燕坐鳬鶩退，行散龜鶴從。", "得句陵子美，高世猶房公。", "想此據胡牀，長嘯延清風。", "想此躡珠履，和月吸酒鍾。", "想此援采毫，醉題揖遥峰。", "想此披綺裘，憑高目征鴻。", "逸駕渺難追，風光爲誰容。", "空餘翰墨香，披拂葭葦叢。", "翠琰子由賦，正聲響笙鏞。", "千年古徐州，綺疏貫晴虹。", "過眼不再讀，恨我性識蒙。", "喬木噪晚鴉，低囘馬首東。", "綠綺有餘韻，因之訊仙翁。"]'),
('ee6ca2d3-125e-4f04-bf4b-41d0796b42eb','送安少愚下第東歸','程公許','宋','宋诗','song-poetry','','[]','去年遊凌雲，傳觀一篇書。',288,'全唐诗/poet.song.194000.json','["去年遊凌雲，傳觀一篇書。", "問客誰所作，作者安少愚。", "少愚賓城人，萬里走東吳。", "憫俗日搶攘，正途欲荒蕪。", "磊塊不能平，憂憤何當攄。", "推枕一長歎，落筆萬字餘。", "才難繆取舍，政棼費爬梳。", "國讎不可忘，儲德要力扶。", "肝膈無留藏，首末詳繹鋪。", "吾豈貪狥名，致主於唐虞。", "書成詣匭投，甘心斧鉞誅。", "九天隔雲雨，萬目爭睢盱。", "聖恩不忍殺，放使歸田廬。", "我心日起敬，未見長欷歔。", "今年科詔頒，君來試成都。", "邂逅忽傾蓋，名下信不虛。", "貌不踰中人，若爲膽滿軀。", "革囊三尺劍，束書一蹇馿。", "蹙頞談世事，抵掌嗤俗儒。", "慨慷三策陳，傲睨衆口諛。", "諸公眼如月，誰遣紫奪朱。", "少愚囅然笑，得失毫髮如。", "行止諒由天，通塞何關渠。", "歸歟三間茅，搜我萬卷儲。"]'),
('2c6c425d-9ef3-4608-bf0d-23ca3fa258a6','贈吳郡諸居士','程公許','宋','宋诗','song-poetry','','[]','終南徑甚捷，結茆鄰帝鄉。',144,'全唐诗/poet.song.194000.json','["終南徑甚捷，結茆鄰帝鄉。", "朝爲谷口翁，暮爲省中郎。", "先生獨何事，寄傲臨滄浪。", "才高世莫染，德薰名自香。", "青黄分誰數，膏火竟堪傷。", "遊心聖賢域，脫身憂患場。", "世路雖齟齬，天衢自騰驤。", "捫虱竟誰見，卧龍興何長。", "借居仲奄里，未升公德堂。", "十年逐流擯，千里坐相忘。", "頹齡或可借，辟穀豈無方。", "終期繼青蓮，摇筆頌紫陽。"]'),
('387cc778-c33b-4ab7-a041-750ac4607559','過眉山謁鄉耆宿李八丈提刑','程公許','宋','宋诗','song-poetry','','[]','憶昔下吳會，拜公古渝州。',168,'全唐诗/poet.song.194000.json','["憶昔下吳會，拜公古渝州。", "別來忽星紀，不知幾三秋。", "豈不願舂糧，占烏渠渠屋。", "良期苦難儷，千里勞遠目。", "公家難兄弟，與蜀關重輕。", "峨眉疊連娟，石筍屹崢嶸。", "維國有著龜，維士有司命。", "並生天地間，受命獨也正。", "憂端日搶攘，世論滋軟熟。", "誰謂空谷遠，有美人如玉。", "我如南州橘，托根非不深。", "踰淮恐成枳，望遠勞我心。", "鮐背髮皤然，齒頰探骨鯁。", "跪履乞一言，書紳以自儆。"]'),
('3c71b069-14c2-4898-8998-bf933e346006','述志','程公許','宋','宋诗','song-poetry','','[]','仙曹寄江干，吏隠適吾願。',156,'全唐诗/poet.song.194000.json','["仙曹寄江干，吏隠適吾願。", "西軒館梅友，屋老狸鼠覘。", "坐令高世姿，不耐塵網罥。", "殷勤數問訊，餘力稍營繕。", "八窗敞虛明，孤標對老健。", "佇立慘澹中，恍覺容采絢。", "天風發奇芬，霜月潑冷艷。", "官卑苟逃責，交淡日相見。", "凍摇哦詩吻，堅作忍饑面。", "癡頑信可憐，無取復奚羨。", "村醪未必佳，苦味且耐嚥。", "洗醆壽親尊，春和元不欠。", "勿競桃李場，恐爲吾友玷。"]'),
('5b515d02-d074-49a1-bd27-2a3574af44be','三年銜恤絕不吟詩既奉祥祭觸緒摧裂偶得古詩三章呈叔逢兄併似彥威姪  其一','程公許','宋','宋诗','song-poetry','','[]','髧髦聯鴈隊，娛侍三老人。',72,'全唐诗/poet.song.194000.json','["髧髦聯鴈隊，娛侍三老人。", "清風一家法，歡顔四時春。", "轉爥二十年，俯仰含悲辛。", "聚散泡起滅，了知幻非真。", "忽忽如有見，耿耿恨難平。", "孝愛自天性，寧與迹俱陳。"]'),
('c3645065-699d-41db-b55d-e52193d3cfbe','三年銜恤絕不吟詩既奉祥祭觸緒摧裂偶得古詩三章呈叔逢兄併似彥威姪  其二','程公許','宋','宋诗','song-poetry','','[]','母慈不逮養，翁健長相依。',72,'全唐诗/poet.song.194000.json','["母慈不逮養，翁健長相依。", "重關一囘首，及瓜時當歸。", "平安墨未乾，諱問心有疑。", "繭足跛菅屨，高堂空繐幃。", "罔象不可索，流光倏如馳。", "五鼎嗟奚及，一生風樹悲。"]'),
('dabc6237-6b31-40f3-b250-a9d804930a10','三年銜恤絕不吟詩既奉祥祭觸緒摧裂偶得古詩三章呈叔逢兄併似彥威姪  其三','程公許','宋','宋诗','song-poetry','','[]','秋風殷巖壑，萬木皆商謳。',72,'全唐诗/poet.song.194000.json','["秋風殷巖壑，萬木皆商謳。", "棘人有餘哀，攬衣良夜遒。", "三年輟清吟，寸腸堆百憂。", "淚眥日以眵，霜根一何稠。", "棣華幸有依，竹林可俱遊。", "心事期歲晚，庶無墜前修。"]'),
('be14ea5e-fcb4-4a5b-b14f-e11f02359c92','遊仙二章上范殿撰潔菴先生  其一','程公許','宋','宋诗','song-poetry','','[]','風埃曀八表，濤瀾浩無涯。',120,'全唐诗/poet.song.194000.json','["風埃曀八表，濤瀾浩無涯。", "岧嶢崑崙峰，高與星緯排。", "真人撫元運，太虛以爲家。", "控轡下碧落，蜚步凌紫霞。", "周覽興未已，歸憩誰與偕。", "喬松撫瑶瑟，偓佺薦瓊花。", "顰蹙睨塵世，腐鼠紛攫拏。", "迢遥五雲佩，蕩漾八月槎。", "我欲往從之，層雲不可階。", "素心耿相照，退當三月齋。"]'),
('4b211ce4-a228-47bd-9ba5-cb937ab1f4f7','遊仙二章上范殿撰潔菴先生  其二','程公許','宋','宋诗','song-poetry','','[]','空山學仙子，幽獨性成癖。',120,'全唐诗/poet.song.194000.json','["空山學仙子，幽獨性成癖。", "誰令一念差，失脚塵網密。", "隨緣翫泡影，隠思曉繼夕。", "了了三生夢，掣電了無跡。", "豈不志遠遊，誰爲傅羽翼。", "抱關覘紫氣，跪履問黄石。", "靜慮儻冥契，玄機詎難入。", "縞髮古仙公，遺世而獨立。", "惝恍如有遇，一言曰守一。", "引臂許相從，長生託瑶籍。"]'),
('75f202d2-938c-4bf4-a0e0-a5513a1c8d4d','送悅齋先生','程公許','宋','宋诗','song-poetry','','[]','風塵三十年，世途日險窄。',276,'全唐诗/poet.song.194000.json','["風塵三十年，世途日險窄。", "嬋娟棄土梗，倚市競容澤。", "大雅何寂寥，志士三歎息。", "維皇惠斯文，爲國永壽脉。", "靈光巋獨存，碩果有不食。", "坤維返全璧，北墅歸散策。", "天開景氣新，晴破層冰積。", "疇咨耿宵慮，圖任先耆德。", "披雲絢天章，趣駕覲宸極。", "喉舌俄申命，股肱待宣力。", "解絃未爲難，航險那可忽。", "涇渭不同流，薰蕕詎相入。", "所虞憤失職，陰拱或伺隙。", "事須衆賢和，乃可殄行堲。", "沉幾陛下聖，虛己言路闢。", "稍欣元氣充，猶慮外憂迫。", "敵情任反覆，廟論須謹密。", "功名百尺竿，家國萬金璧。", "平生一知己，瓣香無愧色。", "駑怯勉荷擔，遲頑費推激。", "大艑駕雲濤，薰風飽帆席。", "丁寧耳面命，遠別何須惜。", "寬以七月程，修門拜赤舄。"]'),
('4460f995-fb0a-47b0-90e0-dfbff14f2703','上後樂劉先生左史十首用襄陽詩兩句行藏堅晚節進退法先民爲韻  其一','程公許','宋','宋诗','song-poetry','','[]','永平昔全盛，舊學尊五更。',48,'全唐诗/poet.song.194000.json','["永平昔全盛，舊學尊五更。", "惜哉趨舍繆，眩眼車服榮。", "恭惟自孔氏，時止亦時行。", "心泰無不足，外內誰重輕。"]'),
('4b5c189c-beed-41b6-848a-fcb836304e28','上後樂劉先生左史十首用襄陽詩兩句行藏堅晚節進退法先民爲韻  其二','程公許','宋','宋诗','song-poetry','','[]','峩豸凜霜簡，立螭迫荷囊。',48,'全唐诗/poet.song.194000.json','["峩豸凜霜簡，立螭迫荷囊。", "從渠衆醉酣，我自深林芳。", "歲晚髮雪白，德稱腰鞓黄。", "世無香山老，誰與論行藏。"]'),
('f3073aea-0107-419a-8b5b-bd1d204ffa2a','上後樂劉先生左史十首用襄陽詩兩句行藏堅晚節進退法先民爲韻  其三','程公許','宋','宋诗','song-poetry','','[]','前谿文緯國，東谿學草玄。',48,'全唐诗/poet.song.194000.json','["前谿文緯國，東谿學草玄。", "補處自天授，絕韋待誰編。", "淵源後谿水，脈絡千載傳。", "茲事端不朽，松石同其堅。"]'),
('109988e2-c4a7-4acc-9780-54273a92174e','上後樂劉先生左史十首用襄陽詩兩句行藏堅晚節進退法先民爲韻  其四','程公許','宋','宋诗','song-poetry','','[]','厚德最耐看，士當論志遠。',48,'全唐诗/poet.song.194000.json','["厚德最耐看，士當論志遠。", "沄沄物歸根，混混泉有本。", "眼明長庚曉，心知歲華晚。", "後生須榘矱，所願加餐飯。"]'),
('294833b7-bca5-47eb-9be5-147831a5e623','上後樂劉先生左史十首用襄陽詩兩句行藏堅晚節進退法先民爲韻  其五','程公許','宋','宋诗','song-poetry','','[]','鹿門憶龐公，栗里懷靖節。',48,'全唐诗/poet.song.194000.json','["鹿門憶龐公，栗里懷靖節。", "我嘗評斯人，用則同稷契。", "空谷倚逍遥，風塵俱騷屑。", "明發耿不寐，長歌彌激烈。"]'),
('bc3aae4d-8d1e-4eda-bc15-2c0b48f2d0ee','上後樂劉先生左史十首用襄陽詩兩句行藏堅晚節進退法先民爲韻  其六','程公許','宋','宋诗','song-poetry','','[]','事往置勿言，積厚報豈恡。',48,'全唐诗/poet.song.194000.json','["事往置勿言，積厚報豈恡。", "毫眉兩山尊，照眼雙璧潤。", "衮衮生公侯，世佩斯文印。", "譬之水盈科，吾方見其進。"]'),
('5f7bb17b-f998-4b9a-a2c3-8d1c8cf3b6d3','上後樂劉先生左史十首用襄陽詩兩句行藏堅晚節進退法先民爲韻  其七','程公許','宋','宋诗','song-poetry','','[]','楚都初拜公，里門跪承誨。',48,'全唐诗/poet.song.194000.json','["楚都初拜公，里門跪承誨。", "一言忽喚醒，頓首汗浹背。", "志遠苦力短，寸進而尺退。", "大書揭齋顔，朝夕警不逮。"]'),
('9b20e4d3-abaf-492b-af9b-77cabfafede7','上後樂劉先生左史十首用襄陽詩兩句行藏堅晚節進退法先民爲韻  其八','程公許','宋','宋诗','song-poetry','','[]','月冷塞垣刁，塵暗西風箑。',48,'全唐诗/poet.song.194000.json','["月冷塞垣刁，塵暗西風箑。", "所思天一方，飄飄管寧帢。", "我欲往從之，問以安樂法。", "雲深波浩蕩，定自鷗鳥狎。"]'),
('19b9bce6-60eb-4838-932b-eef877a30ec7','上後樂劉先生左史十首用襄陽詩兩句行藏堅晚節進退法先民爲韻  其九','程公許','宋','宋诗','song-poetry','','[]','千載嗣韓統，斯文諒關天。',48,'全唐诗/poet.song.194000.json','["千載嗣韓統，斯文諒關天。", "字衮失所歸，何以革其先。", "陟屺有遺恨，琢石圖方鎸。", "百拜涕綆縻，萬一彤史傳。"]'),
('c88d10d2-9220-45e3-aac3-2e4485dde47b','上後樂劉先生左史十首用襄陽詩兩句行藏堅晚節進退法先民爲韻  其一○','程公許','宋','宋诗','song-poetry','','[]','負米困風塵，靦顔白頭親。',48,'全唐诗/poet.song.194000.json','["負米困風塵，靦顔白頭親。", "歎息執戈苦，走也猶幸民。", "依依孔牆夢，拍拍芹水春。", "安得萬里風，駕予往問津。"]'),
('13f92f83-b757-4a2e-999b-06e980cf1f5b','和大著何兵部  其一','程公許','宋','宋诗','song-poetry','','[]','何侯起膠庠，巋立諸老後。',96,'全唐诗/poet.song.194000.json','["何侯起膠庠，巋立諸老後。", "霜空茂檜栢，驚秋笑蒲柳。", "平生經世心，短舞困長袖。", "白頭謁承明，彩闥炳郎宿。", "去國一漁舟，順風輕放溜。", "寒花耀荒寒，靈芝茁腐朽。", "身閒澹無慮，歲熟宜釀酒。", "更將自性觀，妙契得無漏。"]'),
('33858267-56d4-415c-b637-3c7224dda582','和大著何兵部  其二','程公許','宋','宋诗','song-poetry','','[]','憶昔歲云暮，言趨君子堂。',96,'全唐诗/poet.song.194000.json','["憶昔歲云暮，言趨君子堂。", "昕班偶同歸，三度金節涼。", "木天並英遊，東壁分餘光。", "日者對宸扆，直聲動巖廊。", "豈不志歸田，胡遽喧巧簧。", "別久花竹秀，山積書傳香。", "時無塵外交，若許令支郎。", "願言從之遊，珪璧保聞望。"]'),
('bd3dd3a5-ca56-47b7-a5a1-608fec9555ba','和廬陵士尹八俊投贈韻','程公許','宋','宋诗','song-poetry','','[]','白苧裁春衫，京塵可得緇。',168,'全唐诗/poet.song.194000.json','["白苧裁春衫，京塵可得緇。", "一麾江海去，何成復何虧。", "馳驅兩輪朱，蕭騷雙鬢絲。", "所欣歲功就，千里春臺熙。", "素念恥伐檀，煩政戒楚茨。", "同心何自來，邂逅得我師。", "金華仙去遠，文其不在茲。", "諸公競唐體，頹流誰檝維。", "命將騷雅壇，幸子無牢辭。", "爲我緩節歌，紓我商謳悲。", "邊塵塞鄉國，介鱗語侏𠌯。", "登樓仲宣賦，遣興子美詩。", "懷歸自無計，慘戚將奚爲。", "排雲天九重，抒我危苦詞。"]'),
('c451e264-8a4f-4b2e-9cb1-84c40c4a327c','壽張敬立二首  其一','程公許','宋','宋诗','song-poetry','','[]','高堂八十親，備福九五疇。',48,'全唐诗/poet.song.194000.json','["高堂八十親，備福九五疇。", "虎節安山國，鴈序班霜秋。", "積善有源委，觸目皆琳璆。", "一笑壽觴舉，背蘐可忘憂。"]'),
('693bc3a3-cd2e-40ac-adca-19dbe2396c6e','壽張敬立二首  其二','程公許','宋','宋诗','song-poetry','','[]','育德譬源泉，務學如農疇。',48,'全唐诗/poet.song.194000.json','["育德譬源泉，務學如農疇。", "盈科會歸海，力穡當有秋。", "期君懋遠業，東序陳大璆。", "對敭竭忠鯁，一洗宵旰憂。"]'),
('c317105f-5f15-4b76-a6aa-796213d86bec','上憲使張郎中壽借西山集中甲申秋所賦雨荷詩韻','程公許','宋','宋诗','song-poetry','','[]','榮途驚一世，志士獨苦心。',132,'全唐诗/poet.song.194000.json','["榮途驚一世，志士獨苦心。", "君看曲江公，中宵梁父吟。", "豈無平反笑，可使貫索沉。", "獨醒睨衆醉，枉尺那直尋。", "世事本前期，朱明多盛陰。", "氣運有伸屈，扶持要賢能。", "金甌一擲誤，天步深淵臨。", "瓊圃擷衆芳，願以遺美人。", "繡斧岷雪外，閶闔雲海深。", "請彈薰風絃，再拜壽斝斟。", "功名儻來耳，一念君與親。"]'),
('965d746f-eda0-4d37-8dae-1570e14cb85e','壽憲使江寺簿八首以座右公廉勤謹忠信和緩八字爲韻  其一','程公許','宋','宋诗','song-poetry','','[]','並生宇宙間，分殊理則同。',48,'全唐诗/poet.song.194000.json','["並生宇宙間，分殊理則同。", "訂頑有明訓，造化與同功。", "心腹與手足，疴癢均我躬。", "皇皇一仁字，天下皆爲公。"]'),
('038e7c5d-4f82-4faf-8c82-3c34a0f851ca','壽憲使江寺簿八首以座右公廉勤謹忠信和緩八字爲韻  其二','程公許','宋','宋诗','song-poetry','','[]','人心無底谷，貪求何自饜。',48,'全唐诗/poet.song.194000.json','["人心無底谷，貪求何自饜。", "徇名膏火熬，徇財刀蜜甜。", "受命獨也正，取造物者廉。", "孤竹有世守，範防無乃嚴。"]'),
('5bc7b42e-2a10-4d8d-97ff-46ac44b9132b','壽憲使江寺簿八首以座右公廉勤謹忠信和緩八字爲韻  其三','程公許','宋','宋诗','song-poetry','','[]','咸池浴曉光，西汜俄夕曛。',48,'全唐诗/poet.song.194000.json','["咸池浴曉光，西汜俄夕曛。", "流景寧我貰，用志可不勤。", "王事念靡盬，聖恩期策勳。", "歲晚須糗糧，及時力耕耘。"]'),
('338b598d-5fa8-4260-b0a4-2d1ea89f0f56','壽憲使江寺簿八首以座右公廉勤謹忠信和緩八字爲韻  其四','程公許','宋','宋诗','song-poetry','','[]','吾師孔子孫，云莫見乎隠。',48,'全唐诗/poet.song.194000.json','["吾師孔子孫，云莫見乎隠。", "所以盡性學，必於獨也謹。", "兩間陟降異，一念堂奧近。", "何但丹筆持，能使明克允。"]'),
('7a3fdf62-d620-46bc-8f6d-b5d6aec6c8d7','壽憲使江寺簿八首以座右公廉勤謹忠信和緩八字爲韻  其五','程公許','宋','宋诗','song-poetry','','[]','乾坤奠崇卑，君臣分則同。',48,'全唐诗/poet.song.194000.json','["乾坤奠崇卑，君臣分則同。", "中心一有慊，何以字曰忠。", "孔曾爲榘矱，伊周其事功。", "千載誰嗣音，我願順下風。"]'),
('c94c8b1c-564c-4b80-8659-be474e7b1191','壽憲使江寺簿八首以座右公廉勤謹忠信和緩八字爲韻  其六','程公許','宋','宋诗','song-poetry','','[]','豚魚自物耳，猶可孚以信。',48,'全唐诗/poet.song.194000.json','["豚魚自物耳，猶可孚以信。", "疑心一芥我，相靡而相刃。", "君看易中孚，義取說而巽。", "虛心竊實理，可不精體認。"]'),
('5afd69e9-e301-499f-9629-c94aab9c299a','壽憲使江寺簿八首以座右公廉勤謹忠信和緩八字爲韻  其七','程公許','宋','宋诗','song-poetry','','[]','和與同近似，同乃異於和。',48,'全唐诗/poet.song.194000.json','["和與同近似，同乃異於和。", "九官遜虞廷，儆戒而賡歌。", "不然水濟水，後患將如何。", "期公調鼎食，一柱障頹波。"]'),
('86e2f1ef-96d5-4538-9573-8bfbfe0b6f8f','壽憲使江寺簿八首以座右公廉勤謹忠信和緩八字爲韻  其八','程公許','宋','宋诗','song-poetry','','[]','緩有用有體，事須明眼看。',48,'全唐诗/poet.song.194000.json','["緩有用有體，事須明眼看。", "用欲行而宜，體則偏於緩。", "射審固而發，斯理一以貫。", "仁靜壽可占，巧歷那得算。"]'),
('dfb4b074-35b5-4a6e-90a8-d6a3ac2d7b8d','上游參預壽二首  其一','程公許','宋','宋诗','song-poetry','','[]','並生覆載間，肖翹無小大。',120,'全唐诗/poet.song.194000.json','["並生覆載間，肖翹無小大。", "陰陽所發舒，榮瘁各變態。", "若爲壽命獨，厥有松柏檜。", "鬰鬰被澗阿，童童狀車蓋。", "神明扶正直，霜雪表堅耐。", "豈不願擁腫，而使匠石愛。", "大厦須柱撐，寧免萬牛載。", "一柱屹擎天，羣生此依頼。", "尚念楹桷材，無可柞棫拔。", "風雨任震凌，安宅遍宇內。"]'),
('005f7168-2f4b-4187-af87-5377897a84fd','上游參預壽二首  其二','程公許','宋','宋诗','song-poetry','','[]','河流貫陝虢，底柱自中立。',120,'全唐诗/poet.song.194000.json','["河流貫陝虢，底柱自中立。", "江水迸瞿唐，灧澦制其溢。", "豈此一拳多，雲根閟奇質。", "檜柏相因依，烟霞老山澤。", "閟世縱堅久，於人果奚益。", "漲洪彌八埏，睨視如己溺。", "巖巖國嵩岱，萬仞峙鐵壁。", "隻手障狂瀾，九鼎奠磐石。", "我自不動心，深根而寧極。", "還歸金泉山，采藥鍊金液。"]'),
('eb402a55-12e0-4cfe-8e05-0cc008c2e1bd','壽曹大博以東憲臺治新築亭館扁榜寄意 詠歸亭','程公許','宋','宋诗','song-poetry','','[]','聖道如太極，品彙自生成。',108,'全唐诗/poet.song.194000.json','["聖道如太極，品彙自生成。", "二人各言志，點也心和平。", "春風發高詠，懷哉沂水濱。", "千載寄遐思，光景無邊春。", "一潭鑑寒碧，方寸洞虛明。", "執卷恍瞻前，舍瑟鏗有聲。", "勿遣柱後文，醨我春風醇。", "穹舞麗景舒，琴歌南薰清。", "誰知此中樂，天理皆流行。"]'),
('b3d33109-a92f-4e7b-a9b9-2b73793fdeb8','壽曹大博以東憲臺治新築亭館扁榜寄意 垂光亭','程公許','宋','宋诗','song-poetry','','[]','蔚藍水中天，岧嶢千萬重。',108,'全唐诗/poet.song.194000.json','["蔚藍水中天，岧嶢千萬重。", "樓觀聳烟霞，光景浮星虹。", "天上老仙伯，萬劫冰雪容。", "笑下金華山，長歌唳霜鴻。", "一去五百年，山頭忽重逢。", "身衣直指繡，神超蓬海東。", "摇蕩瓊臺光，拍浮玻瓈鍾。", "瓊臺縱可樂，虞庭渴夔龍。", "丹鳳銜詔來，入侍甘泉宮。"]'),
('54d7ea7c-d523-4184-ae8d-c7dba27f926f','壽曹大博以東憲臺治新築亭館扁榜寄意 鶑花世界','程公許','宋','宋诗','song-poetry','','[]','涪江駛清瀏，四山玉連環。',108,'全唐诗/poet.song.194000.json','["涪江駛清瀏，四山玉連環。", "中有一掌平，萬井浮晴烟。", "鶑花隨世界，妙語發天慳。", "公來抉其秘，作堂娛燕閒。", "襲芳皆俗好，伐木友士賢。", "念昔白波洶，止沸談笑間。", "熙熙春臺樂，誰知有今年。", "初度沸歡謠，願公眉壽延。", "移此世界春，浩蕩彌八埏。"]'),
('f33b6892-2196-4abd-a542-0ed616e905ad','壽喬平章三首  其一','程公許','宋','宋诗','song-poetry','','[]','岧嶢崑崙顛，縹緲虛皇宅。',84,'全唐诗/poet.song.194000.json','["岧嶢崑崙顛，縹緲虛皇宅。", "下睨四大洲，何啻一塵積。", "萬類託其間，擾擾無暫息。", "强弱互吞噬，殺氣干斗極。", "虛皇燕五雲，憑軒慘不懌。", "絳節授金童，瓊函探寶冊。", "運會有度期，欲藉老仙伯。"]'),
('f258ceee-8e31-4306-95e8-1f0e2efbd4cf','壽喬平章三首  其二','程公許','宋','宋诗','song-poetry','','[]','老仙何自來，文焰貫東壁。',84,'全唐诗/poet.song.194000.json','["老仙何自來，文焰貫東壁。", "八十五春秋，骨健神氣溢。", "權衡有定度，蓍蔡無遺策。", "若非安期生，定是李八百。", "堅苦海津梁，壽斯文命脉。", "后皇大所畀，陶冶妙無迹。", "故山豈不思，老屋須柱石。"]'),
('3a5f9ba5-a948-4e22-a290-3a00e379a6f6','壽喬平章三首  其三','程公許','宋','宋诗','song-poetry','','[]','屋老當奈何，風雨撼四壁。',84,'全唐诗/poet.song.194000.json','["屋老當奈何，風雨撼四壁。", "主公志經營，所頼有匠石。", "度材林藪幽，計土帑廥積。", "心思妙規製，指授契繩尺。", "逮其萬間具，夫豈一人力。", "柱天紀元功，眉壽永無極。", "周宣當中興，拜手歌考室。"]'),
('d6affd4e-33ca-49d6-af5a-5917c1cbf52a','屏居北郊自秋涉冬絕省人事觸緒有感託之諷吟書雲前一日緝成八章寓興抒情非以言詩也  其一','程公許','宋','宋诗','song-poetry','','[]','氣運有盈虛，品物迭滋耗。',96,'全唐诗/poet.song.194000.json','["氣運有盈虛，品物迭滋耗。", "人生於兩間，誰能長不老。", "胡爲翫鮮榮，而獨恨枯槁。", "婉孌兒女態，愛惜容色好。", "志士競修名，覽鏡慨華皓。", "所念固有殊，達觀同一笑。", "本來真妙明，何有少壯老。", "茲理非言傳，惟心自深造。"]'),
('63a0cc9b-983b-4f5a-a80d-ad2a77659fff','屏居北郊自秋涉冬絕省人事觸緒有感託之諷吟書雲前一日緝成八章寓興抒情非以言詩也  其二','程公許','宋','宋诗','song-poetry','','[]','斷梗得棲泊，高堂擁圖書。',84,'全唐诗/poet.song.194000.json','["斷梗得棲泊，高堂擁圖書。", "中宵風露氣，營我方寸軀。", "靜慮何易感，有銜莫能袪。", "今古一瞬息，智愚等丘墟。", "戰奪日相尋，死生互吞屠。", "念此耿無寐，推枕長嗟吁。", "天理諒好還，人謀何可疏。"]'),
('be0eab60-a575-415e-a9a2-0dab2781edae','屏居北郊自秋涉冬絕省人事觸緒有感託之諷吟書雲前一日緝成八章寓興抒情非以言詩也  其三','程公許','宋','宋诗','song-poetry','','[]','宿嗜本幽閒，世途倦馳騁。',108,'全唐诗/poet.song.194000.json','["宿嗜本幽閒，世途倦馳騁。", "迫茲門戶託，强把冠佩整。", "招手誤一來，麾退諒予警。", "寬恩假郡寄，靜俟亦天幸。", "橐空歸無家，旅泊仰微廩。", "如聞爛柯谷，宛似飛仙境。", "苦饑問豹胎，留渴須遠井。", "天將厚所畀，吾寧不少忍。", "睡起一欠伸，篆烟凝晝永。"]'),
('2e03ce6a-5b88-444b-b935-c85634c91a07','屏居北郊自秋涉冬絕省人事觸緒有感託之諷吟書雲前一日緝成八章寓興抒情非以言詩也  其四','程公許','宋','宋诗','song-poetry','','[]','口爲禍之穽，異者同之仇。',96,'全唐诗/poet.song.194000.json','["口爲禍之穽，異者同之仇。", "誰能噤不語，兀兀如羈囚。", "我豈好違俗，心未忘好修。", "本不慕華顯，寧有忮與求。", "逍遥鵬鷃同，貧賤非所羞。", "風濤漲平陸，駕予一虛舟。", "未如泯機智，鷗鳥與之游。", "吾今已得師，稽首漆園周。"]'),
('0694d584-cd99-4bc6-aac8-3465f3267990','屏居北郊自秋涉冬絕省人事觸緒有感託之諷吟書雲前一日緝成八章寓興抒情非以言詩也  其五','程公許','宋','宋诗','song-poetry','','[]','鳥飛暮知還，螘微亦有藏。',84,'全唐诗/poet.song.194000.json','["鳥飛暮知還，螘微亦有藏。", "遊子悵無託，故鄉那得忘。", "轒轀歲橫騖，生涯日淒涼。", "骨肉各竄匿，冢祠缺烝嘗。", "萬里一緘書，臨風淚千行。", "垂白念汝兄，憂樂苦相望。", "安得附羽翮，奮飛同一觴。"]'),
('59b89ca1-b768-40cb-aa0a-fe82e4b53766','屏居北郊自秋涉冬絕省人事觸緒有感託之諷吟書雲前一日緝成八章寓興抒情非以言詩也  其六','程公許','宋','宋诗','song-poetry','','[]','西陲失支吾，如老屋積腐。',96,'全唐诗/poet.song.194000.json','["西陲失支吾，如老屋積腐。", "牆闥縱蹂躪，堂屋何依怙。", "伊誰階此厲，乃爲元老誤。", "疾痛切吾身，利鈍難逆睹。", "瘴暑困新恩，隕星泣忠武。", "梁壞將安仰，天高杳難訴。", "向來十二樓，捲簾誤一顧。", "灑淚嫁時衣，誰與論心素。"]'),
('a3317984-eae6-4f14-b848-611389e3ec52','屏居北郊自秋涉冬絕省人事觸緒有感託之諷吟書雲前一日緝成八章寓興抒情非以言詩也  其七','程公許','宋','宋诗','song-poetry','','[]','坤維以文瑞，民俗本柔淑。',108,'全唐诗/poet.song.194000.json','["坤維以文瑞，民俗本柔淑。", "何代無戰爭，冤哉今爾酷。", "戎馬塞里墟，劫鈔遍林谷。", "平生金石交，屈指半鬼錄。", "從子尤可哀，別歸奉水菽。", "伯姪併戕殞，荼毒復荼毒。", "探囊數幅書，吞聲不忍讀。", "崑崗焮烈焰，寧辨石與玉。", "叩首一爐香，請爲遺黎贖。"]'),
('fde8aba2-3ec5-4ad9-8977-04ce01fd10d3','屏居北郊自秋涉冬絕省人事觸緒有感託之諷吟書雲前一日緝成八章寓興抒情非以言詩也  其八','程公許','宋','宋诗','song-poetry','','[]','南山翠鬅鬙，四荔拱故宅。',96,'全唐诗/poet.song.194000.json','["南山翠鬅鬙，四荔拱故宅。", "采衣侍三壽，教愛如夙昔。", "曉然一夢闌，無復萬里隔。", "了知恩愛縛，障我修行力。", "亦嘗勤遍參，漸欲空結習。", "妄念絕攀援，自性非假借。", "百千三昧門，惟此一事實。", "持問諸老禪，少露真消息。"]'),
('1220a0ec-0735-4287-8278-a1a5bb82cc8e','理舟入奉大對臨發有賦','程公許','宋','宋诗','song-poetry','','[]','弱齡誦書史，所慕在經世。',144,'全唐诗/poet.song.194000.json','["弱齡誦書史，所慕在經世。", "靦顔科目中，頗恨愆素志。", "天府兩貢書，恥逐時粧媚。", "諸公誤賞音，偶玷春官第。", "王明渴疇咨，臨軒有故事。", "明當鼓枻下，陛對去天咫。", "采蘭有常供，胡爲輕萬里。", "趨庭願有聞，丁寧汝其識。", "謹無曲學阿，恐作儒冠恥。", "士當志遠大，富貴餘事耳。", "百拜請書紳，誓言其敢替。", "萬古洙泗傳，豈爲青紫計。"]'),
('4ea38cb4-0791-48af-9dac-ed301b761899','良月十六日以祈晴宿齋郊壇寺僧拉登梅巖讀高孝兩朝宸翰記事','程公許','宋','宋诗','song-poetry','','[]','祝冊頒九重，郊丘以晴禱。',180,'全唐诗/poet.song.194000.json','["祝冊頒九重，郊丘以晴禱。", "小臣職駿奔，單車倦塗潦。", "崇阜踰巘崿，層壇敷秸藁。", "中興念經始，面勢若天造。", "濤雲日兩潮，幄霧山四抱。", "袍毳亦可人，杖藜共幽討。", "枯梅傲巖晚，陰壑得寒早。", "勳華昔同來，奎文絢麗藻。", "山靈沐高澤，虹彩軼晴昊。", "苔蹊幾窘步，椶榦撐健倒。", "嵌竇咽泉流，金石韻擊考。", "齋廬耿燈青，簷花垂带縞。", "苦憐風力癡，未快霾陰掃。", "排雲出烏輪，測景進黄道。", "六合還清明，烟霞願投老。"]'),
('41207204-4fbd-472d-8661-15ab3da03530','和憲使張郎中','程公許','宋','宋诗','song-poetry','','[]','四海一奇男，象賢真柬之。',132,'全唐诗/poet.song.194000.json','["四海一奇男，象賢真柬之。", "繡斧外執法，滯淹猶在斯。", "冰壑棟梁具，鳳梭雲錦機。", "粉省趨含香，璽書嗇封泥。", "生平方寸丹，雲端雙闕齊。", "小試川楫手，晒網蘆中磯。", "以道拯世溺，先事防繻袽。", "三江昔怒號，一席今淪漪。", "平波浄縠浪，祥風浹瑶池。", "八極匯濤瀾，四顧蛟涎危。", "孰能戒維楫，重與歌平夷。"]'),
('c1e8792f-40fe-44d6-b55b-02eaca1e6e9e','上茶使鄒郎中孟卿  其一','程公許','宋','宋诗','song-poetry','','[]','四海一道鄉，千古有生意。',48,'全唐诗/poet.song.194000.json','["四海一道鄉，千古有生意。", "元宗得君侯，風流是以似。", "窅然天機深，寧以物欲累。", "丈夫要如此，步步皆實地。"]'),
('be17d712-b3ca-43e9-b2a0-a72fa7d48df4','上茶使鄒郎中孟卿  其二','程公許','宋','宋诗','song-poetry','','[]','政術自學術，本來同一機。',48,'全唐诗/poet.song.194000.json','["政術自學術，本來同一機。", "後生溺華采，用世理或違。", "恭惟自孔氏，六籍探指歸。", "心清事自簡，吏瘠民則肥。"]'),
('6749ac4a-61aa-439f-885a-2ce13a8688b4','上茶使鄒郎中孟卿  其三','程公許','宋','宋诗','song-poetry','','[]','忍話去年事，令我膽欲碎。',48,'全唐诗/poet.song.194000.json','["忍話去年事，令我膽欲碎。", "公獨於此時，砥柱衆流匯。", "事難見君子，爾曹費車載。", "海山危風濤，當有巨鼇戴。"]'),
('68dda37c-b74b-4f91-829c-551c88710896','上茶使鄒郎中孟卿  其四','程公許','宋','宋诗','song-poetry','','[]','節傳擁玉帳，天遣西南來。',48,'全唐诗/poet.song.194000.json','["節傳擁玉帳，天遣西南來。", "怦怦朱絲繩，皎皎明鏡臺。", "稂莠亟芟夷，本根費栽培。", "度外廣物色，世豈真乏才。"]'),
('14d1d4bd-5149-4ea9-99b6-dd75e9a76f0d','上茶使鄒郎中孟卿  其五','程公許','宋','宋诗','song-poetry','','[]','廣文官獨冷，博士冗不治。',48,'全唐诗/poet.song.194000.json','["廣文官獨冷，博士冗不治。", "况此侯國泮，贅哉童子師。", "蕭散非鄭老，文章慙退之。", "可能冰雪地，一借春風吹。"]'),
('a67d870d-86cf-41e6-92fb-80ce1a45d264','喜雨上西清崔先生','程公許','宋','宋诗','song-poetry','','[]','東皇司發生，何以忽僤怒。',204,'全唐诗/poet.song.194000.json','["東皇司發生，何以忽僤怒。", "旱乾遍兩川，陰陽錯常度。", "侍晨秉清德，方嶽煩卧護。", "隠憂切四體，曉夕煎百慮。", "尪暴奚以爲，丘禱元有素。", "皇明一頷首，膏澤倏如霔。", "豐隆鼓增氣，耕父愁失據。", "苧桑鬰華滋，餠餌當厭飫。", "乃知天九重，不隔香一炷。", "宇宙滿戈甲，椎剝劇刀鋸。", "殺氣慘未除，衆慼那得籲。", "毋以休咎徵，諉曰水旱數。", "憂端轉搶攘，邦本須愛護。", "願公遲東歸，爲帝寬西顧。", "以萬金良藥，起衆兆沉痼。", "使民安農疇，櫜弓藏武庫。", "爲霖澤四海，媲迹商巖傅。"]'),
('f3377d55-cf9d-4b3b-ae36-693799d545ef','工侍國史奉御香禱雪上竺前一夕雪瑞已應道間志喜成詩以示敬借韻同賦','程公許','宋','宋诗','song-poetry','','[]','庚子歲維夏，亢陽一何驕。',288,'全唐诗/poet.song.194000.json','["庚子歲維夏，亢陽一何驕。", "侵尋徂暑迫，惻怛聖慮焦。", "祈禱喧三農，雩祀奔百僚。", "商飈忽以厲，老魃意愈囂。", "萬井沸湯釜，四野烜赤熛。", "俄聞罪己詔，還下中興朝。", "寶香款太一，嘉薦羞廟祧。", "移蹕給孤園，熏心梵音潮。", "芝蓋屏不御，鸞扇亦罷摇。", "還宮慘玉色，轉燭翻天瓢。", "小臣忝侍祠，囊封叩層霄。", "帝念亦勞止，暵災殊未消。", "良月始沾洽，封畿轉蕭條。", "白瑞彌渴望，沍陰那易料。", "測景展繡紋，飛霜困青要。", "麥芒鬰不吐，蔬甲半已凋。", "足蹷叢祠趨，潔蠲沉水燒。", "忱念交肸蠁，同雲散瓊瑶。", "夜窗訝明皎，曉檻俄紛飄。", "天意竟作慳，瞬息倏已消。", "冬瘟幸稍壓，蝗蟄故自饒。", "東皇趣命駕，北斗將旋杓。", "更須絮亂撥，間作珠碎跳。", "儻幸尺許積，庶幾食可邀。"]'),
('95f993ef-609d-4814-be15-f7128d72bf99','代上夔帥丁文伯','程公許','宋','宋诗','song-poetry','','[]','璧月行素空，流魄寒潭水。',252,'全唐诗/poet.song.194000.json','["璧月行素空，流魄寒潭水。", "水非與月期，月豈待濯洗。", "天光發於定，妙契元一理。", "士生無南北，樂在相知心。", "同行不同調，有如辰與參。", "一言針芥投，山水皆知音。", "畏齋天下士，執鞭愧我後。", "當時儉府蓮，最說庾公秀。", "十年一欠伸，西樓黯回首。", "油幢古夔子，鎖棘外南宮。", "寶鑑貯英裁，氈筆題至公。", "訊舊一以悽，浩蕩華表風。", "宇縣莽烟塵，人物嘆今眇。", "蘭芷閟其芳，所御或荼蓼。", "隠思不遑寐，令我憂心悄。", "古今幾枰棋，勝敗無常形。", "世豈欠國手，一著何可輕。", "但恐當局迷，渠知死可生。", "向來一寸心，行世幾濩落。", "矯性動有妨，幽思誰與豁。", "爲君歌慨慷，長風起天末。"]'),
('ddd78ddc-89c3-4907-978c-8030f7e97b84','入都一年餘舍館五遷最後得楊園空屋僻遠市囂寬潔爽塏火後莊文府以中旨攘奪倉皇徙寓奉常之寅清堂成五言長篇','程公許','宋','宋诗','song-poetry','','[]','瀆江萬里來，武林一年客。',192,'全唐诗/poet.song.194000.json','["瀆江萬里來，武林一年客。", "飄摇無定棲，一一得安宅。", "委巷遠塵囂，八窗耿虛白。", "冰曹省造請，公退味禪寂。", "乃者赤熛怒，橫爲閭井厄。", "羈貧幸我貰，安坐有慙色。", "侯門意睥睨，府檄加峻迫。", "倉皇襆衣被，包裹到書冊。", "曲臺許借居，虛堂暫休息。", "砌蛩伴宵吟，樹鴉趣晨汲。", "隨寓亦足娛，一枝更須擇。", "是身如浮雲，何所爲定跡。", "顧憐性梗野，雅嗜祇泉石。", "陳力怯荷殳，康屯况無策。", "强顔雜班綴，頗覺非本色。", "時清早得歸，永願守蓬蓽。"]'),
('0b8268db-7b62-40dd-8576-56a541194482','去歲重陽日得彥威信附六月間二小姪及從弟姪所寄書自蜀閫遞中附至歷言去冬今春所遭兵禍及有司督迫科調之苦喜其存全哀其窘蹙灑涕如霰寄訊邀其下峽而邊事又告急未知其達與否也會杪冬見邸報宣諭使者余公侍郎改命授鉞盡護蜀師意欲以此事歸控骨肉會聚茲事其諧矣喜極涕零遂成長篇','程公許','宋','宋诗','song-poetry','','[]','令節恩賜沐，把菊開清尊。',288,'全唐诗/poet.song.194000.json','["令節恩賜沐，把菊開清尊。", "天涯信音來，拆緘爲一欣。", "展視未竟幅，淚雨溢帨帉。", "辭家甫八年，邊塵覆全坤。", "平生幾親故，半爲兵死魂。", "縱脫虎口涎，亦復馬鬣墳。", "所幸二猶子，從弟偕諸孫。", "崎嶇矛戟中，偶得性命存。", "意欲守丘壠，死不去榆枌。", "是時陳理卿，受命開帥垣。", "奮身艱危際，勉圖戡濟勳。", "鏟壕峙城壁，鋤荒列營屯。", "敵至誓固守，爲力良艱勤。", "變故起肘腋，轅帳塞轒轀。", "一死事則已，萬恨誰與論。", "遺氓能幾何，天未許貸原。", "貔虎蹔斂退，寇盜還紛紛。", "哀我數子者，挈孥競驚奔。", "亦不免維縶，恐迫甚溺焚。", "掠奪幸得脫，歸來匿空村。", "生涯蕩無餘，暴斂何寡恩。", "萬里遠訴我，重我憂心熏。", "爾苦我得知，爾創我得捫。", "豈不憶松檟，歲時薦炮燔。"]'),
('771ddb6f-0ed1-425a-9809-b9c8531a741b','感事建除體二首  其一','程公許','宋','宋诗','song-poetry','','[]','建國維藝祖，受命同有虞。',144,'全唐诗/poet.song.194000.json','["建國維藝祖，受命同有虞。", "除苛五閏後，返朴邃古初。", "滿盈持以道，德澤久不渝。", "平治二百年，中原忽榛蕪。", "定亂得高皇，如日升昏衢。", "執中嗣堂播，奕葉垂範模。", "破碎今已殘，敵人踵闚𨵦。", "危哉武休破，漢沔幾丘墟。", "成功頼諸將，三蜀仍覆盂。", "收藏問何時，官已迫征輸。", "開倉儲百穀，爲我供軍須。", "閉關且堅守，民力庶少蘇。"]'),
('bad93e3a-b858-495e-bce1-3c38eb09db58','感事建除體二首  其二','程公許','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','建大將旗鼓，遴選茲維艱。',144,'全唐诗/poet.song.194000.json','["建大將旗鼓，遴選茲維艱。", "除授得其人，國勢維泰山。", "滿朝綬若若，熟謀須萬全。", "平生想衛霍，摧枯無留難。", "定論真黷武，亦足激懦孱。", "執爵酹太宮，感慨清淚潸。", "破敵豈無策，百年祇長嘆。", "危機屢反復，地險失故關。", "成敗雖運數，人謀忌訑謾。", "收民心第一，根本無創殘。", "開納智與勇，及時護風寒。", "閉口勿多言，天道諒好還。"]'),
('9ef7a2fa-0608-49fd-9d9c-ddc383311a55','木皮口紀事爲故沔戎帥何進賦也','程公許','宋','宋诗','song-poetry','','[]','驅車木皮口，地接嘉陵市。',288,'全唐诗/poet.song.194000.json','["驅車木皮口，地接嘉陵市。", "山川鬰盤紆，草木慘憔悴。", "昔在歲辛卯，大將何憨子。", "行營與賊遇，力戰遂死此。", "道逢田舍翁，款曲問所以。", "耳目親見聞，朴忠今無比。", "沉鷙老不衰，甘苦同戰士。", "以此得士心，急難不相棄。", "閫制力主和，豈虞敵情詭。", "幣篚方交馳，羽書俄狎至。", "初冬二十五，坌入我內地。", "或渡河而馳，或截路以伺。", "俄然斡腹來，陡若自天墜。", "諸軍抽摘餘，精銳能有幾。", "千兵僅烏合，轉鬭殊未已。", "可忍負將軍，同生亦同死。", "落日塵土昏，鼓寒聲不起。", "至今堆阜間，白骨猶紛委。", "語罷聲悽哽，相顧潛灑淚。", "念昔佐戎軒，世屯未云弭。", "主公極仁明，慘惻念此事。", "露章求恤典，爵子嚴廟祀。", "意將勸忠臣，爲國當盡瘁。", "儒守陳西和，武將田與李。"]'),
('0973f3b0-8bdc-4c67-bf7f-89aeee519258','祖餞三山趙茂實二首  其一','程公許','宋','宋诗','song-poetry','','[]','煌煌洛陽城，衢術萬國通。',120,'全唐诗/poet.song.194000.json','["煌煌洛陽城，衢術萬國通。", "車塵日交騖，襟期那易同。", "目成者誰歟，言笑春怡融。", "我自商聲歌，君亦手絲桐。", "西風忽以厲，高情逐雲鴻。", "輟筆金鑾坡，一麾滄海東。", "補過要汲直，草詔須陸公。", "盈庭愕相顧，蹇蹇胡不容。", "君去我獨留，我闕誰與攻。", "况復狗尾續，羞顔蓮炬紅。"]'),
('1418c9ee-4d31-4944-9250-0ab2b9a086fd','祖餞三山趙茂實二首  其二','程公許','宋','宋诗','song-poetry','','[]','三生巖壑姿，失脚紅塵踏。',120,'全唐诗/poet.song.194000.json','["三生巖壑姿，失脚紅塵踏。", "羨君得郡去，勝事踵康樂。", "雲海渺無津，烟霞互開闔。", "似聞石門蘚，猶带屐齒蠟。", "惜哉荒遊誤，竟爲時論薄。", "秉誼以事君，奚間暌與合。", "矧是侯社貴，艱哉保障託。", "宣室恐渴思，趣歸職獻納。", "我拙念請閒，鴈蕩恣飛屩。", "及君留郡齋，爲我拂塵榻。"]'),
('f00adfdc-7999-4203-9d1a-7a32a6e1dd84','送本仲聘君分韻得良字','程公許','宋','宋诗','song-poetry','','[]','國家全盛時，幅員萬里長。',288,'全唐诗/poet.song.194000.json','["國家全盛時，幅員萬里長。", "委幣到空谷，靡才不周行。", "豈其貴自珍，而病匿弗彰。", "南渡今百年，蜀遠天一方。", "彝典僅歲貢，幾人與庭揚。", "况復多沮撓，誰不甘摧藏。", "戎軒起耆哲，禮羅極精詳。", "穎脫者家父，玉質而金相。", "邂逅志念同，惻怛根本傷。", "拔尤首推轂，有詔催嚴裝。", "吾黨一吐氣，彙征類破荒。", "慨昔升璧水，瀝血籲紫皇。", "百壬眩縮頸，斯文彌耿光。", "倫魁合騫飛，吏選何回翔。", "孰知五色絲，未盡一皂囊。", "殺氣昏宇宙，洚流渺津梁。", "何以却外侮，盍先正皇綱。", "翕合賢德聚，更須股肱良。", "壽脈庶可續，客邪不難防。", "癙思耿宵寤，傾耳鳴朝陽。", "名節勉自立，官職那得忙。", "大難我同榜，諸老競剡章。", "渠豈州縣材，籍甚英俊場。", "相期上連璧，少待同飛航。"]'),
('a47d695c-e990-4193-ac62-54d44023ee5e','以堰事走永康宿金馬早行見雪山排霄極明麗因感行役之苦邛守程叔達郎中便民五事欲牛溪轉船朝廷下其議於帥臣監司不知衆議僉諧否也','程公許','宋','宋诗','song-poetry','','[]','雨響清客夢，雨晴催客行。',132,'全唐诗/poet.song.194000.json','["雨響清客夢，雨晴催客行。", "迥野曉寥落，界天玉崢嶸。", "銀海眩雙照，瓊鈎對孤明。", "英雲强吐吞，杲日還晶熒。", "邂逅得奇觀，瞻相愜幽情。", "意疑邃古初，立極扶西傾。", "誰知絕險外，復有蓬婆城。", "青天危輓輸，剽攘加怖驚。", "奏函籲衆慼，仁言韙宗英。", "早願虎口奪，少紓魴尾赬。", "不勞嚴僕射，分弓窺敵營。"]'),
('8a9453aa-6b97-44e9-b0ce-977303607a10','又以堰事滯留姜主簿學父載酒相勞於離堆新繁宰鮮于子清永康理曹季德夫導江士鮮于才卿同會','程公許','宋','宋诗','song-poetry','','[]','穿江慨秦守，瞻岷懷子長。',204,'全唐诗/poet.song.194000.json','["穿江慨秦守，瞻岷懷子長。", "成書著不刊，明德益難忘。", "千載志尚友，百里職勸相。", "每負伐檀恥，欲期盡心償。", "籠石飽冬霽，雲車喧春陽。", "經始愧前哲，憫勞得仇香。", "選勝山水窟，浣我冰雪腸。", "飛幰集諸彥，引睇周八荒。", "暖翠凝黛面，晴雲抹川梁。", "清歌勸引滿，佳趣殊未央。", "舉頭萬仞雪，中有千斯倉。", "采薇亦勞止，薄斂恐未遑。", "何當洗甲兵，無以累廟堂。", "文移寬郡邑，靴鞭却藩方。", "源清流乃浚，葉瘁根必傷。", "念此意惝怳，憑高歌慨慷。", "不如邀飛仙，更與釂一觴。"]'),
('12a4666f-fe70-44cb-94fb-073274026a98','李西清先生創凌霄觀於潼川府治紅樓之上賦詩敬和韻','程公許','宋','宋诗','song-poetry','','[]','丈人氣湖海，合卧百尺樓。',276,'全唐诗/poet.song.194000.json','["丈人氣湖海，合卧百尺樓。", "引袖麾八極，無處豁前眸。", "肯以治城志，而忘天下憂。", "窘步爭徑捷，危炊迷劍頭。", "攀天限九閽，起家先一州。", "顧瞻衆山會，慘澹春色浮。", "憑高展遐眺，幾幅烟雨秋。", "象緯逼紫宸，飈輪通十洲。", "吏衙散鳬鶩，野盟參鷺鷗。", "所思隔秋水，倚天看吳鉤。", "寄懷廣莫外，任運逍遥遊。", "遐哉郝使君，一往歲月遒。", "名字著不朽，實繄杜參謀。", "後先五百年，意氣有此不。", "不須蘇門嘯，我自商聲謳。", "烟霞雜揮灑，風月共獻酬。", "跡忝梁苑舊，目送涪江流。", "可能呼小艇，醉歌賡四愁。", "宇縣暗矛戟，田原輟耡耰。", "念公志經綸，季孟忠武侯。", "肯袖斲泥手，江海寂寞休。", "檻前水東注，鼓枻不可留。", "撫翼附青雲，忍滯鶑谷幽。"]'),
('63ea7c74-ec96-4905-bfd2-61f8df8273b1','送考功劉大著出守嘉禾分韻得相字','程公許','宋','宋诗','song-poetry','','[]','夙昔抱奇志，取友周四方。',228,'全唐诗/poet.song.194000.json','["夙昔抱奇志，取友周四方。", "遠遊阻風塵，隠思鬰衷腸。", "羞以麋鹿性，綴茲鴛鷺行。", "三年去復還，同省皆望郎。", "劉侯交最久，德履金玉相。", "佩瓊矯衆嫮，製荷耿孤芳。", "暫寄錦衾直，倚登白玉堂。", "忽以刺郡請，翻然整歸裝。", "安輿擁鶴髮，懷綬榮錦鄉。", "那知槜李城，騎竹喧道傍。", "矯首候鳴騶，如渴須飲漿。", "紫禁屢入對，從前幾封章。", "肯袖活國手，春疇課耕桑。", "納約易爲入，公寧久回翔。", "熟看氣弘毅，致遠可易量。", "蹇我歸未能，遲留重慙惶。", "亦思丐一麾，庶以毫髮償。", "樂莫樂心知，執手歌慷慨。", "安得飛霞佩，雲霄相頡頏。"]'),
('ce8315f8-ca0d-4632-8845-d316ee2b26f5','送李季才戶部出守衡陽','程公許','宋','宋诗','song-poetry','','[]','君來我去國，我還君得州。',228,'全唐诗/poet.song.194000.json','["君來我去國，我還君得州。", "世事巧違人，參辰不同謀。", "庚午蜀貢琛，君名亞龍頭。", "回翔三十年，班序晚見收。", "邊聲震宇縣，樞筦須良籌。", "心期白粉闈，晉扈翠雲裘。", "忽以外庸請，高軒擁前騶。", "展也清廟器，若爲南國侯。", "事會轉轇轕，材難費搜求。", "似聞石廩峰，瓊佩鬰飛浮。", "其下維清湘，杜蘭滿汀洲。", "官閒足娛玩，聊以寬隠憂。", "良會當有期，玉泉來蹇修。", "芳聲保不沫，歲晏終綢繆。", "我迂諒無補，行世况鮮儔。", "言歸承明直，塵容祇含羞。", "思土重紆軫，風埃苦淹留。", "佇君建名業，同理溯峽舟。", "白首三間茅，相依岷峨陬。"]'),
('0a46eaa0-b905-497a-8c05-6e5b40aa6015','遂寧喻生畫鹿甚精介同官梁知丞謁余因令作八幅圖帳適赤城觀主惠一鹿甚馴未數日忽又一鹿奔至縣圃非邑士所豢養者竟不詳其所自來物理感召畫龍而致真龍似未足爲誕也借邑士張權父詩韻以贈之','程公許','宋','宋诗','song-poetry','','[]','生不逮治古，郊藪觀鳳麟。',144,'全唐诗/poet.song.194000.json','["生不逮治古，郊藪觀鳳麟。", "頗愛麋鹿性，似是我輩人。", "食苹詠周雅，祝網依湯仁。", "幸不主八卦，非關十二辰。", "無魂休我欺，掇皮詳皆真。", "佳哉喻生筆，能與元吉倫。", "雅可簿書堆，坐有澗壑春。", "適意自起卧，匿樹如徼巡。", "便思投手板，長嘯岸白綸。", "藉爾爲我駕，仙會陪末陳。", "人生幾舜華，洞天自靈椿。", "謹護此畫本，勿遣侵俗塵。"]'),
('95e29851-fc45-4323-ace4-e90f56164ebb','縣齋秋懷  其一','程公許','宋','宋诗','song-poetry','','[]','璣衡斡霄極，裘葛參歲功。',72,'全唐诗/poet.song.194000.json','["璣衡斡霄極，裘葛參歲功。", "榮瘁均一氣，何獨悲秋風。", "往哲不我待，今俗誰與同。", "渥丹易槁木，鬢鬒忽飛蓬。", "丈夫秉壯節，自信無終窮。", "願勒羲和鞭，長繫扶桑東。"]'),
('52c28230-36c4-442a-bba0-f288948095e0','縣齋秋懷  其二','程公許','宋','宋诗','song-poetry','','[]','弱齡去激昂，漸老增感慨。',72,'全唐诗/poet.song.194000.json','["弱齡去激昂，漸老增感慨。", "所親日以疏，既往不可貸。", "世途轉艱棘，意行懼顛沛。", "乾坤一戰場，今古幾變態。", "超超浮丘伯，何修獨堅耐。", "駕言從之游，永嘯塵劫外。"]'),
('fc876ba2-777a-4f1c-a7a3-4535df9c15e8','縣齋秋懷  其三','程公許','宋','宋诗','song-poetry','','[]','幼學自魯鄒，素心卑管商。',60,'全唐诗/poet.song.194000.json','["幼學自魯鄒，素心卑管商。", "誰令簡書縛，課我星火忙。", "我自友古人，渠肯兄孔方。", "飛檄浩盈几，泛窺隠中腸。", "閣束且登樓，雲鴻秋著行。"]'),
('a8ff05a8-b2e7-4d51-81c5-ecf05e80c734','縣齋秋懷  其四','程公許','宋','宋诗','song-poetry','','[]','春渠鍼綠秧，秋畦壓黄雲。',60,'全唐诗/poet.song.194000.json','["春渠鍼綠秧，秋畦壓黄雲。", "積憂稍緩带，轉手俄空囷。", "况彼東人子，石田加灼焚。", "算緡方趣辦，蒙袂須勸分。", "誰爲本根慮，天高聞不聞。"]'),
('1983153b-4186-4508-bf13-da2b8af1abda','縣齋秋懷  其五','程公許','宋','宋诗','song-poetry','','[]','瞿瞿彼奚窺，樊圃漫折柳。',72,'全唐诗/poet.song.194000.json','["瞿瞿彼奚窺，樊圃漫折柳。", "金甌費將護，鼎餗戒顛覆。", "屯雲曖將夕，西風一搔首。", "沉思扶持計，誰是穎脫手。", "需臑毋久翫，利處那得久。", "癙思恐傷人，聊復一杯酒。"]'),
('6a0d37ba-ad87-40f3-a80c-172232130c93','縣齋秋懷  其六','程公許','宋','宋诗','song-poetry','','[]','雲濤扶胥口，烟雨匯澤涯。',96,'全唐诗/poet.song.194000.json','["雲濤扶胥口，烟雨匯澤涯。", "知心隔湖海，悠悠我之思。", "玉堂真學士，衡門且棲遲。", "那知古渠陽，無地逃駭機。", "昔在肩洪崖，風騷屹相推。", "道遠苦莫致，孰與一解頤。", "皎皎彼白駒，空谷誰縶維。", "吉士國元氣，須造物扶持。"]'),
('10919c11-f059-4983-bb94-0deb1bafb913','縣齋秋懷  其七','程公許','宋','宋诗','song-poetry','','[]','蜀西金天晶，氣稟勇於義。',84,'全唐诗/poet.song.194000.json','["蜀西金天晶，氣稟勇於義。", "時臺紬書樂，一麾豈其志。", "堂堂蜀公孫，加璧不可致。", "語默未易闚，經綸那得避。", "君看西山岑，鬰積好雲氣。", "膚寸澤四海，斂退無一事。", "持以問亨泉，寒洌忍自閟。"]'),
('7aaf2732-abe6-4063-9bc3-b1ba22b58e1c','縣齋秋懷  其八','程公許','宋','宋诗','song-poetry','','[]','曉案環吏牘，朱墨勘舛差。',72,'全唐诗/poet.song.194000.json','["曉案環吏牘，朱墨勘舛差。", "自公借隙光，書函眩眼花。", "千里有命駕，同心樂無涯。", "秋空霜月明，秋山雲氣佳。", "留連忽重陽，列坐粲九華。", "良會不可失，醉酣整烏紗。"]'),
('c87c222b-4eeb-4889-b482-5ea28d66ed5e','縣齋秋懷  其九','程公許','宋','宋诗','song-poetry','','[]','古人日以遠，古心誰與共。',84,'全唐诗/poet.song.194000.json','["古人日以遠，古心誰與共。", "陳編如有覿，整袂神自竦。", "晝短疲衆喧，夜永息羣動。", "頼此一炷膏，假我數行誦。", "古今費探討，心力老賓送。", "世味久已空，餘業此偏重。", "歲晚儻得閒，只願書冊擁。"]'),
('e330865c-2f8b-4519-9339-f7ab8f2891c9','縣齋秋懷  其一○','程公許','宋','宋诗','song-poetry','','[]','學仙宗無爲，學禪空萬緣。',72,'全唐诗/poet.song.194000.json','["學仙宗無爲，學禪空萬緣。", "自昔抱奇志，師心爲真傳。", "失脚墮世網，茲事幾棄捐。", "惟有一念息，不受物欲牽。", "空花起滅處，我心長泊然。", "冷暖渠自知，妙處非言筌。"]'),
('ed24e59a-e645-499e-8cc5-e6b945e7d7dd','勞農安德鎮古剎過句德華園二首  其一','程公許','宋','宋诗','song-poetry','','[]','青煒留中分，風日和且釅。',132,'全唐诗/poet.song.194000.json','["青煒留中分，風日和且釅。", "冰綃熨遠空，雲錦織方甸。", "農政自古然，長官欲身勸。", "皤皤彼黄髮，懇懇余素念。", "胼胝無乃勞，推瀝不敢怨。", "文移窘星火，日夕靦顔面。", "所欣歲洊熟，况復江可堰。", "蒙袂奚自來，儲粟何以贍。", "瓣香企璇穹，徧界雨美膳。", "使民樂耕桑，爲國罷征戰。", "堯俗可盡封，嗚呼何日見。"]'),
('83b42331-e040-403b-8bbe-64e7fe562a7e','勞農安德鎮古剎過句德華園二首  其二','程公許','宋','宋诗','song-poetry','','[]','招提款松竹，古碣閲楷籀。',132,'全唐诗/poet.song.194000.json','["招提款松竹，古碣閲楷籀。", "惠然二友佳，共此一巵釂。", "扶携涉幽園，邂逅展遐眺。", "海棠飲未酣，芳檻破微笑。", "何如老桂叢，傲睨幾年少。", "清言愜襟期，轉首俄夕照。", "箯輿度杳靄，石梁穿窈窕。", "留連得奇賞，傲朗可無誚。", "聊憑一餉歡，緩我憂心悄。", "明知古難挽，嫌與俗同調。", "民勞儻得醫，氣脈猶可壽。"]'),
('67dd38d1-27b7-47dc-a95c-78f32f3f1df8','送平章解機政以保寧之節榮還里第','程公許','宋','宋诗','song-poetry','','[]','孔山高嵯峩，其下一區宅。',252,'全唐诗/poet.song.194000.json','["孔山高嵯峩，其下一區宅。", "敷床萬牙籤，寧取籯金積。", "委身事君子，星駕莫遑息。", "豈不念林巖，政爾柄樞極。", "巨川爾杭之，陛下心以懌。", "累章拜俞旨，告廷敭顯冊。", "一笑堂印拋，我友浮丘伯。", "士以名德重，如護萬金璧。", "受寵惕臨深，持滿常懼溢。", "恭惟學古胸，富有經世策。", "探懷取二三，興運際五百。", "賢人如參朮，足以壯國脈。", "茲理要密庸，寧復膠於迹。", "肘後可無傳，能使壽金石。", "先生還孔山，宸奎揭素壁。", "似勝平泉墅，林立萬株石。", "向來翹材館，楹桷富山積。", "終焉愧輪囷，可能補寸尺。", "淛潮浪拍天，歸帆風借力。", "百拜壽斯文，華皓配南極。", "何當脫拘攣，日侍維摩室。"]'),
('01fd8ab6-f6b3-4ed0-ac04-70fe3b3703c2','瀘水清','程公許','宋','宋诗','song-poetry','','[]','瀘水清，瀘水之清如鏡平。',408,'全唐诗/poet.song.194000.json','["瀘水清，瀘水之清如鏡平。", "蜀江西來流沄沄，內江胥命如逡巡。", "兩江合處聳百雉，表裏益梓巴夔分，如戶有限齒有唇。", "雲南與夜郎，甫隔東西鄰。", "山川之險守在人，武侯氣燄千古猶長存。", "有來范侯人中英，蜀國忠文之子孫，清姿勁氣排秋旻。", "立朝物望高縉紳，睥睨衆醉甘獨醒。", "烏臺縱好羞呈身，十年江海心朝廷。", "瀘水清，我歌慷慨君試聽。", "蜀東諸鎮瀘最重，范侯之來更覺一面如金城。", "東軍之驕昔所患，南詔之黠那易馴。", "我侯方寸澄止水，鎮以寡欲撫以誠。", "重門嚴柝夕烽冷，紫邏雜耕膏雨勻。", "七年逗遛不得去，邊民愛侯有如父母親。", "今年北邊羽書急，兩川夫調紛苛征。", "吏敲門，農輟耕，期限迫星火，頃刻那得停。", "黄金棄賣如土賤，楮幣翔踴餘貫緡。", "立談之頃富作貧，縣官忍復規其贏。", "五十六州洶洶如浪沸，獨有三瀘之江清復清。", "有客東州來，爲我委曲陳。", "范侯疇昔澹無累，貫朽之積本爲民。", "二分官與輸一分，一分猶恐民顰呻。", "軍儲糴本仍借給，少待秋熟寬作程，風和日晏江上村。", "老醉稚擁爭扶迎，吏呼何曾怒目瞠。"]'),
('83ae5031-cc8e-48ab-ac2a-2ebeab88ab4e','青山高爲宋郎中德之作','程公許','宋','宋诗','song-poetry','','[]','青山高，六六峰。',412,'全唐诗/poet.song.194000.json','["青山高，六六峰。", "瑶鎸嵽嶪千萬仞，斗起西南天半空。", "蒸嵐噴薄不得洩，翠屏掩靄深幾重。", "不知丹梯委曲到何許，飛樓傑觀縹緲疑神功。", "丈人天上足官府，愛此疊嶂高巃嵷。", "奏疏白玉京，此山上帝之離宮。", "臣請爲帝守宮鑰，檢課列仙功行之異同。", "帝憑玉几頷其奏，導以絳節雙青童。", "岳靈嶪峩遠奔命，其下瀆鬼趨濛鴻。", "丹書校錄曉繼夕，朱衣執侍嚴且恭。", "赤明龍漢屈指今幾劫，珠幢羽帔可想不可蹤。", "雲璈鏗鍧洞天曉，步虛寥亮閶闔風。", "有時山空夜永斗柄出復沒，眩眼千炬煜煜燈吐紅。", "嗚呼青山高兮六六峰，丈人宮闕兮遠層穹，飛仙來往兮安得逢。", "山中人兮媚幽獨，烜山緒兮雪谿翁。", "形癯霄漢舞皓鶴，神茂晴巒森老松。", "三生曾侍丈人之左右，出入孔老竺乾之學該以通。", "把茅山間二十年，幽棲活計那諱窮。", "白雲四壁兮風月窗櫳，玉泉如飴兮柏實可饔。", "丈人憫世日混濁，敕遣下山開瞽矇。", "被髮鞭麒麟，駕霆呵靈霳。", "高岡一鳴衆鳥瘖不吐，修門再入九虎獰以攻。", "飄然整我飛霞佩，佳山水處挾冊從。", "仙槎尚有樓突兀，蕩漾萬頃風濤中。"]'),
('4d675adf-2765-4e84-a665-382567b14886','岷峨歎','程公許','宋','宋诗','song-poetry','','[]','出門厭氛囂，歸卧集萬感。',386,'全唐诗/poet.song.194000.json','["出門厭氛囂，歸卧集萬感。", "憑高一以眺，忽覺岷峨慘。", "岷峨山色千古同，非烟非霧愁溟濛。", "杜陵昔歎珠玉走，彼猶有幸天府供。", "人才何但珠玉貴，不得與爾包貢同上明光宮。", "山靈對我有慙色，茲事如何專汝責。", "非關地氣有衰旺，直恐峽山之流日夜蕩潏傷土脈。", "不然君相造命天地同其公，車書萬里文軌通。", "南金東箭輸不竭，岷峨之産何獨窮。", "沉思夜繼日，嘆息復嘆息。", "忽夢神官自天下，手持山靈一尺檄。", "鴻濛昔剖分，帝命作鎮主坤文。", "石紐之禹爲帝平水土，周家創業繫我彭濮人。", "紀信忠漢世，甘受黄屋焚。", "何武仗劍起，義不屈莽新。", "費貽任永恥爲井蛙辱，張綱李固義烈排秋旻。", "炎精焰冷國鼎峙，惟我全蜀倔强爲漢臣。", "人人名節九鼎重，餘事文章兼隠淪。", "子雲相如王子淵，康山之李金華陳。", "涪江釣叟卜君平，千載猶能想清塵。", "皇皇藝祖得天統，北辰中天衆星拱。", "蜀遠只在殿西頭，一言撤盡藩牆壅。", "陳蘇范氏奮孤寒，事業詞華兩推重。", "渡江勳績張與虞，太史之李如晉董。"]'),
('d7978c34-e640-4eed-afa2-a4ca2644ecf5','憶昔行送李成之徵君','程公許','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','憶昔與君同射策，同舟同館心膠漆。',397,'全唐诗/poet.song.194000.json','["憶昔與君同射策，同舟同館心膠漆。", "萬言入奏甘棄置，頼有湖山好看客。", "歸裝濡滯及黄池，半菽寒菹作除夕。", "慨慷相與期古人，聊復名場借梯級。", "君家三秀立分鼎，太阿覺君鋒更穎。", "吏行鳬鶩鬨塵坌，寒露玉壺夐光炯。", "五羊仙伯兩眼明月秋，薦書萬里徹冕旒。", "四賢同時一網收，朔風扶柂長江流。", "遲頑我自費推激，隠憂百罹霜鬢出。", "未能勇决便幽棲，寧免隨陽睨殘粒。", "送君矯翮玉霄去，爲我一破胸怏悒。", "向來四海李兵部，正色立朝古遺直。", "九原凜凜有生氣，餘憤須與君湔滌。", "世故翻覆况多端，沉思使我心膽寒。", "誰生厲階今爲梗，涓涓不窒驚濤瀾。", "不知聚幾州鐵鑄此錯，百尺竿頭一步底處著。", "天位天職特用軒輊人，明眼勘破定何物。", "波流何可金石轉，鮑肆詎能蘭麝奪。", "君不見考功望郎諫疏瀝忠赤，垂紳滿朝皆太息。", "信有宗工妙繩尺，梁園我亦塵下客。", "法當冗散逃百謫，滿意諸賢拱霄極。", "讜言正論囊封溢，國勢不難一枰活。", "正途未易荆榛闢，有謀勿憚時造膝。", "救溺拯焚奚可失，海南波寬老龍蟄。"]'),
('0f6c59c1-1f0d-4aa6-8016-bb28451c501c','涪州荔子園行和友人韻','程公許','宋','宋诗','song-poetry','','[]','愁雲暖日愁無邊，荔枝園下客艤船。',264,'全唐诗/poet.song.194000.json','["愁雲暖日愁無邊，荔枝園下客艤船。", "嗚呼宴安毒於鴆，燎原戒之爝火燃。", "楊家妖女去復入，開元天寶治亂如手翻覆間。", "綠雲一縷天上去，食自不旨寢不安。", "長生昵語月皎皎，沉香醉夢春酣酣。", "羯鼓數聲花破萼，霓裳一曲天開顔。", "薰風殿開苦嫌熱，驪山聯轡來遊盤。", "汗綃紅透心渴煩，荔枝不來慘不懽。", "飛塵一騎關山曉，奔騰那知血濺道。", "一朝羽檄漁陽來，决策西狩殊匆草。", "百年宗社棄若遺，何計奈渠春風貌。", "雨鐸琅璫驚昨夢，雲棧崎嶇回馬首。", "凄凉故驛疾揚鞭，歲月轉眼弩落弦。", "張后李父自一時，西內荒階滿苔錢。", "金鑑難忘曲江相，浯頌長憐聱叟元。", "涪陵荔枝不須辨故物，紫金鱸骨何幸還陵園。"]'),
('40441500-35b1-48d9-842c-375838e5dca7','蕊珠歌','程公許','宋','宋诗','song-poetry','','[]','五雲鬰勃天九重，俯視人境塵濛濛。',336,'全唐诗/poet.song.194000.json','["五雲鬰勃天九重，俯視人境塵濛濛。", "元和遷校品秩穹，以帝命鎮北坎宮。", "玄袍金鎧丁甲從，洞陰戰勝魔絕蹤。", "際江之涯鍾氏童，宿運冥契晞玄風。", "躡屩千里心忡忡，戃恍忽與師匠逢。", "桑梓歸愒敢不共，精廬築就鈴岡東。", "州西一舍獅子峰，烟霞萬壑鎖鬰葱。", "勢與紫霄爭長雄，樓觀營築擬翠蓬。", "真遊下駐鳴笙鏞，可無法言牖羣蒙。", "帝何言哉層穹窿，溟涬未辨奚所宗。", "五文開明日曈矓，三洞流出金口中。", "瑶函錦囊密緘封，飈輪八面轟霻霳。", "駿奔百靈翔六龍，一念與誦萬過同。", "登揖金母朝木公，六天獰戾數有終。", "申命校錄帝所恫，保制劫運禳災凶。", "剪馘鬼怪囚北酆，邊垂罷戰年屢豐。", "妖氛退掃正道隆，臣許職牧羞妄庸。", "願見皇圖還時雍，蕊珠七言歌舂容。", "爲師勸相鳩僝工，咄嗟千桂凌碧空。", "開度益廣積累功，丹臺列名仙籍通。", "伐石著詞傳無窮，長與此山同峻崇。"]'),
('b017d6ad-9c3a-44f7-b4f8-fb7d22da34e1','唐彭州改創南樓爲賦長歌','程公許','宋','宋诗','song-poetry','','[]','小洛陽城春日釅，翠幙家家誇國艷。',334,'全唐诗/poet.song.194000.json','["小洛陽城春日釅，翠幙家家誇國艷。", "圍花命酒十日狂，何如水月山雲日日長相見。", "西州藩牧最佳處，古木陰森湖瀲灧。", "湖漘傑觀倚南牆，剝雨催風歲久不能繕。", "後先知有幾賢牧，因循何啻閲亭傳。", "算緡懼不貸主計，星火那能卹諸縣。", "丹崖唐侯來布宣，世故平生金百鍊。", "能將姦穽先杜斂，不勞民膜加鍼砭。", "焦心常念足公儲，退食遑暇娛賓燕。", "迨茲再稔治最成，聊爾計工財力羨。", "岧嶢飛檻抗雲表，顯敞華堂屹湖面。", "搜攬一州勝處尋丈間，恍覺蓬萊鼇首抃。", "樓成侯已迫瓜戍，澹雲寒烟有餘戀。", "君不見高詹事，吟詩花嶼巴箋絢。", "又不見宋朝散，照坐鞋紅玉壺勸。", "至今子美子瞻詩集中，能使吾州千古風流擅。", "唐侯美政前哲同，能自勒文比黄絹。", "謭陋愧我拙吟咏，漫綰秋蛇汙碑篆。", "江山風月今猶昔，墨客詞人元不欠。", "誰能落筆萬丈飛晴虹，九鼎雪山之銀堋江練。"]'),
('0dab2660-e298-4800-b0c9-3e7206c7e747','送仲嘉弟東歸赴湖州長興尉','程公許','宋','宋诗','song-poetry','','[]','喬松天與歲寒節，直從拱把禁霜雪。',256,'全唐诗/poet.song.194000.json','["喬松天與歲寒節，直從拱把禁霜雪。", "如君生小樂真筌，衆說咻之莫能奪。", "青春閉閤蛾眉怨，永日啖茹庖烟絕。", "交朋勸止徒爾爲，我亦無言可開說。", "老親坐堂眉不開，姑請聊向人間來。", "人間可欲如涕唾，此心久已同寒灰。", "太虛浮雲漫塵點，明鏡過影常往回。", "宰官居士等人耳，捨喧取靜非兼該。", "知君心量已超越，去盡障塞真奇哉。", "王城蝸屋欣再睹，燭盡鴉啼夜深語。", "云從投足窺吏曹，始知敝屣人爭恥。", "長興風物吾所羨，朝拏扁舟晚叩縣。", "霜刃割魚慎莫嘗，唯有青銅可照面。", "我行作吏三十秋，日暮不歸鳥飛倦。", "臨分欲效昔人言，畏子機鋒如閃電。", "出門揮手即江湖，猛利應無兒女戀。"]'),
('0e653c6a-106d-4cbc-aa0d-daba86267c6c','題會慶建福宮長歌','程公許','宋','宋诗','song-poetry','','[]','赤城峩峩五嶽尊，帝命作鎮西南坤。',336,'全唐诗/poet.song.194000.json','["赤城峩峩五嶽尊，帝命作鎮西南坤。", "崇岡遠自太白分，旁騫三峩下荆門。", "黛面負扆如帝宸，羣峰翼趨候臨軒。", "眈眈千柱樓雲根，黍禾之福此駿奔。", "叢霄其上爲崑崙，上帝宮闕森五雲。", "統御三界庀列真，精廬福地周八垠。", "稽首丈人希夷君，鼎峙潜廬猶弟昆。", "仙班峻極何司存，事嚴跡秘誰得聞。", "我亦三生師玄元，失脚世網如籠樊。", "雨淚懺洗一炷熏，琅函蘂笈披靈文。", "龍蹻無路尋軒轅，洪崖何處避俗喧。", "上皇羅家插青旻，麻姑公遠相爲鄰。", "欲往從之躡飈輪，凡骨未蛻空逡巡。", "白雲英爽恐未泯，似聞樵叟猶花坪。", "高尚無爲默不言，遺世獨立非不仁。", "世自迫隘汙我清，一杯聊共雲端論。", "松風忽作天籟鳴，浮雲富貴何足云。", "度世可不保此身，寸田荆棘當鋤耘。", "鬰儀結璘時吐吞，不願泛海尋蓬瀛。", "不願駕鶴朝玉京，只願餐霞餌黄精。", "閉息默坐持洞經，長與玉皇爲外臣。"]'),
('fe2030ba-e3d7-4198-a834-39c2130e423a','儲福觀謁唐玉真公主祠','程公許','宋','宋诗','song-poetry','','[]','華萼樓前花冥冥，三郎雅知睦天倫。',136,'全唐诗/poet.song.194000.json','["華萼樓前花冥冥，三郎雅知睦天倫。", "脂田恩厚脫屣輕，獨將泡影觀此身。", "碧瑶六六秀蜀岷，朝來鬰勃連夕曛，石壇虛呵存谷神。", "笳鼓驚散羯鼓春，兄來問信杳莫聞。", "瑶池宴酣歸未醒，千巖萬壑空烟雲。", "一念之差隔幾塵，蓬萊誰信有太真。", "平生我亦厭俗氛，秘籙曾受金闕君。", "玄機儻有三生因，不妨牧羊學初平。"]'),
('154e71a0-bf68-4cb8-bef3-d971f0abceb1','謝新胥口監征趙立之','程公許','宋','宋诗','song-poetry','','[]','魯壁嶧碑遠莫覩，艱哉河漢訊鼗鼓。',357,'全唐诗/poet.song.194000.json','["魯壁嶧碑遠莫覩，艱哉河漢訊鼗鼓。", "披荒摸搭不厭多，繙閱端能助稽古。", "向來四壁風雨秋，誰遣彯纓羣玉府。", "終年骯髒甘謫墮，采采蒿菁不盈筥。", "豈無蠹簡供咀味，竟恨白石費烹煮。", "有來剝啄契襟期，明誠無乃同而祖。", "千金湊買不知惜，傾囊要我細摩撫。", "評書已愧老蕭翁，作歌况擬昌黎愈。", "臨池强自學點𪑮，效顰寧容避譏侮。", "隸畫聊從祖逖窺，篆體那與陽冰侶。", "拜嘉深恐傷廉甚，贈詩想更用心苦。", "擔夫爭道大娘舞，精思神悟失寒暑。", "銛鋒未易畫錐沙，拱璧暗投等黄土。", "羊棗共嗜能幾何，圓規寧免齟方矩。", "岷峨之陽一茅宇，門無雜賓况市賈。", "圓書悔不偕載行，瞻佇崇朝不能俯。", "遥憐兵火暗跌蕩，守護童僕何不武。", "辱君珍贈補闕亡，金薤龍梭粲可數。", "我不能捨我靈龜觀朶頤，炊烟不動睡味恰與破衲宜。", "殷盤周鼎愧君古人以相期，瓠壺呺然問字無一奇。", "試烹苦茗能來與我共商略，功名兒戲可須千字淮西碑。"]'),
('fbc1d077-054b-4258-b552-aa69194e0c17','牛頭山寺','程公許','宋','宋诗','song-poetry','','[]','菩薩住處牛頭山，應真亦復棲其間。',64,'全唐诗/poet.song.194000.json','["菩薩住處牛頭山，應真亦復棲其間。", "寶坊樓觀疊高下，新城粉雉相回環。", "崎嶇石磴雲生屐，眼波不盡涪江碧。", "江外青山春自浮，曾與詩翁格椽筆。"]'),
('c5d5fc46-5e01-49ca-8bff-589a12a7da7e','爲建平詹使君賦山泉','程公許','宋','宋诗','song-poetry','','[]','秋風慄憀宋玉宅，湍波磕湧三閭祠。',224,'全唐诗/poet.song.194000.json','["秋風慄憀宋玉宅，湍波磕湧三閭祠。", "行人莫蚩我邦陋，離騷千古芳菲菲。", "使君玉立筍班上，得州如斗不薄之。", "冠峨切雲佩陸離，欲與二子論襟期。", "官居髣髴蓬島似，翠霧白雲山四圍。", "向來專情在巖壑，愛此線溜來逶迤。", "搜巖剔藪作幽事，便有一派銀河垂。", "釀泉爲酒旨且冽，環滁之樂同一時。", "有時痛飲挾騷讀，聲和泉石含餘悽。", "天涯有客倦行李，雲間小隊來追隨。", "窺公心源瑩澄徹，亦如此水涅不緇。", "里無追胥關薄征，峽山今是春臺熙。", "邦人恐公日邊在，誰卹我老字我蚩。", "何人勒銘泉上石，後千萬年甘棠詩。"]'),
('a489294b-3421-4879-a8cb-01ddfe8d4e9c','和南風歌','程公許','宋','宋诗','song-poetry','','[]','華清舞徹霓裳散，五音繁會宵達旦。',128,'全唐诗/poet.song.194000.json','["華清舞徹霓裳散，五音繁會宵達旦。", "人間何限失意人，西商凄切離騷亂。", "我所思兮在東周，小雅盡廢心之憂。", "更堪羌調日嘈雜，徑欲洗耳寒江流。", "那君十指含清風，家無卓錐心願豐。", "仙翁賞音那易得，水流益濬山益崇。", "疲氓望翁起憔悴，蒲輪加璧幸可致。", "請君抱琴往從之，解慍阜財皇有意。"]'),
('56fdab16-50f7-4fad-8371-8a356e23627e','喜雨歌','程公許','宋','宋诗','song-poetry','','[]','去年堰决秋雨霪，南畝粒米如黄金。',240,'全唐诗/poet.song.194000.json','["去年堰决秋雨霪，南畝粒米如黄金。", "縣官只道歲中熟，輸租歸家雷隠腹。", "老翁戒兒力鋤耰，忍饑少待明年秋。", "那知六月又不雨，二江之流幾齟齬。", "揵石震撼渠欲枯，天遠不聞人號呼。", "皇華使者民司命，腸日九回恐民病。", "齋居蔬食勤箋天，灌口牲幣加明蠲。", "燎烟升空忽黮䨴，須臾六合澤霶霈。", "連宵簷響未渠休，溝塍泫泫膏乳流。", "疲氓彈指拜公賜，枵腸便覺有生意。", "邊城十年戢干戈，鄰焰逼我將奈何。", "可憐十室九垂罄，倉卒軍需何以應。", "人情但知樂苟偷，更須熟爲根本謀。", "察公憂民意懇懇，定知憂國慮深遠。", "爲公志喜商聲謳，願公爲霖澤九州。"]'),
('dee6ce6e-04cb-4e9f-8992-d2c3d737def7','喜雨上使君','程公許','宋','宋诗','song-poetry','','[]','塞垣昏昏纏殺氣，春陽暵旱慘如燬。',256,'全唐诗/poet.song.194000.json','["塞垣昏昏纏殺氣，春陽暵旱慘如燬。", "老蛟熟睡呼不起，暴尪鞭巫徒爲耳。", "雲將族兮俄披靡，飛廉之怒誰或使。", "綿州刺史亦勞止，寢不遑安食不旨。", "瀝膽濡毫肝作紙，封章夜訴天尺咫。", "電幟簸紅雷虺虺，一篩時有萬絲委。", "旬浹頻占垤封蟻，半夜流膏活千里。", "瓦溝佳聲密飄灑，簫韶九奏未堪擬。", "焦卷一朝有生意，夢魚之占立可俟。", "中原格鬭何時已，軍儲急須問庚癸。", "剝膚駸駸幾及髓，國脈所寄將奚恃。", "腐儒流浪半環水，月蠹太倉三斛米。", "干時無策顙有泚，况忍懶書酣晝寐。", "知元道州漢良吏，可無長歌爲志喜。", "北風漲塵目易瞇，安得天河一湔洗。", "豐年高廩萬億秭，重見周道平如砥。"]'),
('36572711-6747-454f-a2ad-e260dfcbab5b','西瞻堂','程公許','宋','宋诗','song-poetry','','[]','子長愛奇隘八荒，岷雪千仞瓊珮鏘。',64,'全唐诗/poet.song.194000.json','["子長愛奇隘八荒，岷雪千仞瓊珮鏘。", "太守德厚民不忘，倚公筆椽輝耿光。", "西瞻大書揭高堂，倚欄起我意激昂。", "鏤冰刻楮非文章，男子可不志四方。"]'),
('d46407c3-3157-4721-abb4-f59f9cd459a7','送李微之以史學召','程公許','宋','宋诗','song-poetry','','["\u6cf0\u5c71", "\u957f\u6c5f"]','鴻蜚冥冥天宇空，誰令矯翮修門羾。',320,'全唐诗/poet.song.194000.json','["鴻蜚冥冥天宇空，誰令矯翮修門羾。", "承平在昔朝多賢，猶念丘園天爵共。", "泰山豹林來復去，河南白雲堅不動。", "斯文程伊嗣興起，露門日日峨冠誦。", "雖然去就跡參差，高風等是光吾宋。", "秀巖素心非少室，萬卷本期供世用。", "當家幸有二仲賢，不妨老子琴三弄。", "紛披竹素勤日課，蕭索松風酣午夢。", "有來虞旌賁空谷，例與蜀珍入包貢。", "中興鉅典未殺青，千古傳疑須折衷。", "文孫嗣服渴延佇，太史泚筆待錯綜。", "姦諛已死不難誅，古今一轍猶聚訟。", "緇衣信能心愛士，白駒誰復語含諷。", "丈夫出處亦何常，毫芒難博丘山重。", "勿學退之憂史禍，勿似子長誇雍從。", "孤騫終不嚇腐鼠，覽輝未易來翔鳳。", "平生我亦煎百憂，四月長江遠追送。", "丁寧寄語季成甫，東華冠蓋真一鬨。", "時撐小舫漾湖光，莫遣紅塵撲飛鞚。", "扶持姱節早歸來，世故紛紛付時棟。"]'),
('4b9a85df-81ef-45c7-9521-8f97bde3d13a','送別周憲使','程公許','宋','宋诗','song-poetry','','[]','春風浩蕩龍泓口，逢逢船鼓驚雷吼。',384,'全唐诗/poet.song.194000.json','["春風浩蕩龍泓口，逢逢船鼓驚雷吼。", "皇華使者捧徵書，萬里飛帆上南斗。", "岷峨上下十六城，後先持節知幾人。", "公來非爭赫赫名，止水何曾風浪生。", "腕裏權衡一丹筆，與天通處惟欽恤。", "孰知疾惡有剛腸，乃似霜空鷹隼擊。", "撓之不濁澄不清，渠自好醜吾何心。", "蔽以一言仁者勇，嗜欲淺者天機深。", "疇昔聲華塞穹壤，旰食遥知渴忠讜。", "紛紛鰍鱔困掇拾，縱壑之鱗多漏網。", "公歸便合橫南床，或袖諫紙朝明光。", "好將外臺督姦手，鋤却廿年荆棘荒。", "功名時來寧我貸，不朽之傳軒冕外。", "攬轡埋輪自一時，至今日月炳前載。", "才踈意廣一腐儒，青冥倚公借吹噓。", "病卧錦江八十日，出門搔首空踟躕。", "西南望遠長安日，寒雋陸沉幾千百。", "乞與開陳政事堂，更把夾囊細收拾。", "軍興料須色目繁，師老力屈民煩冤。", "養疽一朝思潰裂，廟謀得不憂本根。", "三年福星耀參井，愛士如渴民如命。", "只今歸覲太微庭，勿忘棠郊日延頸。", "腐儒州縣甘浮沉，骯髒羞作附驥蠅。", "佇公入和南風琴，磨崖大書頌中興。"]'),
('13a7ed28-4930-462e-a4e1-2d758d93fda9','送崔吉甫外刺安康分韻得客字','程公許','宋','宋诗','song-poetry','','[]','崔郎神駿如天馬兮來西極，霜蹄蹴踏汗流赤。',314,'全唐诗/poet.song.194000.json','["崔郎神駿如天馬兮來西極，霜蹄蹴踏汗流赤。", "不令長楸嘶風扈屬車，亦合交河涉冰摧敵魄。", "世無善御如王良，可能帖耳受鞭策。", "棧雲嵯峩漢江碧，一眼長淮天不隔。", "風寒幾處索調護，我有奇謀同藥石。", "囊書行萬里，三載京華客。", "浮雲黯黮一掃空，歸來雙劍翔鳬舄。", "行臺岌嶪立分鼎，叱咤風霆人辟易。", "文書曉夜來急急，吏衙事牘看山積。", "那知退食清心堂，萬卷敷床客滿席。", "落落一世誰憐才，令我推枕三太息。", "翺翔半刺頭欲雪，袖長奈何地褊迫。", "我聞安康坦途走洛師，內與荆襄梁益通血脈。", "軍興生聚計蕭條，嗷嗷悲鴻尚中澤。", "鼓鼙何日當罷警，濟時孰是良籌畫。", "薰風催熟崆峒麥，本根須人爲愛惜。", "志士慘淡意則同，摻袪况復念行役。", "君看老驥久伏櫪，一蹴千里如咫尺。", "醉歸爲君慨慷擊唾壺，天雞三叫東方白。"]'),
('5d9e6377-d23b-474e-a3e3-342697504f3e','觀浩齋楊先生偕後溪劉先生白鶴魏校書潼川南樓唱酬三復嘆仰馳介詢問以古篆體書西銘爲壽，並和元韻','程公許','宋','宋诗','song-poetry','','[]','一日不見如三秋，人如湘浦春風樓。',256,'全唐诗/poet.song.194000.json','["一日不見如三秋，人如湘浦春風樓。", "危途崔嵬坂九折，萬事變滅水一漚。", "我公方寸湛古井，砥柱四海之頹流。", "藝蘭九畹媚幽處，公暇獨立誰爲儔。", "畏虎一悟真知說，亡羊不向諸子搜。", "默參鄒軻論直養，長與潛聖同四憂。", "綉衣方看霄漢立，青雲忽賦汎濫浮。", "平生得趣稽古樂，如水赴海無時休。", "考槃棲我書萬卷，有意晚歲專一丘。", "時無子西賦招隠，貪伴漁翁歸釣涪。", "澗瀍脈絡元不斷，洙泗氣象端可侔。", "身縻簡書去無繇，夜夢策蹇霜滿裘。", "悠悠底是歸宿處，願聞一語歸而求。", "勇撤臯比誰復見，訂頑之訓萬古留。", "篆書爲公揭素壁，千里持寄寬離愁。", "玄關道祕杳莫授，玉鑰爲我一啟不。"]'),
('ca2e87c9-0a13-458a-9237-360a526cc991','池口昭明太子釣磯蜀僧住山相邀訪古和壁間韻','程公許','宋','宋诗','song-poetry','','[]','繫船池口汎濫遊，老禪邀我半日留。',128,'全唐诗/poet.song.194000.json','["繫船池口汎濫遊，老禪邀我半日留。", "岸莎堤柳度窈窕，初暑忽送風雨秋。", "蕭郎釣臺三間屋，萬頃烟波媚幽獨。", "長令千載好事人，貪爲淮山流遠目。", "芊芊蔓草迷長竿，臺城直作平野寬。", "那知萬古文選理，不盡詞源八節灘。", "英魂遠逝招不得，謫仙小杜底處覓。", "插天崷崒九芙蓉，試與憑高閒物色。"]'),
('a0aed618-a2ae-41e1-b54c-7e7cb76efcaa','多勝亭','程公許','宋','宋诗','song-poetry','','[]','昌黎文章緯河漢，只合彯纓侍香案。',368,'全唐诗/poet.song.194000.json','["昌黎文章緯河漢，只合彯纓侍香案。", "帝遣騎麟下大荒，肯爲吾州一笑粲。", "至今千里被膏沐，猶自霱雲餘絢燦。", "後二百年來祖侯，不以左官興寤歎。", "西園作堂娛歲豐，東城選勝湖波漫。", "不知此湖孰經始，秀水之涯矗堤垾。", "花嶼逶迤雙徑通，荷蕩淼莽三塘貫。", "憑堤築臺夐清曠，羈官頼此泄憤惋。", "嘉二三子南渡來，營葺頗能還舊觀。", "風流轉燭冷如鐵，仆雨摧風存者半。", "蹇余意倦直承明，次補適來忝藩翰。", "腐不能通柱後文，拙尤不辨牙籌算。", "自公正須豁滯懣，時屈何能事輪奐。", "支傾補壞聊復爾，護邃培高足娛玩。", "江山入手要彈壓，風月無邊供判斷。", "高賢一語真實錄，勝游雖多此爲冠。", "水花岸草錯雲錦，雨瘴清嵐無界畔。", "忘機自與鷗鷺親，無事從渠鳬鶩散。", "老仙音塵可得追，移得盧家石堅悍。", "題評倚重南軒翁，瞻相如瑟黄流瓚。", "迂頑我豈經世具，乞身去詠南山矸。", "作詩聊與來者期，何去後思可稱讚。", "尚友三賢自不差，時復憑熊一來看。"]'),
('f0456f95-d984-45d7-b47b-5613fddd467e','和賈伯用架橋築堤韻','程公許','宋','宋诗','song-poetry','','[]','策蹇僕僕忘寒溫，勞心惻惻桑棗村。',64,'全唐诗/poet.song.194000.json','["策蹇僕僕忘寒溫，勞心惻惻桑棗村。", "長虹卧穩烟雨面，千金屹障波濤痕。", "涉川利作初九益，括囊肯爲六四坤。", "道旁築室勿與議，可使正論成排根。"]'),
('b624e9a1-2e57-40b4-8811-11d423f351e1','六和塔寺館三宿和秀江亭詩牌韻','程公許','宋','宋诗','song-poetry','','[]','鯨呿鼇擲三神山，幻境起滅指顧間。',64,'全唐诗/poet.song.194000.json','["鯨呿鼇擲三神山，幻境起滅指顧間。", "東西帆檣來復去，得似上方僧獨閒。", "看山看水知多少，詩債責償殊未了。", "膠膠擾擾竟何如，早結把茅佚吾老。"]'),
('36406518-3448-44f4-beea-9d681148a733','雪峰道院','程公許','宋','宋诗','song-poetry','','[]','琅函真筌何所云，丈人嵯峩五嶽尊。',160,'全唐诗/poet.song.194000.json','["琅函真筌何所云，丈人嵯峩五嶽尊。", "矞雲晝護耀魄寶，玉繩夜低天市垣。", "瓊瑶其上矗千仞，冰雪爲人醒醉魂。", "飛鴻沒處杳難辨，飼虎遺跡應猶存。", "甘泉使君趣丘壑，薰爐默坐存崑崙。", "高齋圖史羅左右，大厦風月相吐吞。", "巖泉酒熟芳桂蘂，茶鼎火活蒼松根。", "坐邀麻姑來擘脯，祇恐摩詰難亡言。", "界天之雪滿窗戶，喚起老仙重與論。", "丁寧來者時汛掃，燕寢可避蜂衙喧。"]'),
('d1d90d79-26d1-45ce-b349-ab1ad5443079','凌雲李聖可西郊別墅創小亭屬余作風月無邊古篆四字爲扁顔平岡馮炳仲賦詩和者盈軸因賦此','程公許','宋','宋诗','song-poetry','','[]','我不願築受降城朔方職總管，又不願金狨繫馬西池萬人看。',202,'全唐诗/poet.song.194000.json','["我不願築受降城朔方職總管，又不願金狨繫馬西池萬人看。", "只願寬閒寂寞濱，倚醉高吟青玉案。", "秋霜斫蟹草泥滑，春浪叉魚楊柳貫。", "江湖長恐寸心違，世界饒君左手斷。", "水寒軒檻碧萬頃，山掃巫娥雲一段。", "鶴唳那愁蕙帳空，羊裘未讓嚴陵岸。", "是家太白孕英精，待詔鑾坡摛藻翰。", "藕船駕得玉井來，荔支腰重金章煥。", "至今人物說淳熙，可並成周歌伴奐。", "誰令七葉侍中貂，風月無邊奉娛翫。", "犧尊屢喚𣂏玉液，科斗何能體先漢。", "相期雲路早騫翔，分明世澤流波漫。"]'),
('fde4642d-8bad-4d8a-a05f-0f5a202d8321','諸友載酒飲滄江海棠下公許以上壽親庭不克與勝賞翌日招飲出示新作敬和元韻','程公許','宋','宋诗','song-poetry','','[]','杜陵老翁身轉蓬，浣花溪頭詩更工。',256,'全唐诗/poet.song.194000.json','["杜陵老翁身轉蓬，浣花溪頭詩更工。", "向來隠語最沉著，錦宮花里看曉紅。", "想當繞樹經營時，吟思拍拍春醅醲。", "重跗疊萼今勝昔，五百年遠誰爲容。", "使君結廬滄江上，補處不隔牛馬風。", "竹蹊花塢穿窈窕，佳趣似是桃源同。", "一年好春海棠擅，隔牆恨不載酒從。", "頗聞花陰喧語笑，何似橘仙隠巴邛。", "主人眼底有青白，風流駭俗阮嗣宗。", "化工不耐凌鑠苦，故使分薄阿堵中。", "那知陽春恣陶寫，何物芥此雲夢胸。", "玉湖亭上一尊酒，柳花漠漠江溶溶。", "錦機轉眼雪糝逕，還有明年春再逢。", "要知造物無盡藏，那肯一日居成功。", "商謳爲公不成調，誰叫閶闔箋天公。", "晚紅一醉亦聊爾，休逐滄浪垂釣翁。"]'),
('8b7096a4-aad4-4e7d-8314-60691a44321b','楊子春酌飲清節亭示諸公舊賦索和','程公許','宋','宋诗','song-poetry','','[]','雨餘熱喘思澡雪，有客叩門筇九節。',128,'全唐诗/poet.song.194000.json','["雨餘熱喘思澡雪，有客叩門筇九節。", "相携款竹墨池家，竹間張飲碧筒折。", "樅樅玉立肩相齊，何羨掖垣歌紫微。", "會須把臂入林去，山王掉首麾去之。", "骨相恐難飛食肉，功名浪費殺青竹。", "渭川自有千戶封，持此較彼差不俗。", "平生我亦厭榮觀，爲君醉眠蘄簟寒。", "人間有此碧玉鏡，那怕火繖張炎官。"]'),
('63705163-6e6e-4074-83b7-e15585b03770','滿戌有日置酒學宮爲諸友贈別','程公許','宋','宋诗','song-poetry','','[]','左綿山川平且寬，周遭四境皆奇觀。',168,'全唐诗/poet.song.194000.json','["左綿山川平且寬，周遭四境皆奇觀。", "廣文官曹冰雪寒，摧風剝雨無時安。", "巧手無麫良獨難，慚汗如瀋時一歎。", "浪浪春雨紅杏壇，堆盤苜蓿空闌干。", "三年轉燭槐夢殘，明當西郊掛征鞍。", "平生但知取友端，忍御艾蕭捐杜蘭。", "丁寧何須勸加餐，活計不但故紙鑽。", "孔轍回環顔一簞，君民堯舜無兩般。", "此印萬古元不刓，聚奎堂中儼衣冠，尚友謹勿輕杇墁。", "丈夫事業期不刊，脚根牢取百尺竿。"]'),
('7d364860-c88a-427d-bb6f-ac9cdab2e739','九日以酒贈雪江胡賢良蒙惠詩和韻','程公許','宋','宋诗','song-poetry','','[]','蓀壁辛楣芰荷屋，靜揖秋風酣聖讀。',128,'全唐诗/poet.song.194000.json','["蓀壁辛楣芰荷屋，靜揖秋風酣聖讀。", "占斷湖天拓戶封，不待詔書賜一曲。", "紅塵車馬交衢術，渠肯冠霞立於獨。", "滿城風雨又重陽，念子蕭踈對寒菊。", "雙壺遣贈灧蛆浮，想見羈愁盡蛾伏。", "高人一巢有餘地，底須駟馬駕車軸。", "但得長年交酒聖，不妨一笑命騷僕。", "若云歸隠須買田，巢由嗤人未免俗。"]'),
('0a157b35-a5a8-4e6b-81b6-5df729fa06d9','碧雲程道士自清江相過示以玉淵劉清叔詩借韻同賦','程公許','宋','宋诗','song-poetry','','[]','掣鈴者誰金門客，神秀迫人似曾識。',96,'全唐诗/poet.song.194000.json','["掣鈴者誰金門客，神秀迫人似曾識。", "八返未問龍虎交，一杯且薦琳腴碧。", "我昔卜隠大面山，招旌驅人難得閒。", "梗野自適麋鹿性，逡巡遠引鵷鷺班。", "始青一氣色非色，此中自有金丹訣。", "政須趺坐共商量，忍向塵勞磨歲月。"]'),
('d43ec4a2-98a2-43c7-8de6-7800f87c60b6','爲玉汝賦蓴湖借田家樂府韻','程公許','宋','宋诗','song-poetry','','[]','蓴湖何物堪怡悅，與鑑湖境無差別。',96,'全唐诗/poet.song.194000.json','["蓴湖何物堪怡悅，與鑑湖境無差別。", "詩人胸貯冰雪清，湖邊吟作寒螿鳴。", "紫蓴可羹菰可飯，把茅自足了一生。", "食前方丈位鈞軸，何如深林一枝足。", "寬閒之野寂寞濱，釣有緡竿耕有犢。", "男兒何須嗟命薄，富貴不淫貧賤樂。"]'),
('4565104d-fc10-4f04-a1e4-9f5f46f26c59','李宰和唐子西芙蓉溪詩索同賦','程公許','宋','宋诗','song-poetry','','[]','子西詩律傷於嚴，掉頭沉吟春飲酣。',96,'全唐诗/poet.song.194000.json','["子西詩律傷於嚴，掉頭沉吟春飲酣。", "何曾一字低處著，有似國工精手談。", "千古江山長媚好，水曹依舊清風掃。", "只慙次補較非才，更願乞靈依此老。", "天涯憔悴一詩窮，溪流泯泯山叢叢。", "事須登臨作酬賞，剩破酒榼官泥紅。"]'),
('cf9b9b1d-65e7-4d3e-8f98-052a1667abee','李季實以龍鶴山菜餠見惠長句將之呂兄亦有和章借韻答謝','程公許','宋','宋诗','song-poetry','','[]','山林遠志久封殖，誤隨小草輒輕出。',128,'全唐诗/poet.song.194000.json','["山林遠志久封殖，誤隨小草輒輕出。", "得似乾淳太史公，萬古不磨董狐筆。", "太史龍鶴山中人，翫心竹素如醉醒。", "鍊師喜爲作妙供，靈苗相間叢卉生。", "七年飄摇湖海客，生怕魚鯉腐關膈。", "圓規得自太史孫，清苦本來同氣質。", "十洲地産富瓊芝，龍鶴何曾欠蕨薇。", "與君約歸如有期，躍鯉何用薑芥胹。"]'),
('c4ccae19-ca9a-43b2-a12e-93f4b16063bd','和鍾道士若谷投贈韻','程公許','宋','宋诗','song-poetry','','[]','流年衮衮灘頭浪，蕭騷白髮三千丈。',262,'全唐诗/poet.song.194000.json','["流年衮衮灘頭浪，蕭騷白髮三千丈。", "人生榮祿底須多，何嗟及矣負米養。", "滄溟不禁尾閭泄，養素略窺道家說。", "庶幾真一復保全，可以衆言强分裂。", "瀛洲醉揮碧霞盃，集雲峰前偶此來。", "吏衙鳬散鈴索靜，怪有飛佩鏘瓊瑰。", "紫霄洞經曾熟讀，歸來烟霞繞冠服。", "嵯峨千仞獅子峰，寒棲旋營數間屋。", "飈遊爲我晷刻停，汲泉引滿如海鯨。", "要學旌陽累功行，不妨天詔遲飛昇。", "岷峨念歸可輕發，枉辦青鞋并布襪。", "禁闥侯藩信所遭，幾曾仰空虛咄咄。", "爐薰浪擬叩玄微，何如趙州東院西。", "了知此理只麽是，亡羊何必惑多蹊。", "自心有疑須自斷，勿用周遮添著一重案。", "鍊師鍊師爲我印證之，六合同風兮九州共貫。"]'),
('641e777e-4ac2-4dc2-8007-8db61d4a0c4f','和陸放翁笑詩呈雲端子','程公許','宋','宋诗','song-poetry','','[]','道人身佩含景蒼精龍，灑落不與流俗同。',80,'全唐诗/poet.song.194000.json','["道人身佩含景蒼精龍，灑落不與流俗同。", "酒酣興逸不覺一捧腹，那似義府有刀藏其中。", "人間萬事誰醜復誰好，兒童何知不必便驚倒。", "試問虎溪三士之樂如此不，霜寒夜永勿遣虛觥籌。"]'),
('bc806959-7291-4958-b700-b72bdee102fc','別雲端子和元字韻','程公許','宋','宋诗','song-poetry','','[]','玉樓雙聳吟肩寒，自孔氏出參玄元。',64,'全唐诗/poet.song.194000.json','["玉樓雙聳吟肩寒，自孔氏出參玄元。", "荒尋得君相指似，清吐對我如瀾翻。", "歸歟金華葺茅屋，間有洞戶通麻源。", "世塵轇轕勿浪出，執手且須空此尊。"]'),
('b72fa0f5-57f0-41d1-b948-026612f5d33a','寄謝碧雲張高士','程公許','宋','宋诗','song-poetry','','[]','臨邛自昔多仙才，鶴鳴神丹夜昭回。',317,'全唐诗/poet.song.194000.json','["臨邛自昔多仙才，鶴鳴神丹夜昭回。", "唐鴻都客尤奇俊，飛神碧落超蓬萊。", "宋采石戰强敵摧，少微褒封自公台。", "玄風寥寥閟寒灰，那知軒髯張，心印今復傳雲來。", "儒釋老氏鼎立如三才，凡囿形數由剸裁。", "授非其人委烟埃，如碧雲張亦異哉。", "幾年願見心渴梅，吾徒笑我老尚孩。", "三生髣髴同侍劫刃臺，羊腸百折何獨行虺隤。", "赤城醮盟三月齋，青雲有梯攀崔嵬，星冠禹步旋斗魁。", "天門蕩蕩金碧堆，章函歷上九虎開。", "津梁爽靈帝所哀，瞬息命令傳風雷。", "帝宸留侍非不佳，眷此濁海多劫災。", "力扶道法授沉埋，三千功行之積仙可階。", "世人汩沒井底蛙，各主其教相觝排。", "吾師思以一理該，與我心契無復猜。", "何當歲晚棄置塵累，棲巖一龕烟雲相與儕。", "芝朮可庖露可杯，商略道藴生死裁。", "左携羨門安期右洪崖，超塵沙劫馭氣凌九垓。"]'),
('25c0f846-edba-401c-ad0c-9d83220b8804','和小阮沇感時韻','程公許','宋','宋诗','song-poetry','','[]','豆籩列炙凌丘垤，有酒如澠旨且洌。',176,'全唐诗/poet.song.194000.json','["豆籩列炙凌丘垤，有酒如澠旨且洌。", "得似年豐世小康，漁樵結社談蜚屑。", "畏途羊腸徧宇縣，二十年間行未徹。", "憂時無力爲支撐，問計商顔未能决。", "頻年水旱釀災眚，况復刀兵值空劫。", "剜瘡補肉不遑恤，椎膚瀝髓供一切。", "詩歌碩鼠想樂郊，澤自無魚可堪竭。", "何時天狼隕芒焰，盡驅狐兔縶故穴。", "危機欲濟重坎陷，暴征須戢猛火烈。", "所期世路靜風塵，甘隠瓜疇耘露瓞。", "阿咸年少知激昂，勉法前修立功業。"]'),
('6b47f0d1-7dcd-48e9-9b19-6c8911454c38','先兄叔逢種花盆池秋初開一朵二姪感悼成韻作柏梁體答之','程公許','宋','宋诗','song-poetry','','[]','懷昔三昆皆青春，揮毫翻水驚鬼神。',120,'全唐诗/poet.song.194000.json','["懷昔三昆皆青春，揮毫翻水驚鬼神。", "我方丱角瞠後塵，有如奔林鹿甡甡。", "高堂壽朋鬢嚲銀，時節歌舞綵服新，二十年間存幾人。", "叔氏終老一葛巾，盆池折花秋中旬。", "共房感我雙瓜辛，無窮生意根陳陳。", "寸卉雖微均我身，壅培涵浸宜及辰。", "一氣之運屈必伸，子如不信有蒼旻。"]'),
('67f698cb-6441-4762-acc7-f2e28e573505','一冬無雪和陸放翁梅詩陸句豪誇余句清苦要自不失梅兄本分家風也','程公許','宋','宋诗','song-poetry','','[]','清羸怯問黄昏月，呵手寒窗寄幽絕。',128,'全唐诗/poet.song.194000.json','["清羸怯問黄昏月，呵手寒窗寄幽絕。", "一枝幽艷棖觸人，花與詩人皆本色。", "孤山飛鶴舞空去，詩家何曾絕正脈。", "經營慘澹空亡奇，不如倚筆珊瑚格。", "滕六冬來偏放惰，暖日暄風渾坼破。", "便擬飛章上訴天，怕主林神合連坐。", "我昔與梅同謫墮，隨分世塵聊贖過。", "薰天肉食休問渠，萬古清芬首陽餓。"]'),
('4765e96a-b926-4407-b01f-9327f85230c8','制幕孫君即益昌舍館疊石栽竹於盆池索賦','程公許','宋','宋诗','song-poetry','','[]','好山意度如高人，偃蹇那肯來朱門。',208,'全唐诗/poet.song.194000.json','["好山意度如高人，偃蹇那肯來朱門。", "青油幕中盛快士，愛山惟恐不能致。", "昭亭東望天一涯，武擔亦復歸遲遲。", "開窗延得竹君瘦，借竹爲媒來石友。", "烟雲吐吞一席間，瓦盆取月湖海寬。", "羽書撤警文書省，一炷水沉銷日永。", "不嗔鄰客喚門頻，支頤對翫玉嶙峋。", "平生我亦烟霞痼，强擬爲君援筆賦。", "破除幾許白雲腴，腸枯搜攪一句無。", "昨宵夢怕大刀折，詩債未償寧許別。", "從君差樂休念歸，賸借前箸裨籌帷。", "主公威聲劘敵壘，旆旌行拂終南翠。", "若携諸吏上崢嶸，容我後乘陪載賡。"]'),
('96f4f9c0-5260-4904-afd5-0b52a38b5d46','別馮伯昭新班歸三榮末句乞呈似使君王萬里年兄','程公許','宋','宋诗','song-poetry','','[]','東郭滄江市橋柳，邂逅論心成二友。',208,'全唐诗/poet.song.194000.json','["東郭滄江市橋柳，邂逅論心成二友。", "仙曹如水往復來，永晝論文間巵酒。", "十五年間如掣電，屋梁落月幾回首。", "愛君沖靜天機深，玉雪照我驚老醜。", "寶屏兩月同舍館，青眼相看祇如舊。", "秋風一鶚空百鷙，四海知心悅齋老。", "鵲聲查查客當還，鶴髮倚門春一笑。", "榮途埃𡏖倦馳騖，聖域工夫窺窔奧。", "拏雲豈無九霄志，緩轡徐驅千里道。", "平生我亦重擇交，與君同盟期耐久。", "紛紜歸夢促嚴裝，黯淡羈情更分手。", "旭川夙擅溪壑勝，雌堂况得文章守。", "贏糧寧憚兩日程，龍洞烟霞共幽討。"]'),
('ecc574c2-e904-4d29-9bfa-a96032228382','投贈洪倅司令舜俞','程公許','宋','宋诗','song-poetry','','[]','博陵先生天下士，圭瓚鼎彝宗廟器。',259,'全唐诗/poet.song.194000.json','["博陵先生天下士，圭瓚鼎彝宗廟器。", "駕風閶闔駐參旗，要與疲氓起憔悴。", "同來誰是儉府僚，一朶庾蓮吐秋水。", "義以取人道自任，河陽主賓信奇偉。", "誰云風月立分鼎，待借前籌答知己。", "峨岷其下十六城，魴魚鱍鱍更赬尾。", "情傷涸轍轉清波，陡覺濠梁復生意。", "井梧幕府省文書，雪界松圍絕烟燧。", "餘事何妨筆墨工，浣谿新沐烟雲膩。", "老翁補處待公續，燕外鷗邊儘吟思。", "主公佇還丹地峻，携上崢嶸去天咫。", "社樗愧我本亡奇，冷落官曹窮五技。", "何階方便來相招，醪醴一朝饗厚味。", "燕臺𡽱嶪萬金黄，豈意謙勤從隗始。", "眇然人物索扶持，勿惜拔茅多引類。", "君不見璇杓一夜摇天東，人間萬物皆春風。"]'),
('d7dd6f45-04b6-47c2-930b-e840fa306764','和謝孟彝祕丞館中書懷','程公許','宋','宋诗','song-poetry','','[]','虎頭一生信癡絕，虛名誤人可多竊。',323,'全唐诗/poet.song.194000.json','["虎頭一生信癡絕，虛名誤人可多竊。", "蕭踈白髮寧可貸，流浪紅塵幾時歇。", "三神山夐隔囂紛，衆君子聚瑩冰雪。", "麈犀時接寶唾香，玄關要待玉{𥫗氐}掣。", "緬懷元祐載賡唱，誰爲崇丘補亡缺。", "直廬竹帛不停披，酺池齋盂寧浪出。", "故都何在渺烟埃，湖山也自佳風月。", "擬結齊盟修故事，莫向深杯辭百罰。", "烝哉與我心事同，詩來可作成規揭。", "甚慙老醜强塗抹，得與嬋娟夸二八。", "靜思世故殊未艾，澒洞憂端不可掇。", "由來館殿育英髦，期爲朝家效絲髮。", "不然坐費玉帛招，奚異信手沙土撮。", "天閽何曾九關隔，愚慮或補萬分一。", "諸君信是廊廟具，老我已愧瓶罌溢。", "驚看淋漓灑巨軸，豈比呻吟點枯筆。", "吾儕立名要不朽，榮祿過眼才一瞥。", "從今朝謁得休暇，勿使文會多間闊。", "摩挲尊罍品書畫，上下古今商得失。", "乞歸早得隠林巖，誇與漁樵舊人說。"]'),
('3bf8f1c9-0f96-42f0-9583-96eb3e6b7dab','和使君王子堅游鄧氏天開圖畫韻','程公許','宋','宋诗','song-poetry','','[]','春風滿城開笑顔，使君明當出遊山。',128,'全唐诗/poet.song.194000.json','["春風滿城開笑顔，使君明當出遊山。", "東州山川北佳麗，凌雲耀日季孟間。", "紫絲步障元不要，飛檻層欄一憑眺。", "歲豐民樂征調寬，挾四老仙共舒嘯。", "使君吟肩李杜齊，落筆便覺三山低。", "招來倦客同賡載，韻險令我窘見擠。", "烟霞風月無疆界，不憂寒具油侵壞。", "寄謝摩詰休苦心，使君詩是有聲畫。"]'),
('c270b44d-6415-4c3d-af4d-8e3f4937e97f','壽悅齋李先生','程公許','宋','宋诗','song-poetry','','[]','君不見溫公崇福十五年，上下千載書法嚴。',345,'全唐诗/poet.song.194000.json','["君不見溫公崇福十五年，上下千載書法嚴。", "又不見蜀公靜退不待耄，鐘律製成天一笑。", "樂則行之憂則違，出處無非聖之時。", "一朝都人擁馬首，留相天子不得辭。", "潁昌胡爲屹不動，各以就去揭榘儀。", "悅齋先生天下士，琬琰琮璜國鎮瑞。", "盛名姱節耀古今，歲晚松階猶候對。", "時臺劇談鋸蜚屑，志堂析疑{𥫗氐}啟鑰。", "夜歸風雨一龕燈，目電窺書光爍爍。", "禹貢山川如指掌，漆園之解無郭象。", "更將次五訂箕疇，不妨後覺勤鑽仰。", "年來岷峨殊愴悽，公與潔齋名德齊。", "長庚磊磊配曉月，士有司命國蔡蓍。", "卧架詩書差足樂，憑高忍見楚氛惡。", "豈不望公勇拂衣，正恐百姓須公活。", "願公相業追元祐，以一至誠服雄狡。", "願公眉壽如東軒，黄髮皤皤國元老。", "雲蒸雨族霈作霖，賢以類聚治乃興。", "卷舒在公亦何心，四海矯首西山岑。", "薰風自南一披襟，起舞稱壽千黄金。", "洗耳五絃虞氏琴，爲公緩軫歌嗣音。"]'),
('3ef54def-b16f-4d9b-bafe-1ce52060fcce','壽李子先','程公許','宋','宋诗','song-poetry','','[]','正陽用事月初吉，騎鯨之孫生此日。',160,'全唐诗/poet.song.194000.json','["正陽用事月初吉，騎鯨之孫生此日。", "滴露能將三畫吞，積風少忍六月息。", "平生最耐反復看，其文炳彪心地直。", "骨肉十年長眼青，今年差覺叢談密。", "一尊稱處薰風曉，紅藥丫頭香露濕。", "誰令絕艷殿光景，羣葩斂避表獨立。", "洗盡人間丹粉妍，傾國傾城須正色。", "文章瑞世寧論晚，時來造物能借力。", "爲君折花起長歌，請君滿引無餘瀝。", "丹霄一武不難梯，更看飛階弄吟筆。"]'),
('f34c386b-1888-4d8b-81e7-a4354c91f88a','壽廷邁叔祖','程公許','宋','宋诗','song-poetry','','[]','吾宗譜牒祖通義，蟬聯到公十五世。',304,'全唐诗/poet.song.194000.json','["吾宗譜牒祖通義，蟬聯到公十五世。", "五派之分同一源，如木有本瓜有蔕。", "公家門戶最赫奕，簪紱相承真鮮儷。", "堂堂鐵面渠州牧，能以方寸永來裔。", "用之不盡地自寬，信有詩書爲可繼。", "龍駒墮地汗流赭，修途萬里自迢遞。", "箭鋒巧中由基的，桂香慳與春官第。", "誰知風雨短檠燈，慣作儒生窮活計。", "彤檐問俗歷三州，和平斂退鋒芒銳。", "羹藜任笑庖烟冷，嚼蠟倦親歌舌脆。", "似聞皇華催遣送，斗城未必能留滯。", "廣平傳緒五百年，凜凜千鈞若旒綴。", "藉公一力爲挽回，澡刷家聲舊芳桂。", "平生况耐反覆看，穮蔉懸知多斂穧。", "鼎來富貴正黑頭，粲粲芝蘭滿庭砌。", "周盟有幸聯肺腑，魯泮居然覺疣贅。", "所願宗風振寂寥，敢將末路竊聲勢。", "霧雨濛濛梅子黄，廉泉堂上薰風細。", "千金稱壽意何如，自倚情親爲新製。"]'),
('103946f6-2e93-41f0-972c-a7ab6e605c12','壽漕使者權帥黄大監','程公許','宋','宋诗','song-poetry','','[]','金華仙人紫綺裘，朝戲三山暮十洲。',328,'全唐诗/poet.song.194000.json','["金華仙人紫綺裘，朝戲三山暮十洲。", "偶經劍浦弭節留，浪花噴雪躍兩虯。", "海若禠氣馮夷愁，精英爲公一日收。", "義理之窟探魯鄒，詞章之工迫韓歐。", "榮途砥平不停輈，盛名何自徹冕旒。", "粉省賜香馥衣裯，萬里持節寬顧憂。", "更煩幕府開碧油，文書堆案如陵丘。", "焦心靡憚勤咨諏，賓朋遝進奚所求。", "否臧吾豈無陽秋，吏姦膽破民病瘳。", "肯綮可見才刃優，孰知學富用力周，取之不窮繭絲抽。", "寶書移監交置郵，斗水那能局吞舟。", "事機鼎來寧易投，紫清側席渴告猶。", "東風破冷初和柔，皇覽揆度當孟陬。", "矞雲我亦分餘庥，無階稱壽𣂏玉甌。", "眼明西南百尺樓，繡天錦地十六州。", "雅拜何以祈寵休，早徵環召飛鵠頭。", "潁川歸趣鼎鉉調，偉業定自追前修。", "承家有子文炳彪，燈燈之傳天與謀。", "殿前峩冠進鴻疇，杏園亦復聯俊游。", "斯文壽脈江漢流，何羨韋平世通侯。"]'),
('c780dbbb-6742-430c-9fef-8638d4d14112','壽程使君和獲白鴈詩韻','程公許','宋','宋诗','song-poetry','','[]','流膏千里喧笑聲，祥心萬丈南極星。',176,'全唐诗/poet.song.194000.json','["流膏千里喧笑聲，祥心萬丈南極星。", "祈年未了香火債，饌客肯汙刀鑊腥。", "此心與民同疴癢，出令可忍奔風霆。", "仙人飛來丹楓闕，俗眼詫見白鶴翎。", "蟻封縈策屈良御，牛軱輟刃煩庖丁。", "立談千仗環鐵甕，傾耳千行頒紫冥。", "雅知方寸厚培殖，未覺雙鬢輕飄零。", "馬蹄去踏東華塵，猿吟恐辜北山靈。", "賸將石田沃雨露，更爲嘉穀除蟊螟。", "寥寥宗風特扶起，懇懇善頌何丁寧。", "長生祕籙啟雲笈，紫府丹臺元不扃。"]'),
('e5a0f050-9253-42a7-8798-772c85c47fdb','壽制使董侍郎','程公許','宋','宋诗','song-poetry','','[]','秋雲陰陰壓邊城，秋風颯颯飛邊塵。',396,'全唐诗/poet.song.194000.json','["秋雲陰陰壓邊城，秋風颯颯飛邊塵。", "淮堧夕烽連峴首，往來羽檄無時停。", "那知籌邊樓上一長嘯，環六十郡皆陽春。", "老翁哺兒誇說尹，連年我倉歌既盈。", "皇明如在殿西角，恩許借留爲福星。", "六弧標慶當揆度，載途鼎沸歌謠聲。", "請公細酌成都酒，拄笏看度西山雲。", "只將祭酒瞪目意，坐鎮坤軸如砥平。", "可憐兒輩見坎井，孰知我公身遠萬里心朝廷。", "天生人物關運數，豈爲爾較山重輕。", "浙江時巡今四葉，上流地險如建瓴。", "强敵逆天天久厭，力困尚逞牙距獰。", "膽折棧雲不敢向，介胄酣眠宵徹明。", "雅知折衝妙方略，胸中歷歷不啻風雪身經行。", "我聞四海如一體，手足雖異脈絡元相親。", "癢疴何適不關我，仁者頃刻安得寧。", "吾皇盛德堯舜主，包瑕匿垢韜厥靈。", "一朝震怒詔薄伐，天戈所指壺漿迎。", "西南倚公九鼎重，草木亦自知威名。", "寶書斑斕真學士，陣圖指授諸將軍。", "頻來寵光對赫奕，富有學問規經綸。", "蜀才自昔比齊魯，公既崇學揚其文。", "更須度外廣物色，聲病未可拘豪英。", "蜀民生理日艱急，公既減賤矜其貧。"]'),
('39d2c724-91f8-4881-8b3d-dee66451ff2b','壽東師楊尚書','程公許','宋','宋诗','song-poetry','','[]','去年拜公北定堂，中秋翫月喧絲簧。',406,'全唐诗/poet.song.194000.json','["去年拜公北定堂，中秋翫月喧絲簧。", "長風趣駕泝江艇，恨不初度𣂏一觴。", "轉頭玉鑑秋又滿，北定風景遥相望。", "寸心炯炯千里共，欲往從之川路長。", "五年爲帝屏南服，掃清塞塵爲樂鄉。", "盡捐歲糴爲丁壯，米斛二萬饒積倉。", "民無箕斂士宿飽，一面屹立如金湯。", "平安遥夜飛炬火，燕寢永晝凝清香。", "雅知烹鮮不可擾，豈無發硎善而藏。", "官閒選勝極曠奧，天巧爲公時雨暘。", "五峰講席環子佩，北巖布金開道場。", "要將名教植根本，參以佛法芟莠稂。", "君不見海觀烟濤碧萬頃，衛公心眼周八荒。", "又不見開福浮屠玉千尺，給事願力同覺皇。", "得如我公志淑艾，未許二老相頡頏。", "眇然人物殊乏使，鼎來事會那可常。", "維北有斗天喉舌，乃作福星私一方。", "何不喚歸坐巖廊，五色線補舜衣裳。", "拓開賢路舊荆棘，勿遣旄頭森角芒。", "腐儒憂世心慷慨，百未一成鬢蒼浪。", "公憐不麾客倚牆，肯借齒頰加雌黄。", "頌言我豈知己私，民亦勞止須小康。", "岐山之顛豈無巢鳳凰，何時口銜瑞圖飛高岡。", "我亦刷翅相從千仞翔，引吭一聲鳴朝陽，請賦卷阿之詩之九章。"]');
